-- =====================================================================
-- Migration 102 — БОЛЬШОЕ ОБНОВЛЕНИЕ Этап 5.3/5.5: наполненные уроки
-- (7 и 8-26 июля) — тема+теория+quiz(+доп. сервис) для 156 занятий по 5
-- рабочим предметам × 3 группы. Контент авторски написан за один проход
-- (обеспечивает последовательность тем без повторов) через параллельный
-- Workflow-прогон 15 агентов — см. resheniya.md, раздел "Этап 5".
--
-- Урок за 7 июля (единственный прошедший день) получает status='completed'
-- + started_at/ended_at; остальные (8-26 июля) — 'scheduled', как и
-- пустышки после 26 июля (миграция 100).
-- =====================================================================
DO $$
DECLARE
  v_school_id CONSTANT uuid := 'a0a0a0a0-0000-0000-0000-000000000001';
  v_group_id uuid;
  v_subject_id uuid;
  v_lesson_id uuid;
  v_stage_id uuid;
  lesson_data jsonb;
  quiz_item jsonb;
  qpos int;
BEGIN
  -- === 10-А класс | Робототехника (9 уроков) ===
  SELECT id INTO v_group_id FROM public.groups WHERE name = '10-А класс';
  SELECT id INTO v_subject_id FROM public.subjects WHERE group_id = v_group_id AND name = 'Робототехника';
  IF NOT EXISTS (SELECT 1 FROM public.lessons WHERE group_id = v_group_id AND subject_id = v_subject_id AND description IS NOT NULL) THEN
    FOR lesson_data IN SELECT * FROM jsonb_array_elements('[{"topic":"Введение в робототехнику: понятие и классификация","objective":"Сформировать общее представление о робототехнике как междисциплинарной науке и научить классифицировать роботов по назначению и степени автономности.","theory":"Робототехника — это междисциплинарная область науки и техники, объединяющая механику, электронику, программирование и искусственный интеллект для создания автоматических устройств — роботов, способных выполнять полезные действия без постоянного участия человека. Слово «робот» происходит от чешского «robota» — тяжёлый труд; впервые оно прозвучало в пьесе Карела Чапека «R.U.R.» в 1920 году, хотя идеи механических помощников появились ещё в античности.\n\nНастоящая промышленная робототехника началась в середине XX века: в 1954 году Джордж Девол запатентовал первого программируемого манипулятора, а в 1961 году на заводе General Motors начал работать первый промышленный робот Unimate — он поднимал раскалённые металлические детали, заменяя человека на опасной операции. С тех пор роботы прошли путь от простых механических рук до марсоходов, хирургических роботов, беспилотных автомобилей и бытовых пылесосов.\n\nРоботов классифицируют по нескольким признакам. По назначению выделяют промышленных роботов (сварка, сборка на заводах), сервисных роботов (уборка, доставка, медицина, образование) и исследовательских роботов (космические аппараты, подводные дроны). По степени автономности различают роботов с дистанционным управлением (человек управляет каждым движением, как у сапёрного робота), полуавтономных (робот выполняет задачу, но человек контролирует ключевые решения) и полностью автономных (робот сам воспринимает окружение и действует без оператора — например, робот-пылесос, строящий карту квартиры).\n\nВажно понимать разницу между роботом и обычной автоматической машиной: робот обязательно обладает тремя компонентами — способностью воспринимать среду (сенсоры), «принимать решения» (управляющая программа) и физически воздействовать на мир (исполнительные механизмы). Стиральная машина выполняет заданную программу, но не реагирует на изменения среды — это не робот в строгом смысле. А робот-пылесос, «видящий» препятствие и меняющий маршрут, уже удовлетворяет этому определению.\n\nСегодня робототехника развивается на стыке физики, математики, программирования и электроники и применяется в промышленности, медицине, сельском хозяйстве, космических исследованиях и повседневной жизни. Изучая этот курс, вы пройдёте путь от базовых понятий электроники и микроконтроллеров до создания собственных алгоритмов управления роботом.","quiz":[{"question":"От какого слова произошёл термин «робот»?","options":["Английского \"robot\" (машина)","Чешского \"robota\" (тяжёлый труд)","Греческого \"robos\" (механизм)","Латинского \"robur\" (сила)"],"correctIndex":1},{"question":"В каком произведении и когда впервые появилось слово «робот»?","options":["В романе Айзека Азимова, 1942 год","В пьесе Карела Чапека «R.U.R.», 1920 год","В фильме «Метрополис», 1927 год","В статье Норберта Винера, 1948 год"],"correctIndex":1},{"question":"Какое устройство считается первым промышленным роботом, начавшим работу на заводе General Motors?","options":["ASIMO","Unimate","Roomba","Sojourner"],"correctIndex":1},{"question":"Какие три компонента обязательно должны быть у настоящего робота?","options":["Экран, батарея, корпус","Сенсоры, управляющая программа, исполнительные механизмы","Камера, GPS, Wi-Fi модуль","Колёса, двигатель, пульт управления"],"correctIndex":1},{"question":"Почему обычную стиральную машину нельзя назвать роботом в строгом смысле?","options":["У неё нет электродвигателя","Она не выполняет программу","Она не реагирует на изменения окружающей среды","Она слишком большая"],"correctIndex":2},{"question":"К какому типу по степени автономности относится робот-пылесос, самостоятельно строящий карту квартиры и объезжающий препятствия?","options":["Дистанционно управляемый","Полуавтономный","Полностью автономный","Программируемый вручную"],"correctIndex":2},{"question":"К какой категории роботов по назначению относится робот, выполняющий сварку кузовов автомобилей на заводе?","options":["Сервисный","Исследовательский","Промышленный","Бытовой"],"correctIndex":2}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-07T08:30:00+05:00","ends_at":"2026-07-07T09:15:00+05:00","room":"301"},{"topic":"Архитектура робота: сенсоры, контроллер, приводы","objective":"Научить выделять и объяснять функции основных структурных блоков любого робота: сенсоров, контроллера, приводов и цепи обратной связи.","theory":"Любого робота, независимо от его сложности — от простого робота-пылесоса до марсохода — можно описать через единую структурную схему из четырёх ключевых элементов: сенсоров (датчиков), контроллера (мозга), исполнительных устройств (приводов) и цепи обратной связи, которая их объединяет.\n\nСенсоры — это «органы чувств» робота. Они преобразуют физические величины окружающего мира (расстояние, свет, температуру, звук, положение) в электрические сигналы, понятные контроллеру. Ультразвуковой датчик измеряет расстояние до препятствия, посылая звуковую волну и замеряя время её возврата; фоторезистор реагирует на уровень освещённости; энкодер на валу колеса подсчитывает обороты. Без сенсоров робот был бы «слеп» и мог бы только слепо выполнять заранее заданную последовательность действий.\n\nКонтроллер — это «мозг» робота, обычно микроконтроллер (например, плата Arduino) или более мощный микрокомпьютер. Он получает данные от сенсоров, обрабатывает их согласно заложенному алгоритму и принимает решение, какую команду отправить исполнительным устройствам. Например, если датчик сообщает контроллеру «препятствие в 10 см», программа может содержать правило: «если расстояние меньше 15 см — остановиться и повернуть».\n\nИсполнительные устройства (актуаторы, приводы) — это «мышцы» робота, превращающие команды контроллера в физическое действие: электродвигатели постоянного тока (вращают колёса), сервоприводы (поворачивают руку-манипулятор на заданный угол), шаговые двигатели (обеспечивают точное позиционирование), а также светодиоды, динамики, электромагниты.\n\nЧетвёртый и самый важный принцип — обратная связь (feedback loop). Это непрерывный цикл: сенсоры считывают состояние мира → контроллер анализирует данные и принимает решение → приводы выполняют действие → это действие изменяет мир → сенсоры снова считывают новое состояние. Благодаря этому циклу робот способен адаптироваться к изменяющейся обстановке, а не просто повторять заученную программу. Робот, следующий по чёрной линии на полу, постоянно считывает датчиками положение линии и корректирует направление движения — классический пример замкнутого контура обратной связи.\n\nПонимание этой архитектуры — сенсоры, контроллер, приводы, обратная связь — фундаментально для всего дальнейшего изучения робототехники: каждая следующая тема курса подробно раскрывает один из этих блоков.","quiz":[{"question":"Как называется компонент робота, преобразующий физические величины (свет, расстояние, температуру) в электрический сигнал?","options":["Привод","Контроллер","Сенсор","Источник питания"],"correctIndex":2},{"question":"Какую роль в роботе выполняет микроконтроллер (например, Arduino)?","options":["Питает робота энергией","Обрабатывает данные и принимает решения — это «мозг» робота","Преобразует электрический сигнал в механическое движение","Измеряет расстояние до препятствий"],"correctIndex":1},{"question":"Что из перечисленного является примером исполнительного устройства (актуатора)?","options":["Ультразвуковой датчик","Фоторезистор","Сервопривод","Энкодер"],"correctIndex":2},{"question":"Как называется принцип, при котором результат действия робота снова считывается сенсорами и влияет на следующее решение контроллера?","options":["Программирование","Обратная связь","Калибровка","Автоматизация"],"correctIndex":1},{"question":"Почему робот без сенсоров не может считаться по-настоящему адаптивным?","options":["Он не сможет двигаться вообще","Он не будет реагировать на изменения окружающей среды","У него не будет источника питания","Он не сможет подключиться к компьютеру"],"correctIndex":1},{"question":"Робот едет по чёрной линии на полу и постоянно подстраивает направление движения. Какой принцип архитектуры робота здесь проявляется?","options":["Одноразовая калибровка","Замкнутый контур обратной связи","Дистанционное управление","Отсутствие контроллера"],"correctIndex":1},{"question":"Какой пример правильно иллюстрирует полную цепочку «сенсор → контроллер → привод»?","options":["Ультразвуковой датчик измеряет расстояние → Arduino анализирует данные → мотор останавливает робота","Мотор вращает колесо → Arduino включает светодиод → датчик измеряет температуру","Сервопривод поворачивается → датчик считывает угол → мотор выключается без анализа","Контроллер сразу воздействует на мир, минуя сенсоры и приводы"],"correctIndex":0}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-08T10:20:00+05:00","ends_at":"2026-07-08T11:05:00+05:00","room":"301"},{"topic":"Основы электроники: ток, напряжение, закон Ома","objective":"Научить объяснять понятия тока, напряжения и сопротивления и применять закон Ома для расчёта простых электрических цепей робота.","theory":"Любой робот — это, прежде всего, электрическая система, и чтобы понимать, как работают его сенсоры, контроллер и приводы, необходимо знать три базовые величины: силу тока, напряжение и сопротивление.\n\nЭлектрический ток (I) — упорядоченное движение заряженных частиц по проводнику. Он измеряется в амперах (А) и показывает, сколько заряда проходит через сечение проводника за секунду. Чем больше ток, тем «сильнее» электрический поток — но слишком большой ток может перегреть и повредить компоненты робота, поэтому в схемах применяют ограничивающие резисторы.\n\nНапряжение (U), или разность потенциалов, измеряется в вольтах (В) и показывает, с какой «силой» заряд проталкивается по цепи — это аналог разницы давления, заставляющей воду течь по трубе. Источники питания робота создают именно напряжение: например, плата Arduino Uno обычно питается напряжением 5 В, а сервоприводы и моторы — от 5 до 12 В.\n\nСопротивление (R) измеряется в омах (Ом) и характеризует, насколько сильно материал препятствует прохождению тока. Резисторы вносят в цепь заданное сопротивление, чтобы ограничить ток и защитить чувствительные элементы, например светодиоды, от перегорания.\n\nЭти три величины связаны законом Ома: I = U / R, где сила тока прямо пропорциональна напряжению и обратно пропорциональна сопротивлению. Если увеличить напряжение при том же сопротивлении, ток вырастет; если увеличить сопротивление при том же напряжении, ток уменьшится. Например, если к резистору 220 Ом подключить источник 5 В, через него потечёт ток I = 5 / 220 ≈ 0,023 А (23 мА) — именно такой расчёт инженеры делают перед подключением светодиода к Arduino, чтобы не сжечь его.\n\nВажно понимать два типа соединения элементов: последовательное (компоненты идут друг за другом, ток одинаков) и параллельное (компоненты подключены к одним точкам цепи, напряжение одинаково, а ток распределяется между ветвями). В схемах роботов часто используются оба типа: несколько светодиодов индикации могут быть соединены параллельно, а резистор-ограничитель — последовательно с каждым.\n\nПонимание этих основ электроники необходимо каждому, кто хочет не просто копировать готовые схемы, а осознанно проектировать электронную начинку своего робота, правильно подбирая резисторы и источники питания.","quiz":[{"question":"В каких единицах измеряется электрический ток?","options":["Вольты","Амперы","Омы","Ватты"],"correctIndex":1},{"question":"Что показывает напряжение в электрической цепи?","options":["Количество заряда, прошедшего за секунду","Разность потенциалов, «толкающую» заряд по цепи","Степень сопротивления материала","Мощность, потребляемую роботом"],"correctIndex":1},{"question":"Какова формула закона Ома?","options":["U = I + R","I = U / R","R = I / U","U = I / R"],"correctIndex":1},{"question":"Резистор сопротивлением 100 Ом подключён к источнику напряжением 5 В. Чему приблизительно равен ток в цепи?","options":["0,05 А","5 А","500 А","0,5 А"],"correctIndex":0},{"question":"Зачем в цепь со светодиодом обычно добавляют резистор-ограничитель?","options":["Чтобы увеличить яркость свечения","Чтобы ограничить ток и защитить светодиод от перегорания","Чтобы изменить цвет свечения","Чтобы уменьшить напряжение источника питания до нуля"],"correctIndex":1},{"question":"Чем отличается параллельное соединение элементов от последовательного?","options":["При параллельном соединении напряжение на элементах одинаково, а ток распределяется между ветвями","При параллельном соединении через все элементы течёт одинаковый ток","Параллельное соединение возможно только для резисторов","При параллельном соединении элементы обязательно должны иметь разное сопротивление"],"correctIndex":0},{"question":"Какую величину измеряют в омах?","options":["Силу тока","Мощность","Сопротивление","Напряжение"],"correctIndex":2}],"hasExternalService":true,"externalServiceType":"wokwi","externalServiceTask":"Соберите в Wokwi простую цепь: источник 5 В, резистор 220 Ом и светодиод. Рассчитайте по закону Ома ток в цепи и убедитесь, что светодиод не перегорает.","starts_at":"2026-07-09T12:10:00+05:00","ends_at":"2026-07-09T12:55:00+05:00","room":"301"},{"topic":"Микроконтроллеры и Arduino: архитектура и первая программа","objective":"Познакомить с архитектурой микроконтроллера и структурой простейшей программы (скетча) на плате Arduino.","theory":"Микроконтроллер — это миниатюрный компьютер на одной микросхеме, объединяющий процессор, память и порты ввода-вывода, специально предназначенный для управления электронными устройствами, в том числе роботами. В отличие от обычного компьютера, микроконтроллер не запускает операционную систему и не работает с множеством одновременных задач — он выполняет одну заранее загруженную программу снова и снова, точно и предсказуемо, что идеально подходит для управления роботом в реальном времени.\n\nОдна из самых популярных платформ для обучения робототехнике — Arduino, семейство плат с открытой архитектурой, созданное в 2005 году в Италии, чтобы сделать электронику доступной даже новичкам. Плата Arduino Uno построена на микроконтроллере ATmega328P и содержит: цифровые входы-выходы (читают/задают сигнал 0 или 1, «выключено» или «включено»), аналоговые входы (позволяют считывать диапазон значений, например уровень освещённости), разъём питания и порт USB для загрузки программы с компьютера.\n\nПрограммы для Arduino пишут на упрощённом варианте C++ в среде Arduino IDE. Структура любой Arduino-программы («скетч») состоит из двух обязательных функций. Функция setup() выполняется один раз при включении платы — в ней настраивают режимы работы пинов (например, объявляют, что пин 13 будет выходом для светодиода). Функция loop() выполняется бесконечно по кругу, пока плата включена, — в ней описывается основная логика поведения робота: считывание датчиков, принятие решений, управление моторами.\n\nКлассический первый пример изучения Arduino — программа мигания светодиода («Blink»). Она включает светодиод командой digitalWrite(13, HIGH), выжидает паузу командой delay(1000) (1000 миллисекунд = 1 секунда), затем выключает светодиод командой digitalWrite(13, LOW) и снова делает паузу — весь этот код помещён в функцию loop(), поэтому мигание повторяется бесконечно. Этот пример демонстрирует главный принцип работы контроллера робота: программа выполняется циклически, шаг за шагом, управляя реальными физическими устройствами через конкретные команды.\n\nПонимание архитектуры микроконтроллера и структуры setup()/loop() — фундамент, на котором строится вся дальнейшая работа с датчиками и приводами робота: каждый новый компонент, подключённый к роботу, будет считываться или управляться именно внутри этих двух функций.","quiz":[{"question":"Чем микроконтроллер принципиально отличается от обычного персонального компьютера?","options":["Он не может быть подключён к USB","Он выполняет одну заранее загруженную программу циклически, без операционной системы","Он не имеет памяти","Он работает только с языком Python"],"correctIndex":1},{"question":"На каком микроконтроллере построена плата Arduino Uno?","options":["Raspberry Pi","ATmega328P","ESP32","Intel Core i3"],"correctIndex":1},{"question":"Какая функция в Arduino-программе выполняется только один раз при включении платы?","options":["loop()","setup()","delay()","main()"],"correctIndex":1},{"question":"Какая функция в Arduino-программе выполняется бесконечно, пока плата включена?","options":["setup()","loop()","start()","init()"],"correctIndex":1},{"question":"Что делает команда delay(1000) в программе Arduino?","options":["Считывает данные с датчика","Приостанавливает выполнение программы на 1000 миллисекунд (1 секунду)","Увеличивает яркость светодиода в 1000 раз","Перезапускает плату"],"correctIndex":1},{"question":"Чем отличаются цифровые пины Arduino от аналоговых?","options":["Цифровые читают/задают только 0 или 1, аналоговые — диапазон значений","Аналоговые пины работают только с моторами","Цифровые пины нельзя использовать для вывода сигнала","Различий нет, это два названия одного и того же"],"correctIndex":0},{"question":"В каком году и где была создана платформа Arduino?","options":["2010 год, США","2005 год, Италия","1998 год, Япония","2015 год, Германия"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-14T08:30:00+05:00","ends_at":"2026-07-14T09:15:00+05:00","room":"301"},{"topic":"Датчики в робототехнике: принципы работы и подключение","objective":"Научить объяснять принципы работы основных типов датчиков робота и их подключение к микроконтроллеру.","theory":"Датчики (сенсоры) — устройства, превращающие физические явления окружающего мира в электрические сигналы, понятные микроконтроллеру. Без датчиков робот не способен воспринимать реальность и реагировать на неё, поэтому выбор и правильное подключение датчиков — один из ключевых этапов проектирования любого робота.\n\nУльтразвуковой датчик расстояния (например, HC-SR04) — один из самых распространённых сенсоров в учебной робототехнике. Он работает по принципу эхолокации: излучатель посылает короткий ультразвуковой импульс (около 40 кГц, за пределами слышимости человека), импульс отражается от препятствия и возвращается к приёмнику. Зная скорость звука в воздухе (около 343 м/с) и измерив время между отправкой и приёмом сигнала, контроллер вычисляет расстояние: расстояние = (скорость звука × время) / 2 (делим на два, так как звук проходит путь до препятствия и обратно). Такие датчики применяют для объезда препятствий и измерения расстояний.\n\nИнфракрасный (ИК) датчик работает похожим образом, но использует инфракрасное излучение; он часто применяется в датчиках линии — простых модулях с ИК-светодиодом и фотоприёмником, определяющих, тёмная или светлая поверхность под датчиком (чёрная линия отражает меньше света, чем белый фон), что используется в роботах, следующих по размеченной трассе.\n\nДатчик температуры (термистор или цифровой DHT11) изменяет сопротивление или выдаёт цифровой код в зависимости от температуры среды, позволяя роботу отслеживать перегрев компонентов или температуру в теплице.\n\nГироскоп и акселерометр измеряют соответственно угловую скорость вращения и линейное ускорение; их комбинация (часто в одном модуле IMU) позволяет роботу определять свою ориентацию в пространстве и удерживать равновесие — критически важно для шагающих и балансирующих роботов.\n\nВажно понимать: аналоговые датчики (фоторезистор, термистор) выдают непрерывный диапазон значений и подключаются к аналоговым входам (A0–A5 на Arduino Uno), тогда как цифровые датчики выдают только два состояния (0 или 1) и подключаются к цифровым пинам. При проектировании схемы важно учитывать напряжение питания датчика (обычно 3,3 В или 5 В) и не превышать допустимый ток, чтобы не повредить компонент.\n\nПравильный выбор и калибровка датчиков напрямую определяют, насколько «умным» и адекватным окружающей обстановке будет поведение готового робота.","quiz":[{"question":"По какому принципу работает ультразвуковой датчик расстояния HC-SR04?","options":["Измеряет яркость отражённого света","Измеряет время прохождения звукового импульса до препятствия и обратно (эхолокация)","Измеряет изменение магнитного поля","Измеряет температуру воздуха между датчиком и препятствием"],"correctIndex":1},{"question":"Почему в формуле расчёта расстояния ультразвуковым датчиком время умножается на скорость звука и делится на 2?","options":["Потому что звук идёт до препятствия и обратно, проходя двойной путь","Потому что датчик излучает два импульса одновременно","Это эмпирический коэффициент без физического смысла","Потому что скорость звука измеряется в двойных метрах"],"correctIndex":0},{"question":"Как работает простой ИК-датчик линии?","options":["Определяет тёмную и светлую поверхность по разнице отражённого инфракрасного света","Считывает магнитную полосу под линией","Использует камеру для распознавания цвета","Измеряет температуру поверхности линии"],"correctIndex":0},{"question":"Что измеряет гироскоп в составе инерциального измерительного блока (IMU)?","options":["Расстояние до препятствий","Угловую скорость вращения","Температуру окружающей среды","Уровень освещённости"],"correctIndex":1},{"question":"Для чего роботу может понадобиться акселерометр?","options":["Для измерения линейного ускорения и определения ориентации/равновесия","Для измерения силы тока в цепи","Для передачи данных по Wi-Fi","Для подсчёта пройденного расстояния колеса"],"correctIndex":0},{"question":"К какому типу пинов микроконтроллера следует подключать датчик, выдающий непрерывный диапазон значений (например, фоторезистор)?","options":["К цифровому пину","К аналоговому пину","К пину питания","К любому пину без разницы"],"correctIndex":1},{"question":"Что важно учитывать при подключении датчика к плате Arduino, помимо типа сигнала?","options":["Только цвет проводов","Напряжение питания датчика и допустимый ток, чтобы не повредить его","Только длину соединительных проводов","Только массу датчика"],"correctIndex":1},{"question":"Какая частота ультразвукового импульса обычно используется в датчике HC-SR04?","options":["Около 40 кГц (за пределами слышимости человека)","Около 40 Гц (низкий гул)","Около 4 МГц (радиочастота)","Ультразвук в датчике не используется вовсе"],"correctIndex":0}],"hasExternalService":true,"externalServiceType":"wokwi","externalServiceTask":"Соберите в Wokwi схему из Arduino Uno и ультразвукового датчика HC-SR04, напишите программу, вычисляющую расстояние до препятствия и выводящую его в Serial Monitor.","starts_at":"2026-07-15T10:20:00+05:00","ends_at":"2026-07-15T11:05:00+05:00","room":"301"},{"topic":"Приводы: DC-моторы, сервоприводы, шаговые двигатели","objective":"Научить различать основные типы приводов робота и объяснять принципы их работы и области применения.","theory":"Исполнительные устройства, или приводы (актуаторы), превращают электрические команды контроллера в механическое движение — это «мышцы» робота. В учебной робототехнике чаще всего применяются три типа электродвигателей: двигатели постоянного тока (DC-моторы), сервоприводы и шаговые двигатели, каждый из которых решает свою задачу.\n\nДвигатель постоянного тока (DC-мотор) — самый простой и распространённый привод. При подаче напряжения на его выводы вал начинает вращаться с определённой скоростью; если поменять полярность напряжения, направление вращения изменится на противоположное. DC-моторы используют для привода колёс мобильного робота: два независимых мотора на левом и правом колесе позволяют роботу ехать прямо (одинаковая скорость), поворачивать (разная скорость) или разворачиваться на месте (противоположные направления). Поскольку микроконтроллер не может выдать достаточный ток для мотора напрямую, между ними ставят драйвер двигателя (например, L298N), усиливающий сигнал и защищающий контроллер.\n\nСервопривод — двигатель со встроенным редуктором и датчиком положения (потенциометром), позволяющий точно устанавливать вал в заданный угол (обычно от 0° до 180°) и удерживать это положение. Сервоприводы управляются импульсным сигналом (ШИМ, широтно-импульсная модуляция): длительность импульса определяет угол поворота вала. Их применяют там, где нужна точная позиция, а не непрерывное вращение — например, для поворота манипулятора-«клешни», поворота головы с датчиком расстояния, управления рулём робота-машинки.\n\nШаговый двигатель устроен сложнее: его вал поворачивается не плавно, а дискретными «шагами» строго определённого размера (например, 1,8° за шаг), причём контроллер точно знает, на сколько шагов повернулся вал, даже без отдельного датчика положения. Это делает шаговые двигатели незаменимыми там, где нужна высокая точность позиционирования без обратной связи — например, в 3D-принтерах, ЧПУ-станках и роботизированных руках.\n\nВыбор типа привода зависит от задачи: для быстрого и простого вращения колёс подойдёт DC-мотор с драйвером; для точного угла поворота в ограниченном диапазоне — сервопривод; для высокой точности позиционирования на много оборотов — шаговый двигатель. Часто в одном роботе сочетаются несколько типов приводов: DC-моторы для передвижения и сервопривод для поворота манипулятора.","quiz":[{"question":"Что произойдёт с DC-мотором, если поменять полярность подаваемого на него напряжения?","options":["Мотор перестанет работать навсегда","Направление вращения вала изменится на противоположное","Скорость вращения увеличится вдвое","Мотор превратится в сервопривод"],"correctIndex":1},{"question":"Зачем между микроконтроллером и DC-мотором обычно устанавливают драйвер двигателя?","options":["Чтобы уменьшить напряжение питания микроконтроллера","Чтобы усилить сигнал и обеспечить достаточный ток, защитив контроллер","Чтобы преобразовать DC-мотор в шаговый","Чтобы добавить датчик расстояния"],"correctIndex":1},{"question":"Каким сигналом управляют сервоприводом?","options":["Постоянным напряжением фиксированной величины","Импульсным сигналом ШИМ, длительность которого задаёт угол поворота","Аналоговым звуковым сигналом","Радиосигналом Bluetooth"],"correctIndex":1},{"question":"В каком диапазоне углов обычно работает стандартный сервопривод?","options":["От 0° до 45°","От 0° до 180°","От 0° до 360° без ограничений","Только фиксированные 90°"],"correctIndex":1},{"question":"Чем принципиально отличается шаговый двигатель от обычного DC-мотора?","options":["Он вращается только в одном направлении","Его вал поворачивается дискретными шагами известного размера, что даёт точное позиционирование без отдельного датчика","Он не требует электропитания","Он используется только для звуковых сигналов"],"correctIndex":1},{"question":"Как мобильный робот с двумя независимыми DC-моторами на колёсах может развернуться на месте?","options":["Вращая оба мотора с одинаковой скоростью в одну сторону","Вращая моторы в противоположных направлениях","Отключив оба мотора","Это невозможно без третьего колеса"],"correctIndex":1},{"question":"Где чаще всего применяют шаговые двигатели?","options":["В пультах дистанционного управления","В 3D-принтерах, ЧПУ-станках и системах точного позиционирования","Только в бытовых вентиляторах","Только в источниках питания"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-16T12:10:00+05:00","ends_at":"2026-07-16T12:55:00+05:00","room":"301"},{"topic":"Алгоритмы управления роботом: ветвления и циклы","objective":"Научить строить алгоритмы управления поведением робота с использованием линейных структур, условных операторов (ветвлений) и циклов.","theory":"Поведение любого робота задаётся алгоритмом — точной последовательностью инструкций, которую выполняет контроллер. Чтобы робот вёл себя разумно и реагировал на изменения обстановки, а не просто повторял одну и ту же последовательность действий, программисты используют три базовые управляющие конструкции: линейную последовательность, ветвление и цикл. Эти конструкции — фундамент любого языка программирования, включая C++ для Arduino, Python и визуальные блочные языки вроде Scratch или Blockly.\n\nЛинейный алгоритм — простейший тип, в котором команды выполняются строго одна за другой, сверху вниз, без пропусков и повторений. Например: «включить мотор → подождать 2 секунды → выключить мотор» — робот проедет ровно 2 секунды и остановится, независимо от того, что происходит вокруг. Такой алгоритм подходит только для простейших предсказуемых сценариев.\n\nВетвление (условный оператор if...else) позволяет роботу выбирать разные действия в зависимости от данных, полученных от датчиков. Синтаксис: «ЕСЛИ (условие истинно) ТО (действие А) ИНАЧЕ (действие Б)». Например: «ЕСЛИ расстояние до препятствия меньше 15 см, ТО остановиться и повернуть направо, ИНАЧЕ продолжать движение вперёд». Именно ветвление превращает робота из простого исполнителя программы в устройство, реагирующее на реальную обстановку.\n\nЦикл — конструкция, позволяющая многократно повторять один и тот же блок команд, пока выполняется определённое условие, без дублирования кода вручную. Есть цикл с фиксированным числом повторений (например, «повторить 4 раза: проехать вперёд и повернуть на 90°» нарисует квадратный маршрут) и цикл с условием (например, «пока датчик линии не обнаружит линию — двигаться вперёд»), выполняющийся, пока условие остаётся истинным, причём заранее неизвестно точное число повторений. Функция loop() в Arduino — это уже готовый «бесконечный цикл», внутри которого чаще всего размещают собственные вложенные циклы и ветвления.\n\nНа практике эти конструкции почти всегда комбинируются: типичная программа объезда препятствий представляет собой бесконечный цикл, внутри которого на каждой итерации считывается датчик расстояния и выполняется ветвление (если препятствие близко — повернуть, иначе — ехать прямо). Умение комбинировать линейные блоки, ветвления и циклы — ключевой навык алгоритмического мышления, без которого невозможно написать содержательную программу управления роботом.","quiz":[{"question":"Что представляет собой линейный алгоритм?","options":["Последовательность команд, выполняемых одна за другой без ветвлений и повторений","Программу с бесконечным количеством условий","Алгоритм, который никогда не завершается","Набор команд, выполняемых в случайном порядке"],"correctIndex":0},{"question":"Какая конструкция позволяет роботу выбирать разные действия в зависимости от показаний датчика?","options":["Линейная последовательность","Ветвление (if...else)","Комментарий в коде","Переменная"],"correctIndex":1},{"question":"Робот должен: «если расстояние меньше 15 см — повернуть, иначе — ехать прямо». Какую конструкцию здесь используют?","options":["Цикл с фиксированным числом повторений","Ветвление","Линейный алгоритм без условий","Рекурсию"],"correctIndex":1},{"question":"Какую конструкцию нужно использовать, чтобы робот проехал по маршруту в форме квадрата, повторив 4 раза «вперёд и поворот на 90°»?","options":["Ветвление","Цикл с фиксированным числом повторений","Линейный алгоритм без циклов","Функцию delay() без условий"],"correctIndex":1},{"question":"Чем цикл с условием отличается от цикла с фиксированным числом повторений?","options":["Он выполняется, пока истинно указанное условие, и заранее неизвестно точное число повторений","Он всегда выполняется ровно один раз","Он не может содержать вложенные команды","Он используется только для мигания светодиода"],"correctIndex":0},{"question":"Чем фактически является функция loop() в Arduino с точки зрения алгоритмических конструкций?","options":["Линейным алгоритмом без повторений","Готовым бесконечным циклом","Разновидностью ветвления","Функцией, которая выполняется только один раз"],"correctIndex":1},{"question":"Типичная программа объезда препятствий сочетает цикл и ветвление. Что при этом происходит на каждой итерации цикла?","options":["Робот навсегда останавливается","Считывается датчик расстояния и выполняется проверка условия (повернуть или ехать прямо)","Программа завершает работу","Меняется код программы на лету"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"blockly_games","externalServiceTask":"Пройдите уровни игры «Лабиринт» (Maze) в Blockly Games, используя блоки условий (если/иначе) и циклов (повторить) для построения кратчайшего маршрута — это аналог алгоритма объезда препятствий роботом.","starts_at":"2026-07-21T08:30:00+05:00","ends_at":"2026-07-21T09:15:00+05:00","room":"301"},{"topic":"Обратная связь и основы ПИД-регулирования","objective":"Познакомить с принципом замкнутого контура управления и базовыми идеями ПИД-регулирования на примере движения робота.","theory":"В предыдущих темах мы рассмотрели, что робот воспринимает мир через датчики и воздействует на него через приводы. Но простое ветвление «если... то...» часто оказывается недостаточным для по-настоящему плавного и точного поведения робота — например, для удержания робота точно на линии. Для таких задач применяют более совершенный принцип — замкнутый контур управления с обратной связью и, в частности, ПИД-регулирование.\n\nПредставим робота, движущегося по чёрной линии с помощью двух ИК-датчиков. Простейший алгоритм («если левый датчик видит линию — повернуть влево, если правый — повернуть вправо») заставляет робота двигаться рывками, зигзагом. Причина в том, что такой алгоритм реагирует только на факт отклонения, но не учитывает, насколько сильно робот отклонился и как быстро нарастает это отклонение.\n\nПИД-регулятор решает эту проблему, вычисляя управляющий сигнал на основе трёх составляющих одновременно. Первая — пропорциональная (П): воздействие пропорционально текущей ошибке — разнице между желаемым и фактическим положением робота. Чем сильнее робот отклонился, тем резче он корректирует курс; чем ближе к линии — тем мягче коррекция. Вторая — интегральная (И): учитывает накопленную за время ошибку и помогает устранить небольшое, но постоянное отклонение, которое одна пропорциональная составляющая убрать не может (например, из-за неидеально откалиброванных моторов). Третья — дифференциальная (Д): реагирует на скорость изменения ошибки и «тормозит» слишком резкую коррекцию, предотвращая перерегулирование и колебания робота из стороны в сторону.\n\nИтоговый управляющий сигнал вычисляется как сумма всех трёх составляющих, каждая умножается на свой коэффициент (Kp, Ki, Kd) — подбор этих коэффициентов («настройка ПИД-регулятора») является практической задачей инженера: слишком большой Kp приведёт к резким колебаниям, слишком маленький — к медленной, вялой реакции робота.\n\nВажно понимать: ПИД-регулирование — не единственный, а лишь наиболее распространённый способ реализации плавной обратной связи; его применяют не только в робототехнике, но и в системах климат-контроля, автопилотах, промышленной автоматике. Понимание идеи «учитывать не только текущую ошибку, но и её накопление и скорость изменения» — важный шаг от простого программирования по правилам «если-то» к инженерному проектированию систем управления, которые ведут себя плавно и устойчиво даже в изменчивых условиях.","quiz":[{"question":"Почему простое ветвление «если левый датчик видит линию — повернуть влево» часто приводит к зигзагообразному движению робота?","options":["Потому что датчики вообще не работают","Потому что алгоритм реагирует только на факт отклонения, не учитывая его величину и скорость нарастания","Потому что моторы всегда работают синхронно","Потому что линия слишком широкая"],"correctIndex":1},{"question":"За что отвечает пропорциональная (П) составляющая ПИД-регулятора?","options":["За учёт накопленной ошибки за время работы","За реакцию, пропорциональную текущей величине ошибки","За полное отключение моторов при любой ошибке","За скорость изменения датчиков"],"correctIndex":1},{"question":"Какую проблему решает интегральная (И) составляющая ПИД-регулятора?","options":["Устраняет небольшое, но постоянное накопленное отклонение, которое одна пропорциональная составляющая убрать не может","Мгновенно останавливает робота","Увеличивает скорость датчиков","Заменяет собой пропорциональную составляющую"],"correctIndex":0},{"question":"Какую роль играет дифференциальная (Д) составляющая ПИД-регулятора?","options":["Увеличивает резкость коррекции курса","Реагирует на скорость изменения ошибки и сглаживает резкие колебания","Хранит историю всех предыдущих ошибок без ограничения","Отвечает за питание моторов"],"correctIndex":1},{"question":"Что произойдёт, если коэффициент Kp (пропорциональной составляющей) выбрать слишком большим?","options":["Робот будет двигаться идеально плавно","Робот будет резко колебаться, перерегулируя курс","Робот вообще перестанет реагировать на датчики","Ничего не изменится"],"correctIndex":1},{"question":"Где ещё, помимо робототехники, применяется принцип ПИД-регулирования?","options":["Только в компьютерных играх","В системах климат-контроля, автопилотах, промышленной автоматике","Только в текстовых редакторах","ПИД-регулирование больше нигде не применяется"],"correctIndex":1},{"question":"Как вычисляется итоговый управляющий сигнал ПИД-регулятора?","options":["Как максимум из трёх составляющих","Как сумма пропорциональной, интегральной и дифференциальной составляющих, каждая со своим коэффициентом","Как произведение всех показаний датчиков","Управляющий сигнал вообще не зависит от составляющих"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-22T10:20:00+05:00","ends_at":"2026-07-22T11:05:00+05:00","room":"301"},{"topic":"Итоговый проект: проектирование автономного робота","objective":"Научить применять весь изученный материал курса для проектирования концепции автономного робота, решающего конкретную практическую задачу.","theory":"Заключительная тема курса объединяет все изученные ранее блоки — архитектуру робота, электронику, микроконтроллеры, датчики, приводы, алгоритмы управления и обратную связь — в единый процесс инженерного проектирования: от идеи до работающего прототипа. Этот процесс принято описывать через несколько последовательных этапов, которые используют инженеры и в промышленности, и в учебных проектах.\n\nПервый этап — постановка задачи. Прежде чем проектировать что-либо, нужно чётко сформулировать, какую проблему решает робот и в каких условиях он будет работать: например, «робот-помощник, который перевозит небольшие грузы по коридору школы, объезжая препятствия и останавливаясь у нужного кабинета» — такая формулировка сразу задаёт требования к конструкции.\n\nВторой этап — выбор архитектуры и компонентов. Из постановки задачи вытекает список необходимых сенсоров (ультразвуковой датчик для объезда препятствий, ИК-датчики линии для навигации, возможно, датчик цвета для метки нужного кабинета), приводов (два DC-мотора с драйвером) и контроллера (Arduino Uno, если задача несложная, либо более мощная плата для сложных вычислений). Важно продумать электрическую схему: рассчитать напряжения и токи, подобрать источник питания, выдерживающий одновременную работу моторов.\n\nТретий этап — разработка алгоритма управления. Здесь используются все изученные конструкции: бесконечный цикл loop() как основа поведения, ветвления для реакции на препятствия и метки, возможно, элементы ПИД-регулирования для плавного движения по линии. Полезно сначала описать алгоритм словами или блок-схемой, прежде чем писать код — это помогает избежать логических ошибок.\n\nЧетвёртый этап — сборка и тестирование прототипа. Важно тестировать робота постепенно: сначала проверить каждый компонент отдельно (моторы вращаются в нужную сторону, датчик корректно измеряет расстояние), и только затем объединять всё в систему. Такой подход экономит время, потому что находить ошибку в изолированном модуле проще, чем в сложной собранной системе.\n\nПятый этап — доработка (итерация). Ни один рабочий прототип не получается идеальным с первого раза: инженеры постоянно тестируют, находят слабые места (например, ПИД-коэффициенты требуют подстройки, или датчик даёт ложные срабатывания) и вносят изменения — это нормальная и необходимая часть инженерного процесса, а не признак неудачи.\n\nОсвоив весь путь от базовой электроники до алгоритмов и обратной связи, вы теперь обладаете необходимым набором знаний, чтобы самостоятельно спроектировать концепцию собственного автономного робота, решающего реальную практическую задачу.","quiz":[{"question":"Какой первый этап инженерного проектирования робота?","options":["Написание кода","Чёткая постановка задачи: какую проблему решает робот и в каких условиях работает","Пайка электронной схемы","Заказ деталей"],"correctIndex":1},{"question":"Что определяется на этапе выбора архитектуры и компонентов робота?","options":["Список нужных сенсоров, приводов и контроллера, а также электрическая схема","Только цвет корпуса робота","Только название робота","Только язык программирования без учёта задачи"],"correctIndex":0},{"question":"Зачем перед написанием кода полезно сначала описать алгоритм словами или блок-схемой?","options":["Это требование языка программирования","Это помогает заранее избежать логических ошибок","Без этого код не скомпилируется","Это требуется только для сложных роботов с ИИ"],"correctIndex":1},{"question":"Почему рекомендуется тестировать каждый компонент робота отдельно перед сборкой полной системы?","options":["Так требует производитель Arduino","Потому что находить ошибку в изолированном модуле проще, чем в сложной собранной системе","Отдельное тестирование не имеет смысла","Чтобы сэкономить электричество"],"correctIndex":1},{"question":"Что означает «итерация» в контексте инженерного проектирования робота?","options":["Однократную сборку без доработок","Постоянное тестирование, выявление слабых мест и внесение изменений в прототип","Полную замену всех компонентов на новые","Отказ от проекта при первой ошибке"],"correctIndex":1},{"question":"Робот-помощник должен объезжать препятствия и двигаться по размеченному коридору. Какие датчики из изученного курса логично включить в его конструкцию?","options":["Только датчик температуры","Ультразвуковой датчик расстояния и ИК-датчики линии","Только гироскоп","Датчики в такой задаче не нужны вовсе"],"correctIndex":1},{"question":"Почему обнаружение ошибок и слабых мест в готовом прототипе робота — это нормальная часть процесса, а не признак неудачи?","options":["Потому что ни один рабочий прототип не получается идеальным с первого раза, и доработка — обязательный этап инженерии","Потому что роботы никогда не работают правильно","Потому что тестирование не влияет на качество робота","Потому что это единственный способ продать проект"],"correctIndex":0}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-23T12:10:00+05:00","ends_at":"2026-07-23T12:55:00+05:00","room":"301"}]'::jsonb)
    LOOP
      INSERT INTO public.lessons (group_id, subject_id, topic, title, description, status, starts_at, ends_at, started_at, ended_at, room, school_id)
      VALUES (
        v_group_id, v_subject_id, lesson_data->>'topic', lesson_data->>'topic', lesson_data->>'objective',
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN 'completed' ELSE 'scheduled' END,
        (lesson_data->>'starts_at')::timestamptz, (lesson_data->>'ends_at')::timestamptz,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'starts_at')::timestamptz ELSE NULL END,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'ends_at')::timestamptz ELSE NULL END,
        lesson_data->>'room', v_school_id
      )
      RETURNING id INTO v_lesson_id;

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, duration_min, school_id)
      VALUES (v_lesson_id, 1, 'middle', 'theory', 'presentation', lesson_data->>'topic', lesson_data->>'theory', 15, v_school_id);

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, duration_min, school_id)
      VALUES (v_lesson_id, 2, 'middle', 'task', 'quiz_qia', 'Проверь себя', 15, v_school_id)
      RETURNING id INTO v_stage_id;

      qpos := 0;
      FOR quiz_item IN SELECT * FROM jsonb_array_elements(lesson_data->'quiz')
      LOOP
        qpos := qpos + 1;
        INSERT INTO public.quiz_questions (stage_id, question_text, options, correct_option_index, position, points, time_per_question_seconds, school_id)
        VALUES (v_stage_id, quiz_item->>'question', quiz_item->'options', (quiz_item->>'correctIndex')::int, qpos, 1, 30, v_school_id);
      END LOOP;

      IF (lesson_data->>'hasExternalService')::boolean THEN
        INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, config, duration_min, school_id)
        VALUES (
          v_lesson_id, 3, 'middle', 'task', lesson_data->>'externalServiceType',
          lesson_data->>'externalServiceTask', lesson_data->>'externalServiceTask',
          jsonb_build_object('url',
            CASE lesson_data->>'externalServiceType'
              WHEN 'wokwi' THEN 'https://wokwi.com/projects/new/arduino-uno'
              WHEN 'codesandbox' THEN 'https://codesandbox.io/p/sandbox/vanilla'
              WHEN 'geogebra' THEN 'https://www.geogebra.org/classic'
              WHEN 'phet' THEN 'https://phet.colorado.edu/sims/html/forces-and-motion-basics/latest/forces-and-motion-basics_en.html'
              WHEN 'desmos' THEN 'https://www.desmos.com/calculator'
              WHEN 'blockly_games' THEN 'https://blockly.games/'
              WHEN 'visualgo' THEN 'https://visualgo.net/en'
              WHEN 'p5js' THEN 'https://editor.p5js.org/'
              WHEN 'excalidraw' THEN 'https://excalidraw.com/'
              WHEN 'learningapps' THEN 'https://learningapps.org/'
              WHEN 'sqlonline' THEN 'https://sqlime.org/'
              WHEN 'h5p' THEN 'https://h5p.eduos.snruz.uz/library'
              ELSE NULL
            END
          ),
          15, v_school_id
        );
      END IF;
    END LOOP;
  END IF;

  -- === 10-А класс | Русский язык (11 уроков) ===
  SELECT id INTO v_group_id FROM public.groups WHERE name = '10-А класс';
  SELECT id INTO v_subject_id FROM public.subjects WHERE group_id = v_group_id AND name = 'Русский язык';
  IF NOT EXISTS (SELECT 1 FROM public.lessons WHERE group_id = v_group_id AND subject_id = v_subject_id AND description IS NOT NULL) THEN
    FOR lesson_data IN SELECT * FROM jsonb_array_elements('[{"topic":"Функциональные стили речи: общая характеристика","objective":"Дать учащимся представление о системе функциональных стилей русского языка и научить различать сферы использования каждого стиля.","theory":"Русский язык — не единая застывшая система, а живой организм, который обслуживает разные сферы общения: науку, право, политику, искусство, повседневную жизнь. В зависимости от того, где и с какой целью мы говорим или пишем, мы выбираем разные языковые средства — лексику, синтаксические конструкции, интонацию. Это явление называется функциональной стилистикой, а разновидности языка, закреплённые за определёнными сферами общения, — функциональными стилями речи.\n\nВ русском языке принято выделять пять функциональных стилей: научный, официально-деловой, публицистический, художественный и разговорный. Первые четыре относятся к книжным стилям — они используются преимущественно в письменной, подготовленной речи и подчиняются строгим нормам. Разговорный стиль обслуживает неофициальное, спонтанное общение и допускает отступления от строгих норм литературного языка.\n\nКаждый стиль характеризуется через три параметра: сферу применения (где используется), функцию (какую задачу решает — сообщить точные знания, регламентировать поведение, воздействовать на мнение, создать образ или просто пообщаться) и языковые особенности (лексика, синтаксис, характерные конструкции). Например, научный стиль обслуживает сферу науки и образования, его функция — сообщение объективных знаний, а языковые приметы — термины, сложные предложения с причинно-следственными связями, отсутствие эмоциональной окраски. Официально-деловой стиль работает в сфере права и делопроизводства, его задача — точно регламентировать отношения между людьми и организациями, поэтому для него характерны клише и стандартные обороты.\n\nВажно понимать, что стили не существуют изолированно друг от друга: в реальных текстах часто происходит взаимопроникновение стилей — например, публицистический текст может включать элементы научного стиля (статистику, термины) и художественного (образные выражения). Однако для каждого текста можно определить доминирующий, ведущий стиль — именно он задаёт общий характер текста.\n\nУмение определять стиль текста — практический навык: он необходим при написании сочинения на экзамене, где требуется соблюдать единство стиля, и при анализе текстов на ЕГЭ, где часто нужно определить стилевую принадлежность отрывка. В следующих уроках мы подробно разберём каждый из книжных стилей — их признаки, жанры и характерные языковые средства.","quiz":[{"question":"Сколько функциональных стилей принято выделять в русском языке?","options":["3","4","5","6"],"correctIndex":2},{"question":"Какой стиль обслуживает сферу науки и образования?","options":["официально-деловой","научный","публицистический","разговорный"],"correctIndex":1},{"question":"Какая функция является ведущей для официально-делового стиля?","options":["воздействие на мнение","создание художественного образа","регламентация отношений","непринуждённое общение"],"correctIndex":2},{"question":"Какой стиль относится к некнижным (устным, неподготовленным) стилям?","options":["научный","публицистический","разговорный","художественный"],"correctIndex":2},{"question":"По каким трём параметрам характеризуется функциональный стиль?","options":["сфера применения, функция, языковые особенности","автор, жанр, объём","тема, идея, план","лексика, фонетика, морфология"],"correctIndex":0},{"question":"Что происходит со стилями в реальных текстах?","options":["они никогда не смешиваются","возможно взаимопроникновение стилей","только разговорный стиль смешивается с другими","стили полностью заменяют друг друга"],"correctIndex":1},{"question":"Зачем нужно уметь определять стиль текста?","options":["только для развлечения","для соблюдения единства стиля в сочинении и анализа текста на экзамене","это не нужно в жизни","только для написания стихов"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-07T09:25:00+05:00","ends_at":"2026-07-07T10:10:00+05:00","room":"301"},{"topic":"Научный стиль речи","objective":"Научить учащихся распознавать признаки научного стиля и его основные жанры, а также использовать характерные языковые средства этого стиля.","theory":"Научный стиль речи обслуживает сферу науки, техники и образования. Его основная функция — сообщение точных, объективных, проверенных знаний, объяснение закономерностей и доказательство гипотез. Тексты научного стиля мы встречаем в учебниках, монографиях, диссертациях, статьях в научных журналах, а также в докладах и рефератах, которые пишут сами школьники.\n\nКлючевая особенность научного стиля — терминологичность. Термин — это слово или словосочетание, которое обозначает специальное понятие науки и имеет строго определённое, однозначное значение (например, «морфема», «фотосинтез», «интеграл»). В отличие от обычных слов, термины не допускают эмоциональной окраски и множественности толкований.\n\nДля научного стиля характерна также отвлечённая, обобщающая лексика: слова, называющие не конкретные предметы, а абстрактные понятия, процессы, свойства («развитие», «взаимодействие», «зависимость»). Часто используются существительные, образованные от глаголов и прилагательных (нагревание, устойчивость), которые придают тексту книжный, безличный характер.\n\nСинтаксис научного стиля тяготеет к сложным предложениям с чёткой логической структурой — особенно к сложноподчинённым предложениям с придаточными причины, следствия, условия, поскольку наука выявляет причинно-следственные связи между явлениями. Характерны вводные слова, указывающие на логику изложения: «во-первых», «следовательно», «таким образом». Автор научного текста, как правило, избегает местоимения «я», предпочитая безличные конструкции или «мы»: не «я обнаружил», а «было обнаружено» или «мы установили».\n\nВнутри научного стиля выделяют подстили: собственно научный (монография, диссертация, статья) — рассчитан на специалистов; научно-учебный (учебник, лекция) — адресован учащимся и объясняет материал доступнее; научно-популярный (статья в популярном журнале) — рассчитан на широкую аудиторию и допускает элементы образности для облегчения восприятия сложного материала.\n\nПри работе с научным текстом важно уметь отличать его от публицистического: даже если оба текста посвящены одной теме, научный текст будет опираться на факты, статистику, термины и логическую аргументацию, тогда как публицистический — на эмоциональное воздействие и оценочность. Понимание признаков научного стиля пригодится не только на уроках русского языка, но и при подготовке рефератов и проектных работ по любым предметам.","quiz":[{"question":"Какова основная функция научного стиля?","options":["воздействие на эмоции","сообщение точных объективных знаний","создание художественного образа","регламентация деловых отношений"],"correctIndex":1},{"question":"Что такое термин?","options":["слово с эмоциональной окраской","слово, обозначающее специальное понятие науки с однозначным значением","просторечное слово","устаревшее слово"],"correctIndex":1},{"question":"Какие придаточные предложения наиболее характерны для научного стиля?","options":["придаточные места","придаточные причины и следствия","придаточные уступки","придаточные сравнения"],"correctIndex":1},{"question":"Какую форму местоимения предпочитает автор научного текста вместо «я»?","options":["«ты»","«он»","«мы» или безличные конструкции","«они»"],"correctIndex":2},{"question":"Какой подстиль научного стиля адресован широкой аудитории?","options":["собственно научный","научно-учебный","научно-популярный","официально-научный"],"correctIndex":2},{"question":"Чем научный текст принципиально отличается от публицистического на ту же тему?","options":["он короче","опирается на факты, термины и логику, а не на эмоции","не содержит фактов","всегда пишется от первого лица"],"correctIndex":1},{"question":"Какое слово характерно именно для лексики научного стиля?","options":["«красотища»","«взаимодействие»","«эх»","«маленький»"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"learningapps","externalServiceTask":"Создать задание на сопоставление терминов научного стиля с их определениями (упражнение «Найди пару» в LearningApps).","starts_at":"2026-07-08T11:15:00+05:00","ends_at":"2026-07-08T12:00:00+05:00","room":"301"},{"topic":"Официально-деловой стиль речи","objective":"Познакомить учащихся с признаками официально-делового стиля и научить составлять деловые документы (заявление, объяснительная записка) с соблюдением стилевых норм.","theory":"Официально-деловой стиль обслуживает сферу правовых и административных отношений: законодательство, делопроизводство, дипломатию. Мы встречаемся с ним при чтении законов, уставов, договоров, а также когда сами пишем заявление, расписку, доверенность или объяснительную записку. Основная функция этого стиля — точное, однозначное регламентирование отношений между людьми, организациями и государством, поэтому здесь недопустима двусмысленность или эмоциональность.\n\nГлавная черта официально-делового стиля — стандартизированность. Тексты строятся по устойчивым моделям — формулярам, где почти не остаётся места для индивидуального творчества автора. Используются речевые клише и устойчивые обороты: «в соответствии с», «в связи с тем что», «настоящим удостоверяется», «довожу до вашего сведения». Эти клише не считаются недостатком стиля — напротив, они обеспечивают предельную ясность и предсказуемость документа для любого читателя.\n\nЛексика официально-делового стиля включает канцеляризмы — слова и обороты, характерные именно для деловых бумаг (например, «нижеподписавшийся», «вышеуказанный», «надлежащий»), а также большое количество отглагольных существительных («выполнение», «предоставление», «оформление»). Употребляются сложносокращённые слова и аббревиатуры официальных наименований (ООО, РФ, вуз). Точность достигается за счёт полных наименований, дат, чисел, отсутствия синонимической замены терминов на протяжении текста.\n\nСинтаксис отличается прямым порядком слов, преобладанием повествовательных невосклицательных предложений, обилием однородных членов и осложнённых конструкций (причастных и деепричастных оборотов), что позволяет уместить в одном предложении максимум информации без потери точности. Личные местоимения и оценочные слова практически отсутствуют.\n\nВнутри официально-делового стиля выделяют подстили: законодательный (тексты законов и кодексов), дипломатический (международные договоры, ноты) и канцелярский, или административно-деловой (заявления, приказы, справки, протоколы) — именно с этим подстилем школьники сталкиваются чаще всего в повседневной практике.\n\nВладение официально-деловым стилем — практический навык, необходимый каждому взрослому человеку: от него зависит, будет ли документ иметь юридическую силу и правильно ли будет понят адресатом. Поэтому важно с ранних лет учиться писать заявления и другие деловые бумаги по образцу, с соблюдением реквизитов и стандартных формулировок.","quiz":[{"question":"Какая сфера обслуживается официально-деловым стилем?","options":["наука","право и делопроизводство","искусство","бытовое общение"],"correctIndex":1},{"question":"Что такое речевое клише в деловом стиле?","options":["ошибка в тексте","устойчивый стандартный оборот, обеспечивающий ясность","художественный приём","диалектное слово"],"correctIndex":1},{"question":"Как называются слова и обороты, характерные для деловых бумаг, например «нижеподписавшийся»?","options":["термины","канцеляризмы","архаизмы","неологизмы"],"correctIndex":1},{"question":"Какой подстиль официально-делового стиля представлен заявлениями и справками?","options":["законодательный","дипломатический","канцелярский (административно-деловой)","публицистический"],"correctIndex":2},{"question":"Что наименее характерно для официально-делового стиля?","options":["точность формулировок","эмоциональная оценочность","стандартизированность","клише"],"correctIndex":1},{"question":"Какой жанр НЕ относится к официально-деловому стилю?","options":["заявление","расписка","ода","протокол"],"correctIndex":2},{"question":"Почему в деловых текстах избегают синонимической замены терминов?","options":["чтобы текст казался длиннее","чтобы сохранить предельную точность и однозначность","чтобы избежать повторов","это требование художественного стиля"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-10T08:30:00+05:00","ends_at":"2026-07-10T09:15:00+05:00","room":"301"},{"topic":"Публицистический стиль речи","objective":"Научить учащихся выявлять признаки публицистического стиля, его жанры и приёмы речевого воздействия на читателя.","theory":"Публицистический стиль обслуживает сферу общественно-политической жизни: он используется в газетах, журналах, на телевидении, радио, в интернет-СМИ, а также в устных публичных выступлениях — на митингах, дебатах, в ораторской речи. Название стиля происходит от слова «публичный», то есть открытый, общественный. Основная функция публицистики двойная: информирование (сообщить читателю о событиях) и воздействие (сформировать у него определённое мнение, отношение, побудить к действию). Именно сочетание этих двух функций отличает публицистический стиль от чисто информативного научного или делового.\n\nЯзыковые особенности публицистического стиля напрямую вытекают из его функции воздействия. Лексика здесь эмоционально окрашена и оценочна: авторы используют слова с ярко выраженной положительной или отрицательной коннотацией («блистательная победа», «вопиющее беззаконие»), общественно-политическую терминологию («демократия», «электорат», «санкции»), а также разговорные элементы для создания эффекта близости к читателю. Часто встречаются риторические вопросы, восклицательные предложения, обращения к читателю — всё это усиливает эмоциональное воздействие текста.\n\nСинтаксис публицистики разнообразен: с одной стороны, используются короткие, рубленые фразы для динамики и выразительности, с другой — развёрнутые периоды с параллельными конструкциями для убедительности. Характерный приём — заголовки-интриги, часто построенные на игре слов, аллюзии или прецедентном тексте (цитате, известной фразе), чтобы привлечь внимание читателя ещё до чтения основного текста.\n\nПублицистический стиль богат жанрами, которые делятся на информационные (заметка, репортаж, интервью — их задача преимущественно сообщить факты) и аналитические или художественно-публицистические (статья, очерк, фельетон, эссе — здесь на первый план выходит авторская оценка и воздействие). Репортаж стремится к объективности и хронологической точности изложения событий, а очерк допускает элементы художественности, образные средства, авторские размышления.\n\nВажно уметь отличать публицистический текст от других стилей: в отличие от научного текста публицистика не стремится к исчерпывающей объективности и допускает оценку автора; в отличие от официально-делового текста она эмоциональна и не следует жёстким формулярам; в отличие от художественного текста публицистика всегда опирается на реальные, а не вымышленные факты и события. Умение анализировать публицистический текст особенно важно для выполнения заданий ЕГЭ, связанных с определением позиции автора и средств воздействия на читателя.","quiz":[{"question":"Какие две функции сочетает публицистический стиль?","options":["информирование и регламентация","информирование и воздействие","регламентация и воздействие","развлечение и обучение"],"correctIndex":1},{"question":"Что означает слово «публицистический» по происхождению?","options":["тайный","публичный, общественный","научный","деловой"],"correctIndex":1},{"question":"Какая лексика характерна для публицистики?","options":["строго нейтральная и безоценочная","эмоционально окрашенная и оценочная","только канцелярская","только диалектная"],"correctIndex":1},{"question":"К какой группе жанров относится репортаж?","options":["аналитические","информационные","художественные","деловые"],"correctIndex":1},{"question":"Чем публицистика отличается от художественного стиля?","options":["не использует эмоциональные средства","опирается на реальные факты, а не на вымысел","не имеет автора","не бывает в письменной форме"],"correctIndex":1},{"question":"Какой приём часто используется в заголовках публицистических текстов?","options":["строгая нейтральность","игра слов, аллюзия, цитата","отсутствие заголовков","только цифры"],"correctIndex":1},{"question":"Какой жанр допускает элементы художественности и авторские размышления?","options":["заметка","протокол","очерк","расписка"],"correctIndex":2}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-13T08:30:00+05:00","ends_at":"2026-07-13T09:15:00+05:00","room":"301"},{"topic":"Художественный стиль и тропы — Часть 1","objective":"Познакомить учащихся с признаками художественного стиля речи и научить распознавать основные тропы (эпитет, метафора, сравнение, олицетворение) в тексте.","theory":"Художественный стиль речи обслуживает сферу искусства слова — прозу, поэзию, драматургию. В отличие от других книжных стилей, его функция не сводится к сообщению информации или воздействию на общественное мнение: главная задача художественного текста — создать эстетически значимый образ, вызвать у читателя эмоциональный отклик, передать авторское видение мира через конкретные, чувственно воспринимаемые картины.\n\nКлючевая особенность художественного стиля — образность. Автор не просто называет предмет или явление, а рисует его так, чтобы читатель мог его увидеть, услышать, почувствовать. Для этого используется вся палитра языковых средств: художественный стиль свободно вбирает в себя элементы всех остальных стилей — научные термины, канцеляризмы, просторечия, диалектизмы, — если это служит художественной задаче. Только в художественном стиле слово может приобретать переносное значение, не связанное со словарной нормой, — это основа тропов.\n\nТроп — это оборот речи, в котором слово или выражение употреблено в переносном значении для создания художественного образа. Рассмотрим четыре базовых тропа. Эпитет — образное, художественное определение, подчёркивающее характерный признак предмета: «золотая осень», «мёртвая тишина». В отличие от обычного определения (например, «деревянный стол»), эпитет всегда эмоционально окрашен и субъективен. Сравнение — сопоставление одного предмета или явления с другим на основе общего признака, оформленное с помощью союзов «как», «будто», «словно», либо творительного падежа: «луна плыла, как лебедь» или «луна лебедем плыла». Метафора — скрытое сравнение, перенос названия одного предмета на другой по сходству, но без союзов-показателей: «горит восток зарёй», «море смеётся». Метафора сложнее сравнения, потому что сходство в ней не проговаривается прямо, а читатель должен его домыслить. Олицетворение — разновидность метафоры, при которой неживому предмету или явлению приписываются свойства живого существа: «ветер воет», «природа проснулась».\n\nВажно не путать эти тропы между собой: главный критерий разграничения — наличие или отсутствие сравнительного союза (это отличает сравнение от метафоры) и то, приписываются ли предмету именно человеческие/живые свойства (это отличает олицетворение от обычной метафоры). Умение находить тропы в тексте необходимо для анализа художественного произведения на уроках литературы и для выполнения заданий ЕГЭ на определение средств выразительности. В следующем уроке мы продолжим изучение художественного стиля и разберём стилистические фигуры — более сложные приёмы организации художественной речи.","quiz":[{"question":"Какова главная задача художественного стиля речи?","options":["сообщить точные факты","регламентировать отношения","создать эстетический образ и вызвать эмоциональный отклик","убедить в политической позиции"],"correctIndex":2},{"question":"Что такое троп?","options":["ошибка речи","оборот речи со словом в переносном значении для создания образа","синтаксическая конструкция","стиль речи"],"correctIndex":1},{"question":"Что такое эпитет?","options":["скрытое сравнение","образное эмоционально окрашенное определение","сопоставление с союзом «как»","приписывание неживому предмету свойств живого"],"correctIndex":1},{"question":"Чем метафора отличается от сравнения?","options":["метафора не использует сравнительные союзы, сходство домысливается","метафора всегда короче","метафора используется только в поэзии","разницы нет"],"correctIndex":0},{"question":"Какой пример является олицетворением?","options":["«золотая осень»","«ветер воет»","«тихий, как мышь»","«стол из дерева»"],"correctIndex":1},{"question":"Какое средство выразительности использовано во фразе «луна плыла, как лебедь»?","options":["метафора","олицетворение","сравнение","эпитет"],"correctIndex":2},{"question":"Почему художественный стиль может включать элементы других стилей (терминов, просторечий)?","options":["это ошибка автора","это служит художественной задаче создания образа","так положено по правилам","это признак неграмотности"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"h5p","externalServiceTask":"Создать интерактивное упражнение H5P (Mark the Words / Drag the Words) на определение вида тропа в приведённых примерах из художественных текстов.","starts_at":"2026-07-14T09:25:00+05:00","ends_at":"2026-07-14T10:10:00+05:00","room":"301"},{"topic":"Художественный стиль и тропы — Часть 2","objective":"Научить учащихся распознавать и различать стилистические фигуры речи (антитеза, градация, анафора, риторический вопрос, инверсия) и понимать их роль в тексте.","theory":"На предыдущем уроке мы разобрали тропы — приёмы, основанные на переносном значении слова. Однако художественная выразительность речи создаётся не только на уровне слова, но и на уровне построения предложения и текста. Такие приёмы называются стилистическими (риторическими) фигурами — это особые синтаксические конструкции, которые усиливают выразительность высказывания за счёт необычного расположения слов или повторов, а не за счёт переносного значения.\n\nАнтитеза — стилистическая фигура, основанная на резком противопоставлении понятий, образов, состояний: «Они сошлись: волна и камень, стихи и проза, лёд и пламень» (А. С. Пушкин). Антитеза помогает автору подчеркнуть контраст, сделать характеристику героя или явления более рельефной. Часто в основе антитезы лежат слова-антонимы.\n\nГрадация — расположение слов или выражений в порядке нарастания (реже — убывания) их смыслового или эмоционального значения: «Не жалею, не зову, не плачу» (С. А. Есенин) — здесь чувства усиливаются от строки к строке. Восходящая градация создаёт эффект нарастающего напряжения, нисходящая — постепенного ослабления.\n\nАнафора (единоначатие) — повтор одного и того же слова или словосочетания в начале нескольких строк, предложений или строф: «Клянусь я первым днём творенья, клянусь его последним днём…» (М. Ю. Лермонтов). Анафора создаёт ритмическую упорядоченность текста и усиливает эмоциональное воздействие повторяемого слова. Противоположный приём — эпифора — повтор в конце строк или предложений.\n\nРиторический вопрос — вопрос, который не требует ответа, потому что ответ и так очевиден или невозможен; он задаётся не для получения информации, а для усиления эмоционального воздействия и привлечения внимания читателя к проблеме: «Куда ж нам плыть?» (А. С. Пушкин). Риторическое восклицание и риторическое обращение действуют по тому же принципу — они выражают эмоцию автора, а не ждут ответной реакции.\n\nИнверсия — нарушение обычного, прямого порядка слов в предложении с целью выделить, подчеркнуть какой-то член предложения: перестановка сказуемого на первое место в «Белеет парус одинокий» акцентирует внимание именно на действии.\n\nСтилистические фигуры, в отличие от тропов, не создают переносного значения слова, а работают на уровне синтаксиса — порядка слов, повтора, структуры предложения. На экзамене важно уметь отличать тропы от фигур: если приём связан с переносным значением слова — это троп, если с построением предложения — это фигура. Комплексное владение и тропами, и фигурами позволяет глубоко анализировать художественный текст и понимать авторский замысел.","quiz":[{"question":"В чём принципиальное отличие стилистической фигуры от тропа?","options":["фигура работает на уровне синтаксиса, а не переносного значения слова","фигура всегда длиннее","фигуры используются только в поэзии","разницы нет, это синонимы"],"correctIndex":0},{"question":"Какая фигура основана на резком противопоставлении?","options":["градация","антитеза","анафора","инверсия"],"correctIndex":1},{"question":"Что такое анафора?","options":["повтор в конце строк","единоначатие — повтор в начале строк","вопрос без ответа","нарушение порядка слов"],"correctIndex":1},{"question":"Приведите пример риторического вопроса.","options":["«Волна и камень, лёд и пламень»","«Куда ж нам плыть?»","«Белеет парус одинокий»","«Не жалею, не зову, не плачу»"],"correctIndex":1},{"question":"Что такое инверсия?","options":["нарушение прямого порядка слов для выделения члена предложения","повтор слова","противопоставление","нарастание значения"],"correctIndex":0},{"question":"Что создаёт градация в тексте «Не жалею, не зову, не плачу»?","options":["контраст","нарастание или убывание эмоционального значения","вопрос без ответа","перестановку слов"],"correctIndex":1},{"question":"Как называется фигура, противоположная анафоре (повтор в конце строк)?","options":["инверсия","эпифора","градация","антитеза"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-15T11:15:00+05:00","ends_at":"2026-07-15T12:00:00+05:00","room":"301"},{"topic":"Текст: тема, идея, средства связи предложений","objective":"Научить учащихся определять тему и основную мысль текста, а также распознавать средства связи предложений в тексте.","theory":"Текст — это не просто набор отдельных предложений, а целостное речевое произведение, в котором предложения связаны по смыслу и грамматически, образуя единство. Чтобы работать с текстом осознанно — понимать его, анализировать, писать сочинения, — нужно уметь выделять его ключевые категории: тему, основную мысль и средства связи между предложениями.\n\nТема текста — это то, о чём говорится в тексте, предмет речи, который можно сформулировать в виде словосочетания («тема Родины», «проблема отцов и детей»). Основная мысль (идея) — это то, что автор хочет сказать по поводу темы, вывод, к которому он подводит читателя; она формулируется уже в виде законченного предложения-утверждения. Например, тема — «дружба», а основная мысль конкретного текста об этой теме может звучать так: «настоящая дружба проверяется трудностями». Важно не путать тему с основной мыслью: тема отвечает на вопрос «о чём текст?», идея — на вопрос «что автор хотел сказать?».\n\nПредложения в тексте связаны друг с другом двумя основными способами. Цепная (последовательная) связь — самый распространённый тип, при котором каждое следующее предложение развивает мысль, высказанную в предыдущем: новая информация одного предложения становится темой для следующего, как звенья цепи. Параллельная связь встречается реже — при ней все предложения абзаца независимо друг от друга связаны с одним общим, как правило первым, предложением; такая связь характерна, например, для описаний, где каждое предложение раскрывает какую-то одну сторону общей картины.\n\nДля связи предложений используются лексические и грамматические средства. К лексическим средствам относятся: лексический повтор, синонимы и синонимические замены (в том числе описательные обороты и слова-заместители типа «этот учёный», «данное явление»), однокоренные слова, антонимы, слова одной тематической группы. К грамматическим средствам связи относятся: личные, указательные и притяжательные местоимения («он», «этот», «его»), союзы и союзные слова в начале предложения («однако», «поэтому», «зато»), наречия времени и места («тогда», «там», «затем»), единство видо-временных форм глаголов-сказуемых, а также синтаксический параллелизм — одинаковое построение соседних предложений.\n\nУмение находить средства связи предложений в тексте — это не только теоретическое знание для выполнения тестовых заданий ЕГЭ, но и практический инструмент, который помогает писать собственные связные, логичные тексты — сочинения, изложения, эссе — вместо набора разрозненных фраз.","quiz":[{"question":"Как правильно сформулировать тему текста?","options":["в виде законченного предложения-вывода","в виде словосочетания, называющего предмет речи","в виде вопроса","в виде списка фактов"],"correctIndex":1},{"question":"На какой вопрос отвечает основная мысль (идея) текста?","options":["«о чём текст?»","«что автор хотел сказать по поводу темы?»","«сколько абзацев в тексте?»","«какой стиль у текста?»"],"correctIndex":1},{"question":"Что характерно для цепной связи предложений?","options":["каждое предложение развивает мысль предыдущего, как звенья цепи","все предложения независимо связаны с одним первым предложением","предложения никак не связаны","связь только через союзы"],"correctIndex":0},{"question":"Для какого типа речи чаще всего характерна параллельная связь предложений?","options":["для рассуждения","для описания","для повествования","для делового письма"],"correctIndex":1},{"question":"Какое средство связи относится к лексическим?","options":["личное местоимение","лексический повтор и синонимическая замена","союз «поэтому»","наречие «там»"],"correctIndex":1},{"question":"Какое средство связи относится к грамматическим?","options":["однокоренные слова","указательное местоимение «этот»","синонимы","антонимы"],"correctIndex":1},{"question":"Зачем нужно уметь находить средства связи предложений в тексте?","options":["только для тестов ЕГЭ","это помогает писать собственные связные и логичные тексты","это не имеет практического значения","только для устной речи"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-17T08:30:00+05:00","ends_at":"2026-07-17T09:15:00+05:00","room":"301"},{"topic":"Типы речи: повествование, описание, рассуждение","objective":"Научить учащихся распознавать и различать типы речи — повествование, описание, рассуждение — по их структурным и языковым признакам.","theory":"Помимо стилей речи, тексты классифицируются ещё по одному основанию — функционально-смысловому типу речи, то есть по способу изложения содержания. В русском языке выделяют три основных типа речи: повествование, описание и рассуждение. Один и тот же стиль (например, художественный) может реализовываться через любой из этих типов, и наоборот — тип речи не привязан жёстко к одному стилю: рассуждение встречается и в научном, и в публицистическом, и в разговорном стиле.\n\nПовествование — это тип речи, который рассказывает о событиях, происходящих в определённой последовательности во времени: что случилось сначала, что потом, чем закончилось. Композиционно повествование строится по схеме: завязка — развитие действия — кульминация — развязка. Языковой приметой повествования является преобладание глаголов, особенно глаголов совершенного вида в форме прошедшего времени, которые обозначают сменяющие друг друга действия («вышел, увидел, остановился, вернулся»). К повествованию можно поставить общий вопрос «что произошло?».\n\nОписание — это тип речи, который характеризует предмет, человека, явление или место, перечисляя его признаки, которые существуют одновременно, а не сменяют друг друга во времени. Композиция описания статична: общее впечатление — детали — общая оценка. Языковой приметой описания является обилие прилагательных, причастий и слов со значением качества, а также сказуемых, выраженных именами прилагательными или существительными («небо было ясным», «лес — густой и тёмный»). К описанию ставится вопрос «какой?».\n\nРассуждение — это тип речи, в котором автор излагает свои мысли по какому-либо вопросу, доказывает или опровергает какое-либо положение, объясняет причины явлений. Композиция рассуждения строится по логической схеме: тезис (утверждение, которое нужно доказать) — аргументы (доказательства, примеры) — вывод. Языковой приметой рассуждения являются вводные слова, указывающие на логику мысли («во-первых», «следовательно», «таким образом», «значит»), а также сложноподчинённые предложения с придаточными причины, следствия, условия. К рассуждению ставится вопрос «почему?».\n\nНа практике чистые типы речи в тексте встречаются редко — чаще всего происходит их комбинирование: например, в художественном тексте повествование о событиях может прерываться описанием пейзажа или рассуждением героя о смысле произошедшего. Умение различать типы речи и определять, какой из них преобладает в конкретном фрагменте, необходимо для анализа текста на экзамене и для осознанного построения собственного сочинения — ведь именно тип речи определяет, какую композиционную схему и какие языковые средства нужно выбрать при написании той или иной части текста.","quiz":[{"question":"Сколько функционально-смысловых типов речи принято выделять?","options":["два","три","четыре","пять"],"correctIndex":1},{"question":"Какой вопрос характерен для повествования?","options":["«какой?»","«почему?»","«что произошло?»","«сколько?»"],"correctIndex":2},{"question":"Какая композиционная схема характерна для повествования?","options":["тезис — аргументы — вывод","завязка — развитие действия — кульминация — развязка","общее впечатление — детали — оценка","вопрос — ответ"],"correctIndex":1},{"question":"Какая часть речи преобладает в описании?","options":["глаголы совершенного вида","прилагательные и причастия","вводные слова","союзы причины"],"correctIndex":1},{"question":"Какая композиционная схема характерна для рассуждения?","options":["тезис — аргументы — вывод","завязка — кульминация — развязка","общее впечатление — детали","вопрос без схемы"],"correctIndex":0},{"question":"Привязан ли тип речи жёстко к одному функциональному стилю?","options":["да, рассуждение бывает только в научном стиле","нет, один тип речи может встречаться в разных стилях","да, повествование бывает только в художественном стиле","типы речи и стили — это одно и то же"],"correctIndex":1},{"question":"Что происходит с типами речи в реальных текстах чаще всего?","options":["они строго изолированы друг от друга","они комбинируются в пределах одного текста","используется только один тип на весь текст","типы речи не встречаются вместе никогда"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"learningapps","externalServiceTask":"Создать в LearningApps упражнение на классификацию (сортировку) фрагментов текста по типам речи: повествование, описание, рассуждение.","starts_at":"2026-07-20T08:30:00+05:00","ends_at":"2026-07-20T09:15:00+05:00","room":"301"},{"topic":"Лексические нормы: паронимы, синонимы, антонимы","objective":"Научить учащихся различать паронимы и правильно использовать синонимы и антонимы для повышения точности и выразительности речи.","theory":"Лексические нормы — это правила словоупотребления, то есть правила выбора слова, точно соответствующего его значению, стилю и контексту. Нарушение лексических норм — одна из самых частых речевых ошибок, поэтому в старших классах особое внимание уделяется работе с паронимами, синонимами и антонимами — словами, которые легко перепутать или неточно использовать.\n\nПаронимы — это однокоренные слова, близкие по звучанию, но разные по значению: «одеть» и «надеть», «эффектный» и «эффективный», «дипломат» и «дипломант», «представить» и «предоставить». Паронимы часто путают именно из-за звукового сходства, но их значения принципиально различаются, и замена одного слова другим ведёт к смысловой ошибке. Например, «надеть пальто» (на себя), но «одеть ребёнка» (кого-то другого); «эффектное платье» (производящее впечатление), но «эффективный метод» (результативный). Задания на паронимы регулярно встречаются в ЕГЭ, поэтому важно не механически заучивать пары, а понимать логику различия их значений через словообразовательный анализ и сочетаемость слова.\n\nСинонимы — это слова, различные по звучанию, но близкие или совпадающие по значению («смелый» — «храбрый» — «отважный»). Синонимы редко бывают полностью тождественны — обычно они различаются оттенками значения (смысловые синонимы: «бежать» — «мчаться», где второе слово указывает на большую скорость), стилистической окраской (стилистические синонимы: «лицо» — нейтральное, «лик» — высокое, «морда» — сниженное для человека) или сочетаемостью с другими словами. Умение выбирать точный синоним из синонимического ряда — признак речевого мастерства: оно позволяет избегать неоправданных повторов и точнее передавать мысль или отношение к предмету речи.\n\nАнтонимы — это слова с противоположным значением («горячий» — «холодный», «добро» — «зло»). Антонимы используются не только для констатации противоположности, но и как основа стилистического приёма антитезы, а также оксюморона — сочетания противоположных по значению слов в одном словосочетании («живой труп», «горячий снег»), создающего яркий, парадоксальный образ.\n\nВладение лексическими нормами напрямую влияет на точность, ясность и выразительность речи. Неточный выбор слова из ряда паронимов или синонимов может исказить смысл высказывания или создать неуместный стилистический эффект — например, использование сниженного синонима в официальном тексте. Поэтому работа со словарями синонимов, антонимов и паронимов должна стать постоянной привычкой при подготовке к сочинению и при редактировании собственного текста.","quiz":[{"question":"Что такое паронимы?","options":["слова с противоположным значением","однокоренные слова, близкие по звучанию, но разные по значению","слова, совпадающие по значению","устаревшие слова"],"correctIndex":1},{"question":"Какая пара слов является примером паронимов?","options":["«горячий — холодный»","«надеть — одеть»","«смелый — храбрый»","«бежать — идти»"],"correctIndex":1},{"question":"Чем обычно различаются синонимы в синонимическом ряду?","options":["они абсолютно тождественны","оттенками значения, стилистической окраской или сочетаемостью","только количеством букв","они не могут различаться"],"correctIndex":1},{"question":"Что такое антонимы?","options":["однокоренные слова","слова с противоположным значением","слова, близкие по звучанию","заимствованные слова"],"correctIndex":1},{"question":"Что такое оксюморон?","options":["сочетание противоположных по значению слов, создающее парадоксальный образ","повтор слова","вопрос без ответа","скрытое сравнение"],"correctIndex":0},{"question":"Какой вариант употреблён верно: «эффектный метод лечения» или «эффективный метод лечения»?","options":["«эффектный метод лечения»","«эффективный метод лечения»","оба варианта верны","оба варианта неверны"],"correctIndex":1},{"question":"Почему важно владеть лексическими нормами при подготовке к сочинению?","options":["это не имеет значения для смысла текста","неточный выбор слова может исказить смысл или создать неуместный стилистический эффект","только для увеличения объёма текста","нормы важны только в официально-деловом стиле"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-21T09:25:00+05:00","ends_at":"2026-07-21T10:10:00+05:00","room":"301"},{"topic":"Сложносочинённое и сложноподчинённое предложение","objective":"Научить учащихся различать сложносочинённые и сложноподчинённые предложения, определять смысловые отношения между частями и правильно расставлять знаки препинания.","theory":"Сложное предложение состоит из двух и более грамматических основ (простых предложений), объединённых в одно целое по смыслу, интонационно и с помощью союзов или союзных слов. По способу связи частей сложные предложения делятся на две большие группы: сложносочинённые (ССП) и сложноподчинённые (СПП).\n\nВ сложносочинённом предложении части равноправны, ни одна из них не зависит грамматически от другой, и они соединяются сочинительными союзами: соединительными («и», «да» в значении «и», «ни…ни»), противительными («а», «но», «да» в значении «но», «зато», «однако»), разделительными («или», «либо», «то…то»). Между частями ССП обычно ставится запятая: «Солнце село, и на землю опустились сумерки». Смысловые отношения между частями ССП различаются в зависимости от союза: соединительные союзы выражают одновременность или последовательность событий, противительные — противопоставление, разделительные — чередование или взаимоисключение явлений.\n\nВ сложноподчинённом предложении части неравноправны: одна из них — главная, другая — придаточная, зависящая от главной и присоединяемая с помощью подчинительных союзов («потому что», «чтобы», «хотя», «если», «когда») или союзных слов («который», «где», «куда», «почему», выступающих одновременно и членом придаточного предложения). Придаточное предложение отвечает на вопрос, который можно поставить от главной части, и раскрывает: обстоятельство (времени, места, причины, цели, условия, уступки, следствия, образа действия), определение (придаточное определительное, отвечающее на вопрос «какой?») или дополнение (придаточное изъяснительное, раскрывающее содержание мысли, речи, восприятия). Например: «Я знаю (что?), что завтра будет дождь» — придаточное изъяснительное; «Дом (какой?), который стоит на горе, виден издалека» — придаточное определительное; «Мы вышли (когда?), когда дождь закончился» — придаточное времени.\n\nКлючевое различие между ССП и СПП — не только формальное (тип союза), но и смысловое: части ССП можно в большинстве случаев поменять местами без принципиального изменения смысла, а части СПП переставить нельзя, не разрушив логическую зависимость. Кроме того, союзное слово в СПП («который», «где») можно заменить другим членом предложения, а союз — никогда, потому что союз не является членом предложения.\n\nПри расстановке знаков препинания важно правильно определить границы частей сложного предложения и найти союз или союзное слово: именно перед подчинительным союзом ставится запятая в СПП, а в ССП запятая ставится перед сочинительным союзом, кроме случаев, когда части имеют общий второстепенный член.","quiz":[{"question":"Чем части сложносочинённого предложения отличаются от частей сложноподчинённого?","options":["части ССП равноправны, части СПП — главная и зависимая","части ССП всегда длиннее","в ССП нет запятых","разницы нет"],"correctIndex":0},{"question":"Какой союз является сочинительным?","options":["«потому что»","«чтобы»","«но»","«который»"],"correctIndex":2},{"question":"Какой вид придаточного отвечает на вопрос «какой?»","options":["изъяснительное","определительное","придаточное цели","придаточное условия"],"correctIndex":1},{"question":"В предложении «Я знаю, что завтра будет дождь» какой тип придаточного?","options":["определительное","изъяснительное","придаточное места","придаточное уступки"],"correctIndex":1},{"question":"Чем союзное слово отличается от союза в СПП?","options":["союзное слово является членом придаточного предложения, союз — нет","союзное слово всегда стоит в конце","союз можно заменить местоимением","разницы нет"],"correctIndex":0},{"question":"Можно ли поменять местами главную и придаточную части СПП без разрушения смысла?","options":["да, всегда можно","нет, это разрушит логическую зависимость частей","это зависит только от длины предложения","придаточная часть не может стоять после главной"],"correctIndex":1},{"question":"Какой тип отношений выражают противительные союзы в ССП?","options":["одновременность","противопоставление","чередование","причину"],"correctIndex":1},{"question":"Перед чем ставится запятая в сложноподчинённом предложении?","options":["перед сочинительным союзом","перед подчинительным союзом или союзным словом","в начале предложения всегда","запятая не ставится никогда"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"h5p","externalServiceTask":"Создать интерактивное упражнение H5P (Fill in the Blanks) на расстановку знаков препинания и определение типа придаточного в сложноподчинённых предложениях.","starts_at":"2026-07-22T11:15:00+05:00","ends_at":"2026-07-22T12:00:00+05:00","room":"301"},{"topic":"Сложное предложение с разными видами связи","objective":"Научить учащихся анализировать сложные предложения с разными видами связи (сочинительной, подчинительной, бессоюзной) и выполнять их полный синтаксический разбор.","theory":"Завершая изучение синтаксиса сложного предложения, важно рассмотреть наиболее сложный тип конструкций — сложные предложения с разными видами связи, где сочетаются сочинительная, подчинительная и бессоюзная связь между несколькими простыми предложениями в составе одного сложного целого. Такие предложения часто называют многочленными сложными предложениями, и именно они чаще всего встречаются в развёрнутых, стилистически богатых текстах — художественных и публицистических.\n\nПрежде всего вспомним третий, ещё не рассмотренный подробно тип связи — бессоюзную. В бессоюзном сложном предложении (БСП) части соединяются без союзов и союзных слов, только по смыслу и интонационно, а знак препинания (запятая, точка с запятой, двоеточие или тире) зависит от смысловых отношений между частями. Запятая или точка с запятой ставится при перечислении событий («Дул ветер, шёл дождь, темнело»). Двоеточие ставится, если вторая часть раскрывает причину, поясняет или дополняет содержание первой (в первую часть мысленно можно вставить «потому что», «а именно», «и увидел, что»): «Я выглянул в окно: шёл сильный дождь». Тире ставится, если вторая часть содержит следствие, резкое противопоставление, сравнение или если события сменяют друг друга быстро (можно мысленно вставить «поэтому», «но», «как будто»): «Сказано — сделано».\n\nКогда в одном предложении сочетаются разные виды связи, разбор такого предложения проводится в несколько этапов. Сначала выделяются все грамматические основы и определяются границы частей. Затем предложение делится на смысловые блоки по сочинительной или бессоюзной связи верхнего уровня — это самые крупные структурные части. После этого внутри каждого блока определяется, есть ли подчинительная связь: главная и придаточная часть, — и устанавливается тип придаточного. Наконец, строится схема предложения, показывающая иерархию частей: сначала общее деление на блоки, затем внутренняя структура каждого блока.\n\nНапример, в предложении «Дождь прекратился, и когда выглянуло солнце, все вышли на улицу» первый уровень связи — сочинительная (союз «и», соединяющий два блока), а внутри второго блока — подчинительная связь (придаточное времени «когда выглянуло солнце», зависящее от главной части «все вышли на улицу»).\n\nУмение анализировать сложные предложения с разными видами связи — это не просто технический навык синтаксического разбора, а показатель зрелого владения языком: такие конструкции позволяют выражать сложные, многоплановые мысли с точной передачей причинно-следственных, временных и логических отношений между событиями. Этот навык особенно важен при выполнении синтаксического разбора на экзамене и при редактировании собственных развёрнутых текстов — сочинений и эссе, где часто требуются именно такие многочленные конструкции.","quiz":[{"question":"Как соединяются части в бессоюзном сложном предложении?","options":["с помощью сочинительных союзов","с помощью подчинительных союзов","без союзов и союзных слов, по смыслу и интонации","только с помощью союзных слов"],"correctIndex":2},{"question":"Когда в БСП ставится двоеточие?","options":["при перечислении событий","если вторая часть поясняет, раскрывает причину первой","если вторая часть содержит резкое противопоставление","никогда"],"correctIndex":1},{"question":"Когда в БСП ставится тире?","options":["при перечислении","если вторая часть содержит следствие, противопоставление или быструю смену событий","только перед прямой речью","запятая и тире взаимозаменяемы всегда"],"correctIndex":1},{"question":"Что называют сложным предложением с разными видами связи?","options":["простое предложение с одним союзом","многочленное предложение, где сочетаются сочинительная, подчинительная и/или бессоюзная связь","предложение без грамматической основы","сложносочинённое предложение с одним союзом"],"correctIndex":1},{"question":"Какой первый шаг при разборе предложения с разными видами связи?","options":["сразу определить тип придаточного","выделить все грамматические основы и границы частей","поставить только знаки препинания","определить стиль текста"],"correctIndex":1},{"question":"В предложении «Дождь прекратился, и когда выглянуло солнце, все вышли на улицу» какая связь является связью верхнего (первого) уровня?","options":["подчинительная","бессоюзная","сочинительная","все части независимы"],"correctIndex":2},{"question":"Какой тип придаточного во второй части того же предложения («когда выглянуло солнце»)?","options":["придаточное определительное","придаточное времени","придаточное изъяснительное","придаточное цели"],"correctIndex":1},{"question":"Почему важно владеть многочленными сложными конструкциями?","options":["они не нужны в реальной речи","они позволяют точно передавать сложные логические отношения между событиями в развёрнутых текстах","они используются только в официально-деловом стиле","это устаревшая форма речи"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-24T08:30:00+05:00","ends_at":"2026-07-24T09:15:00+05:00","room":"301"}]'::jsonb)
    LOOP
      INSERT INTO public.lessons (group_id, subject_id, topic, title, description, status, starts_at, ends_at, started_at, ended_at, room, school_id)
      VALUES (
        v_group_id, v_subject_id, lesson_data->>'topic', lesson_data->>'topic', lesson_data->>'objective',
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN 'completed' ELSE 'scheduled' END,
        (lesson_data->>'starts_at')::timestamptz, (lesson_data->>'ends_at')::timestamptz,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'starts_at')::timestamptz ELSE NULL END,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'ends_at')::timestamptz ELSE NULL END,
        lesson_data->>'room', v_school_id
      )
      RETURNING id INTO v_lesson_id;

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, duration_min, school_id)
      VALUES (v_lesson_id, 1, 'middle', 'theory', 'presentation', lesson_data->>'topic', lesson_data->>'theory', 15, v_school_id);

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, duration_min, school_id)
      VALUES (v_lesson_id, 2, 'middle', 'task', 'quiz_qia', 'Проверь себя', 15, v_school_id)
      RETURNING id INTO v_stage_id;

      qpos := 0;
      FOR quiz_item IN SELECT * FROM jsonb_array_elements(lesson_data->'quiz')
      LOOP
        qpos := qpos + 1;
        INSERT INTO public.quiz_questions (stage_id, question_text, options, correct_option_index, position, points, time_per_question_seconds, school_id)
        VALUES (v_stage_id, quiz_item->>'question', quiz_item->'options', (quiz_item->>'correctIndex')::int, qpos, 1, 30, v_school_id);
      END LOOP;

      IF (lesson_data->>'hasExternalService')::boolean THEN
        INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, config, duration_min, school_id)
        VALUES (
          v_lesson_id, 3, 'middle', 'task', lesson_data->>'externalServiceType',
          lesson_data->>'externalServiceTask', lesson_data->>'externalServiceTask',
          jsonb_build_object('url',
            CASE lesson_data->>'externalServiceType'
              WHEN 'wokwi' THEN 'https://wokwi.com/projects/new/arduino-uno'
              WHEN 'codesandbox' THEN 'https://codesandbox.io/p/sandbox/vanilla'
              WHEN 'geogebra' THEN 'https://www.geogebra.org/classic'
              WHEN 'phet' THEN 'https://phet.colorado.edu/sims/html/forces-and-motion-basics/latest/forces-and-motion-basics_en.html'
              WHEN 'desmos' THEN 'https://www.desmos.com/calculator'
              WHEN 'blockly_games' THEN 'https://blockly.games/'
              WHEN 'visualgo' THEN 'https://visualgo.net/en'
              WHEN 'p5js' THEN 'https://editor.p5js.org/'
              WHEN 'excalidraw' THEN 'https://excalidraw.com/'
              WHEN 'learningapps' THEN 'https://learningapps.org/'
              WHEN 'sqlonline' THEN 'https://sqlime.org/'
              WHEN 'h5p' THEN 'https://h5p.eduos.snruz.uz/library'
              ELSE NULL
            END
          ),
          15, v_school_id
        );
      END IF;
    END LOOP;
  END IF;

  -- === 10-А класс | Математика (14 уроков) ===
  SELECT id INTO v_group_id FROM public.groups WHERE name = '10-А класс';
  SELECT id INTO v_subject_id FROM public.subjects WHERE group_id = v_group_id AND name = 'Математика';
  IF NOT EXISTS (SELECT 1 FROM public.lessons WHERE group_id = v_group_id AND subject_id = v_subject_id AND description IS NOT NULL) THEN
    FOR lesson_data IN SELECT * FROM jsonb_array_elements('[{"topic":"Действительные числа, модуль и числовые промежутки","objective":"Систематизировать знания о числовых множествах и научиться работать с модулем числа и числовыми промежутками.","theory":"В 10 классе мы обобщаем всё, что известно о числах. Множество натуральных чисел N = {1,2,3,...} используется для счёта. Добавив к нему ноль и отрицательные числа, получаем множество целых чисел Z. Если разрешить деление, то есть рассматривать числа вида m/n, где m — целое, n — натуральное, получаем множество рациональных чисел Q. Однако не всякое число можно представить в виде дроби: например, √2, π — иррациональные числа. Объединение рациональных и иррациональных чисел образует множество действительных чисел R. Между этими множествами существует включение: N ⊂ Z ⊂ Q ⊂ R.\n\nВажным понятием является модуль (абсолютная величина) числа a, обозначаемый |a|. Модуль показывает расстояние от точки a на числовой прямой до нуля и определяется так: |a| = a, если a ≥ 0; |a| = -a, если a < 0. Например, |5| = 5, |-3| = 3, |0| = 0. Модуль всегда неотрицателен. Геометрически |a - b| — это расстояние между точками a и b на числовой прямой. Это свойство активно используется при решении уравнений и неравенств с модулем, а также неравенств вида |x - a| < r, которое означает, что x находится в промежутке (a - r; a + r).\n\nЧисловые промежутки — удобная форма записи множеств чисел, удовлетворяющих неравенствам. Различают: отрезок [a; b] — включает оба конца; интервал (a; b) — не включает концы; полуинтервалы [a; b) и (a; b] — включают только один конец; лучи (-∞; a), (-∞; a], (a; +∞), [a; +∞). Например, решение неравенства 2x - 3 < 5 записывается как x < 4, то есть x ∈ (-∞; 4).\n\nПри решении неравенств с модулем нужно раскрывать модуль по определению или использовать геометрический смысл. Например, |x - 2| ≤ 3 означает, что расстояние от x до 2 не больше 3, то есть -3 ≤ x - 2 ≤ 3, откуда -1 ≤ x ≤ 5, или x ∈ [-1; 5].\n\nПонимание числовых множеств и модуля — фундамент для дальнейшего изучения функций, уравнений и неравенств в старшей школе, включая степенные, показательные и логарифмические выражения, где часто требуется учитывать область допустимых значений.","quiz":[{"question":"Какое множество чисел включает в себя все остальные?","options":["N","Z","Q","R"],"correctIndex":3},{"question":"Чему равен |-7|?","options":["-7","7","0","1/7"],"correctIndex":1},{"question":"Как записать интервал, не включающий концы 2 и 5?","options":["[2;5]","(2;5)","[2;5)","(2;5]"],"correctIndex":1},{"question":"Решите неравенство |x-2| ≤ 3.","options":["x∈[-1;5]","x∈(-1;5)","x∈[-5;1]","x∈(-∞;-1]∪[5;+∞)"],"correctIndex":0},{"question":"Число √2 принадлежит множеству:","options":["только Z","только Q","R, но не Q","N"],"correctIndex":2},{"question":"Чему равно |a-b| геометрически?","options":["сумме a и b","расстоянию между точками a и b на числовой прямой","произведению a и b","среднему арифметическому a и b"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-07T10:20:00+05:00","ends_at":"2026-07-07T11:05:00+05:00","room":"301"},{"topic":"Степень с рациональным показателем и её свойства","objective":"Ввести понятие степени с рациональным показателем и научиться применять её свойства при преобразовании выражений.","theory":"В основной школе мы изучали степень с натуральным и целым показателем: a^n = a·a·...·a (n раз), a^0 = 1 (a≠0), a^(-n) = 1/a^n. В 10 классе это понятие расширяется до рационального показателя.\n\nПусть a > 0, n — натуральное число, n ≥ 2. Тогда a^(1/n) = ⁿ√a (корень n-й степени из a). Например, 8^(1/3) = ³√8 = 2, 16^(1/4) = ⁴√16 = 2.\n\nДля рационального показателя m/n (где m — целое, n — натуральное, дробь несократима) степень определяется как a^(m/n) = ⁿ√(a^m) = (ⁿ√a)^m, при a > 0. Например, 27^(2/3) = (³√27)² = 3² = 9.\n\nВажно: показатель определяется при a>0, чтобы избежать противоречий при разных представлениях одной и той же дроби m/n.\n\nСвойства степени с рациональным показателем аналогичны свойствам степени с целым показателем (при a>0, b>0, p, q ∈ Q):\n1) a^p · a^q = a^(p+q)\n2) a^p : a^q = a^(p-q)\n3) (a^p)^q = a^(p·q)\n4) (a·b)^p = a^p · b^p\n5) (a/b)^p = a^p / b^p\n\nПример: упростить выражение 3^(1/2) · 3^(3/2) = 3^(1/2+3/2) = 3² = 9. Другой пример: (16^(1/2))^(1/2) = 16^(1/4) = 2, так как 2^4=16.\n\nПри решении задач полезно переходить от корней к степеням и обратно. Например, выражение √a · ³√a можно записать как a^(1/2) · a^(1/3) = a^(1/2+1/3) = a^(5/6) = ⁶√(a^5).\n\nЭти свойства станут основой при изучении степенной функции, а затем — показательной функции, где показатель степени становится переменной величиной. Умение свободно переходить между корнями и степенями с дробным показателем необходимо для упрощения сложных выражений и решения уравнений в дальнейших темах курса.","quiz":[{"question":"Чему равно 8^(1/3)?","options":["2","3","4","8"],"correctIndex":0},{"question":"Чему равно 27^(2/3)?","options":["3","6","9","81"],"correctIndex":2},{"question":"Какое условие обязательно для a в выражении a^(m/n) при общем определении?","options":["a<0","a=0","a>0","a — любое"],"correctIndex":2},{"question":"Упростите 3^(1/2)·3^(3/2).","options":["3","6","9","3^(3/4)"],"correctIndex":2},{"question":"Чему равно (16^(1/2))^(1/2)?","options":["2","4","8","16"],"correctIndex":0},{"question":"Как записать a^(5/6) через корень?","options":["√(a^5)","⁶√(a^5)","⁵√(a^6)","a^(6/5)"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-08T08:30:00+05:00","ends_at":"2026-07-08T09:15:00+05:00","room":"301"},{"topic":"Степенная функция: свойства и график","objective":"Изучить свойства степенной функции y = x^p при различных значениях показателя p и научиться строить и анализировать её график.","theory":"Степенной функцией называется функция вида y = x^p, где p — фиксированное действительное число, а x — переменная (в отличие от показательной функции, где переменная находится в показателе). Свойства степенной функции существенно зависят от значения показателя p.\n\n1) Если p — натуральное чётное число (2,4,6,...), функция определена на всей числовой прямой, чётная, убывает на (-∞;0] и возрастает на [0;+∞), принимает значения y ≥ 0. Пример: y = x².\n\n2) Если p — натуральное нечётное число (1,3,5,...), функция определена на всей прямой, нечётная, возрастает на всей области определения. Пример: y = x³.\n\n3) Если p — отрицательное чётное целое (например, -2), функция определена при x≠0, чётная, при x>0 убывает, при x<0 возрастает, график состоит из двух ветвей в I и II четвертях, приближающихся к осям.\n\n4) Если p — отрицательное нечётное число (например, -1, гипербола y=1/x), функция определена при x≠0, нечётная, убывает на каждом из промежутков, ветви расположены в I и III четвертях.\n\n5) Если p — положительное нецелое (например, 1/2, то есть y=√x), функция определена при x≥0, возрастает, y≥0.\n\n6) Если p — отрицательное нецелое, функция определена при x>0, убывает, y>0.\n\nОбщая точка всех графиков при p≠0 — точка (1;1), потому что 1^p = 1 при любом p.\n\nПри построении графика степенной функции важно сначала определить область определения (учитывая чётность/нечётность показателя), затем исследовать монотонность и симметрию, и только потом строить график по характерным точкам.\n\nПонимание поведения степенных функций с разными показателями важно для сравнения роста функций и подготовит к изучению показательной и логарифмической функций, где также анализируются монотонность, область определения и асимптотическое поведение.","quiz":[{"question":"При каком p функция y=x^p является чётной и определена на всей прямой?","options":["p — нечётное натуральное","p — чётное натуральное","p — отрицательное","p — дробное"],"correctIndex":1},{"question":"Какова область определения функции y=√x?","options":["x∈R","x≥0","x>0","x≠0"],"correctIndex":1},{"question":"Через какую точку проходят графики всех степенных функций y=x^p (p≠0)?","options":["(0;0)","(1;1)","(1;0)","(0;1)"],"correctIndex":1},{"question":"Как ведёт себя функция y=1/x при x→0+?","options":["стремится к 0","стремится к +∞","остаётся постоянной","стремится к -∞"],"correctIndex":1},{"question":"Функция y=x³ является:","options":["чётной","нечётной","ни чётной ни нечётной","периодической"],"correctIndex":1},{"question":"При p=-2 график функции y=x^p расположен в четвертях:","options":["I и III","I и II","II и IV","только в I"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"desmos","externalServiceTask":"Постройте в Desmos графики y=x², y=x³, y=√x, y=1/x, y=x^(-2) на одной плоскости, сравните их поведение при x>0, x<0 и отметьте общую точку (1;1).","starts_at":"2026-07-09T11:15:00+05:00","ends_at":"2026-07-09T12:00:00+05:00","room":"301"},{"topic":"Иррациональные уравнения и их решение","objective":"Научиться решать иррациональные уравнения, содержащие корни, с обязательной проверкой найденных корней или учётом ОДЗ.","theory":"Иррациональным называется уравнение, в котором переменная находится под знаком корня. Простейший вид: √(f(x)) = g(x). Основной метод решения — возведение обеих частей уравнения в степень, соответствующую показателю корня, чтобы избавиться от радикала.\n\nДля уравнения √(f(x)) = g(x) справедливо: возводя обе части в квадрат, получаем f(x) = g(x)², но это уравнение может иметь посторонние корни, так как возведение в чётную степень — необратимая операция. Поэтому корректная схема решения такова: √(f(x)) = g(x) ⟺ { f(x) = g²(x); g(x) ≥ 0 }.\n\nПример 1: √(2x+3) = x. Возводим в квадрат: 2x+3 = x². Получаем x² - 2x - 3 = 0, откуда x=3 или x=-1. Проверяем условие g(x)=x≥0: x=3 подходит, x=-1 не подходит (посторонний корень). Ответ: x=3.\n\nЕсли уравнение содержит два радикала: √(f(x)) = √(g(x)), то оно равносильно системе f(x)=g(x), f(x)≥0.\n\nБолее сложные уравнения вида √(f(x)) + √(g(x)) = h(x) решаются последовательным уединением радикалов и возведением в степень несколько раз, либо методом замены переменной.\n\nПример 2: √(x+7) - √(x-1) = 2. Уединяем один корень: √(x+7) = 2 + √(x-1). Возводим в квадрат: x+7 = 4 + 4√(x-1) + (x-1). Упрощаем: x+7 = x+3+4√(x-1), откуда 4 = 4√(x-1), √(x-1)=1, x-1=1, x=2. Проверка: √9 - √1 = 3-1=2 — верно.\n\nОбязательный этап решения любого иррационального уравнения — проверка полученных корней подстановкой в исходное уравнение или строгий учёт ОДЗ и условий неотрицательности на каждом шаге. Это отличает иррациональные уравнения от большинства алгебраических: возведение в чётную степень может порождать посторонние корни, которые необходимо отсеивать.\n\nИррациональные уравнения часто встречаются в задачах на движение, геометрических задачах с применением теоремы Пифагора, а также в физике, поэтому владение методом их решения важно для дальнейшего изучения курса.","quiz":[{"question":"Что необходимо сделать после решения иррационального уравнения?","options":["Ничего, сразу дать ответ","проверить корни подстановкой в исходное уравнение","умножить ответ на 2","взять модуль ответа"],"correctIndex":1},{"question":"Уравнение √(f(x))=g(x) равносильно системе:","options":["f(x)=g²(x) и g(x)≥0","f(x)=g(x) и f(x)≥0","f(x)=g²(x) без условий","f(x)≥0 только"],"correctIndex":0},{"question":"Решите √(2x+3)=x, укажите верный корень.","options":["x=-1","x=3","x=0","x=1"],"correctIndex":1},{"question":"Почему при возведении в квадрат могут появиться посторонние корни?","options":["Потому что возведение в квадрат — необратимая операция для отрицательных чисел","потому что квадрат всегда положителен","потому что корень не существует","потому что x всегда больше 0"],"correctIndex":0},{"question":"В уравнении √(f(x))=√(g(x)) достаточно потребовать:","options":["f(x)=g(x) и f(x)≥0","f(x)=-g(x)","f(x)>g(x)","ничего дополнительного не нужно"],"correctIndex":0},{"question":"Решите √(x+7)-√(x-1)=2.","options":["x=1","x=2","x=3","x=9"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-10T12:10:00+05:00","ends_at":"2026-07-10T12:55:00+05:00","room":"301"},{"topic":"Показательная функция: свойства и график","objective":"Ввести понятие показательной функции, изучить её свойства и график в зависимости от основания.","theory":"Показательной функцией называется функция вида y = a^x, где a>0, a≠1, x — любое действительное число (в отличие от степенной функции, здесь переменная стоит в показателе, а основание фиксировано).\n\nОбласть определения показательной функции — все действительные числа, область значений — все положительные числа (0;+∞), то есть график всегда расположен выше оси Ox и никогда её не пересекает (ось Ox — горизонтальная асимптота).\n\nПоведение функции зависит от основания a: если a>1, функция возрастает на всей области определения (например, y=2^x, y=3^x); если 0<a<1, функция убывает на всей области определения (например, y=(1/2)^x).\n\nВсе графики показательных функций проходят через точку (0;1), так как a^0=1 при любом a>0. Ещё одна характерная точка — (1;a).\n\nПоказательная функция не имеет ни максимумов, ни минимумов, она монотонна на всей области определения, что позволяет решать показательные уравнения и неравенства методом сравнения показателей при равных основаниях.\n\nКлючевое свойство: показательная функция инъективна, то есть если a^x1 = a^x2, то x1 = x2 (при a>0, a≠1). Это свойство лежит в основе решения простейших показательных уравнений вида a^x = a^b ⟺ x = b.\n\nПример: решить уравнение 2^x = 8. Так как 8 = 2³, получаем 2^x = 2³, откуда x=3.\n\nПоказательная функция описывает множество процессов в природе и технике: рост популяций, радиоактивный распад, изменение атмосферного давления с высотой, начисление сложных процентов в банке по формуле S = S₀·(1+p/100)^n.\n\nОтдельное место занимает число e ≈ 2,71828... (число Эйлера) — основание натуральной показательной функции y=e^x, широко используемой в математическом анализе, физике и экономике.\n\nПри построении графика показательной функции полезно отметить опорные точки (0;1), (1;a), (-1;1/a), учесть асимптоту y=0 и направление монотонности в зависимости от основания.","quiz":[{"question":"Какова область значений функции y=a^x при a>0, a≠1?","options":["R","(0;+∞)","[0;+∞)","(-∞;0)"],"correctIndex":1},{"question":"Через какую точку проходит график любой показательной функции y=a^x?","options":["(1;0)","(0;1)","(0;0)","(1;1)"],"correctIndex":1},{"question":"При каком условии на a функция y=a^x возрастает?","options":["0<a<1","a>1","a=1","a<0"],"correctIndex":1},{"question":"Решите уравнение 2^x=8.","options":["2","3","4","8"],"correctIndex":1},{"question":"Что является горизонтальной асимптотой графика y=a^x?","options":["x=0","y=0","y=1","x=1"],"correctIndex":1},{"question":"Какое свойство лежит в основе решения a^x1=a^x2 ⟹ x1=x2?","options":["Чётность функции","монотонность (инъективность) показательной функции","периодичность","ограниченность"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"desmos","externalServiceTask":"Постройте в Desmos графики y=2^x, y=(1/2)^x и y=3^x с использованием слайдера для основания a; определите, как основание влияет на скорость роста/убывания и подтвердите точку (0;1).","starts_at":"2026-07-13T09:25:00+05:00","ends_at":"2026-07-13T10:10:00+05:00","room":"301"},{"topic":"Показательные уравнения: основные методы решения","objective":"Научиться решать показательные уравнения методом приведения к одинаковому основанию и вынесения общего множителя.","theory":"Показательным называется уравнение, в котором переменная содержится в показателе степени. Простейшее показательное уравнение имеет вид a^x = b, где a>0, a≠1.\n\nОсновной метод решения — приведение обеих частей уравнения к одинаковому основанию, после чего используется свойство инъективности показательной функции: a^f(x) = a^g(x) ⟺ f(x) = g(x).\n\nПример 1: 3^(2x-1) = 27. Так как 27=3³, получаем 3^(2x-1)=3³, откуда 2x-1=3, x=2.\n\nПример 2: 5^(x²-4x) = 1. Так как 1 = 5⁰, получаем x²-4x=0, откуда x=0 или x=4.\n\nЕсли основания разных степеней можно привести к общему, это тоже упрощает уравнение. Например, 4^x = 8^(x-1). Приводим к основанию 2: 4=2², 8=2³, получаем 2^(2x) = 2^(3x-3). Отсюда 2x=3x-3, x=3.\n\nВторой важный метод — вынесение общего множителя за скобки, когда уравнение содержит сумму степеней с одинаковым основанием, но разными показателями. Например, 2^(x+2) + 2^x = 40. Разложим: 2^x·2² + 2^x = 40, то есть 2^x(4+1)=40, 2^x=8=2³, x=3.\n\nТретий метод — замена переменной, применяется, когда уравнение сводится к квадратному относительно a^x. Например, 4^x - 5·2^x + 4 = 0. Заметим, что 4^x = (2^x)², и введём замену t=2^x, t>0. Получаем t² - 5t + 4 = 0, откуда t=1 или t=4. Возвращаемся: 2^x=1 ⟹ x=0; 2^x=4 ⟹ x=2. Ответ: x=0, x=2.\n\nПри решении важно помнить, что показательная функция принимает только положительные значения, поэтому при замене t=a^x обязательно указывается условие t>0, и отрицательные или нулевые значения t отбрасываются как посторонние.\n\nПоказательные уравнения часто встречаются в задачах на моделирование реальных процессов — например, при определении времени, за которое популяция бактерий достигнет заданного размера, или при расчёте периода полураспада радиоактивного вещества.\n\nОсвоение базовых методов создаёт основу для решения более сложных показательных уравнений, которые будут рассмотрены на следующем уроке.","quiz":[{"question":"Решите уравнение 3^(2x-1)=27.","options":["x=1","x=2","x=3","x=4"],"correctIndex":1},{"question":"Чему равно решение уравнения 5^(x²-4x)=1?","options":["x=0 и x=4","только x=0","только x=4","x=1 и x=5"],"correctIndex":0},{"question":"При решении 4^x-5·2^x+4=0 какая замена используется?","options":["t=4^x","t=2^x","t=x²","t=5^x"],"correctIndex":1},{"question":"Почему при замене t=a^x требуется условие t>0?","options":["Показательная функция всегда положительна","t не может быть целым","a должно быть меньше 1","это условие не нужно"],"correctIndex":0},{"question":"Решите 2^(x+2)+2^x=40.","options":["x=2","x=3","x=4","x=5"],"correctIndex":1},{"question":"Уравнение 4^x=8^(x-1) при переходе к основанию 2 даёт:","options":["2x=3x-3","2x=3x","x=3x-3","4x=8x-8"],"correctIndex":0}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-14T10:20:00+05:00","ends_at":"2026-07-14T11:05:00+05:00","room":"301"},{"topic":"Показательные уравнения — Часть 2","objective":"Освоить решение более сложных показательных уравнений и систем уравнений с несколькими показательными выражениями.","theory":"Продолжаем изучение показательных уравнений, переходя к более сложным конструкциям: уравнениям с двумя разными основаниями, не сводящимися напрямую друг к другу, показательно-степенным уравнениям и системам.\n\n1) Метод деления на показательное выражение. Если уравнение содержит выражения вида a^(2x) и (a·b)^x или b^(2x), полезно разделить обе части на одно из слагаемых. Пример: 9^x - 6^x = 2·4^x. Разделим обе части на 4^x: (9/4)^x - (6/4)^x = 2, то есть (3/2)^(2x) - (3/2)^x - 2=0. Пусть t=(3/2)^x, t>0: t²-t-2=0, (t-2)(t+1)=0, t=2 (t=-1 не подходит). (3/2)^x=2, откуда x = log_{1.5}2.\n\n2) Однородные показательные уравнения. Уравнение вида A·a^(2x) + B·(ab)^x + C·b^(2x) = 0 называется однородным относительно a^x и b^x и решается делением на b^(2x) с последующей заменой t=(a/b)^x.\n\n3) Системы показательных уравнений с двумя переменными. Например: {2^x·3^y=12; 2^(x+1)·3^(y-1)=8}. Такие системы решаются подбором подходящих значений или комбинацией уравнений. Проверим x=2, y=1: 2²·3¹=4·3=12 — верно; проверим второе: 2³·3⁰=8·1=8 — верно. Ответ: x=2, y=1.\n\n4) Показательно-степенные уравнения вида f(x)^(g(x)) = f(x)^(h(x)) требуют рассмотрения нескольких случаев: f(x)=1 (тождество верно при любых показателях), f(x)=-1 с чётными показателями, и f(x)>0, f(x)≠1 (тогда g(x)=h(x)).\n\nПример: (x-2)^(x²-4) = 1. Рассмотрим случаи: а) x-2=1 ⟹ x=3; б) x-2=-1 и x²-4 чётное ⟹ x=1, но 1-4=-3 нечётное, не подходит; в) x²-4=0 и x-2≠0 ⟹ x=±2, x=2 даёт основание 0 (не подходит), x=-2: основание -4, показатель 0, (-4)^0=1 — подходит. Ответ: x=3, x=-2.\n\nТакие уравнения требуют внимательности и проверки каждого случая отдельно, а также учёта ОДЗ: основание степени с переменным показателем должно быть определено корректно.","quiz":[{"question":"При решении 9^x-6^x=2·4^x на что удобно разделить обе части?","options":["На 9^x","На 4^x","На 6^x","На x"],"correctIndex":1},{"question":"Однородное показательное уравнение решается заменой:","options":["t=x","t=(a/b)^x","t=a+b","t=ab"],"correctIndex":1},{"question":"В системе {2^x·3^y=12; 2^(x+1)·3^(y-1)=8} решением является:","options":["x=1,y=2","x=2,y=1","x=0,y=0","x=3,y=1"],"correctIndex":1},{"question":"Уравнение f(x)^(g(x))=f(x)^(h(x)) при f(x)=1 выполняется:","options":["никогда","при любых показателях","только при g(x)=h(x)","только при x=0"],"correctIndex":1},{"question":"В примере (x-2)^(x²-4)=1 значение x=-2 подходит, потому что:","options":["основание равно 1","показатель степени равен 0, а основание отлично от 0","x²-4 положительно","основание больше 1"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-15T08:30:00+05:00","ends_at":"2026-07-15T09:15:00+05:00","room":"301"},{"topic":"Показательные неравенства и их решение","objective":"Научиться решать показательные неравенства, используя монотонность показательной функции.","theory":"Показательным называется неравенство, в котором переменная входит в показатель степени, например a^x > b или a^(f(x)) < a^(g(x)).\n\nКлючевая идея решения — использовать свойство монотонности показательной функции y=a^x: если a>1, функция возрастает, поэтому неравенство a^(f(x)) > a^(g(x)) равносильно f(x) > g(x); если 0<a<1, функция убывает, поэтому неравенство равносильно f(x) < g(x) (знак меняется на противоположный).\n\nПример 1: решить 2^(x-1) > 8. Так как 8=2³ и основание 2>1, неравенство равносильно x-1>3, откуда x>4.\n\nПример 2: решить (1/3)^x ≤ 9. Так как 9=(1/3)^(-2) и основание 1/3<1, неравенство равносильно x ≥ -2 (знак меняется), то есть x∈[-2;+∞).\n\nЕсли основания разных степеней разные, но неравенство можно свести к общему основанию — например, 4^x < 8, то приводим 4=2², 8=2³, получаем 2^(2x) < 2³. Так как 2>1, неравенство равносильно 2x<3, x<1.5.\n\nДля более сложных неравенств применяется метод замены переменной. Пример: решить 9^x - 4·3^x + 3 ≤ 0. Пусть t=3^x, t>0. Получаем t²-4t+3≤0, откуда (t-1)(t-3)≤0, значит t∈[1;3]. Возвращаемся: 1 ≤ 3^x ≤ 3, то есть 0 ≤ x ≤ 1.\n\nВажно всегда учитывать знак основания при переходе от неравенства с показателями к неравенству с самими показателями — это самая частая ошибка учеников: при основании меньше единицы знак неравенства обязательно меняется на противоположный, а при основании больше единицы — сохраняется.\n\nТакже при использовании замены переменной t=a^x нельзя забывать про условие t>0.\n\nПоказательные неравенства применяются, например, для нахождения интервалов времени, за которые количество вещества станет меньше заданного порога, или для определения условий, при которых вложенная сумма денег превысит определённое значение при заданной процентной ставке.","quiz":[{"question":"Неравенство 2^(x-1) > 8 равносильно (при основании 2>1):","options":["x-1<3","x-1>3","x<3","x>3"],"correctIndex":1},{"question":"Решите (1/3)^x ≤ 9.","options":["x≥-2","x≤-2","x≥2","x≤2"],"correctIndex":0},{"question":"При основании 0<a<1 знак неравенства a^f(x) > a^g(x) при переходе к f(x) и g(x):","options":["сохраняется","меняется на противоположный","становится равенством","зависит от x"],"correctIndex":1},{"question":"Решите 9^x-4·3^x+3≤0.","options":["x∈[0;1]","x∈[1;3]","x∈(-∞;0]","x∈[3;+∞)"],"correctIndex":0},{"question":"При замене t=a^x в неравенстве обязательно учитывать условие:","options":["t<0","t>0","t=0","t — целое"],"correctIndex":1},{"question":"Приведите 4^x<8 к основанию 2 и решите.","options":["x<1.5","x>1.5","x<3","x<2"],"correctIndex":0}],"hasExternalService":true,"externalServiceType":"desmos","externalServiceTask":"В Desmos постройте графики y=2^(x-1) и y=8, найдите точку пересечения и определите промежуток, где 2^(x-1) > 8, сравните с аналитическим решением x>4.","starts_at":"2026-07-16T11:15:00+05:00","ends_at":"2026-07-16T12:00:00+05:00","room":"301"},{"topic":"Понятие логарифма и его свойства","objective":"Ввести понятие логарифма как операции, обратной возведению в степень, и изучить основные свойства логарифмов.","theory":"Логарифмом числа b по основанию a (a>0, a≠1, b>0) называется показатель степени, в которую нужно возвести a, чтобы получить b. Обозначается log_a b. По определению: a^(log_a b) = b.\n\nНапример, log_2 8 = 3, так как 2³=8. log_5 25 = 2, так как 5²=25. log_3 (1/9) = -2, так как 3^(-2)=1/9.\n\nЛогарифм существует только при b>0 и при a>0, a≠1.\n\nОсобые случаи: log_a 1 = 0 (так как a⁰=1); log_a a = 1 (так как a¹=a).\n\nДесятичный логарифм (основание 10) обозначается lg b = log_10 b. Натуральный логарифм (основание e≈2,71828) обозначается ln b = log_e b.\n\nОсновные свойства логарифмов (при a>0, a≠1, x>0, y>0):\n1) log_a(xy) = log_a x + log_a y.\n2) log_a(x/y) = log_a x - log_a y.\n3) log_a(x^p) = p·log_a x.\n4) log_a b = log_c b / log_c a (формула перехода к новому основанию, c>0, c≠1).\n5) log_a b = 1/log_b a.\n\nПример 1: вычислить log_2 8 + log_2 4. По свойству суммы: log_2(8·4) = log_2 32 = 5.\n\nПример 2: упростить log_3 x² при x>0: log_3(x²) = 2 log_3 x.\n\nПример 3: вычислить log_2 5 · log_5 2. По формуле перехода log_5 2 = 1/log_2 5, значит произведение равно 1.\n\nЛогарифмы были изобретены для упрощения сложных вычислений — умножение и деление больших чисел сводились к сложению и вычитанию их логарифмов. Сегодня логарифмическая шкала используется в физике (шкала Рихтера, децибелы, шкала pH), в информатике (сложность алгоритмов), в биологии и экономике.\n\nПонимание свойств логарифма — необходимая база для изучения логарифмической функции, а также для решения логарифмических уравнений и неравенств, которые будут рассмотрены в следующих уроках. Важно чётко запоминать области допустимых значений при преобразовании логарифмических выражений.","quiz":[{"question":"Чему равен log_2 8?","options":["2","3","4","8"],"correctIndex":1},{"question":"Чему равен log_a 1 при допустимом a?","options":["1","0","a","-1"],"correctIndex":1},{"question":"Свойство log_a(xy) равно:","options":["log_a x · log_a y","log_a x + log_a y","log_a x - log_a y","(log_a x)(log_a y)"],"correctIndex":1},{"question":"Чему равен log_a(x^p)?","options":["p+log_a x","p·log_a x","(log_a x)^p","log_a x / p"],"correctIndex":1},{"question":"Формула перехода к новому основанию: log_a b =","options":["log_c a / log_c b","log_c b / log_c a","log_b a","1/(a·b)"],"correctIndex":1},{"question":"Вычислите log_2 5 · log_5 2.","options":["0","1","2","10"],"correctIndex":1},{"question":"При каких условиях определён log_a b?","options":["a>0, a≠1, b>0","a и b — любые","a>1, b<0","a≠0, b≠0"],"correctIndex":0}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-17T12:10:00+05:00","ends_at":"2026-07-17T12:55:00+05:00","room":"301"},{"topic":"Логарифмическая функция: свойства и график","objective":"Изучить свойства логарифмической функции, её график и связь с показательной функцией как обратной.","theory":"Логарифмической функцией называется функция вида y = log_a x, где a>0, a≠1. Эта функция является обратной к показательной функции y=a^x: log_a(a^x)=x и a^(log_a x)=x (при x>0).\n\nОбласть определения логарифмической функции — только положительные числа: (0;+∞), поскольку логарифм определён лишь для положительных аргументов. Область значений — все действительные числа.\n\nПоведение функции зависит от основания: при a>1 функция возрастает на всей области определения; при 0<a<1 функция убывает.\n\nГрафик логарифмической функции всегда проходит через точку (1;0), так как log_a 1=0 при любом допустимом a. Вертикальная асимптота — ось Oy: при x→0+ значение log_a x стремится к -∞ (при a>1) или к +∞ (при 0<a<1).\n\nПоскольку показательная и логарифмическая функции с одинаковым основанием взаимно обратны, их графики симметричны относительно прямой y=x. Например, график y=log_2 x получается отражением графика y=2^x относительно этой прямой.\n\nЛогарифмическая функция монотонна, а значит инъективна: log_a x1 = log_a x2 ⟹ x1=x2 (при x1,x2>0). Это свойство — основа решения простейших логарифмических уравнений.\n\nСравнение логарифмов с разными аргументами при одном основании также опирается на монотонность: если a>1 и x1<x2, то log_a x1 < log_a x2; если 0<a<1 и x1<x2, то log_a x1 > log_a x2.\n\nЛогарифмическая функция описывает, например, шкалу pH в химии (pH = -lg[H+]), интенсивность звука в децибелах и многие другие явления, где важен медленный, логарифмический рост величины при быстром росте аргумента.","quiz":[{"question":"Какова область определения функции y=log_a x?","options":["R","(0;+∞)","[0;+∞)","(-∞;0)"],"correctIndex":1},{"question":"Через какую точку проходит график любой логарифмической функции?","options":["(0;1)","(1;0)","(0;0)","(1;1)"],"correctIndex":1},{"question":"При каком условии на a функция y=log_a x убывает?","options":["a>1","0<a<1","a=1","a<0"],"correctIndex":1},{"question":"Графики y=a^x и y=log_a x симметричны относительно:","options":["оси Ox","прямой y=x","оси Oy","начала координат"],"correctIndex":1},{"question":"Что происходит с log_a x при x→0+ и a>1?","options":["стремится к 0","стремится к -∞","стремится к +∞","остаётся постоянным"],"correctIndex":1},{"question":"Какая функция является обратной к y=log_a x?","options":["y=x^a","y=a^x","y=x/a","y=a/x"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"desmos","externalServiceTask":"Постройте в Desmos графики y=2^x, y=log_2 x и прямую y=x. Убедитесь в симметрии графиков относительно прямой y=x и найдите точку пересечения y=log_2 x с осью Ox.","starts_at":"2026-07-20T09:25:00+05:00","ends_at":"2026-07-20T10:10:00+05:00","room":"301"},{"topic":"Логарифмические уравнения: методы решения","objective":"Научиться решать логарифмические уравнения с обязательным учётом области допустимых значений.","theory":"Логарифмическим называется уравнение, содержащее переменную под знаком логарифма. Простейшее уравнение имеет вид log_a f(x) = b, которое равносильно f(x) = a^b.\n\nВажнейший этап решения любого логарифмического уравнения — нахождение ОДЗ, то есть множества значений x, при которых все логарифмы имеют смысл (аргумент каждого логарифма должен быть положительным, основание — положительным и не равным 1).\n\nОсновной метод решения уравнения вида log_a f(x) = log_a g(x) — использование инъективности логарифмической функции: такое уравнение равносильно системе {f(x) = g(x); f(x) > 0}.\n\nПример 1: log_3(x+2) = log_3(2x-1). ОДЗ: x>0,5. Уравнение: x+2=2x-1, откуда x=3. Проверяем ОДЗ: подходит.\n\nПример 2: log_2(x²-x) = log_2(3x-3). Уравнение: x²-x=3x-3, x²-4x+3=0, x=1 или x=3. ОДЗ: x²-x>0 и 3x-3>0, итого x>1. Проверяем: x=1 не входит в ОДЗ, x=3 входит. Ответ: x=3.\n\nЕсли уравнение содержит логарифмы с разными основаниями, их сначала приводят к одному основанию по формуле перехода.\n\nЧасто применяется метод замены переменной, когда уравнение сводится к квадратному относительно log_a x. Пример: (log_2 x)² - 3log_2 x + 2 = 0. Пусть t=log_2 x. Получаем t²-3t+2=0, t=1 или t=2. Возвращаемся: log_2 x=1 ⟹ x=2; log_2 x=2 ⟹ x=4. Оба значения положительны — входят в ОДЗ. Ответ: x=2, x=4.\n\nТакже используются свойства логарифмов для упрощения уравнения перед решением, но важно помнить, что применение этих свойств может сужать или расширять ОДЗ, поэтому финальную проверку корней в исходном уравнении желательно проводить всегда.\n\nЛогарифмические уравнения — распространённый тип заданий на итоговой аттестации, поэтому важно отработать навык нахождения и учёта ОДЗ на каждом шаге решения.","quiz":[{"question":"Что обязательно нужно найти перед решением логарифмического уравнения?","options":["Производную","ОДЗ (область допустимых значений)","период функции","асимптоту"],"correctIndex":1},{"question":"Уравнение log_a f(x)=log_a g(x) равносильно системе:","options":["f(x)=g(x) и f(x)>0","f(x)=-g(x)","f(x)>g(x)","f(x)=g(x) без условий"],"correctIndex":0},{"question":"Решите log_3(x+2)=log_3(2x-1).","options":["x=1","x=3","x=2","x=0.5"],"correctIndex":1},{"question":"В уравнении log_2(x²-x)=log_2(3x-3) корень x=1 отбрасывается, потому что:","options":["не удовлетворяет ОДЗ","не является целым числом","слишком мал","не удовлетворяет знаку минус"],"correctIndex":0},{"question":"Решите (log_2 x)²-3log_2 x+2=0.","options":["x=1,x=2","x=2,x=4","x=4,x=8","x=1,x=4"],"correctIndex":1},{"question":"Какая замена используется в уравнении с (log_a x)²?","options":["t=x²","t=log_a x","t=a^x","t=1/x"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-21T10:20:00+05:00","ends_at":"2026-07-21T11:05:00+05:00","room":"301"},{"topic":"Логарифмические неравенства и их решение","objective":"Научиться решать логарифмические неравенства с учётом монотонности логарифмической функции и ОДЗ.","theory":"Логарифмическое неравенство содержит переменную под знаком логарифма, например log_a f(x) > log_a g(x) или log_a f(x) > b.\n\nПервый и обязательный шаг — определение ОДЗ: аргументы всех логарифмов должны быть положительны.\n\nДалее применяется свойство монотонности логарифмической функции: если a>1 (функция возрастает), неравенство log_a f(x) > log_a g(x) равносильно системе {f(x) > g(x); f(x)>0; g(x)>0} — знак сохраняется; если 0<a<1 (функция убывает), неравенство равносильно системе {f(x) < g(x); f(x)>0; g(x)>0} — знак меняется на противоположный.\n\nПример 1: решить log_2(x-1) > log_2 3. ОДЗ: x>1. Так как основание 2>1, неравенство равносильно x-1>3, x>4. С учётом ОДЗ ответ: x∈(4;+∞).\n\nПример 2: решить log_{0.5}(2x-1) ≥ -2. Перепишем: -2 = log_{0.5} 4. Получаем log_{0.5}(2x-1) ≥ log_{0.5} 4. ОДЗ: x>0,5. Так как основание 0,5<1, знак меняется: 2x-1 ≤ 4, x ≤ 2,5. С учётом ОДЗ: x∈(0,5; 2,5].\n\nДля неравенств вида log_a f(x) > b (без логарифма справа) удобно представить b как log_a(a^b) и далее действовать так же.\n\nПри решении более сложных неравенств применяется метод замены переменной с последующим методом интервалов. Пример: (log_3 x)² - log_3 x - 2 < 0, ОДЗ: x>0. Пусть t=log_3 x. Неравенство t²-t-2<0 равносильно (t-2)(t+1)<0, откуда t∈(-1;2). Возвращаемся: -1 < log_3 x < 2, то есть x∈(1/3; 9).\n\nЧастая ошибка учащихся — забыть про смену знака неравенства при основании меньше единицы, а также забыть учесть ОДЗ в финальном ответе. Итоговый ответ является результатом пересечения решения неравенства и ОДЗ.\n\nЛогарифмические неравенства регулярно встречаются в заданиях профильного уровня и требуют аккуратности на каждом этапе решения.","quiz":[{"question":"Первый шаг при решении логарифмического неравенства:","options":["подобрать ответ","найти ОДЗ","построить график","продифференцировать"],"correctIndex":1},{"question":"При основании a>1 неравенство log_a f(x)>log_a g(x) равносильно:","options":["f(x)<g(x)","f(x)>g(x) (с учётом ОДЗ)","f(x)=g(x)","f(x)≥g(x) всегда"],"correctIndex":1},{"question":"При основании 0<a<1 знак неравенства при переходе к f(x) и g(x):","options":["сохраняется","меняется на противоположный","становится равенством","неопределён"],"correctIndex":1},{"question":"Решите log_2(x-1)>log_2 3.","options":["x∈(1;4)","x∈(4;+∞)","x∈(-∞;4)","x∈(3;+∞)"],"correctIndex":1},{"question":"Итоговый ответ логарифмического неравенства получают как:","options":["объединение решения и ОДЗ","пересечение решения неравенства и ОДЗ","только решение неравенства","только ОДЗ"],"correctIndex":1},{"question":"Решите (log_3 x)²-log_3 x-2<0.","options":["x∈(1/3;9)","x∈(-1;2)","x∈(3;9)","x∈(1/9;3)"],"correctIndex":0}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-22T08:30:00+05:00","ends_at":"2026-07-22T09:15:00+05:00","room":"301"},{"topic":"Радианная мера угла и тригонометрический круг","objective":"Ввести радианную меру угла, единичную (тригонометрическую) окружность и основные тригонометрические тождества.","theory":"До сих пор мы измеряли углы в градусах, где полный оборот равен 360°. В математическом анализе и тригонометрии удобнее использовать радианную меру угла. Один радиан — это угол, опирающийся на дугу окружности, длина которой равна радиусу этой окружности. Поскольку длина всей окружности равна 2πR, полный оборот (360°) соответствует углу 2π радиан. Отсюда: 180° = π радиан, и формулы перевода: α(рад) = α(°)·π/180; α(°) = α(рад)·180/π.\n\nНапример, 90° = π/2 рад, 60° = π/3 рад, 45° = π/4 рад, 30° = π/6 рад.\n\nДля определения тригонометрических функций произвольного угла используется единичная окружность (тригонометрический круг) — окружность радиуса 1 с центром в начале координат. Угол α откладывается от положительного направления оси Ox против часовой стрелки (при α>0) или по часовой стрелке (при α<0). Точка пересечения соответствующего луча с окружностью имеет координаты (cos α; sin α).\n\nТакое определение позволяет находить синус и косинус для любого действительного угла. Например, sin(π/2)=1, cos(π)=-1, sin(3π/2)=-1, cos(2π)=1.\n\nТангенс и котангенс угла определяются как tg α = sin α / cos α (при cos α≠0) и ctg α = cos α / sin α (при sin α≠0).\n\nОсновное тригонометрическое тождество, следующее из уравнения единичной окружности x²+y²=1: sin²α + cos²α = 1 для любого угла α.\n\nИз основного тождества выводятся дополнительные тождества: tg α · ctg α = 1; 1 + tg²α = 1/cos²α; 1 + ctg²α = 1/sin²α.\n\nЗнаки синуса и косинуса зависят от координатной четверти: в I четверти оба положительны, во II — синус положителен, косинус отрицателен, в III — оба отрицательны, в IV — синус отрицателен, косинус положителен.\n\nПонимание радианной меры и единичной окружности — фундамент всей тригонометрии: на этой основе строятся графики тригонометрических функций, решаются тригонометрические уравнения и неравенства.","quiz":[{"question":"Скольким радианам равен угол 180°?","options":["π/2","π","2π","π/4"],"correctIndex":1},{"question":"Чему равна длина дуги, соответствующая одному радиану, на окружности радиуса R?","options":["2R","πR","R","R/2"],"correctIndex":2},{"question":"Координаты точки на единичной окружности, соответствующей углу α, равны:","options":["(sin α; cos α)","(cos α; sin α)","(tg α; ctg α)","(α; α)"],"correctIndex":1},{"question":"Основное тригонометрическое тождество:","options":["sin α + cos α = 1","sin²α + cos²α = 1","sin α · cos α = 1","sin α - cos α = 1"],"correctIndex":1},{"question":"Чему равен sin(π/2)?","options":["0","1","-1","1/2"],"correctIndex":1},{"question":"В какой четверти синус отрицателен, а косинус положителен?","options":["I","II","III","IV"],"correctIndex":3},{"question":"Как связаны tg α и ctg α?","options":["tg α + ctg α = 1","tg α · ctg α = 1","tg α = ctg α","tg α - ctg α = 0"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"geogebra","externalServiceTask":"В GeoGebra постройте единичную окружность, отметьте углы 0, π/6, π/4, π/3, π/2, π, покажите отрезки sin и cos для каждого угла и проверьте тождество sin²α+cos²α=1.","starts_at":"2026-07-23T11:15:00+05:00","ends_at":"2026-07-23T12:00:00+05:00","room":"301"},{"topic":"Простейшие тригонометрические уравнения","objective":"Научиться решать простейшие тригонометрические уравнения вида sin x = a, cos x = a, tg x = a с использованием общих формул решений.","theory":"Тригонометрическим называется уравнение, содержащее переменную под знаком тригонометрической функции. Простейшие уравнения — sin x = a, cos x = a, tg x = a, ctg x = a — решаются по стандартным формулам, полученным из свойств тригонометрических функций и единичной окружности.\n\nУравнение cos x = a имеет решения только при -1≤a≤1. Общая формула: x = ±arccos a + 2πn, n∈Z, где arccos a ∈ [0;π]. Например, cos x = 1/2: arccos(1/2)=π/3, поэтому x = ±π/3 + 2πn, n∈Z.\n\nУравнение sin x = a также имеет решения только при -1≤a≤1. Общая формула: x = (-1)^n · arcsin a + πn, n∈Z, где arcsin a ∈ [-π/2;π/2]. Например, sin x = √2/2: arcsin(√2/2)=π/4, поэтому x = (-1)^n·π/4 + πn, n∈Z.\n\nУравнение tg x = a имеет решение при любом действительном a: x = arctg a + πn, n∈Z, где arctg a ∈ (-π/2;π/2). Например, tg x=1: x=π/4+πn, n∈Z.\n\nУравнение ctg x = a: x = arcctg a + πn, n∈Z, где arcctg a ∈ (0;π).\n\nЧастные случаи: sin x = 0 ⟹ x = πn; sin x = 1 ⟹ x = π/2 + 2πn; sin x = -1 ⟹ x = -π/2 + 2πn; cos x = 0 ⟹ x = π/2 + πn; cos x = 1 ⟹ x = 2πn; cos x = -1 ⟹ x = π + 2πn.\n\nПример 1: решить sin x = 1/2. arcsin(1/2)=π/6. По формуле x=(-1)^n·π/6+πn, n∈Z.\n\nПример 2: решить cos(2x) = 0. Используем частный случай для аргумента 2x: 2x = π/2+πn, откуда x = π/4 + πn/2, n∈Z.\n\nЕсли уравнение сводится к простейшему через замену (например, 2sin²x - sin x - 1 = 0, где t=sin x, 2t²-t-1=0, t=1 или t=-1/2), сначала решается алгебраическое уравнение относительно t, а затем для каждого допустимого значения t (обязательно из отрезка [-1;1]) решается простейшее тригонометрическое уравнение.\n\nВажно всегда проверять, что найденное значение a для sin x=a или cos x=a лежит в пределах [-1;1] — иначе уравнение не имеет решений. Умение решать простейшие тригонометрические уравнения — необходимая база для дальнейшего изучения курса.","quiz":[{"question":"При каких значениях a уравнение cos x=a имеет решения?","options":["a — любое","-1≤a≤1","a>0","a≥1"],"correctIndex":1},{"question":"Общая формула решения sin x=a:","options":["x=arcsin a+2πn","x=(-1)^n·arcsin a+πn","x=±arcsin a+2πn","x=arcsin a+πn"],"correctIndex":1},{"question":"Решите tg x=1.","options":["x=π/4+πn, n∈Z","x=π/2+πn","x=π+πn","x=π/4+2πn"],"correctIndex":0},{"question":"Частный случай sin x=0 даёт решение:","options":["x=π/2+πn","x=πn","x=2πn","x=π/2+2πn"],"correctIndex":1},{"question":"Область значений арксинуса:","options":["[0;π]","[-π/2;π/2]","(-π/2;π/2)","[-1;1]"],"correctIndex":1},{"question":"Решите cos(2x)=0.","options":["x=π/4+πn/2, n∈Z","x=π/2+πn","x=π/4+πn","x=π+πn/2"],"correctIndex":0},{"question":"В уравнении 2sin²x-sin x-1=0 после замены t=sin x получаем корни:","options":["t=1, t=-1","t=1, t=-1/2","t=0, t=1","t=2, t=-2"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-24T12:10:00+05:00","ends_at":"2026-07-24T12:55:00+05:00","room":"301"}]'::jsonb)
    LOOP
      INSERT INTO public.lessons (group_id, subject_id, topic, title, description, status, starts_at, ends_at, started_at, ended_at, room, school_id)
      VALUES (
        v_group_id, v_subject_id, lesson_data->>'topic', lesson_data->>'topic', lesson_data->>'objective',
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN 'completed' ELSE 'scheduled' END,
        (lesson_data->>'starts_at')::timestamptz, (lesson_data->>'ends_at')::timestamptz,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'starts_at')::timestamptz ELSE NULL END,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'ends_at')::timestamptz ELSE NULL END,
        lesson_data->>'room', v_school_id
      )
      RETURNING id INTO v_lesson_id;

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, duration_min, school_id)
      VALUES (v_lesson_id, 1, 'middle', 'theory', 'presentation', lesson_data->>'topic', lesson_data->>'theory', 15, v_school_id);

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, duration_min, school_id)
      VALUES (v_lesson_id, 2, 'middle', 'task', 'quiz_qia', 'Проверь себя', 15, v_school_id)
      RETURNING id INTO v_stage_id;

      qpos := 0;
      FOR quiz_item IN SELECT * FROM jsonb_array_elements(lesson_data->'quiz')
      LOOP
        qpos := qpos + 1;
        INSERT INTO public.quiz_questions (stage_id, question_text, options, correct_option_index, position, points, time_per_question_seconds, school_id)
        VALUES (v_stage_id, quiz_item->>'question', quiz_item->'options', (quiz_item->>'correctIndex')::int, qpos, 1, 30, v_school_id);
      END LOOP;

      IF (lesson_data->>'hasExternalService')::boolean THEN
        INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, config, duration_min, school_id)
        VALUES (
          v_lesson_id, 3, 'middle', 'task', lesson_data->>'externalServiceType',
          lesson_data->>'externalServiceTask', lesson_data->>'externalServiceTask',
          jsonb_build_object('url',
            CASE lesson_data->>'externalServiceType'
              WHEN 'wokwi' THEN 'https://wokwi.com/projects/new/arduino-uno'
              WHEN 'codesandbox' THEN 'https://codesandbox.io/p/sandbox/vanilla'
              WHEN 'geogebra' THEN 'https://www.geogebra.org/classic'
              WHEN 'phet' THEN 'https://phet.colorado.edu/sims/html/forces-and-motion-basics/latest/forces-and-motion-basics_en.html'
              WHEN 'desmos' THEN 'https://www.desmos.com/calculator'
              WHEN 'blockly_games' THEN 'https://blockly.games/'
              WHEN 'visualgo' THEN 'https://visualgo.net/en'
              WHEN 'p5js' THEN 'https://editor.p5js.org/'
              WHEN 'excalidraw' THEN 'https://excalidraw.com/'
              WHEN 'learningapps' THEN 'https://learningapps.org/'
              WHEN 'sqlonline' THEN 'https://sqlime.org/'
              WHEN 'h5p' THEN 'https://h5p.eduos.snruz.uz/library'
              ELSE NULL
            END
          ),
          15, v_school_id
        );
      END IF;
    END LOOP;
  END IF;

  -- === 10-А класс | Английский язык (14 уроков) ===
  SELECT id INTO v_group_id FROM public.groups WHERE name = '10-А класс';
  SELECT id INTO v_subject_id FROM public.subjects WHERE group_id = v_group_id AND name = 'Английский язык';
  IF NOT EXISTS (SELECT 1 FROM public.lessons WHERE group_id = v_group_id AND subject_id = v_subject_id AND description IS NOT NULL) THEN
    FOR lesson_data IN SELECT * FROM jsonb_array_elements('[{"topic":"Present Perfect vs Past Simple: систематизация","objective":"Научиться осознанно выбирать между Present Perfect и Past Simple в зависимости от контекста и слов-маркеров времени.","theory":"В 10 классе важно не только помнить формулы времён, но и понимать логику их использования. Present Perfect (have/has + V3) описывает действие, которое произошло в неопределённом прошлом, но результат или связь с настоящим моментом важны прямо сейчас. Например: ''I have already finished my homework'' — важен результат: домашнее задание готово сейчас. Past Simple (V2/-ed), наоборот, обозначает законченное действие в конкретный момент прошлого, который либо назван, либо подразумевается: ''I finished my homework at 8 pm yesterday'' — точное время указано, связь с настоящим не важна.\n\nСлова-маркеры помогают выбрать правильное время. Present Perfect: already, yet, just, ever, never, since, for, recently, so far, this week/month/year (если период ещё не закончился). Past Simple: yesterday, last week/month/year, ago, in 2019, when I was a child — все они указывают конкретный, уже закончившийся момент времени.\n\nОсобое внимание — разница между since и for: since употребляется с точкой отсчёта во времени (since 2020, since Monday), а for — с продолжительностью (for three years, for a long time). Оба слова используются с Present Perfect, если действие продолжается или его результат актуален сейчас: ''I have lived in Tashkent since 2015'' (я до сих пор здесь живу).\n\nЧастая ошибка — использование Present Perfect с точным указанием прошедшего времени: нельзя сказать ''I have seen him yesterday'', правильно — ''I saw him yesterday'', потому что yesterday закрывает период и не связан с настоящим моментом.\n\nЕщё один нюанс: в британском английском Present Perfect часто используется для новостей и недавних событий (''I have just received your message''), тогда как в американском варианте в тех же ситуациях нередко допустим Past Simple (''I just received your message''). В школьных учебниках и на экзаменах, как правило, ориентируются на британскую норму.\n\nТаким образом, чтобы выбрать правильное время, нужно задать себе вопрос: важен ли момент времени в прошлом (тогда Past Simple) или важен результат и связь с настоящим (тогда Present Perfect). Понимание этой логики — основа для изучения более сложных времён, таких как Present Perfect Continuous и Past Perfect, которые мы разберём в следующих уроках.","quiz":[{"question":"\"She ___ her homework already.\"","options":["has done","did","done","doing"],"correctIndex":0},{"question":"\"We ___ to Paris in 2019.\"","options":["have been","have gone","went","go"],"correctIndex":2},{"question":"Какое слово-маркер указывает на Past Simple (не Present Perfect)?","options":["already","just","yesterday","since"],"correctIndex":2},{"question":"Выберите правильное предложение.","options":["I have seen him yesterday.","I have see him yesterday.","I seen him yesterday.","I saw him yesterday."],"correctIndex":3},{"question":"\"I have lived here ___ 2015.\"","options":["for","ago","during","since"],"correctIndex":3},{"question":"Какое слово используется с указанием продолжительности (a length of time)?","options":["since","ago","for","yet"],"correctIndex":2},{"question":"\"They ___ never ___ sushi before.\"","options":["did / eat","has / eaten","do / eat","have / eaten"],"correctIndex":3}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-07T12:10:00+05:00","ends_at":"2026-07-07T12:55:00+05:00","room":"301"},{"topic":"Present Perfect Continuous: длительность действия","objective":"Освоить образование и употребление Present Perfect Continuous для описания длительных действий, связанных с настоящим.","theory":"Present Perfect Continuous (have/has been + V-ing) используется, когда важна не столько результат, сколько сам процесс действия — его длительность, которая либо продолжается до сих пор, либо только что закончилась, но её следы видны в настоящем. Формула: have/has + been + Ving. Пример: ''I have been studying English for five years'' — учу английский уже пять лет и продолжаю. ''She has been crying'' — она плакала (недавно закончила), и это видно по её лицу сейчас.\n\nВажно различать Present Perfect Simple и Present Perfect Continuous. Simple акцентирует результат/факт завершённости: ''I have written three emails today'' (конкретный результат, количество). Continuous акцентирует процесс: ''I have been writing emails all morning'' (весь процесс, сколько времени это заняло, без акцента на количество).\n\nНекоторые глаголы (stative verbs) — know, believe, love, want, understand, belong — обычно не употребляются в Continuous формах вообще, поэтому с ними используют только Present Perfect Simple: ''I have known her for ten years'' (неправильно ''have been knowing'').\n\nМаркеры времени: for, since, all day/morning/week, lately, recently — они часто встречаются как с Perfect Simple, так и с Perfect Continuous, поэтому выбор зависит именно от смысла (результат vs процесс), а не только от маркера.\n\nЕщё пример контраста: ''He has painted the wall'' (стена покрашена — результат готов) vs ''He has been painting the wall'' (он был занят покраской — возможно, ещё не закончил, но это объясняет, почему у него испачканы руки).\n\nОтрицательная и вопросительная формы строятся стандартно: ''Have you been waiting long?'' / ''I haven''t been sleeping well recently.'' В 10 классе важно не только правильно образовывать форму, но и понимать прагматику: когда мы хотим подчеркнуть процесс и его влияние на текущий момент, выбираем Continuous; когда важен факт или результат — Simple.","quiz":[{"question":"\"I ___ English for five years.\"","options":["studied","am studying","have been studying","has been studying"],"correctIndex":2},{"question":"Какое предложение подчёркивает процесс, а не результат?","options":["I have written the report.","I wrote the report.","I have been writing the report all day.","I write the report."],"correctIndex":2},{"question":"Какой глагол обычно НЕ употребляется в Continuous формах?","options":["run","study","write","know"],"correctIndex":3},{"question":"\"Her eyes are red because she ___.\"","options":["cries","is crying","has cried","has been crying"],"correctIndex":3},{"question":"\"___ you ___ long?\" (waiting)","options":["Are / waiting","Did / wait","Have / been waiting","Have / waited"],"correctIndex":2},{"question":"Выберите правильное предложение.","options":["He has been knowing her for years.","He has know her for years.","He knows her since years.","He has known her for years."],"correctIndex":3}],"hasExternalService":true,"externalServiceType":"learningapps","externalServiceTask":"Сопоставь предложения с Present Perfect Simple и Present Perfect Continuous с правильным объяснением значения (результат vs процесс) в упражнении на сопоставление LearningApps.","starts_at":"2026-07-08T13:05:00+05:00","ends_at":"2026-07-08T13:50:00+05:00","room":"301"},{"topic":"Past Perfect Simple: действие до момента в прошлом","objective":"Научиться использовать Past Perfect для обозначения действия, завершившегося раньше другого действия в прошлом.","theory":"Past Perfect Simple (had + V3) показывает, что одно действие в прошлом произошло раньше другого прошедшего действия — это ''прошлое в прошлом''. Формула одинакова для всех лиц: had + причастие прошедшего времени (V3/-ed). Пример: ''When I arrived at the station, the train had already left'' — сначала поезд ушёл (had left), потом я приехал (arrived, Past Simple). Порядок событий важен: более раннее действие — Past Perfect, более позднее — Past Simple.\n\nPast Perfect часто используется с already, just, never, before: ''She had never seen snow before she moved to Russia''. Важно не путать Past Perfect с Present Perfect: Present Perfect связывает прошлое с настоящим моментом речи (''I have finished'' — сейчас), а Past Perfect связывает одно прошедшее событие с другим, более поздним прошедшим событием, а не с настоящим.\n\nТипичная структура: ''By the time + Past Simple, + Past Perfect'' — ''By the time the police arrived, the thief had escaped.'' Также часто используется с before и after: ''After she had finished her homework, she went for a walk''.\n\nЕсть связь с условными предложениями третьего типа, которые мы разберём позже: ''If I had known about the exam, I would have prepared better'' — had known (Past Perfect) показывает нереальное условие в прошлом.\n\nОтрицание: had not (hadn''t) + V3: ''I hadn''t eaten anything before the trip.'' Вопрос: Had + subject + V3: ''Had you ever visited London before that trip?''\n\nВажно тренировать умение определять хронологию событий в тексте и правильно расставлять времена: если событие А произошло раньше события Б, то А оформляется Past Perfect, а Б — Past Simple. Это особенно важно при пересказе историй, написании эссе-нарратива и в дальнейшем — при изучении косвенной речи, где Past Perfect часто заменяет Present Perfect и Past Simple при согласовании времён.","quiz":[{"question":"\"When I arrived, the film ___ already ___.\"","options":["has / started","was / starting","had / started","did / start"],"correctIndex":2},{"question":"\"She had left before he arrived.\" Что произошло раньше?","options":["Он приехал первым","Оба события одновременно","Она уехала первой","Невозможно определить"],"correctIndex":2},{"question":"\"By the time the police arrived, the thief ___.\"","options":["escapes","has escaped","escaped","had escaped"],"correctIndex":3},{"question":"Выберите правильную отрицательную форму.","options":["I hadn''t ate anything.","I haven''t eaten anything before the trip.","I didn''t had eaten anything.","I hadn''t eaten anything."],"correctIndex":3},{"question":"Past Perfect в основном используется, чтобы показать:","options":["действие, происходящее сейчас","общую истину","действие раньше другого действия в прошлом","план на будущее"],"correctIndex":2},{"question":"\"___ you ever ___ London before that trip?\"","options":["Did / visit","Were / visiting","Have / visited","Had / visited"],"correctIndex":3}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-09T08:30:00+05:00","ends_at":"2026-07-09T09:15:00+05:00","room":"301"},{"topic":"Способы выражения будущего времени","objective":"Научиться выбирать между will, be going to и Present Continuous для выражения разных типов будущих действий.","theory":"В английском языке нет одной ''будущей формы'' — есть несколько способов говорить о будущем, и выбор зависит от намерения говорящего. Will + инфинитив без to используется для: 1) спонтанных решений, принятых прямо в момент речи (''The phone is ringing — I''ll answer it''); 2) обещаний, предложений (''I will always love you'', ''I''ll help you carry the bags''); 3) предсказаний без явных доказательств, часто с think/probably (''I think it will rain tomorrow'').\n\nBe going to + инфинитив используется для: 1) заранее принятых планов и намерений (''We are going to visit Samarkand next month''); 2) предсказаний, основанных на видимых прямо сейчас признаках (''Look at those clouds — it''s going to rain'').\n\nPresent Continuous (be + V-ing) используется для будущего, когда речь идёт о конкретной договорённости с указанием времени и места: ''I am meeting Sarah at 6 pm on Friday'' — это уже согласовано. Разница между going to и Present Continuous тонкая: going to — это намерение (''I''m going to call her'' — планирую), а Present Continuous — уже подтверждённая договорённость (''I''m calling her at 5'' — точно назначено).\n\nЕщё один способ — Present Simple для расписаний, которые не зависят от воли человека (транспорт, программы): ''The train leaves at 9 am tomorrow'' — расписание фиксировано.\n\nЧастая ошибка — использовать will там, где нужно going to, при наличии явных доказательств в настоящем: нельзя сказать ''Look, she will fall!'', когда человек уже падает — правильно ''she''s going to fall''.\n\nТакже стоит запомнить Future Continuous (will be + Ving) для действия в конкретный момент в будущем (''At 8 pm tomorrow I will be watching the match'') — эта форма подробнее рассматривается в старших темах.\n\nПонимание разницы между этими формами помогает точнее выражать намерения, планы и прогнозы — важный навык как для устной речи, так и для письменных заданий формата эссе или письма.","quiz":[{"question":"Спонтанное решение в момент речи:","options":["I''m going to answer it","I''m answering it","I''ll answer it","I answer it"],"correctIndex":2},{"question":"\"Look at those clouds — it ___ rain.\"","options":["will","rains","is raining","is going to"],"correctIndex":3},{"question":"Заранее согласованная договорённость с точным временем:","options":["I will meet Sarah","I''m going to meet Sarah someday","I meet Sarah","I''m meeting Sarah at 6pm on Friday"],"correctIndex":3},{"question":"Расписание поезда (фиксированный график):","options":["The train is going to leave at 9.","The train will leave at 9.","The train is leaving.","The train leaves at 9 tomorrow."],"correctIndex":3},{"question":"\"She''s going to fall!\" — почему используется going to?","options":["это обещание","есть видимое доказательство прямо сейчас","это фиксированное расписание","это спонтанное решение"],"correctIndex":1},{"question":"Какое предложение выражает обещание?","options":["I''m loving you.","I love you tomorrow.","I will always love you.","I''m going to love you."],"correctIndex":2},{"question":"Какая форма подходит для заранее обдуманного намерения (не спонтанного)?","options":["will","Past Simple","Present Simple","be going to"],"correctIndex":3}],"hasExternalService":true,"externalServiceType":"h5p","externalServiceTask":"Пройди интерактивное упражнение H5P на выбор правильной формы будущего времени (will / going to / Present Continuous) в диалогах о планах на выходные.","starts_at":"2026-07-10T10:20:00+05:00","ends_at":"2026-07-10T11:05:00+05:00","room":"301"},{"topic":"Пассивный залог: Present и Past Passive","objective":"Научиться образовывать и уместно использовать Present Simple Passive и Past Simple Passive.","theory":"Пассивный залог (Passive Voice) используется, когда важнее само действие или его объект, а не тот, кто его совершил. Формула: be (в нужном времени) + V3 (причастие прошедшего времени). Present Simple Passive: am/is/are + V3. Пример: ''English is spoken all over the world'' — кем именно говорят, не важно, важен факт. Past Simple Passive: was/were + V3. Пример: ''This bridge was built in 1889'' — важно, что мост построен, а не кто строил.\n\nСравним активный и пассивный залог: активный — ''Workers built this bridge in 1889''; пассивный — ''This bridge was built in 1889''. При трансформации объект действия становится подлежащим, глагол превращается в be + V3, а исполнитель либо опускается, либо добавляется через by: ''This novel was written by Tolstoy.''\n\nПассив особенно уместен в научных и деловых текстах, новостях, инструкциях, где акцент на факте, а не на исполнителе: ''New rules were introduced last year''; ''The report is checked every month''; ''Mistakes were made'' (классический пример, когда исполнитель намеренно скрывается).\n\nВажно правильно образовывать вопросы и отрицания. Вопрос: ''Is English spoken in Canada?'' / ''Was the letter sent yesterday?'' Отрицание: ''The letter wasn''t sent on time.'' / ''These products aren''t sold here.''\n\nЧастая ошибка — забывать глагол be или использовать неправильную форму причастия: неправильно ''The house build in 1990'', правильно ''The house was built in 1990''. Также не все глаголы могут употребляться в пассиве — только переходные (transitive), то есть те, после которых есть прямое дополнение (build something), а непереходные (arrive, happen, die) пассива не имеют.\n\nПонимание пассивного залога важно для чтения академических текстов и написания формальных эссе, где личный исполнитель действия часто неважен или неизвестен. В следующем уроке мы рассмотрим более сложные формы пассива — с модальными глаголами и в перфектных временах.","quiz":[{"question":"\"English ___ all over the world.\"","options":["speaks","spoke","is spoken","was speaking"],"correctIndex":2},{"question":"\"This bridge ___ in 1889.\"","options":["built","is built","builds","was built"],"correctIndex":3},{"question":"Active: \"Tolstoy wrote this novel.\" Passive:","options":["This novel wrote by Tolstoy.","This novel is written by Tolstoy.","This novel was writing by Tolstoy.","This novel was written by Tolstoy."],"correctIndex":3},{"question":"Правильная вопросительная форма в пассиве:","options":["English is spoken in Canada?","Is English spoken in Canada?","Does English spoken in Canada?","Is English speaks in Canada?"],"correctIndex":1},{"question":"Какой глагол НЕЛЬЗЯ использовать в пассиве (он непереходный)?","options":["write","send","arrive","build"],"correctIndex":2},{"question":"Отрицательная форма Past Passive:","options":["The letter not sent on time.","The letter isn''t sent on time.","The letter didn''t sent on time.","The letter wasn''t sent on time."],"correctIndex":3}],"hasExternalService":true,"externalServiceType":"h5p","externalServiceTask":"Выполни интерактивное упражнение H5P на трансформацию действительных предложений в страдательный залог (Present/Past Passive) на материале об истории и науке.","starts_at":"2026-07-13T10:20:00+05:00","ends_at":"2026-07-13T11:05:00+05:00","room":"301"},{"topic":"Пассивный залог — Часть 2: перфект и модальный пассив","objective":"Освоить образование пассива в перфектных временах и с модальными глаголами.","theory":"Продолжаем тему пассивного залога, переходя к более сложным конструкциям: Present Perfect Passive, Past Perfect Passive и Modal Passive. Формула Present Perfect Passive: have/has + been + V3. Пример: ''The documents have already been signed'' — документы уже подписаны, исполнитель не назван. Past Perfect Passive: had + been + V3: ''The room had been cleaned before the guests arrived''.\n\nМодальный пассив образуется по формуле: modal verb + be + V3. Это частая конструкция в правилах, инструкциях, законах. Примеры: ''This form must be completed in black ink'' (обязательность); ''The meeting could be postponed'' (возможность); ''Homework should be submitted by Friday'' (рекомендация); ''The problem can be solved easily'' (возможность решения). Сама форма модального глагола не меняется, меняется только следующая часть — be + V3 вместо простого инфинитива.\n\nВажно не путать модальный пассив с перфектным модальным пассивом: ''The letter should have been sent yesterday'' (should + have been + V3) — выражает сожаление о том, что действие не было выполнено, хотя должно было.\n\nFuture Passive образуется как will + be + V3: ''The results will be announced tomorrow.'' Это часто встречается в новостях: ''New regulations will be introduced next year.''\n\nПассив с модальными и перфектными формами особенно часто встречается в академическом и деловом английском: инструкциях к экзаменам (''Answers must be written in the answer sheet''), договорах, законах, научных статьях (''It has been proven that...'').\n\nДля правильного построения таких предложений полезно всегда выделять три элемента: модальный/вспомогательный глагол, be и причастие V3, и не забывать, что be всегда стоит перед смысловым глаголом в третьей форме. Тренировка трансформации предложений из активного залога в пассивный с модальными и перфектными формами — отличный способ закрепить материал перед переходом к косвенной речи, где мы снова встретим согласование времён и трансформацию структур.","quiz":[{"question":"\"The documents ___ already ___.\"","options":["has / signed","have / been signed","was / signed","have / signed"],"correctIndex":1},{"question":"Модальный пассив: \"This form ___ in black ink.\"","options":["must complete","must completed","must be completed","must being completed"],"correctIndex":2},{"question":"\"The letter should have been sent yesterday\" выражает:","options":["план на будущее","обязательство на завтра","сожаление о несделанном","привычку в прошлом"],"correctIndex":2},{"question":"Future Passive: \"The results ___ tomorrow.\"","options":["will announce","are announced","announced","will be announced"],"correctIndex":3},{"question":"Past Perfect Passive: \"The room ___ before the guests arrived.\"","options":["had cleaned","was cleaned","has been cleaned","had been cleaned"],"correctIndex":3},{"question":"Правильная модальная пассивная конструкция с обязательством:","options":["Homework should submitted by Friday.","Homework should be submit by Friday.","Homework should being submitted by Friday.","Homework should be submitted by Friday."],"correctIndex":3}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-14T12:10:00+05:00","ends_at":"2026-07-14T12:55:00+05:00","room":"301"},{"topic":"Косвенная речь: утверждения и вопросы","objective":"Научиться переводить прямую речь (утверждения и вопросы) в косвенную с правильным согласованием времён.","theory":"Косвенная речь (Reported Speech) передаёт слова другого человека без кавычек, обычно вводится глаголами say, tell, ask. Ключевое правило — согласование времён (Sequence of Tenses): если глагол, вводящий речь, стоит в прошедшем времени (said, told), то время в передаваемой части сдвигается на одну ступень назад. Present Simple → Past Simple: ''I like tea'' → ''She said (that) she liked tea.'' Present Continuous → Past Continuous: ''I am working'' → ''He said he was working.'' Present Perfect → Past Perfect: ''I have finished'' → ''She said she had finished.'' Past Simple → Past Perfect: ''I saw him'' → ''He said he had seen him.'' Will → would: ''I will help'' → ''She said she would help.''\n\nТакже меняются местоимения и указатели времени/места: I → he/she, my → his/her, this → that, here → there, now → then, today → that day, tomorrow → the next day, yesterday → the day before, last week → the week before.\n\nПример: прямая речь ''I am going to visit my grandmother tomorrow,'' she said → косвенная: She said (that) she was going to visit her grandmother the next day.\n\nПри переводе вопросов порядок слов меняется на прямой, вспомогательные do/does/did исчезают, вопросительный знак не ставится. Общие вопросы вводятся союзами if или whether: ''Do you like coffee?'' she asked → She asked if I liked coffee. Специальные вопросы сохраняют вопросительное слово, но меняют порядок: ''Where do you live?'' he asked → He asked where I lived.\n\nЧастые ошибки: сохранение вопросительного порядка слов (неправильно: ''He asked where did I live''), пропуск союза if/whether, отсутствие изменения времени. Важно помнить: если вводящий глагол стоит в настоящем времени (says, tells), то время в передаваемой части НЕ меняется: ''He says he is tired'' → ''He says (that) he is tired.''\n\nЭта тема готовит нас ко второй части — передаче в косвенной речи приказов, просьб и советов, где вместо согласования времён используется инфинитивная конструкция.","quiz":[{"question":"\"I like tea,\" she said. → She said that she ___ tea.","options":["likes","like","liked","has liked"],"correctIndex":2},{"question":"\"I am working,\" he said. → He said he ___ working.","options":["is","has been","were","was"],"correctIndex":3},{"question":"\"Do you like coffee?\" she asked. → She asked ___ I liked coffee.","options":["that","what","if","where"],"correctIndex":2},{"question":"\"Where do you live?\" he asked. → He asked ___.","options":["where did I live","where do I live","where I live","where I lived"],"correctIndex":3},{"question":"\"I will help you,\" she said. → She said she ___ help me.","options":["will","helped","has helped","would"],"correctIndex":3},{"question":"\"tomorrow\" в косвенной речи обычно превращается в:","options":["the day before","yesterday","that day","the next day"],"correctIndex":3},{"question":"\"He says he is tired\" — время не меняется, потому что:","options":["это вопрос","это приказ","вводящий глагол стоит в настоящем времени","вводящий глагол стоит в прошедшем времени"],"correctIndex":2}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-15T13:05:00+05:00","ends_at":"2026-07-15T13:50:00+05:00","room":"301"},{"topic":"Косвенная речь — Часть 2: приказы и просьбы","objective":"Научиться передавать в косвенной речи приказы, просьбы и советы с помощью инфинитивных конструкций.","theory":"В отличие от утверждений и вопросов, приказы, просьбы и советы в косвенной речи передаются не через согласование времён, а через конструкцию: глагол + (кому) + инфинитив с частицей to (или его отрицательную форму not to + инфинитив). Основные вводящие глаголы: tell, ask, advise, order, warn, invite, remind, beg.\n\nПримеры: ''Close the door!'' he said to me → He told me to close the door. Просьба: ''Could you help me, please?'' she asked → She asked me to help her. Отрицательный приказ: ''Don''t touch that!'' she said → She told him not to touch that. Совет: ''You should study more,'' the teacher said → The teacher advised me to study more.\n\nВажно запомнить структуру: verb + object (кому) + to-infinitive. Частая ошибка — использование that-clause вместо инфинитива для приказов: неправильно ''He told me that I close the door'', правильно — ''He told me to close the door.''\n\nДля вежливых просьб (Please, Could you) обычно используется ask: ''Please sit down,'' she said → She asked us to sit down. Для более резких, официальных приказов часто используют order: ''Stand up!'' the officer shouted → The officer ordered the soldiers to stand up.\n\nПри передаче предупреждений (warn) часто используется отрицательная инфинитивная конструкция: ''Don''t go there, it''s dangerous,'' he said → He warned me not to go there.\n\nОтдельно стоит отметить приглашения (invite): ''Would you like to come to my party?'' she asked → She invited me to come to her party.\n\nЕсли в прямой речи содержится вежливая просьба без явного глагола-повеления, но по смыслу это просьба, тоже используем ask + to-infinitive: ''Can you pass the salt?'' → He asked her to pass the salt.\n\nПонимание разницы между тремя типами передачи косвенной речи — через согласование времён (утверждения, вопросы) и через инфинитивную конструкцию (приказы, просьбы, советы) — критически важно для точной передачи чужих слов и часто проверяется в экзаменационных заданиях.","quiz":[{"question":"\"Close the door!\" he said to me. → He ___ me to close the door.","options":["said","asked","told","says"],"correctIndex":2},{"question":"\"Don''t touch that!\" she said. → She told him ___ touch that.","options":["don''t","to not","no to","not to"],"correctIndex":3},{"question":"\"Could you help me, please?\" she asked. → She asked me ___ her.","options":["help","helping","to help","helped"],"correctIndex":2},{"question":"\"You should study more,\" the teacher said. → The teacher ___ me to study more.","options":["told","ordered","asked","advised"],"correctIndex":3},{"question":"Какая структура правильна?","options":["He told me that close the door.","He told to me close the door.","He told me closing the door.","He told me to close the door."],"correctIndex":3},{"question":"\"Don''t go there, it''s dangerous,\" he said. → He ___ me not to go there.","options":["told","asked","invited","warned"],"correctIndex":3}],"hasExternalService":true,"externalServiceType":"learningapps","externalServiceTask":"Сопоставь прямые команды/просьбы с правильным вариантом их передачи в косвенной речи (tell/ask/advise + to-infinitive) в упражнении LearningApps.","starts_at":"2026-07-16T08:30:00+05:00","ends_at":"2026-07-16T09:15:00+05:00","room":"301"},{"topic":"Условные предложения нулевого и первого типа","objective":"Научиться строить и различать Zero Conditional и First Conditional для описания реальных и общих ситуаций.","theory":"Условные предложения (Conditionals) описывают связь между условием (if-clause) и результатом (main clause). Zero Conditional используется для общих истин, законов природы и постоянных фактов: If + Present Simple, + Present Simple. Пример: ''If you heat ice, it melts'' — лёд всегда тает при нагревании, здесь можно заменить if на when без изменения смысла: ''When you heat ice, it melts.''\n\nFirst Conditional описывает реальные, вероятные ситуации в будущем: If + Present Simple, + will + инфинитив. Пример: ''If it rains tomorrow, we will stay at home.'' Важно: после if используется Present Simple, а НЕ will, даже если речь о будущем — частая ошибка: неправильно ''If it will rain, we will stay home'', правильно ''If it rains, we will stay home.''\n\nПорядок частей может меняться: если if-clause стоит первым, после него ставится запятая (''If you study hard, you will pass the exam''); если if-clause стоит вторым, запятая не нужна (''You will pass the exam if you study hard'').\n\nВ First Conditional вместо will в главной части можно использовать can, may, might, must: ''If you finish early, you can leave'' (разрешение); ''If you don''t hurry, you might miss the bus'' (вероятность); ''If the fire alarm rings, you must leave the building'' (обязательство).\n\nТакже в if-clause вместо Present Simple иногда используется Present Continuous или Present Perfect: ''If you are still waiting at 5, call me''; ''If you have finished your homework, you can watch TV.''\n\nОтличие Zero от First Conditional принципиально: Zero — это всегда истинное правило, First — конкретная вероятная ситуация в будущем с неопределённым исходом. Сравните: ''If you mix blue and yellow, you get green'' (Zero) vs ''If I have time tomorrow, I will help you'' (First).\n\nПонимание этих двух типов — фундамент для изучения Second и Third Conditional, которые описывают нереальные и гипотетические ситуации в настоящем и прошлом — тема следующего урока.","quiz":[{"question":"Формула Zero Conditional:","options":["If + Present Simple, + will","If + Past Simple, + would","If + Present Simple, + Present Simple","If + Present Perfect, + will"],"correctIndex":2},{"question":"\"If you heat ice, it ___.\"","options":["will melt","melted","is melting","melts"],"correctIndex":3},{"question":"First Conditional: \"If it rains tomorrow, we ___ at home.\"","options":["stay","will stay","stayed","would stay"],"correctIndex":1},{"question":"Какой вариант правильный?","options":["If it will rain, we will stay home.","If it rain, we will stay home.","If it rains, we will stay home.","If it rains, we stayed home."],"correctIndex":2},{"question":"\"If you don''t hurry, you ___ miss the bus.\" (вероятность)","options":["must","might","can","shall"],"correctIndex":1},{"question":"Zero Conditional описывает:","options":["реальную возможность в будущем","нереальную ситуацию в настоящем","общую истину / научный факт","сожаление о прошлом"],"correctIndex":2},{"question":"\"If you finish early, you ___ leave.\" (разрешение)","options":["must","might","will have to","can"],"correctIndex":3}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-17T10:20:00+05:00","ends_at":"2026-07-17T11:05:00+05:00","room":"301"},{"topic":"Условные предложения второго и третьего типа","objective":"Научиться строить Second и Third Conditional для выражения нереальных ситуаций в настоящем и прошлом.","theory":"Second Conditional описывает нереальную или маловероятную ситуацию в настоящем/будущем. Формула: If + Past Simple, + would + инфинитив. Пример: ''If I had a million dollars, I would travel around the world'' — у меня нет миллиона, это воображаемая ситуация. Несмотря на форму Past Simple, речь идёт НЕ о прошлом, а о нереальном настоящем/будущем.\n\nОсобый случай — глагол be: в классическом английском во всех лицах в Second Conditional используется were, а не was: ''If I were you, I would apologize'' — эта форма особенно часто используется для советов. В разговорной речи допустимо и ''If I was you'', но на письме предпочтительнее were.\n\nThird Conditional описывает нереальную ситуацию в ПРОШЛОМ, часто выражает сожаление об упущенной возможности. Формула: If + Past Perfect, + would have + V3. Пример: ''If I had studied harder, I would have passed the exam'' — я не учился усерднее, и поэтому не сдал экзамен, оба события в прошлом и изменить их уже нельзя.\n\nСравним три условных: First — ''If I study, I will pass'' (реально, в будущем); Second — ''If I studied, I would pass'' (нереально, в настоящем-будущем); Third — ''If I had studied, I would have passed'' (нереально, в прошлом).\n\nВ главной части Second и Third Conditional вместо would можно использовать could или might: ''If I had more time, I could help you'' (Second); ''If we had left earlier, we might have caught the train'' (Third).\n\nСуществует также Mixed Conditional, когда условие относится к прошлому, а результат — к настоящему: ''If I had studied medicine, I would be a doctor now'' (Past Perfect в условии + would + инфинитив без have в результате) — продвинутая конструкция, полезная уже в 10 классе.\n\nЧастые ошибки: использование would в if-clause (неправильно ''If I would have money...''), путаница между would have + V3 и would + V3, забывание Past Perfect в Third Conditional.","quiz":[{"question":"Формула Second Conditional:","options":["If + Present Simple, + will","If + Past Perfect, + would have","If + Past Simple, + would","If + Present Perfect, + would"],"correctIndex":2},{"question":"\"If I ___ a million dollars, I would travel the world.\"","options":["have","will have","has","had"],"correctIndex":3},{"question":"Формальная структура совета:","options":["If I am you, I would apologize.","If I was you, I would apologize.","If I be you, I would apologize.","If I were you, I would apologize."],"correctIndex":3},{"question":"Third Conditional: \"If I had studied harder, I ___ the exam.\"","options":["would pass","passed","will pass","would have passed"],"correctIndex":3},{"question":"\"If I had studied medicine, I would be a doctor now\" — это пример:","options":["First Conditional","Second Conditional","Third Conditional","Mixed Conditional"],"correctIndex":3},{"question":"Какое предложение выражает сожаление о прошлом?","options":["If it rains, I will stay home.","If you heat water, it boils.","If I had studied harder, I would have passed.","If I were rich, I would travel."],"correctIndex":2},{"question":"Какое предложение содержит распространённую грамматическую ошибку?","options":["If I had money, I would help you.","If I would have money, I would help you.","If I have money, I will help you.","If I had had money, I would have helped you."],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-20T10:20:00+05:00","ends_at":"2026-07-20T11:05:00+05:00","room":"301"},{"topic":"Модальные глаголы предположения и вероятности","objective":"Научиться использовать модальные глаголы must, might, could, can''t для выражения степени уверенности в настоящем и прошлом.","theory":"В английском языке модальные глаголы используются не только для выражения обязанности или разрешения, но и для передачи степени уверенности говорящего в том, что что-то является правдой — это modals of deduction (модальные глаголы предположения). Для настоящего времени: modal + инфинитив без to: must (высокая уверенность), may/might/could (возможно, разная степень уверенности), can''t (высокая уверенность в обратном).\n\nПримеры: ''She''s not answering the phone — she must be asleep'' (логичный вывод); ''He might be at work, I''m not sure'' (не уверен); ''That can''t be true — I saw her yesterday in Moscow'' (уверен, что неправда). Важно: для отрицательной уверенности используется именно can''t, а НЕ mustn''t — mustn''t выражает запрет (''You mustn''t smoke here''), а не предположение.\n\nДля прошедшего времени формула меняется: modal + have + V3 (Perfect Infinitive). ''She must have left already'' (логичный вывод из фактов); ''He might have forgotten about the meeting'' (не уверен); ''They can''t have finished the project so quickly'' (сомнение); ''You should have called me'' (это уже упрёк/сожаление, а не предположение).\n\nРазница в степени уверенности принципиальна: must (около 99%, есть весомые доказательства) > may/might/could (примерно 30-50%, просто предположение) > can''t (около 99% уверенности в обратном). Важно не путать эти модальные глаголы предположения с их основными значениями (must — обязанность, can — умение) — контекст подсказывает нужное значение.\n\nЕщё пример контраста времён: ''He is late. He must be stuck in traffic'' (предположение о настоящем) vs ''He was late yesterday. He must have been stuck in traffic'' (предположение о прошлом). Тренировка этой темы важна для развития навыка логического рассуждения на английском языке — умения делать выводы на основе имеющихся данных, что часто встречается в детективных историях и текстах для чтения.","quiz":[{"question":"Какой модальный глагол выражает высокую уверенность, что что-то ИСТИННО (настоящее)?","options":["might","could","can''t","must"],"correctIndex":3},{"question":"\"That can''t be true — I saw her yesterday\" выражает:","options":["разрешение","обязанность","сильную уверенность, что это неправда","умение"],"correctIndex":2},{"question":"Формула предположения о прошлом:","options":["modal + had + V3","modal + be + Ving","modal + V3","modal + have + V3"],"correctIndex":3},{"question":"\"She''s not answering — she ___ be asleep.\"","options":["can","mustn''t","shall","must"],"correctIndex":3},{"question":"Разница между \"can''t\" и \"mustn''t\":","options":["оба выражают умение","can''t = обязанность, mustn''t = разрешение","они означают одно и то же","can''t = уверенность, что неправда; mustn''t = запрет"],"correctIndex":3},{"question":"\"They ___ finished the project so quickly.\" (сомнение, прошлое)","options":["can''t have","shouldn''t","mustn''t have","couldn''t"],"correctIndex":0},{"question":"Какой вариант показывает НАИМЕНЬШУЮ степень уверенности?","options":["must","can''t","must have","might"],"correctIndex":3}],"hasExternalService":true,"externalServiceType":"h5p","externalServiceTask":"Выполни интерактивное упражнение H5P: выбери правильный модальный глагол (must/might/could/can''t + инфинитив или Perfect Infinitive) для детективных ситуаций-загадок.","starts_at":"2026-07-21T12:10:00+05:00","ends_at":"2026-07-21T12:55:00+05:00","room":"301"},{"topic":"Относительные придаточные предложения","objective":"Научиться строить defining и non-defining relative clauses с who, which, that, whose, where.","theory":"Относительные придаточные предложения (Relative Clauses) присоединяются к главному предложению с помощью относительных местоимений и наречий: who (люди), which (предметы/животные), that (люди и предметы, только в defining clauses), whose (принадлежность), where (место), when (время). Они делятся на два типа: defining (ограничительные) и non-defining (описательные).\n\nDefining relative clause содержит существенную информацию, без которой предложение теряет смысл: ''The man who called you is my brother'' — если убрать придаточное, непонятно, о каком man речь. Такие придаточные НЕ выделяются запятыми, who/which можно заменить на that: ''The book that/which I read was interesting.'' Если местоимение является дополнением, его можно опустить: ''The book (that) I read was interesting.''\n\nNon-defining relative clause добавляет дополнительную, необязательную информацию. Такие придаточные ВСЕГДА выделяются запятыми, и that здесь использовать нельзя — только who/which/whose: ''My brother, who lives in London, is a doctor.'' Сравните: ''Students who study hard succeed'' (defining — ограничивает группу) vs ''My classmates, who study very hard, always succeed'' (non-defining — дополнительный факт про всех).\n\nWhose выражает принадлежность: ''That''s the girl whose father is a famous actor.'' Where используется для места: ''This is the school where I studied.'' When — для времени: ''I remember the day when we first met.''\n\nЧастые ошибки: использование that в non-defining clauses (неправильно: ''My brother, that lives in London, is a doctor''), пропуск запятых в non-defining clauses, лишнее личное местоимение после relative pronoun (неправильно: ''The man who he called you'').\n\nПонимание разницы между defining и non-defining clauses важно не только грамматически, но и стилистически — позволяет точно передавать, какая информация ключевая, а какая дополнительная, что особенно важно при написании описательных и аналитических текстов.","quiz":[{"question":"Defining relative clause используется, когда:","options":["информация необязательная","она всегда выделяется запятыми","в ней никогда не используется \"that\"","информация необходима для определения существительного"],"correctIndex":3},{"question":"\"My brother, ___ lives in London, is a doctor.\" (non-defining)","options":["that","which","whose","who"],"correctIndex":3},{"question":"Какое местоимение выражает принадлежность?","options":["who","which","whose","where"],"correctIndex":2},{"question":"\"This is the school ___ I studied.\"","options":["who","which","whose","where"],"correctIndex":3},{"question":"Правильная пунктуация для non-defining clause:","options":["запятые не нужны","запятая только перед","запятая только после","запятые с обеих сторон"],"correctIndex":3},{"question":"Выберите правильное предложение:","options":["My brother whose lives in London is a doctor.","My brother, that lives in London, is a doctor.","My brother, who lives in London, is a doctor.","My brother that lives, in London, is a doctor."],"correctIndex":2},{"question":"В defining clauses, если относительное местоимение — дополнение, оно может быть:","options":["заменено на \"it\"","никогда не опущено","заменено на \"there\"","опущено"],"correctIndex":3}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-22T13:05:00+05:00","ends_at":"2026-07-22T13:50:00+05:00","room":"301"},{"topic":"Герундий и инфинитив после глаголов","objective":"Научиться правильно выбирать герундий (V-ing) или инфинитив (to V) после определённых глаголов.","theory":"В английском языке после многих глаголов может следовать либо герундий (V-ing), либо инфинитив (to + V), и выбор формы часто строго фиксирован для конкретного глагола. Некоторые глаголы требуют только герундий: enjoy, avoid, finish, mind, suggest, imagine, consider, practise, admit, deny, risk, keep (on): ''I enjoy reading books''; ''She avoided answering the question''; ''Have you finished doing your homework?''\n\nДругие глаголы требуют только инфинитив с to: want, decide, plan, hope, promise, agree, refuse, offer, manage, afford, learn, expect, seem: ''I want to travel abroad''; ''They decided to postpone the trip''; ''She refused to answer.''\n\nЕсть глаголы, после которых меняется значение в зависимости от формы. Классические примеры: remember/forget — remember doing (помнить о том, что уже сделал) vs remember to do (не забыть сделать в будущем): ''I remember locking the door'' (помню, как запирал) vs ''Remember to lock the door'' (не забудь запереть). Stop — stop doing (прекратить делать что-то) vs stop to do (остановиться, чтобы сделать что-то другое): ''He stopped smoking'' (бросил курить) vs ''He stopped to smoke'' (остановился, чтобы покурить). Try — try doing (попробовать способ) vs try to do (пытаться, прилагать усилие): ''Try adding more salt'' vs ''I tried to open the door, but it was locked.''\n\nНекоторые глаголы допускают обе формы почти без разницы в значении: like, love, hate, prefer, start, begin, continue: ''I like swimming'' / ''I like to swim'' — оба варианта корректны, хотя в британском английском чаще предпочитают -ing после like/love/hate для общих предпочтений.\n\nПосле предлогов (in, at, of, about, for, without) всегда используется герундий, а не инфинитив: ''I''m interested in learning Spanish'' (не ''to learn''); ''Thank you for helping me.'' После конструкции it + be часто используется инфинитив: ''It''s important to study regularly.''\n\nОсвоение этой темы требует не механического заучивания, а системной практики: рекомендуется завести таблицу ''глагол + gerund/infinitive'' и регулярно пополнять её примерами.","quiz":[{"question":"\"I enjoy ___ books.\"","options":["read","to read","reads","reading"],"correctIndex":3},{"question":"\"They decided ___ the trip.\"","options":["postponing","postpone","to postpone","postponed"],"correctIndex":2},{"question":"\"I remember ___ the door.\" (уже сделано в прошлом)","options":["to lock","lock","locked","locking"],"correctIndex":3},{"question":"\"Remember ___ the door before you leave.\" (напоминание на будущее)","options":["locking","lock","to lock","locked"],"correctIndex":2},{"question":"\"He stopped ___ .\" (полностью бросил привычку)","options":["to smoke","smoke","smoked","smoking"],"correctIndex":3},{"question":"После предлога обычно используется:","options":["инфинитив с to","инфинитив без to","Past Simple","герундий (V-ing)"],"correctIndex":3},{"question":"\"I''m interested ___ Spanish.\"","options":["to learn","learn","learning","in learning"],"correctIndex":3}],"hasExternalService":true,"externalServiceType":"learningapps","externalServiceTask":"Отсортируй список глаголов на две группы — ''требуют герундий'' и ''требуют инфинитив'' — в интерактивном упражнении LearningApps.","starts_at":"2026-07-23T08:30:00+05:00","ends_at":"2026-07-23T09:15:00+05:00","room":"301"},{"topic":"Фразовые глаголы и словообразование","objective":"Расширить словарный запас за счёт распространённых фразовых глаголов и способов словообразования (суффиксы и префиксы).","theory":"Завершающий урок блока посвящён расширению словарного запаса через две темы: фразовые глаголы (phrasal verbs) и словообразование (word formation). Фразовый глагол — сочетание глагола с частицей, которое часто приобретает значение, не связанное напрямую со значением отдельных слов. Например: give up (сдаваться/бросать), look after (заботиться), turn down (отклонить), come across (случайно наткнуться), put off (откладывать), run out of (заканчиваться), figure out (разобраться), get along with (ладить с кем-то).\n\nФразовые глаголы бывают разделяемые (separable) и неразделяемые (inseparable). У разделяемых дополнение можно поставить как после частицы, так и между глаголом и частицей: ''Turn off the light'' = ''Turn the light off''; но если дополнение — местоимение, оно ВСЕГДА ставится между глаголом и частицей: ''Turn it off'' (не ''Turn off it''). Неразделяемые фразовые глаголы не допускают разрыва: ''I ran into my old friend'' — нельзя ''I ran my old friend into''. Некоторые фразовые глаголы вообще не принимают дополнения: ''The plane took off.''\n\nСловообразование — процесс создания новых слов с помощью префиксов и суффиксов. Суффиксы часто определяют часть речи: -tion/-sion, -ment, -ness, -ity превращают в существительные (educate → education, happy → happiness); -able/-ible, -ful, -less, -ive превращают в прилагательные (accept → acceptable, use → useful/useless); -ly превращает прилагательные в наречия (quick → quickly); -ize/-ise, -en превращают в глаголы (modern → modernize, wide → widen).\n\nПрефиксы обычно меняют значение слова, не меняя часть речи: un-, in-, im-, dis-, il-, ir- придают отрицательное значение (happy → unhappy, possible → impossible, agree → disagree, legal → illegal, responsible → irresponsible); re- означает повтор действия (do → redo); over- избыток (eat → overeat); under- недостаток (estimate → underestimate); mis- ошибочность (understand → misunderstand).\n\nЗнание словообразовательных моделей особенно полезно в заданиях типа word formation, где нужно образовать нужную часть речи от данного слова по контексту предложения. Регулярное чтение аутентичных текстов и ведение словаря с разбором фразовых глаголов и производных слов — лучший способ закрепить тему и подготовиться к более продвинутому уровню в 11 классе.","quiz":[{"question":"Значение фразового глагола \"give up\":","options":["начинать","откладывать","продолжать","сдаваться/бросать"],"correctIndex":3},{"question":"Правильное предложение с местоимением-дополнением:","options":["Turn off it.","Turn off the it.","Turn it in off.","Turn it off."],"correctIndex":3},{"question":"\"I ran into my old friend\" означает:","options":["я напал на друга","я избегал друга","я случайно встретил друга","я убежал от друга"],"correctIndex":2},{"question":"educate → education — пример использования суффикса:","options":["-able","-less","-tion","-ly"],"correctIndex":2},{"question":"happy → unhappy использует префикс:","options":["re-","over-","mis-","un-"],"correctIndex":3},{"question":"В слове \"misunderstand\" префикс \"mis-\" означает:","options":["слишком много","снова","не","неправильно"],"correctIndex":3},{"question":"Какой фразовый глагол ниже используется БЕЗ дополнения (непереходный)?","options":["turn off","look after","put off","take off (о самолёте)"],"correctIndex":3}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-24T10:20:00+05:00","ends_at":"2026-07-24T11:05:00+05:00","room":"301"}]'::jsonb)
    LOOP
      INSERT INTO public.lessons (group_id, subject_id, topic, title, description, status, starts_at, ends_at, started_at, ended_at, room, school_id)
      VALUES (
        v_group_id, v_subject_id, lesson_data->>'topic', lesson_data->>'topic', lesson_data->>'objective',
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN 'completed' ELSE 'scheduled' END,
        (lesson_data->>'starts_at')::timestamptz, (lesson_data->>'ends_at')::timestamptz,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'starts_at')::timestamptz ELSE NULL END,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'ends_at')::timestamptz ELSE NULL END,
        lesson_data->>'room', v_school_id
      )
      RETURNING id INTO v_lesson_id;

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, duration_min, school_id)
      VALUES (v_lesson_id, 1, 'middle', 'theory', 'presentation', lesson_data->>'topic', lesson_data->>'theory', 15, v_school_id);

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, duration_min, school_id)
      VALUES (v_lesson_id, 2, 'middle', 'task', 'quiz_qia', 'Проверь себя', 15, v_school_id)
      RETURNING id INTO v_stage_id;

      qpos := 0;
      FOR quiz_item IN SELECT * FROM jsonb_array_elements(lesson_data->'quiz')
      LOOP
        qpos := qpos + 1;
        INSERT INTO public.quiz_questions (stage_id, question_text, options, correct_option_index, position, points, time_per_question_seconds, school_id)
        VALUES (v_stage_id, quiz_item->>'question', quiz_item->'options', (quiz_item->>'correctIndex')::int, qpos, 1, 30, v_school_id);
      END LOOP;

      IF (lesson_data->>'hasExternalService')::boolean THEN
        INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, config, duration_min, school_id)
        VALUES (
          v_lesson_id, 3, 'middle', 'task', lesson_data->>'externalServiceType',
          lesson_data->>'externalServiceTask', lesson_data->>'externalServiceTask',
          jsonb_build_object('url',
            CASE lesson_data->>'externalServiceType'
              WHEN 'wokwi' THEN 'https://wokwi.com/projects/new/arduino-uno'
              WHEN 'codesandbox' THEN 'https://codesandbox.io/p/sandbox/vanilla'
              WHEN 'geogebra' THEN 'https://www.geogebra.org/classic'
              WHEN 'phet' THEN 'https://phet.colorado.edu/sims/html/forces-and-motion-basics/latest/forces-and-motion-basics_en.html'
              WHEN 'desmos' THEN 'https://www.desmos.com/calculator'
              WHEN 'blockly_games' THEN 'https://blockly.games/'
              WHEN 'visualgo' THEN 'https://visualgo.net/en'
              WHEN 'p5js' THEN 'https://editor.p5js.org/'
              WHEN 'excalidraw' THEN 'https://excalidraw.com/'
              WHEN 'learningapps' THEN 'https://learningapps.org/'
              WHEN 'sqlonline' THEN 'https://sqlime.org/'
              WHEN 'h5p' THEN 'https://h5p.eduos.snruz.uz/library'
              ELSE NULL
            END
          ),
          15, v_school_id
        );
      END IF;
    END LOOP;
  END IF;

  -- === 10-А класс | Программирование (11 уроков) ===
  SELECT id INTO v_group_id FROM public.groups WHERE name = '10-А класс';
  SELECT id INTO v_subject_id FROM public.subjects WHERE group_id = v_group_id AND name = 'Программирование';
  IF NOT EXISTS (SELECT 1 FROM public.lessons WHERE group_id = v_group_id AND subject_id = v_subject_id AND description IS NOT NULL) THEN
    FOR lesson_data IN SELECT * FROM jsonb_array_elements('[{"topic":"Алгоритмы и этапы решения задач на компьютере","objective":"Систематизировать знания об алгоритмах, их свойствах и способах записи как основе программирования.","theory":"Алгоритм — это точная и понятная последовательность действий, выполнение которых приводит к решению поставленной задачи за конечное число шагов. Понятие алгоритма лежит в основе всего программирования: прежде чем написать код на любом языке, необходимо продумать порядок действий, который приведёт к результату.\n\nЛюбой алгоритм обладает рядом обязательных свойств. Дискретность означает, что алгоритм состоит из отдельных, чётко разделённых шагов, выполняемых один за другим. Детерминированность (определённость) — каждый шаг однозначно определён и не допускает двойного толкования: при одинаковых исходных данных алгоритм всегда даёт одинаковый результат. Конечность (результативность) — алгоритм должен завершаться за конечное число шагов и приводить к результату, а не «зависать» в бесконечном выполнении. Массовость означает, что алгоритм разрабатывается не для одного конкретного случая, а для целого класса однотипных задач с разными исходными данными. Эффективность — каждый шаг алгоритма должен быть выполним за разумное время имеющимися средствами.\n\nСуществует несколько способов записи алгоритмов. Словесное описание — алгоритм формулируется на естественном языке, что удобно для понимания, но неточно для программирования. Псевдокод — упрощённая запись, приближенная к языку программирования, но без строгого синтаксиса. Блок-схема — графическое представление алгоритма с помощью стандартных фигур (овал — начало/конец, прямоугольник — действие, ромб — условие, параллелограмм — ввод/вывод), соединённых стрелками. И наконец, запись на языке программирования — точная, исполняемая компьютером форма алгоритма.\n\nРешение задачи на компьютере проходит несколько этапов: постановка задачи, формализация (перевод задачи на язык математических понятий), разработка алгоритма, программирование, отладка и тестирование на разных наборах данных, включая граничные случаи, и, наконец, анализ полученных результатов.\n\nПо структуре выделяют три базовых типа алгоритмов: линейный (действия выполняются последовательно без ветвлений и повторов), разветвляющийся (в зависимости от условия выполняется один из вариантов действий) и циклический (последовательность действий повторяется несколько раз). Комбинируя эти три базовые структуры, можно построить алгоритм решения практически любой задачи — именно поэтому их изучение является фундаментом дальнейшего курса программирования.","quiz":[{"question":"Что из перечисленного является обязательным свойством алгоритма?","options":["Дискретность","Красочность","Многословность","Случайность"],"correctIndex":0},{"question":"Какое свойство алгоритма означает, что при одинаковых исходных данных результат всегда будет одинаковым?","options":["Массовость","Детерминированность","Эффективность","Дискретность"],"correctIndex":1},{"question":"Какая геометрическая фигура в блок-схеме используется для обозначения условия (ветвления)?","options":["Прямоугольник","Овал","Ромб","Параллелограмм"],"correctIndex":2},{"question":"Какой этап решения задачи на компьютере идёт сразу после разработки алгоритма?","options":["Постановка задачи","Формализация","Программирование","Анализ результатов"],"correctIndex":2},{"question":"Какой тип алгоритмической структуры используется, когда одна и та же последовательность действий выполняется несколько раз?","options":["Линейный","Разветвляющийся","Циклический","Рекурсивный"],"correctIndex":2},{"question":"Что такое псевдокод?","options":["Графическое изображение алгоритма из фигур","Упрощённая запись алгоритма, приближенная к языку программирования, но без строгого синтаксиса","Точный код на языке Python","Словесное описание задачи заказчиком"],"correctIndex":1},{"question":"Что означает свойство «массовость» алгоритма?","options":["Алгоритм решает только одну конкретную задачу","Алгоритм пригоден для решения целого класса однотипных задач с разными исходными данными","Алгоритм должен быть очень длинным","Алгоритм выполняется одновременно многими людьми"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"blockly_games","externalServiceTask":"Пройти первые 6-8 уровней игры «Лабиринт» (Maze) на Blockly Games, используя команды поворота, движения вперёд и повторения (циклы) для построения алгоритма прохождения лабиринта.","starts_at":"2026-07-07T13:05:00+05:00","ends_at":"2026-07-07T13:50:00+05:00","room":"301"},{"topic":"Переменные, типы данных и операторы в Python","objective":"Научиться объявлять переменные, использовать основные типы данных и арифметические операторы для построения линейных программ на Python.","theory":"В программировании переменная — это именованная область памяти, предназначенная для хранения данных, значение которых может изменяться в ходе выполнения программы. В языке Python переменную не нужно заранее объявлять с указанием типа — достаточно присвоить ей значение с помощью оператора «=», и переменная будет создана автоматически. Например, запись age = 16 создаёт переменную age и сохраняет в ней целое число 16. Такой подход называется динамической типизацией: тип переменной определяется автоматически по присвоенному значению и может меняться при повторном присваивании.\n\nPython поддерживает несколько базовых типов данных. Тип int используется для хранения целых чисел (например, 5, -12, 1000). Тип float — для хранения вещественных (дробных) чисел (например, 3.14, -0.5). Тип str предназначен для хранения текстовых строк, которые записываются в кавычках (например, \"Ташкент\"). Тип bool хранит логические значения True или False и часто используется как результат сравнения. Узнать тип текущего значения переменной можно с помощью функции type().\n\nИногда требуется преобразовать данные из одного типа в другой — для этого используются функции явного преобразования типов: int() преобразует значение в целое число, float() — в вещественное, str() — в строку. Это особенно важно при работе с функцией input(), которая всегда возвращает данные в виде строки, даже если пользователь ввёл число: чтобы выполнить арифметические операции с введённым значением, его нужно предварительно преобразовать, например num = int(input()).\n\nДля выполнения вычислений используются арифметические операторы: + (сложение), - (вычитание), * (умножение), / (деление, всегда возвращающее вещественное число), // (целочисленное деление), % (остаток от деления) и ** (возведение в степень). Действует привычный из математики порядок операций, который можно изменить с помощью круглых скобок.\n\nВывод результатов выполняется функцией print(), а для форматирования строк с подстановкой значений переменных удобно использовать f-строки — запись вида f\"Площадь: {area}\", где выражение в фигурных скобках автоматически вычисляется и вставляется в текст. Например, программа вычисления площади круга: r = float(input()); area = 3.14 * r ** 2; print(f\"Площадь: {area}\").","quiz":[{"question":"Как называется способ определения типа переменной в Python без явного его указания?","options":["Статическая типизация","Динамическая типизация","Жёсткая типизация","Ручная типизация"],"correctIndex":1},{"question":"Какой тип данных хранит значения True и False?","options":["int","str","bool","float"],"correctIndex":2},{"question":"Что вернёт выражение 7 // 2 в Python?","options":["3.5","3","4","1"],"correctIndex":1},{"question":"Что вернёт выражение 7 % 2?","options":["3","3.5","1","0"],"correctIndex":2},{"question":"Какую функцию нужно использовать, чтобы преобразовать строку, введённую пользователем, в целое число?","options":["str()","float()","int()","type()"],"correctIndex":2},{"question":"Какой тип данных всегда возвращает функция input()?","options":["int","float","str","bool"],"correctIndex":2},{"question":"Какое выражение правильно выводит значение переменной area с помощью f-строки?","options":["print(\"Площадь: \" + area)","print(f\"Площадь: {area}\")","print(area + \"Площадь\")","print(type(area))"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-09T09:25:00+05:00","ends_at":"2026-07-09T10:10:00+05:00","room":"301"},{"topic":"Ветвление: условный оператор if-elif-else","objective":"Научиться писать программы с разветвляющейся структурой, используя условный оператор и логические операции.","theory":"Многие задачи невозможно решить линейной последовательностью действий — программа должна выбирать один из нескольких путей выполнения в зависимости от условий. Для этого в Python используется условный оператор if, реализующий алгоритмическую структуру «ветвление».\n\nПростейшая форма: if условие: (далее с отступом идут действия, выполняемые, если условие истинно). Если нужно предусмотреть альтернативу, добавляется блок else, который выполняется, когда условие ложно. Если вариантов больше двух, используется цепочка elif, позволяющая проверить несколько условий последовательно; если ни одно условие не выполнилось, срабатывает завершающий else. В Python границы блоков задаются не скобками, а отступами (обычно 4 пробела) — неправильный отступ приведёт к ошибке или неверной логике программы.\n\nУсловия строятся с помощью операторов сравнения: == (равно), != (не равно), > (больше), < (меньше), >= (больше или равно), <= (меньше или равно). Результатом сравнения всегда является True или False. Простые условия можно объединять в сложные с помощью логических операторов: and (истинно, только если оба условия истинны), or (истинно, если хотя бы одно условие истинно) и not (отрицание). Например, условие «число положительное и чётное» записывается как (n > 0) and (n % 2 == 0).\n\nУсловные операторы можно вкладывать друг в друга — это называется вложенным ветвлением: внутри блока if может находиться ещё один условный оператор, что позволяет проверять более сложные комбинации условий. Например, определение високосного года требует проверки нескольких условий с использованием and, or и вложенности.\n\nРассмотрим примеры: определение чётности числа — если остаток от деления числа на 2 равен нулю (n % 2 == 0), число чётное, иначе нечётное. Другой пример — классификация индекса массы тела (ИМТ): в зависимости от диапазона значений (менее 18.5, от 18.5 до 25, от 25 до 30, более 30) программа с помощью цепочки if-elif-else выводит соответствующую категорию: «недостаток веса», «норма», «избыточный вес» или «ожирение». Такие задачи с несколькими диапазонами значений — классический пример применения ветвления с несколькими условиями.","quiz":[{"question":"Какая конструкция в Python используется для проверки нескольких условий подряд?","options":["while-until","for-in","if-elif-else","try-except"],"correctIndex":2},{"question":"Чем определяются границы блока кода внутри оператора if в Python?","options":["Фигурными скобками","Отступами (пробелами)","Точкой с запятой","Круглыми скобками"],"correctIndex":1},{"question":"Каков результат выражения (5 > 3) and (2 > 4)?","options":["True","False","5","Ошибка"],"correctIndex":1},{"question":"Какой оператор используется для логического «ИЛИ» в Python?","options":["&","and","or","either"],"correctIndex":2},{"question":"Как называется ситуация, когда один оператор if находится внутри блока другого оператора if?","options":["Циклическое ветвление","Вложенное ветвление","Рекурсивное ветвление","Массовое ветвление"],"correctIndex":1},{"question":"Какое условие правильно проверяет, что число n является положительным и чётным?","options":["n > 0 or n % 2 == 0","n > 0 and n % 2 == 0","n > 0 not n % 2 == 0","n % 2 == 0 else n > 0"],"correctIndex":1},{"question":"Что произойдёт, если ни одно из условий в цепочке if-elif не окажется истинным, а блок else отсутствует?","options":["Программа завершится с ошибкой","Выполнится последнее условие elif принудительно","Ни один блок не выполнится, программа продолжит работу дальше","Выполнятся все блоки одновременно"],"correctIndex":2}],"hasExternalService":true,"externalServiceType":"codesandbox","externalServiceTask":"В CodeSandbox создать Python-проект с программой, которая по введённому баллу определяет оценку («отлично», «хорошо», «удовлетворительно», «неудовлетворительно»), используя конструкцию if-elif-else.","starts_at":"2026-07-10T13:05:00+05:00","ends_at":"2026-07-10T13:50:00+05:00","room":"301"},{"topic":"Циклы for и while: организация повторений","objective":"Освоить построение циклических алгоритмов с использованием операторов for и while, включая вложенные циклы.","theory":"Циклы позволяют выполнять один и тот же набор действий многократно, не дублируя код вручную. Без циклов было бы невозможно эффективно обрабатывать большие объёмы данных, например, перебирать элементы списка или повторять вычисления заданное количество раз.\n\nВ Python существует два основных вида циклов. Цикл for используется, когда заранее известно количество повторений либо нужно перебрать элементы последовательности. Чаще всего цикл for сочетается с функцией range(): range(5) даёт числа от 0 до 4, range(2, 7) — от 2 до 6, а range(0, 10, 2) — числа от 0 до 8 с шагом 2. Запись for i in range(5): print(i) пять раз выведет числа от 0 до 4.\n\nЦикл while, в отличие от for, выполняется, пока истинно некоторое условие, и применяется, когда заранее неизвестно точное количество повторений. Синтаксис: while условие: (тело цикла с отступом). Важно, чтобы внутри тела цикла условие рано или поздно стало ложным, иначе цикл станет бесконечным — это одна из самых частых ошибок начинающих.\n\nВнутри циклов используются операторы управления: break немедленно прерывает выполнение цикла, а continue пропускает оставшуюся часть текущей итерации и переходит к следующей.\n\nЦиклы можно вкладывать друг в друга — внешний цикл управляет, например, номером строки, а внутренний — номером столбца. Классический пример — вывод таблицы умножения: внешний цикл перебирает множители от 1 до 9, а внутренний для каждого множителя выводит произведения на все числа от 1 до 9.\n\nЦиклы часто используются вместе с накоплением результата — паттерном «аккумулятор»: перед циклом заводится переменная (sum = 0 или count = 0), а внутри цикла на каждой итерации её значение изменяется. Например, программа подсчёта суммы цифр числа последовательно извлекает последнюю цифру операцией n % 10, прибавляет её к сумме, а затем «отбрасывает» эту цифру целочисленным делением n // 10, повторяя это, пока число не станет равным нулю. Похожим образом с помощью цикла вычисляется последовательность Фибоначчи, где каждое следующее число получается сложением двух предыдущих.","quiz":[{"question":"Какой цикл предпочтительнее использовать, когда точное количество повторений известно заранее?","options":["while","for","if","do-while"],"correctIndex":1},{"question":"Какую последовательность чисел сгенерирует range(2, 7)?","options":["2,3,4,5,6,7","2,3,4,5,6","1,2,3,4,5,6,7","0,1,2,3,4,5,6"],"correctIndex":1},{"question":"Что произойдёт, если условие в цикле while никогда не станет ложным?","options":["Цикл выполнится один раз","Программа выдаст ошибку синтаксиса","Возникнет бесконечный цикл","Python автоматически остановит цикл через 100 итераций"],"correctIndex":2},{"question":"Какой оператор немедленно прерывает выполнение цикла целиком?","options":["continue","break","pass","return"],"correctIndex":1},{"question":"Какой оператор пропускает текущую итерацию и переходит к следующей, не завершая цикл полностью?","options":["break","continue","stop","skip"],"correctIndex":1},{"question":"Как называется конструкция, когда один цикл находится внутри тела другого цикла?","options":["Составной цикл","Вложенный цикл","Двойной оператор","Рекурсивный цикл"],"correctIndex":1},{"question":"В программе подсчёта суммы цифр числа для получения последней цифры используется операция:","options":["n // 10","n % 10","n * 10","n ** 10"],"correctIndex":1},{"question":"Что делает паттерн «аккумулятор» в циклах?","options":["Останавливает цикл раньше времени","Постепенно накапливает результат (например, сумму) в переменной на каждой итерации","Ускоряет выполнение программы","Преобразует цикл for в цикл while"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-13T11:15:00+05:00","ends_at":"2026-07-13T12:00:00+05:00","room":"301"},{"topic":"Одномерные массивы (списки) в Python: создание и обработка","objective":"Научиться создавать одномерные массивы (списки), заполнять их и выполнять базовые операции обработки данных.","theory":"Список (list) в Python — это упорядоченная изменяемая коллекция элементов, которая позволяет хранить сразу много значений под одним именем переменной, в отличие от обычной переменной, хранящей только одно значение. Списки — важнейший инструмент обработки данных: с их помощью удобно хранить оценки ученика, результаты измерений, список товаров и любые другие однотипные наборы данных.\n\nСоздать список можно несколькими способами: перечислив элементы в квадратных скобках через запятую, например numbers = [4, 8, 15, 16, 23], создав пустой список numbers = [] и заполняя его позже, либо преобразовав диапазон чисел в список list(range(10)). Заполнение списка часто выполняется в цикле — например, с помощью random.randint(a, b) можно сгенерировать список из случайных чисел, добавляя их методом append().\n\nКаждый элемент списка имеет индекс, начинающийся с нуля: первый элемент имеет индекс 0. Обращение к элементу производится через квадратные скобки: numbers[0]. Python поддерживает отрицательную индексацию: numbers[-1] обращается к последнему элементу. С помощью среза numbers[2:5] можно получить часть списка от индекса 2 до индекса 4 включительно.\n\nСписки поддерживают методы: append(x) добавляет элемент в конец, insert(i, x) вставляет элемент на позицию i, remove(x) удаляет первое найденное вхождение значения x, а pop(i) удаляет и возвращает элемент по индексу i. Перебор элементов выполняется циклом for: for x in numbers: print(x).\n\nС использованием циклов на списках решается множество типовых задач: вычисление суммы всех элементов, поиск максимального или минимального элемента (сравнение текущего элемента с сохранённым «рекордом»), подсчёт среднего арифметического (сумма, делённая на len(numbers)), а также линейный поиск — последовательный просмотр всех элементов с целью найти элемент с заданным значением или его индекс. Например, чтобы найти индекс максимального элемента, заводят переменные max_value и max_index, инициализируют их первым элементом списка, а затем в цикле сравнивают каждый следующий элемент с текущим максимумом, обновляя обе переменные при нахождении большего значения.","quiz":[{"question":"Какой индекс имеет первый элемент списка в Python?","options":["1","0","-1","Зависит от списка"],"correctIndex":1},{"question":"Что вернёт numbers[-1] для списка numbers = [4, 8, 15, 16, 23]?","options":["4","8","23","Ошибку"],"correctIndex":2},{"question":"Какой метод добавляет элемент в конец списка?","options":["insert()","append()","remove()","pop()"],"correctIndex":1},{"question":"Что вернёт срез numbers[1:3] для списка numbers = [4, 8, 15, 16, 23]?","options":["[8, 15]","[4, 8, 15]","[8, 15, 16]","[15, 16]"],"correctIndex":0},{"question":"Какая функция возвращает количество элементов в списке?","options":["size(numbers)","count(numbers)","len(numbers)","length(numbers)"],"correctIndex":2},{"question":"Как называется последовательный просмотр всех элементов списка для нахождения нужного значения?","options":["Бинарный поиск","Линейный поиск","Сортировка","Индексация"],"correctIndex":1},{"question":"Какой метод удаляет и возвращает элемент списка по указанному индексу?","options":["remove(i)","delete(i)","pop(i)","drop(i)"],"correctIndex":2}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-14T13:05:00+05:00","ends_at":"2026-07-14T13:50:00+05:00","room":"301"},{"topic":"Алгоритмы поиска и сортировки массивов","objective":"Изучить принципы работы алгоритмов сортировки (пузырьком, выбором) и поиска (линейный, бинарный) и уметь реализовать их на Python.","theory":"Сортировка — это упорядочивание элементов массива по определённому признаку, чаще всего по возрастанию или убыванию значений. Сортировка — одна из наиболее часто решаемых задач в программировании, поскольку упорядоченные данные удобнее анализировать и в них быстрее искать нужные значения.\n\nОдин из простейших для понимания алгоритмов — сортировка пузырьком (Bubble Sort). Элементы списка сравниваются попарно (соседние элементы), и если они стоят в неправильном порядке, их меняют местами. За один полный проход самый большой ещё не отсортированный элемент «всплывает», как пузырёк, в конец списка. Проходы повторяются, пока весь список не окажется отсортированным. Реализация использует два вложенных цикла: внешний определяет количество проходов, внутренний — сравнение и обмен соседних элементов.\n\nПохожий по сложности алгоритм — сортировка выбором (Selection Sort). На каждом шаге алгоритм находит индекс минимального элемента среди ещё не отсортированной части списка и меняет его местами с первым элементом этой части. После каждого прохода на своё место в отсортированной части встаёт ровно один элемент.\n\nОба алгоритма при сортировке списка из n элементов выполняют примерно n × n сравнений в худшем случае — их временная сложность имеет порядок O(n²): если размер списка увеличить в 2 раза, время работы вырастет примерно в 4 раза. Эти алгоритмы просты для понимания, но неэффективны для очень больших наборов данных.\n\nПоиск элемента в массиве также можно выполнять по-разному в зависимости от того, отсортирован ли массив. Линейный поиск проверяет элементы по очереди, пока не найдёт нужный, — работает на любом массиве, но в худшем случае требует n сравнений, то есть имеет сложность O(n). Бинарный (двоичный) поиск работает значительно быстрее, но только на предварительно отсортированном массиве: алгоритм сравнивает искомое значение со средним элементом массива и, в зависимости от результата, отбрасывает половину массива, где искомого элемента точно нет, повторяя процедуру для оставшейся половины. Благодаря этому бинарный поиск находит элемент всего за O(log n) сравнений — в массиве из миллиона элементов потребуется не более 20 сравнений вместо миллиона.","quiz":[{"question":"Какой алгоритм сортировки на каждом проходе сравнивает соседние элементы и меняет их местами при неправильном порядке?","options":["Сортировка выбором","Сортировка пузырьком","Бинарный поиск","Линейный поиск"],"correctIndex":1},{"question":"Что делает алгоритм сортировки выбором на каждом шаге?","options":["Меняет местами все элементы случайным образом","Находит минимальный элемент в неотсортированной части и ставит его на своё место","Делит массив пополам","Сравнивает искомый элемент со средним элементом"],"correctIndex":1},{"question":"Какова примерная временная сложность сортировки пузырьком в худшем случае?","options":["O(n)","O(log n)","O(n²)","O(1)"],"correctIndex":2},{"question":"Какой поиск требует предварительно отсортированного массива?","options":["Линейный поиск","Бинарный поиск","Оба вида поиска","Ни один из них"],"correctIndex":1},{"question":"Какова временная сложность бинарного поиска?","options":["O(n)","O(n²)","O(log n)","O(n log n)"],"correctIndex":2},{"question":"Сколько сравнений потребуется линейному поиску в худшем случае для массива из 1000 элементов?","options":["10","1000","100","log(1000)"],"correctIndex":1},{"question":"Что происходит на первом шаге бинарного поиска?","options":["Сравнение искомого значения со средним элементом массива","Проверка первого элемента массива","Сортировка массива","Удаление половины элементов"],"correctIndex":0},{"question":"Если размер массива при сортировке пузырьком увеличить в 2 раза, во сколько примерно раз вырастет время работы?","options":["В 2 раза","В 4 раза","Останется прежним","В 8 раз"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"visualgo","externalServiceTask":"На сайте VisualGo в разделе Sorting пошагово визуализировать сортировку пузырьком (Bubble Sort) и сортировку выбором (Selection Sort) для одного набора чисел, сравнить количество шагов и сделать вывод.","starts_at":"2026-07-16T09:25:00+05:00","ends_at":"2026-07-16T10:10:00+05:00","room":"301"},{"topic":"Функции: разработка модульных программ","objective":"Научиться создавать и использовать собственные функции для структурирования программ и повторного использования кода.","theory":"По мере роста программы код становится всё сложнее читать и поддерживать, если он представляет собой одну длинную последовательность команд. Чтобы структурировать программу и избежать дублирования кода, используются функции — именованные блоки кода, которые можно вызывать многократно из разных мест программы.\n\nВ Python функция определяется с помощью ключевого слова def, за которым следует имя функции, список параметров в круглых скобках и двоеточие; тело функции записывается с отступом. Например: def is_prime(n): — заголовок функции, проверяющей, является ли число n простым. Параметры — переменные, перечисленные в заголовке функции, через которые в неё передаются данные извне. При вызове функции вместо параметров подставляются конкретные значения — аргументы: is_prime(17) передаёт функции аргумент 17.\n\nФункция может возвращать результат своей работы с помощью оператора return, после которого выполнение функции немедленно завершается, а значение передаётся обратно в место вызова. Важно не путать return с print(): print() лишь выводит значение на экран, но не передаёт его дальше в программу, тогда как return позволяет использовать результат работы функции в других вычислениях, например result = is_prime(17). Если функция не содержит return, она возвращает None.\n\nПеременные, объявленные внутри функции, называются локальными — они существуют только во время выполнения функции и недоступны за её пределами. Переменные, объявленные вне всех функций, называются глобальными.\n\nПараметры функции могут иметь значения по умолчанию, которые используются, если при вызове аргумент не был передан явно, например def greet(name, greeting=\"Привет\"): — вызов greet(\"Анна\") подставит greeting=\"Привет\" автоматически.\n\nИспользование функций даёт важные преимущества: декомпозиция — сложная задача разбивается на более простые подзадачи; повторное использование — однажды написанную функцию можно вызывать сколько угодно раз; читаемость — программа, состоящая из хорошо названных функций, легче понятна другому программисту.","quiz":[{"question":"Какое ключевое слово используется для определения функции в Python?","options":["function","def","func","lambda"],"correctIndex":1},{"question":"В чём отличие return от print() внутри функции?","options":["Это одно и то же","return передаёт значение обратно в место вызова, а print() только выводит его на экран","print() работает быстрее","return можно использовать только в циклах"],"correctIndex":1},{"question":"Как называются переменные, объявленные внутри функции и недоступные за её пределами?","options":["Глобальные","Статические","Локальные","Константные"],"correctIndex":2},{"question":"Что вернёт функция, если в её теле отсутствует оператор return?","options":["0","Пустую строку \"\"","None","Ошибку выполнения"],"correctIndex":2},{"question":"Что произойдёт при вызове greet(\"Анна\") для функции def greet(name, greeting=\"Привет\"):?","options":["Возникнет ошибка, так как не хватает аргумента","greeting автоматически получит значение \"Привет\"","name получит значение None","Функция не выполнится"],"correctIndex":1},{"question":"Какое из перечисленных НЕ является преимуществом использования функций?","options":["Повторное использование кода","Улучшение читаемости программы","Автоматическое ускорение работы процессора","Разбиение сложной задачи на простые подзадачи"],"correctIndex":2},{"question":"Что такое аргумент функции?","options":["Имя функции","Конкретное значение, переданное функции при вызове вместо параметра","Оператор return","Тип данных, возвращаемых функцией"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-17T13:05:00+05:00","ends_at":"2026-07-17T13:50:00+05:00","room":"301"},{"topic":"Строки: обработка текстовой информации","objective":"Освоить основные операции обработки строк для решения задач анализа и преобразования текста.","theory":"Строка (str) в Python — это последовательность символов, с которой можно работать во многом так же, как со списком: у строки есть длина, к отдельным символам можно обращаться по индексу, а из строки можно вырезать часть с помощью среза. Например, для строки word = \"программа\" обращение word[0] вернёт символ «п», а срез word[0:4] вернёт подстроку «прог». Доступна и отрицательная индексация: word[-1] обращается к последнему символу.\n\nГлавное отличие строки от списка в том, что строка является неизменяемым (immutable) типом данных: нельзя присвоить новое значение отдельному символу строки — вместо этого создаётся новая строка на основе старой.\n\nPython предоставляет богатый набор методов для работы со строками. len(word) возвращает количество символов. upper() и lower() возвращают копию строки в верхнем или нижнем регистре. split(разделитель) разбивает строку на список подстрок по указанному разделителю: \"мама мыла раму\".split() вернёт [''мама'', ''мыла'', ''раму'']. Обратная операция — join(), соединяющий список строк в одну через указанный разделитель. replace(старое, новое) заменяет все вхождения одной подстроки на другую. find() и index() ищут позицию подстроки внутри строки, а strip() удаляет пробельные символы в начале и конце строки — полезно при обработке пользовательского ввода.\n\nДля объединения строк можно использовать оператор + (конкатенацию), однако при работе с числами удобнее использовать f-строки, которые автоматически преобразуют вставленные значения в текст.\n\nПеребор символов строки, как и элементов списка, выполняется в цикле for: for ch in word: print(ch). Эта возможность лежит в основе множества типовых задач обработки текста. Например, чтобы посчитать количество гласных букв в строке, заводят счётчик count = 0, перебирают каждый символ строки и, если он входит в строку гласных букв, увеличивают счётчик. Другая классическая задача — проверка строки на палиндром: достаточно сравнить исходную строку с её перевёрнутой версией, которую удобно получить срезом с отрицательным шагом word[::-1].","quiz":[{"question":"Какой тип данных является неизменяемым (immutable) в Python?","options":["list","str","dict","Все перечисленные изменяемы"],"correctIndex":1},{"question":"Что вернёт word[0:4] для word = \"программа\"?","options":["\"прог\"","\"прогр\"","\"рог\"","\"п\""],"correctIndex":0},{"question":"Какой метод разбивает строку на список подстрок по разделителю?","options":["join()","split()","replace()","strip()"],"correctIndex":1},{"question":"Какой метод удаляет пробельные символы в начале и конце строки?","options":["trim()","clean()","strip()","cut()"],"correctIndex":2},{"question":"Как получить перевёрнутую строку с помощью среза?","options":["word[::1]","word[::-1]","word[-1:]","word[0:-1]"],"correctIndex":1},{"question":"Что произойдёт при попытке выполнить word[0] = \"П\" для строки word?","options":["Первый символ строки изменится","Возникнет ошибка, так как строки неизменяемы","Строка удвоится","Ничего не произойдёт"],"correctIndex":1},{"question":"Какой метод соединяет список строк в одну строку через заданный разделитель?","options":["split()","join()","merge()","concat()"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-20T11:15:00+05:00","ends_at":"2026-07-20T12:00:00+05:00","room":"301"},{"topic":"Двумерные массивы: работа с матрицами","objective":"Научиться создавать и обрабатывать двумерные массивы (матрицы) с помощью вложенных циклов.","theory":"На практике часто требуется хранить данные, организованные не в виде простого списка, а в виде таблицы — например, оценки нескольких учеников по нескольким предметам или координаты точек на плоскости. Для представления таких табличных данных используется двумерный массив, или матрица, — список, каждый элемент которого сам является списком (список списков).\n\nСоздать двумерный массив можно, например, вручную: matrix = [[1, 2, 3], [4, 5, 6], [7, 8, 9]] — здесь matrix[0] — первая строка [1, 2, 3], а matrix[0][1] — второй элемент первой строки, то есть 2. В общем виде обращение к элементу матрицы имеет вид matrix[i][j], где i — номер строки, а j — номер столбца.\n\nЧаще матрицу создают программно, используя вложенные циклы или списковые включения. Чтобы создать матрицу размером rows на cols, заполненную нулями, можно записать: matrix = [[0 for j in range(cols)] for i in range(rows)]. Важно не использовать [[0] * cols] * rows, поскольку в этом случае все строки будут ссылаться на один и тот же список в памяти, и изменение одного элемента изменит соответствующие элементы во всех строках сразу — частая ошибка начинающих.\n\nДля обхода всех элементов матрицы применяются вложенные циклы: внешний перебирает номера строк, внутренний — номера столбцов: for i in range(rows): for j in range(cols): print(matrix[i][j]).\n\nЧтобы найти сумму всех элементов матрицы, заводят total = 0 и во вложенном цикле прибавляют каждый элемент matrix[i][j]. Чтобы найти сумму элементов главной диагонали, достаточно одного цикла: суммируются элементы matrix[i][i] — это работает только для квадратных матриц. Ещё одна классическая операция — транспонирование матрицы: элемент на позиции [i][j] в результирующей матрице оказывается на позиции [j][i]. С помощью вложенных циклов легко реализуется поэлементное сложение двух матриц одинакового размера. Для аккуратного вывода матрицы на экран удобно в цикле выводить строку целиком с разделителями между элементами, переходя на новую строку после каждой строки матрицы.","quiz":[{"question":"Что представляет собой двумерный массив (матрица) в Python?","options":["Список чисел","Список списков","Строка чисел через запятую","Отдельный тип данных matrix"],"correctIndex":1},{"question":"Как обратиться к элементу матрицы, находящемуся во второй строке (индекс 1) и третьем столбце (индекс 2)?","options":["matrix[2][3]","matrix[1][2]","matrix[3][2]","matrix(1,2)"],"correctIndex":1},{"question":"Сколько циклов обычно требуется для полного обхода всех элементов двумерного массива?","options":["Один","Два вложенных","Три","Ни одного, обход происходит автоматически"],"correctIndex":1},{"question":"Почему нежелательно создавать матрицу конструкцией [[0] * cols] * rows?","options":["Это вызывает синтаксическую ошибку","Все строки будут ссылаться на один и тот же список в памяти","Матрица будет заполнена единицами вместо нулей","Такая конструкция работает только для квадратных матриц"],"correctIndex":1},{"question":"Какие элементы образуют главную диагональ квадратной матрицы?","options":["matrix[i][i] для всех i","matrix[0][j] для всех j","matrix[i][0] для всех i","matrix[i][n-i]"],"correctIndex":0},{"question":"Что происходит при транспонировании матрицы?","options":["Все элементы удваиваются","Строки меняются местами со столбцами","Матрица сортируется по возрастанию","Матрица переворачивается по диагонали справа налево"],"correctIndex":1},{"question":"Что необходимо для поэлементного сложения двух матриц?","options":["Матрицы должны быть квадратными","Матрицы должны иметь одинаковый размер (число строк и столбцов)","Одна из матриц должна состоять из нулей","Матрицы должны быть отсортированы"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-21T13:05:00+05:00","ends_at":"2026-07-21T13:50:00+05:00","room":"301"},{"topic":"Рекурсия: рекурсивные алгоритмы и их применение","objective":"Понять принцип рекурсии, научиться писать рекурсивные функции и сравнивать их с итеративными решениями.","theory":"Рекурсия — это способ решения задачи, при котором функция вызывает саму себя для решения более простой версии той же задачи. Рекурсивный подход особенно естественен для задач, которые по своей природе можно разбить на такую же, но меньшую по масштабу подзадачу.\n\nЛюбая корректно построенная рекурсивная функция содержит два элемента. Базовый случай (база рекурсии) — простейший вариант задачи, ответ на который известен напрямую, без дальнейших вызовов функции; именно база рекурсии останавливает цепочку вызовов. Рекурсивный случай — часть функции, где задача сводится к вызову той же функции, но с «уменьшенными» входными данными, приближающими вычисление к базовому случаю. Если в функции отсутствует база рекурсии, рекурсия становится бесконечной, что приводит к ошибке переполнения стека вызовов (RecursionError в Python).\n\nКлассический пример — вычисление факториала числа n. Математически: 0! = 1 (база рекурсии), а n! = n × (n−1)! для n > 0 (рекурсивный случай). На Python: def factorial(n): if n == 0: return 1; else: return n * factorial(n - 1). При вызове factorial(4) функция вызывает factorial(3), та — factorial(2), и так далее до factorial(0), которая возвращает 1; после этого все отложенные умножения выполняются в обратном порядке, и получается результат 24. Каждый незавершённый вызов хранится в стеке вызовов, поэтому слишком глубокая рекурсия может исчерпать доступную память.\n\nЕщё один известный пример — числа Фибоначчи: fib(0) = 0, fib(1) = 1, fib(n) = fib(n−1) + fib(n−2). Наивное рекурсивное вычисление чисел Фибоначчи крайне неэффективно: одни и те же значения вычисляются повторно много раз, из-за чего время работы растёт экспоненциально, — итеративный вариант с циклом решает ту же задачу за линейное время.\n\nРекурсия особенно уместна там, где сама структура данных или задачи имеет рекурсивную природу: обход вложенных папок файловой системы, работа с деревьями, а также построение фрактальных изображений, например рекурсивное «дерево», у которого от каждой ветки под углом отходят две более короткие ветки, и так до тех пор, пока длина ветки не станет меньше заданного предела.","quiz":[{"question":"Что такое база рекурсии?","options":["Первый вызов функции","Простейший случай задачи, при котором функция возвращает ответ без дальнейших рекурсивных вызовов","Список аргументов функции","Максимальная глубина рекурсии"],"correctIndex":1},{"question":"Что произойдёт, если в рекурсивной функции отсутствует база рекурсии?","options":["Функция выполнится один раз и завершится","Возникнет бесконечная рекурсия и ошибка переполнения стека","Python автоматически добавит базу рекурсии","Функция вернёт None"],"correctIndex":1},{"question":"Чему равен 0! (факториал нуля) по определению, используемому как база рекурсии?","options":["0","1","Не определён","-1"],"correctIndex":1},{"question":"Какой вызов будет фактически завершён (получит результат) первым при вычислении factorial(4)?","options":["factorial(0), после чего последуют отложенные умножения","factorial(4) сразу вернёт 24 без вложенных вызовов","Функция вызовется только один раз","factorial(4) вызовет factorial(5)"],"correctIndex":0},{"question":"Почему «наивное» рекурсивное вычисление чисел Фибоначчи неэффективно для больших n?","options":["Python не поддерживает рекурсию для чисел Фибоначчи","Одни и те же значения вычисляются повторно много раз, время растёт экспоненциально","Числа Фибоначчи нельзя вычислить рекурсивно в принципе","Требуется слишком много переменных"],"correctIndex":1},{"question":"Где хранятся незавершённые (отложенные) вызовы рекурсивной функции во время выполнения?","options":["В отдельном файле на диске","В стеке вызовов","В базе данных","В списке параметров функции"],"correctIndex":1},{"question":"Для какой из задач рекурсивный подход наиболее естественен?","options":["Сложение двух чисел","Обход вложенных папок файловой системы (иерархическая структура)","Вывод текста на экран","Присваивание значения переменной"],"correctIndex":1},{"question":"Что происходит на каждом рекурсивном шаге при построении фрактального дерева?","options":["Длина ветки увеличивается, пока не достигнет максимума","Длина ветки уменьшается, и рисуются новые более короткие ответвления, пока длина не станет меньше предела","Дерево рисуется целиком за один вызов без рекурсии","Все ветки рисуются одинаковой длины"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"p5js","externalServiceTask":"В редакторе p5.js Web Editor написать рекурсивную функцию для рисования фрактального «дерева»: на каждом шаге уменьшать длину ветки и рисовать два новых ответвления под углом, пока длина не станет меньше заданного предела.","starts_at":"2026-07-23T09:25:00+05:00","ends_at":"2026-07-23T10:10:00+05:00","room":"301"},{"topic":"Основы объектно-ориентированного программирования: классы и объекты","objective":"Получить первоначальное представление об объектно-ориентированном программировании: классах, объектах, атрибутах и методах.","theory":"До сих пор мы писали программы в процедурном стиле — как последовательность операторов и функций, обрабатывающих данные. Объектно-ориентированное программирование (ООП) предлагает другой взгляд на организацию кода: программа рассматривается как совокупность взаимодействующих объектов, каждый из которых объединяет в себе данные (состояние) и действия над этими данными (поведение). Такой подход хорошо подходит для моделирования сущностей реального мира — учеников, товаров, геометрических фигур — и широко используется в больших программных проектах.\n\nОсновным строительным блоком ООП является класс — шаблон, описывающий, какими атрибутами (данными) и методами (функциями, определяющими поведение) будут обладать объекты этого класса. Объект — это конкретный экземпляр класса, созданный на основе этого шаблона и обладающий собственными значениями атрибутов. Например, класс Student может описывать общую структуру «ученика» (имя, класс обучения, средний балл), а конкретные объекты этого класса — Дильноза, Тимур, Санжар — будут иметь разные значения этих атрибутов, но одинаковый набор методов.\n\nВ Python класс определяется ключевым словом class: class Student:. Особую роль играет метод __init__(self, ...) — конструктор, который автоматически вызывается при создании нового объекта и используется для задания начальных значений атрибутов. Параметр self присутствует в заголовке каждого метода класса и ссылается на тот конкретный объект, с которым в данный момент работает метод — именно через self внутри методов происходит обращение к атрибутам объекта, например self.name = name сохраняет переданное имя как атрибут объекта.\n\nПример: class Student: def __init__(self, name, grade): self.name = name; self.grade = grade; def print_info(self): print(f\"{self.name}, {self.grade} класс\"). После такого определения можно создать объекты: student1 = Student(\"Дильноза\", 10); student2 = Student(\"Тимур\", 11), а затем вызвать у каждого объекта его собственный метод: student1.print_info() выведет «Дильноза, 10 класс», а student2.print_info() — «Тимур, 11 класс», хотя оба вызова используют один и тот же код метода класса.\n\nЕщё один пример — класс Rectangle с атрибутами width и height, а также методами area(self) и perimeter(self). Такой подход, при котором данные и методы их обработки объединены внутри одной структуры, называется инкапсуляцией — она делает код более организованным и упрощает его понимание, повторное использование и дальнейшее развитие, особенно когда размер и сложность программы растут.","quiz":[{"question":"Что является шаблоном, описывающим атрибуты и методы будущих объектов?","options":["Объект","Класс","Функция","Модуль"],"correctIndex":1},{"question":"Что такое объект в ООП?","options":["То же самое, что класс","Конкретный экземпляр класса с собственными значениями атрибутов","Метод класса","Переменная любого типа"],"correctIndex":1},{"question":"Какой специальный метод автоматически вызывается при создании нового объекта класса в Python?","options":["__main__","__init__","__new__","__create__"],"correctIndex":1},{"question":"На что ссылается параметр self внутри методов класса?","options":["На класс в целом","На конкретный объект, с которым работает метод","На родительский класс","На конструктор"],"correctIndex":1},{"question":"Как называется объединение данных и методов их обработки в единую структуру (класс)?","options":["Наследование","Полиморфизм","Инкапсуляция","Рекурсия"],"correctIndex":2},{"question":"Для класса Student с методом print_info(self), после создания student1 = Student(\"Дильноза\", 10), как правильно вызвать метод?","options":["print_info(student1)","student1.print_info()","Student.print_info()","print_info.student1()"],"correctIndex":1},{"question":"Что вернёт метод area(self) класса Rectangle с атрибутами width и height?","options":["Сумму сторон","Произведение width и height","Удвоенную сумму сторон","Разность сторон"],"correctIndex":1},{"question":"В чём принципиальное отличие ООП от процедурного стиля программирования?","options":["В ООП нельзя использовать циклы","ООП организует программу как совокупность объектов, объединяющих данные и поведение, а не как последовательность действий над отдельными переменными","ООП работает быстрее в любых случаях","В ООП нельзя использовать функции"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-24T13:05:00+05:00","ends_at":"2026-07-24T13:50:00+05:00","room":"301"}]'::jsonb)
    LOOP
      INSERT INTO public.lessons (group_id, subject_id, topic, title, description, status, starts_at, ends_at, started_at, ended_at, room, school_id)
      VALUES (
        v_group_id, v_subject_id, lesson_data->>'topic', lesson_data->>'topic', lesson_data->>'objective',
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN 'completed' ELSE 'scheduled' END,
        (lesson_data->>'starts_at')::timestamptz, (lesson_data->>'ends_at')::timestamptz,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'starts_at')::timestamptz ELSE NULL END,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'ends_at')::timestamptz ELSE NULL END,
        lesson_data->>'room', v_school_id
      )
      RETURNING id INTO v_lesson_id;

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, duration_min, school_id)
      VALUES (v_lesson_id, 1, 'middle', 'theory', 'presentation', lesson_data->>'topic', lesson_data->>'theory', 15, v_school_id);

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, duration_min, school_id)
      VALUES (v_lesson_id, 2, 'middle', 'task', 'quiz_qia', 'Проверь себя', 15, v_school_id)
      RETURNING id INTO v_stage_id;

      qpos := 0;
      FOR quiz_item IN SELECT * FROM jsonb_array_elements(lesson_data->'quiz')
      LOOP
        qpos := qpos + 1;
        INSERT INTO public.quiz_questions (stage_id, question_text, options, correct_option_index, position, points, time_per_question_seconds, school_id)
        VALUES (v_stage_id, quiz_item->>'question', quiz_item->'options', (quiz_item->>'correctIndex')::int, qpos, 1, 30, v_school_id);
      END LOOP;

      IF (lesson_data->>'hasExternalService')::boolean THEN
        INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, config, duration_min, school_id)
        VALUES (
          v_lesson_id, 3, 'middle', 'task', lesson_data->>'externalServiceType',
          lesson_data->>'externalServiceTask', lesson_data->>'externalServiceTask',
          jsonb_build_object('url',
            CASE lesson_data->>'externalServiceType'
              WHEN 'wokwi' THEN 'https://wokwi.com/projects/new/arduino-uno'
              WHEN 'codesandbox' THEN 'https://codesandbox.io/p/sandbox/vanilla'
              WHEN 'geogebra' THEN 'https://www.geogebra.org/classic'
              WHEN 'phet' THEN 'https://phet.colorado.edu/sims/html/forces-and-motion-basics/latest/forces-and-motion-basics_en.html'
              WHEN 'desmos' THEN 'https://www.desmos.com/calculator'
              WHEN 'blockly_games' THEN 'https://blockly.games/'
              WHEN 'visualgo' THEN 'https://visualgo.net/en'
              WHEN 'p5js' THEN 'https://editor.p5js.org/'
              WHEN 'excalidraw' THEN 'https://excalidraw.com/'
              WHEN 'learningapps' THEN 'https://learningapps.org/'
              WHEN 'sqlonline' THEN 'https://sqlime.org/'
              WHEN 'h5p' THEN 'https://h5p.eduos.snruz.uz/library'
              ELSE NULL
            END
          ),
          15, v_school_id
        );
      END IF;
    END LOOP;
  END IF;

  -- === 7-А класс | Робототехника (9 уроков) ===
  SELECT id INTO v_group_id FROM public.groups WHERE name = '7-А класс';
  SELECT id INTO v_subject_id FROM public.subjects WHERE group_id = v_group_id AND name = 'Робототехника';
  IF NOT EXISTS (SELECT 1 FROM public.lessons WHERE group_id = v_group_id AND subject_id = v_subject_id AND description IS NOT NULL) THEN
    FOR lesson_data IN SELECT * FROM jsonb_array_elements('[{"topic":"Что такое робот и робототехника","objective":"Дать ученикам базовое понимание того, что такое робот, из чего он состоит и где применяется робототехника.","theory":"Робототехника — это наука и инженерное направление, которое занимается созданием роботов — устройств, способных выполнять действия автоматически или полуавтоматически, без постоянного участия человека. Слово «робот» происходит от чешского слова «robota», что означает «тяжёлый труд». Впервые это слово использовал чешский писатель Карел Чапек в пьесе 1920 года.\n\nЧто отличает робота от обычной машины, например от стиральной машины? Робот способен воспринимать информацию об окружающем мире с помощью датчиков (сенсоров), обрабатывать эту информацию с помощью «мозга» — контроллера, и совершать действия с помощью исполнительных устройств — актуаторов (моторов, светодиодов, динамиков). Такую связку часто называют циклом «воспринимай — думай — действуй».\n\nНапример, робот-пылесос имеет датчики, которые определяют препятствия (стены, мебель), контроллер, который решает, куда двигаться дальше, и моторы, которые вращают колёса и щётки. Всё это происходит без прямого участия человека.\n\nРоботы окружают нас повсюду. На заводах промышленные роботы-манипуляторы собирают автомобили и электронику быстрее и точнее человека. В медицине хирургические роботы помогают врачам проводить сложные операции с высокой точностью. В космосе роботы-марсоходы исследуют поверхность далёких планет. Дома нас окружают роботы-пылесосы, умные колонки и роботы-игрушки.\n\nРобототехника объединяет знания из нескольких наук: механики (как двигаются части робота), электроники (как работает электрический ток и датчики) и программирования (как заставить робота «думать» и принимать решения). Изучение робототехники развивает инженерное мышление, логику, творчество и умение работать в команде.\n\nРоботов разделяют на несколько типов: промышленные (работают на производстве), сервисные (помогают людям в быту), исследовательские (изучают опасные или труднодоступные места) и образовательные (созданы для обучения, как LEGO Mindstorms или Arduino-наборы).\n\nВ этом курсе мы изучим все три составляющих робота: механику, электронику и программирование, а в конце соберём и запрограммируем собственного простого робота, способного самостоятельно объезжать препятствия.","quiz":[{"question":"От какого слова произошло слово «робот»?","options":["чешского «robota» (труд)","английского «robot» (машина)","латинского «robustus» (крепкий)","греческого «robotikos» (умный)"],"correctIndex":0},{"question":"Кто впервые использовал слово «робот» в своём произведении?","options":["Айзек Азимов","Карел Чапек","Леонардо да Винчи","Никола Тесла"],"correctIndex":1},{"question":"Какой цикл описывает работу робота?","options":["«включи-выключи»","«воспринимай-думай-действуй»","«запусти-останови»","«заряди-работай»"],"correctIndex":1},{"question":"Что выполняет роль «мозга» робота?","options":["датчик","актуатор","контроллер (микроконтроллер)","корпус"],"correctIndex":2},{"question":"Что из перечисленного является актуатором (исполнительным устройством)?","options":["датчик расстояния","мотор колеса","камера","кнопка"],"correctIndex":1},{"question":"Какой тип робота используется для сборки автомобилей на заводе?","options":["образовательный","исследовательский","промышленный","сервисный"],"correctIndex":2},{"question":"Какие науки объединяет робототехника?","options":["только программирование","механику и электронику","механику, электронику и программирование","только механику"],"correctIndex":2},{"question":"Приведите пример сервисного робота.","options":["марсоход","робот-манипулятор на заводе","робот-пылесос","спутник"],"correctIndex":2}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-07T08:30:00+05:00","ends_at":"2026-07-07T09:15:00+05:00","room":"204"},{"topic":"Компоненты робота: сенсоры, актуаторы, контроллер","objective":"Научить учеников различать три ключевых компонента любого робота и объяснять их функции на конкретных примерах.","theory":"На прошлом уроке мы узнали, что каждый робот работает по циклу «воспринимай — думай — действуй». Сегодня разберём подробнее три главных компонента, которые обеспечивают этот цикл: сенсоры, контроллер и актуаторы.\n\nСенсоры (датчики) — это «органы чувств» робота. Они собирают информацию об окружающем мире и превращают её в электрический сигнал, понятный контроллеру. Например, датчик расстояния измеряет, насколько далеко находится препятствие, подобно тому, как летучие мыши используют эхолокацию. Датчик света определяет уровень освещённости, как наш глаз. Датчик касания похож на кожу — он сообщает, когда робот к чему-то прикоснулся.\n\nКонтроллер — это «мозг» робота. Обычно это небольшая плата с микроконтроллером — крошечным компьютером, который выполняет программу, написанную человеком. Контроллер получает данные от сенсоров, обрабатывает их по заданным правилам (алгоритму) и решает, какую команду отправить актуаторам. Самые популярные учебные контроллеры — платы Arduino и микроконтроллеры на базе ESP32. Контроллер работает очень быстро, но делает только то, что заложено в программе.\n\nАктуаторы (исполнительные устройства) — это «мышцы» робота. Они превращают команды контроллера в реальное физическое действие. Самый распространённый актуатор — электромотор, который вращает колёса или манипулятор. Также к актуаторам относятся: сервоприводы (моторы с точным контролем угла поворота), светодиоды и динамики.\n\nВажно понимать, что все три компонента работают только вместе, в связке. Если убрать сенсоры — робот станет «слепым». Если убрать контроллер — некому будет принимать решения. Если убрать актуаторы — робот не сможет ничего сделать, даже если «поймёт», что нужно делать.\n\nРассмотрим пример: робот, который должен остановиться перед стеной. Ультразвуковой датчик (сенсор) постоянно измеряет расстояние до препятствия. Как только расстояние становится меньше 10 сантиметров, контроллер, выполняя записанную программу, отправляет команду моторам (актуаторам) остановиться. Весь процесс происходит за доли секунды, много раз в секунду, поэтому робот двигается плавно и реагирует быстро.\n\nНа следующих уроках мы подробнее изучим каждый из этих компонентов: сначала электронику, потом механику, а затем научимся программировать контроллер.","quiz":[{"question":"Какую роль в роботе выполняют сенсоры?","options":["собирают информацию об окружающем мире","выполняют программу","совершают физическое действие","хранят энергию"],"correctIndex":0},{"question":"Что является «мозгом» робота?","options":["сервопривод","контроллер","датчик","колесо"],"correctIndex":1},{"question":"Какое устройство относится к актуаторам?","options":["датчик света","ультразвуковой датчик","электромотор","кнопка"],"correctIndex":2},{"question":"Какая учебная плата чаще всего используется как контроллер в образовательной робототехнике?","options":["Arduino","USB-флешка","SIM-карта","жёсткий диск"],"correctIndex":0},{"question":"Что произойдёт с роботом, если убрать все сенсоры, но оставить контроллер и актуаторы?","options":["робот будет работать быстрее","робот не сможет реагировать на окружающий мир","робот станет умнее","ничего не изменится"],"correctIndex":1},{"question":"Чем сервопривод отличается от обычного мотора?","options":["он не потребляет энергию","он позволяет точно контролировать угол поворота","он работает только на батарейках","он используется только как датчик"],"correctIndex":1},{"question":"В примере с роботом, который останавливается перед стеной, что измеряет ультразвуковой датчик?","options":["температуру воздуха","уровень освещённости","расстояние до препятствия","скорость ветра"],"correctIndex":2},{"question":"Какой из вариантов правильно описывает порядок работы робота?","options":["актуатор → сенсор → контроллер","контроллер → сенсор → актуатор","сенсор → контроллер → актуатор","сенсор → актуатор → контроллер"],"correctIndex":2}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-08T10:20:00+05:00","ends_at":"2026-07-08T11:05:00+05:00","room":"204"},{"topic":"Электрические цепи: как течёт ток в роботе","objective":"Объяснить ученикам основы электрической цепи и научить собирать простую схему с источником питания, светодиодом и выключателем.","theory":"Любой робот питается электричеством. Чтобы понять, как работает электроника робота, нужно разобраться с базовыми понятиями электрической цепи.\n\nЭлектрическая цепь — это замкнутый путь, по которому течёт электрический ток. Чтобы ток тёк, цепь должна быть замкнутой, без разрывов. Простейшая цепь состоит из трёх обязательных частей: источника питания (батарейка), проводников (провода) и нагрузки — устройства, которое потребляет энергию и выполняет полезную работу (например, светодиод или мотор).\n\nТок — это направленное движение заряженных частиц (электронов) по проводнику. Ток измеряется в амперах (А). Напряжение — это «сила», которая заставляет ток течь по цепи, подобно тому как давление воды заставляет её течь по трубе. Напряжение измеряется в вольтах (В). Обычная пальчиковая батарейка даёт напряжение 1,5 В.\n\nВажный элемент почти любой цепи — выключатель. Он позволяет разрывать или замыкать цепь по желанию. Когда выключатель разомкнут — цепь разорвана, и ток не течёт. Когда замкнут — цепь замкнута, ток течёт, и устройство работает.\n\nЕщё один важный элемент — резистор. Это компонент, который ограничивает силу тока в цепи. Например, светодиод (LED) — очень чувствительный компонент: если подключить его напрямую к батарейке без резистора, слишком большой ток может его сжечь. Поэтому резистор ставят последовательно со светодиодом, чтобы защитить его.\n\nРазличают два основных способа соединения компонентов: последовательное и параллельное. При последовательном соединении компоненты подключены друг за другом, как бусины на нитке, и если один компонент выйдет из строя, вся цепь разомкнётся. При параллельном соединении компоненты подключены на отдельных «ветках» — если одна ветка выйдет из строя, остальные продолжат работать.\n\nПонимание этих основ необходимо, чтобы собирать электронные схемы для робота: подключать датчики, моторы и микроконтроллер правильно, не сжигая компоненты и не создавая короткого замыкания (ситуации, когда ток течёт по цепи с очень маленьким сопротивлением, минуя нагрузку, что может привести к перегреву и повреждению батареи).\n\nСегодня на практике мы соберём простейшую электрическую цепь в виртуальном симуляторе Wokwi: источник питания, резистор, светодиод и выключатель.","quiz":[{"question":"Что необходимо для того, чтобы электрический ток тёк по цепи?","options":["разомкнутая цепь","замкнутая цепь","отсутствие проводов","только батарейка без нагрузки"],"correctIndex":1},{"question":"В каких единицах измеряется электрический ток?","options":["вольты","ватты","амперы","омы"],"correctIndex":2},{"question":"Что измеряется в вольтах?","options":["сила тока","сопротивление","напряжение","мощность"],"correctIndex":2},{"question":"Для чего в цепь со светодиодом ставят резистор?","options":["чтобы увеличить напряжение","чтобы ограничить силу тока и защитить светодиод","чтобы цепь стала параллельной","чтобы отключить питание"],"correctIndex":1},{"question":"Что происходит, когда выключатель разомкнут?","options":["ток течёт быстрее","устройство работает сильнее","цепь разорвана и ток не течёт","напряжение увеличивается"],"correctIndex":2},{"question":"Чем отличается последовательное соединение от параллельного?","options":["при последовательном компоненты подключены друг за другом, а при параллельном — на отдельных ветках","разницы нет","параллельное соединение возможно только с моторами","последовательное соединение используется только в компьютерах"],"correctIndex":0},{"question":"Что такое короткое замыкание?","options":["правильная работа цепи","ситуация, когда ток течёт по цепи с очень маленьким сопротивлением, минуя нагрузку","отключение батарейки","использование резистора"],"correctIndex":1},{"question":"Какое напряжение обычно даёт одна пальчиковая батарейка?","options":["1,5 В","12 В","220 В","5 А"],"correctIndex":0}],"hasExternalService":true,"externalServiceType":"wokwi","externalServiceTask":"Соберите в Wokwi простую схему: батарейка (или Arduino 5V), резистор, светодиод и кнопка-выключатель. Настройте цепь так, чтобы светодиод загорался только при нажатой кнопке.","starts_at":"2026-07-10T09:25:00+05:00","ends_at":"2026-07-10T10:10:00+05:00","room":"204"},{"topic":"Механические передачи: шестерни и приводы робота","objective":"Познакомить учеников с принципом работы шестерён и других механических передач, которые превращают вращение мотора в движение робота.","theory":"Мотор робота вращается с определённой скоростью и создаёт определённую силу (крутящий момент). Но часто нужной скорости или силы недостаточно напрямую. Здесь на помощь приходят механические передачи, самая распространённая из которых — зубчатая передача, или шестерни.\n\nШестерня — это диск с зубцами по краю. Когда две шестерни соединены зубцами, вращение одной передаётся другой. Если шестерни одинакового размера, скорость и сила передаются без изменений, только направление вращения меняется на противоположное. Но если шестерни разного размера — маленькая шестерня, соединённая с большой, будет вращаться быстрее, но с меньшей силой; и наоборот — большая шестерня вращается медленнее, но с большей силой. Это называется «передаточным отношением».\n\nПредставьте велосипед: когда вы едете в гору, вы переключаетесь на маленькую переднюю звёздочку и большую заднюю — крутить педали становится легче, но скорость снижается. На равнине — наоборот. Точно так же работают шестерни в роботе: инженер подбирает нужное передаточное отношение в зависимости от задачи — нужна роботу скорость или сила.\n\nКроме зубчатой передачи существуют и другие механизмы: ремённая передача (шкивы, соединённые ремнём), червячная передача (позволяет очень сильно уменьшать скорость и увеличивать силу, а также «запирает» механизм, чтобы он не вращался в обратную сторону сам по себе) и рычаги (простейший механизм, увеличивающий силу за счёт точки опоры, как у качелей или ножниц).\n\nВ образовательных наборах роботов (например, LEGO Technic) шестерни часто используют, чтобы построить манипулятор, который поднимает небольшие грузы, или колёсную платформу, которая едет быстро, но не очень сильно давит на препятствия.\n\nВажно помнить: передачи не создают энергию из ниоткуда — они лишь перераспределяют её между скоростью и силой. Если передача увеличивает силу в два раза, скорость уменьшается ровно в два раза, и наоборот. Это фундаментальный закон сохранения энергии, который действует во всей технике, включая роботов.\n\nНа следующем уроке мы перейдём от механики к «мозгу» робота — микроконтроллерам и программированию.","quiz":[{"question":"Что такое шестерня?","options":["источник питания","диск с зубцами по краю","датчик расстояния","разновидность резистора"],"correctIndex":1},{"question":"Что происходит, если маленькая шестерня соединена с большой?","options":["обе вращаются с одинаковой скоростью","маленькая шестерня вращается быстрее, но с меньшей силой","большая шестерня вращается быстрее","скорость и сила не меняются"],"correctIndex":1},{"question":"Как называется соотношение размеров шестерён в передаче?","options":["коэффициент трения","передаточное отношение","крутящий момент","напряжение"],"correctIndex":1},{"question":"Какая передача позволяет сильно уменьшить скорость и увеличить силу, а также «запирает» механизм от обратного вращения?","options":["ремённая передача","зубчатая передача из одинаковых шестерён","червячная передача","световая передача"],"correctIndex":2},{"question":"Что иллюстрирует пример с переключением скоростей на велосипеде в гору?","options":["увеличение напряжения","уменьшение силы тока","изменение баланса между скоростью и силой","работу датчика"],"correctIndex":2},{"question":"Что перераспределяют механические передачи?","options":["электрический заряд","скорость и силу","свет и звук","память контроллера"],"correctIndex":1},{"question":"Какой механизм используется в манипуляторе LEGO Technic для подъёма небольших грузов?","options":["датчик света","шестерни","микрофон","аккумулятор"],"correctIndex":1},{"question":"Если передача увеличивает силу в два раза, что произойдёт со скоростью?","options":["увеличится в два раза","останется прежней","уменьшится в два раза","станет равна нулю"],"correctIndex":2}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-14T08:30:00+05:00","ends_at":"2026-07-14T09:15:00+05:00","room":"204"},{"topic":"Микроконтроллеры и основы программы для робота","objective":"Объяснить ученикам, как устроен микроконтроллер и что такое программа, алгоритм и код на примере простых команд для робота.","theory":"Мы уже знаем, что контроллер — это «мозг» робота. Но что находится «внутри» этого мозга и как он понимает, что делать? Ответ — микроконтроллер и программа.\n\nМикроконтроллер — это крошечная микросхема, объединяющая в себе процессор (вычисляет), память (хранит программу и данные) и порты ввода-вывода (подключаются к датчикам и моторам). В отличие от обычного компьютера, микроконтроллер спроектирован для выполнения одной конкретной программы много раз подряд, очень быстро и с низким энергопотреблением. Поэтому микроконтроллеры используют в роботах, бытовой технике, автомобилях и даже в зубных щётках.\n\nПрограмма — это последовательность команд, записанная на понятном компьютеру языке, которая указывает микроконтроллеру, что и в каком порядке делать. Прежде чем написать программу, инженер продумывает алгоритм — чёткую пошаговую инструкцию для решения задачи, ещё до написания кода.\n\nНапример, алгоритм для робота, который должен объехать препятствие, можно описать так: 1) двигаться вперёд; 2) если датчик обнаружил препятствие — остановиться; 3) повернуть направо; 4) снова двигаться вперёд. Этот алгоритм содержит условие («если») — программа проверяет ситуацию и выбирает разные действия в зависимости от результата.\n\nДля программирования микроконтроллеров чаще всего используют язык C/C++ (например, в среде Arduino IDE) или визуальные блочные языки, такие как Scratch или Blockly, где команды представлены в виде разноцветных блоков, соединяющихся друг с другом, как пазл. Блочное программирование удобно для начинающих, потому что не нужно запоминать точный синтаксис — достаточно понимать логику.\n\nЛюбая программа состоит из базовых строительных блоков: последовательность (команды выполняются одна за другой), условие («если... то...») и цикл (повторение действия несколько раз). Эти три конструкции — фундамент любой программы, будь то программа для робота, компьютерная игра или мобильное приложение.\n\nВажно понимать, что микроконтроллер выполняет программу буквально — ровно так, как она написана, без «здравого смысла». Если в алгоритме ошибка (например, забыли условие остановки), робот будет действовать неправильно или бесконечно повторять одно и то же действие.\n\nНа следующем уроке мы подробно разберём, как строить алгоритмы с циклами и условиями, и потренируемся программировать робота, который проходит лабиринт.","quiz":[{"question":"Что такое микроконтроллер?","options":["датчик расстояния","крошечная микросхема с процессором, памятью и портами ввода-вывода","разновидность мотора","источник питания"],"correctIndex":1},{"question":"Что нужно продумать инженеру перед написанием кода программы?","options":["цвет корпуса робота","алгоритм — пошаговую инструкцию решения задачи","стоимость батарейки","размер шестерни"],"correctIndex":1},{"question":"Какая языковая среда чаще всего используется для программирования Arduino?","options":["Photoshop","Arduino IDE (язык C/C++)","Excel","PowerPoint"],"correctIndex":1},{"question":"Что представляют собой блоки в визуальном языке программирования, например Blockly?","options":["физические компоненты робота","разноцветные элементы кода, соединяемые как пазл","типы батареек","виды шестерён"],"correctIndex":1},{"question":"Какая из трёх базовых конструкций программы отвечает за повторение действий?","options":["последовательность","условие","цикл","переменная"],"correctIndex":2},{"question":"Что означает конструкция «если... то...» в программе?","options":["последовательность действий","условие — выбор действия в зависимости от ситуации","цикл повторения","отключение питания"],"correctIndex":1},{"question":"Почему важно, чтобы алгоритм был написан без ошибок?","options":["потому что микроконтроллер выполняет программу буквально, без «здравого смысла»","потому что иначе батарейка сядет быстрее","потому что иначе увеличится напряжение","потому что иначе шестерни сломаются"],"correctIndex":0},{"question":"Что из перечисленного является примером условия в алгоритме объезда препятствия?","options":["«двигаться вперёд»","«если датчик обнаружил препятствие — остановиться»","«повторять 10 раз»","«включить батарейку»"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-15T10:20:00+05:00","ends_at":"2026-07-15T11:05:00+05:00","room":"204"},{"topic":"Алгоритмы движения: циклы и условия для робота","objective":"Научить учеников составлять алгоритмы движения робота с использованием циклов и условных операторов и применить их на практике.","theory":"На прошлом уроке мы узнали, что любая программа строится из трёх базовых конструкций: последовательности, условия и цикла. Сегодня разберём циклы и условия подробнее — именно они позволяют роботу вести себя «умно» и адаптироваться к разным ситуациям, а не просто слепо повторять одну и ту же команду.\n\nЦикл — это конструкция, которая повторяет один и тот же блок команд несколько раз, пока выполняется определённое условие, либо заданное количество раз. Есть два основных типа циклов. Первый — цикл с фиксированным числом повторений («повторить 4 раза»). Например, чтобы робот проехал квадратный маршрут: повторить 4 раза { проехать вперёд на 1 метр; повернуть на 90 градусов }. Это делает программу короче и понятнее.\n\nВторой тип — цикл с условием («повторять, пока...»). Например: «повторять, пока датчик расстояния не покажет меньше 10 см { двигаться вперёд }». Такой цикл продолжается до тех пор, пока не наступит нужное условие. Это полезно, когда заранее неизвестно, сколько шагов потребуется.\n\nУсловный оператор («если... то... иначе...») позволяет роботу выбирать разные действия в зависимости от ситуации. Например: «если датчик света показывает темноту, то включить фары, иначе — выключить фары». Условия можно комбинировать с логическими операторами «И» и «ИЛИ»: «если обнаружено препятствие СПРАВА И СЛЕВА, то развернуться на 180 градусов».\n\nЧасто циклы и условия используют вместе — это называется вложенными конструкциями. Классический пример — алгоритм объезда препятствий: «повторять всегда { если препятствие обнаружено — повернуть направо; иначе — двигаться вперёд }». Здесь бесконечный цикл содержит внутри себя условие, которое на каждом «шаге» проверяет обстановку и выбирает действие.\n\nПри составлении алгоритмов важно избегать типичных ошибок: «бесконечный цикл без выхода» (когда условие для остановки никогда не выполняется, и робот «зависает») и «неверный порядок условий» (когда важное условие проверяется слишком поздно, и робот успевает столкнуться с препятствием). Хороший алгоритм всегда продуман заранее, шаг за шагом, ещё до того, как написан код.\n\nСегодня на практике мы потренируемся строить такие алгоритмы в игровом визуальном редакторе Blockly Games, где нужно провести персонажа через лабиринт, используя ровно те же самые конструкции, которые применяются при программировании настоящих роботов.","quiz":[{"question":"Какая конструкция позволяет повторять один и тот же блок команд несколько раз?","options":["условие","цикл","переменная","последовательность"],"correctIndex":1},{"question":"Какой тип цикла используется, если заранее известно точное количество повторений?","options":["цикл с условием","цикл с фиксированным числом повторений","бесконечный цикл","условный оператор"],"correctIndex":1},{"question":"Когда удобнее использовать цикл «повторять, пока...»?","options":["когда заранее известно точное число шагов","когда число шагов заранее неизвестно и зависит от условия","когда не нужны датчики","когда программа не содержит команд"],"correctIndex":1},{"question":"Что делает условный оператор «если... то... иначе...»?","options":["повторяет действие много раз","выбирает разное действие в зависимости от ситуации","отключает питание робота","увеличивает напряжение"],"correctIndex":1},{"question":"Какие логические операторы можно использовать для комбинирования условий?","options":["«плюс» и «минус»","«И» и «ИЛИ»","«больше» и «меньше»","«старт» и «стоп»"],"correctIndex":1},{"question":"Что называется вложенной конструкцией?","options":["цикл или условие внутри другого цикла или условия","отдельная программа без циклов","батарейка внутри робота","датчик внутри мотора"],"correctIndex":0},{"question":"Какая ошибка приводит к тому, что робот «зависает» и не может остановиться?","options":["слишком короткая программа","бесконечный цикл без выхода","слишком много датчиков","маленькая шестерня"],"correctIndex":1},{"question":"Что нужно сделать до того, как писать код программы?","options":["сразу подключить моторы","продумать алгоритм шаг за шагом","купить новую батарейку","отключить контроллер"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"blockly_games","externalServiceTask":"В игре Blockly Games (раздел «Лабиринт») составьте программу для персонажа, используя циклы повторения и условные операторы «если», чтобы пройти лабиринт минимальным числом блоков.","starts_at":"2026-07-17T09:25:00+05:00","ends_at":"2026-07-17T10:10:00+05:00","room":"204"},{"topic":"Датчики робота: расстояние, свет и касание","objective":"Углубить знания учеников о принципе работы конкретных датчиков и научить выбирать подходящий датчик под задачу.","theory":"На втором уроке мы узнали, что сенсоры — это «органы чувств» робота. Сегодня подробно разберём, как устроены и работают три самых распространённых датчика в образовательной робототехнике: ультразвуковой датчик расстояния, датчик света и датчик касания (кнопка).\n\nУльтразвуковой датчик расстояния измеряет, как далеко находится препятствие, с помощью звука, который человек не слышит (ультразвука), — частота такого звука выше 20 000 Гц. Датчик состоит из излучателя, который посылает короткий ультразвуковой сигнал, и приёмника, который «слушает» эхо — отражённый от препятствия сигнал. Датчик измеряет время между отправкой сигнала и приёмом эха и, зная скорость звука в воздухе (около 343 метров в секунду), вычисляет расстояние до препятствия. Это тот же принцип, которым пользуются летучие мыши и дельфины — эхолокация. Такие датчики используют, чтобы робот останавливался перед стеной или объезжал препятствия.\n\nДатчик света (фоторезистор) измеряет уровень освещённости. Внутри у него специальный материал, электрическое сопротивление которого меняется в зависимости от количества падающего света: чем ярче свет, тем меньше сопротивление, и наоборот. Микроконтроллер считывает это изменение и переводит его в числовое значение уровня освещённости. Такие датчики используются в уличных фонарях, которые автоматически включаются в темноте, или в роботах, которые следуют по светлой или тёмной линии на полу.\n\nДатчик касания (кнопка) — самый простой датчик: он либо замкнут (нажат), либо разомкнут (не нажат), и может передать контроллеру только два состояния — «да» или «нет». Несмотря на простоту, такие датчики очень надёжны и часто используются как «датчики столкновения» на бампере робота.\n\nВыбор датчика зависит от задачи. Если роботу нужно объезжать препятствия на расстоянии — используют ультразвуковой датчик. Если робот должен следовать по линии или реагировать на освещённость — используют датчик света. Если нужно просто обнаружить факт столкновения — достаточно простого датчика касания. Инженеры-робототехники часто комбинируют несколько типов датчиков одновременно, чтобы робот получал более полную картину окружающего мира, — это называется «сенсорное слияние». Например, робот-пылесос использует одновременно датчики касания, датчики расстояния и датчики падения.\n\nНа следующем уроке мы изучим вторую половину цикла «воспринимай-думай-действуй» — моторы, которые заставляют робота двигаться.","quiz":[{"question":"Как работает ультразвуковой датчик расстояния?","options":["измеряет уровень освещённости","посылает ультразвуковой сигнал и измеряет время до приёма эха","определяет цвет поверхности","измеряет температуру воздуха"],"correctIndex":1},{"question":"Какое явление в природе похоже на принцип работы ультразвукового датчика?","options":["фотосинтез","эхолокация летучих мышей","магнетизм","испарение воды"],"correctIndex":1},{"question":"Что происходит с сопротивлением фоторезистора при увеличении яркости света?","options":["сопротивление увеличивается","сопротивление уменьшается","сопротивление не меняется","датчик перестаёт работать"],"correctIndex":1},{"question":"Где часто применяют датчики света?","options":["в кнопках включения","в уличных фонарях с автоматическим включением в темноте","в резисторах","в шестернях"],"correctIndex":1},{"question":"Сколько состояний может передать простой датчик касания (кнопка)?","options":["одно","два («нажат» / «не нажат»)","десять","бесконечное количество"],"correctIndex":1},{"question":"Где обычно располагают датчики касания на роботе?","options":["внутри контроллера","на бампере робота для обнаружения столкновений","в батарейном отсеке","в резисторе"],"correctIndex":1},{"question":"Какой датчик лучше всего подходит для робота, который должен двигаться по светлой линии на полу?","options":["датчик касания","ультразвуковой датчик","датчик света","датчик температуры"],"correctIndex":2},{"question":"Что называется «сенсорным слиянием» (sensor fusion)?","options":["использование только одного датчика","объединение показаний нескольких датчиков для более полной картины мира","отключение всех датчиков","замена датчика мотором"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-21T08:30:00+05:00","ends_at":"2026-07-21T09:15:00+05:00","room":"204"},{"topic":"Моторы робота: управление скоростью и направлением","objective":"Объяснить ученикам принцип работы электромоторов постоянного тока и способы управления их скоростью и направлением вращения.","theory":"Мотор — важнейший актуатор робота, который превращает электрическую энергию в механическое движение — вращение вала. Сегодня разберём, как устроен простейший электромотор постоянного тока (DC-мотор) и как контроллер управляет его скоростью и направлением.\n\nВнутри DC-мотора находится постоянный магнит (статор, неподвижная часть) и электромагнит (ротор, вращающаяся часть, обмотка провода). Когда через обмотку ротора пропускают электрический ток, вокруг неё возникает магнитное поле. Взаимодействие этого поля с полем постоянного магнита создаёт силу, которая заставляет ротор вращаться. Это явление называется электромагнитной индукцией — на нём основана работа практически всех электромоторов в мире.\n\nНаправление вращения мотора зависит от направления тока: если поменять полярность (плюс и минус местами), мотор начнёт вращаться в обратную сторону. В робототехнике для этого используют специальную микросхему — драйвер мотора (например, H-мост), которая позволяет контроллеру быстро и безопасно менять направление тока, а значит, и направление вращения колёс робота — вперёд или назад.\n\nСкорость вращения мотора управляется особым способом подачи напряжения — широтно-импульсной модуляцией (ШИМ, англ. PWM). Суть метода в следующем: вместо постоянного напряжения контроллер очень быстро включает и выключает питание — сотни или тысячи раз в секунду. Если питание включено 100% времени — мотор вращается на полной скорости. Если включено только 50% времени — мотор в среднем получает вдвое меньше энергии и вращается вдвое медленнее. Меняя это соотношение (duty cycle), можно плавно регулировать скорость от нуля до максимума.\n\nПомимо DC-моторов, в робототехнике часто используют сервоприводы — моторы со встроенной электроникой, которые могут повернуться на точный заданный угол и удерживать эту позицию, в отличие от обычного мотора, который просто крутится непрерывно. Сервоприводы применяют там, где нужна точность — например, для поворота «руки» робота-манипулятора. Ещё один вид — шаговые моторы, которые вращаются небольшими точными «шагами» и используются, например, в 3D-принтерах.\n\nЧтобы робот ехал по прямой, оба колёсных мотора должны вращаться с одинаковой скоростью. Чтобы робот повернул — моторы должны вращаться с разной скоростью, а чтобы развернуться на месте — моторы должны вращаться в противоположных направлениях одновременно.\n\nНа следующем, финальном уроке мы объединим всё изученное — электронику, механику, датчики, моторы и программирование — и соберём собственного автономного робота, объезжающего препятствия.","quiz":[{"question":"Что превращает электромотор постоянного тока?","options":["свет в звук","электрическую энергию в механическое вращение","механическое движение в электричество","тепло в свет"],"correctIndex":1},{"question":"Как называется явление, на котором основана работа электромотора?","options":["эхолокация","электромагнитная индукция","фотосинтез","гравитация"],"correctIndex":1},{"question":"Что нужно сделать, чтобы мотор начал вращаться в обратную сторону?","options":["увеличить напряжение","поменять полярность (направление тока)","уменьшить сопротивление","добавить датчик"],"correctIndex":1},{"question":"Какая микросхема позволяет контроллеру безопасно менять направление вращения мотора?","options":["резистор","фоторезистор","драйвер мотора (H-мост)","светодиод"],"correctIndex":2},{"question":"Как называется способ управления скоростью мотора путём быстрого включения и выключения питания?","options":["широтно-импульсная модуляция (ШИМ / PWM)","эхолокация","передаточное отношение","сенсорное слияние"],"correctIndex":0},{"question":"Если коэффициент заполнения (duty cycle) составляет 50%, как будет вращаться мотор по сравнению с полной скоростью?","options":["с той же скоростью","примерно вдвое медленнее","вдвое быстрее","вообще не будет вращаться"],"correctIndex":1},{"question":"Чем сервопривод отличается от обычного DC-мотора?","options":["не потребляет энергию","может повернуться на точный заданный угол и удерживать позицию","работает только от солнечной батареи","используется только как датчик"],"correctIndex":1},{"question":"Что должно произойти с моторами, чтобы робот развернулся на месте?","options":["оба мотора останавливаются","оба мотора вращаются с одинаковой скоростью в одном направлении","моторы вращаются в противоположных направлениях одновременно","отключается один из моторов"],"correctIndex":2}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-22T10:20:00+05:00","ends_at":"2026-07-22T11:05:00+05:00","room":"204"},{"topic":"Проект: автономный робот, объезжающий препятствия","objective":"Объединить знания о механике, электронике, датчиках, моторах и программировании для проектирования алгоритма и схемы автономного робота, объезжающего препятствия.","theory":"На предыдущих восьми уроках мы изучили все составляющие робота по отдельности: что такое робот и его базовый цикл работы, три ключевых компонента (сенсоры, контроллер, актуаторы), электрические цепи, механические передачи, микроконтроллеры и алгоритмы с циклами и условиями, датчики расстояния/света/касания и, наконец, моторы и управление ими. Сегодня мы соберём все эти знания в единый проект — автономного робота, который самостоятельно, без пульта управления, ездит по комнате и объезжает препятствия.\n\nАвтономный робот — это робот, который принимает решения самостоятельно, на основе данных от собственных датчиков, без постоянного управления человеком (в отличие от робота на радиоуправлении). Проектирование такого робота — классическая инженерная задача, которую удобно разбить на четыре этапа.\n\nЭтап 1 — механика. Нужно продумать, как будет устроен корпус: шасси (основа, на которую крепятся остальные детали), два колеса с моторами по бокам и одно опорное колесо спереди или сзади для устойчивости (такая схема называется «дифференциальный привод»).\n\nЭтап 2 — электроника. Нужно собрать схему: контроллер (например, Arduino), подключённый к драйверу моторов (H-мост), который, в свою очередь, подключён к двум DC-моторам; источник питания (батарейный отсек); ультразвуковой датчик расстояния, подключённый к контроллеру для «зрения» робота. Важно не перепутать полярность подключения и правильно рассчитать резисторы там, где это нужно.\n\nЭтап 3 — алгоритм. На основе знаний о циклах и условиях с урока 6 составляем алгоритм поведения: «повторять всегда { измерить расстояние до препятствия датчиком; если расстояние меньше 15 см — остановиться, повернуть направо на случайный угол; иначе — двигаться вперёд }». Этот несложный алгоритм уже позволяет роботу вести себя достаточно «разумно».\n\nЭтап 4 — тестирование и улучшение. После первой версии инженеры почти никогда не останавливаются: они тестируют робота, находят слабые места (например, робот застревает в углу, если справа и слева одновременно есть препятствия) и улучшают алгоритм (например, добавляют правило: «если препятствие со всех сторон — развернуться на 180 градусов»). Этот процесс называется итеративной разработкой.\n\nЭтот подход — деление сложной задачи на механику, электронику, алгоритм и тестирование — используют настоящие инженеры-робототехники во всём мире, от студенческих проектов до марсоходов NASA. Сегодня на практике мы соберём электронную схему нашего автономного робота (контроллер, ультразвуковой датчик, драйвер моторов) в виртуальном симуляторе Wokwi и проверим на модели, что схема собрана правильно и способна считывать расстояние до препятствия.","quiz":[{"question":"Чем автономный робот отличается от робота на радиоуправлении?","options":["у него нет моторов","он принимает решения самостоятельно на основе датчиков, без человека у пульта","он не использует электричество","он всегда движется по прямой"],"correctIndex":1},{"question":"Как называется схема с двумя приводными колёсами по бокам и опорным колесом?","options":["последовательное соединение","дифференциальный привод","передаточное отношение","сенсорное слияние"],"correctIndex":1},{"question":"Какие четыре этапа проектирования робота были рассмотрены на уроке?","options":["механика, электроника, алгоритм, тестирование и улучшение","только программирование и тестирование","только механика и электроника","дизайн, маркетинг, продажа, поддержка"],"correctIndex":0},{"question":"Какой компонент соединяет контроллер и моторы, позволяя менять направление и скорость вращения?","options":["резистор","драйвер моторов (H-мост)","фоторезистор","кнопка"],"correctIndex":1},{"question":"Что делает алгоритм робота, если расстояние до препятствия меньше 15 см?","options":["увеличивает скорость","останавливается и поворачивает направо","выключает датчик","ничего не делает"],"correctIndex":1},{"question":"Как называется процесс постоянного повторения цикла «спроектировал — собрал — протестировал — улучшил»?","options":["эхолокация","итеративная разработка","электромагнитная индукция","широтно-импульсная модуляция"],"correctIndex":1},{"question":"Что стоит сделать, если робот застревает в углу, когда препятствия есть и справа, и слева?","options":["ничего не менять","добавить в алгоритм правило разворота на 180 градусов","отключить датчик расстояния","уменьшить напряжение батарейки"],"correctIndex":1},{"question":"Какой инструмент используется на этом уроке для практической сборки электронной схемы автономного робота?","options":["Blockly Games","Wokwi","Photoshop","Excel"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"wokwi","externalServiceTask":"В Wokwi соберите схему автономного робота: Arduino, ультразвуковой датчик HC-SR04 и драйвер моторов (например, L298N), подключённый к двум DC-моторам. Проверьте, что датчик корректно считывает расстояние в симуляторе.","starts_at":"2026-07-24T09:25:00+05:00","ends_at":"2026-07-24T10:10:00+05:00","room":"204"}]'::jsonb)
    LOOP
      INSERT INTO public.lessons (group_id, subject_id, topic, title, description, status, starts_at, ends_at, started_at, ended_at, room, school_id)
      VALUES (
        v_group_id, v_subject_id, lesson_data->>'topic', lesson_data->>'topic', lesson_data->>'objective',
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN 'completed' ELSE 'scheduled' END,
        (lesson_data->>'starts_at')::timestamptz, (lesson_data->>'ends_at')::timestamptz,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'starts_at')::timestamptz ELSE NULL END,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'ends_at')::timestamptz ELSE NULL END,
        lesson_data->>'room', v_school_id
      )
      RETURNING id INTO v_lesson_id;

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, duration_min, school_id)
      VALUES (v_lesson_id, 1, 'middle', 'theory', 'presentation', lesson_data->>'topic', lesson_data->>'theory', 15, v_school_id);

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, duration_min, school_id)
      VALUES (v_lesson_id, 2, 'middle', 'task', 'quiz_qia', 'Проверь себя', 15, v_school_id)
      RETURNING id INTO v_stage_id;

      qpos := 0;
      FOR quiz_item IN SELECT * FROM jsonb_array_elements(lesson_data->'quiz')
      LOOP
        qpos := qpos + 1;
        INSERT INTO public.quiz_questions (stage_id, question_text, options, correct_option_index, position, points, time_per_question_seconds, school_id)
        VALUES (v_stage_id, quiz_item->>'question', quiz_item->'options', (quiz_item->>'correctIndex')::int, qpos, 1, 30, v_school_id);
      END LOOP;

      IF (lesson_data->>'hasExternalService')::boolean THEN
        INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, config, duration_min, school_id)
        VALUES (
          v_lesson_id, 3, 'middle', 'task', lesson_data->>'externalServiceType',
          lesson_data->>'externalServiceTask', lesson_data->>'externalServiceTask',
          jsonb_build_object('url',
            CASE lesson_data->>'externalServiceType'
              WHEN 'wokwi' THEN 'https://wokwi.com/projects/new/arduino-uno'
              WHEN 'codesandbox' THEN 'https://codesandbox.io/p/sandbox/vanilla'
              WHEN 'geogebra' THEN 'https://www.geogebra.org/classic'
              WHEN 'phet' THEN 'https://phet.colorado.edu/sims/html/forces-and-motion-basics/latest/forces-and-motion-basics_en.html'
              WHEN 'desmos' THEN 'https://www.desmos.com/calculator'
              WHEN 'blockly_games' THEN 'https://blockly.games/'
              WHEN 'visualgo' THEN 'https://visualgo.net/en'
              WHEN 'p5js' THEN 'https://editor.p5js.org/'
              WHEN 'excalidraw' THEN 'https://excalidraw.com/'
              WHEN 'learningapps' THEN 'https://learningapps.org/'
              WHEN 'sqlonline' THEN 'https://sqlime.org/'
              WHEN 'h5p' THEN 'https://h5p.eduos.snruz.uz/library'
              ELSE NULL
            END
          ),
          15, v_school_id
        );
      END IF;
    END LOOP;
  END IF;

  -- === 7-А класс | Русский язык (11 уроков) ===
  SELECT id INTO v_group_id FROM public.groups WHERE name = '7-А класс';
  SELECT id INTO v_subject_id FROM public.subjects WHERE group_id = v_group_id AND name = 'Русский язык';
  IF NOT EXISTS (SELECT 1 FROM public.lessons WHERE group_id = v_group_id AND subject_id = v_subject_id AND description IS NOT NULL) THEN
    FOR lesson_data IN SELECT * FROM jsonb_array_elements('[{"topic":"Причастие как часть речи","objective":"Научиться распознавать причастия в тексте и понимать их двойственную грамматическую природу — признаки глагола и прилагательного.","theory":"Причастие — это особая форма глагола, которая обозначает признак предмета по действию и отвечает на вопросы какой? какая? какое? какие? Например: читающий мальчик (какой мальчик? — тот, который читает), прочитанная книга (какая книга? — та, которую прочитали).\n\nГлавная особенность причастия — двойственная природа: оно совмещает признаки глагола и признаки прилагательного.\n\nОт глагола причастие берёт: 1) вид — совершенный (прочитавший — что сделавший?) или несовершенный (читающий — что делающий?); 2) время — настоящее (пишущий, изучаемый) или прошедшее (написавший, изученный); будущего времени у причастий не бывает; 3) возвратность — наличие или отсутствие -ся (умывающийся — умывающий); 4) переходность — способность управлять существительным в винительном падеже без предлога.\n\nОт прилагательного причастие берёт: 1) изменение по родам (читающий, читающая, читающее); 2) изменение по числам (читающий — читающие); 3) изменение по падежам (читающего, читающему, читающим...); 4) наличие полной и краткой формы (только у страдательных причастий: прочитанная — прочитана); 5) синтаксическую роль — в предложении причастие чаще всего выступает определением (Мальчик, читающий книгу, сидел у окна) или именной частью сказуемого в краткой форме (Книга прочитана).\n\nОтличать причастие от прилагательного помогает вопрос «что делающий?/что сделавший?» вместо простого «какой?», а также возможность заменить причастие оборотом со словом «который»: читающий мальчик — мальчик, который читает.\n\nВ предложении причастие часто образует вместе с зависимыми словами причастный оборот, о котором мы подробно поговорим на следующем уроке.\n\nВажно запомнить: причастия образуются только от глаголов при помощи специальных суффиксов, и в дальнейшем каждому суффиксу мы посвятим отдельное правило.","quiz":[{"question":"Что обозначает причастие?","options":["признак предмета по действию","действие предмета","признак признака","количество предметов"],"correctIndex":0},{"question":"На какие вопросы отвечает причастие?","options":["кто? что?","какой? какая? какое? какие?","как? когда?","сколько?"],"correctIndex":1},{"question":"Какое время НЕ бывает у причастий?","options":["настоящее","прошедшее","будущее","ни одно, у причастий все времена есть"],"correctIndex":2},{"question":"Какой признак причастие берёт от прилагательного?","options":["вид","изменение по родам, числам и падежам","переходность","возвратность"],"correctIndex":1},{"question":"В каком примере причастие выступает определением?","options":["«Книга прочитана.»","«Мальчик, читающий книгу, сидел у окна.»","«Он читает книгу.»","«Читать книгу интересно.»"],"correctIndex":1},{"question":"Какая форма есть только у страдательных причастий?","options":["превосходная степень","краткая форма","звательная форма","форма множественного числа"],"correctIndex":1},{"question":"Каким способом можно проверить, что перед нами причастие, а не прилагательное?","options":["заменить оборотом со словом «который»","заменить синонимом-существительным","заменить наречием","заменить предлогом"],"correctIndex":0}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-07T09:25:00+05:00","ends_at":"2026-07-07T10:10:00+05:00","room":"204"},{"topic":"Действительные и страдательные причастия","objective":"Научиться различать действительные и страдательные причастия и определять, при помощи каких суффиксов они образуются.","theory":"На прошлом уроке мы узнали, что причастие совмещает признаки глагола и прилагательного. Теперь разберёмся, какие бывают причастия по значению.\n\nПричастия делятся на две группы: действительные и страдательные.\n\nДействительное причастие обозначает признак предмета, который сам производит действие. Например: пишущий ученик — ученик, который сам пишет; построивший дом рабочий — рабочий, который сам построил дом.\n\nСтрадательное причастие обозначает признак предмета, над которым действие совершает кто-то другой. Например: письмо, написанное учеником — письмо не само себя написало, его написал ученик; дом, построенный рабочими.\n\nЧтобы не путать эти два вида, можно задать вопрос: «предмет действует сам или действие направлено на предмет?»\n\nОбразуются действительные и страдательные причастия при помощи разных суффиксов, и суффикс зависит от времени и спряжения глагола.\n\nДействительные причастия настоящего времени образуются от основы глагола настоящего времени: у глаголов I спряжения — с суффиксами -ущ-/-ющ- (пишут → пишущий, читают → читающий), у глаголов II спряжения — с суффиксами -ащ-/-ящ- (дышат → дышащий, строят → строящий).\n\nДействительные причастия прошедшего времени образуются от основы инфинитива с суффиксами -вш- (если основа оканчивается на гласную: писать → писавший) или -ш- (если основа оканчивается на согласную: нести → нёсший).\n\nСтрадательные причастия настоящего времени образуются от основы глагола настоящего времени: у глаголов I спряжения — с суффиксом -ем- (читают → читаемый), у глаголов II спряжения — с суффиксом -им- (видят → видимый).\n\nСтрадательные причастия прошедшего времени образуются от основы инфинитива с суффиксами -нн- (прочитать → прочитанный), -енн- (построить → построенный) или -т- (открыть → открытый).\n\nВажно помнить: страдательные причастия образуются только от переходных глаголов (тех, которые могут иметь при себе прямое дополнение в винительном падеже без предлога), а действительные — и от переходных, и от непереходных.","quiz":[{"question":"Что обозначает действительное причастие?","options":["признак предмета, который сам производит действие","признак предмета, над которым совершают действие","количество действий","время действия"],"correctIndex":0},{"question":"Что обозначает страдательное причастие?","options":["признак предмета, который сам действует","признак предмета, над которым действие совершает кто-то другой","признак признака","последовательность действий"],"correctIndex":1},{"question":"Какое причастие в словосочетании «прочитанная книга»?","options":["действительное","страдательное","ни одно из вариантов не подходит","и то и другое одновременно"],"correctIndex":1},{"question":"Какой суффикс у действительных причастий настоящего времени I спряжения?","options":["-ущ-/-ющ-","-ащ-/-ящ-","-ем-/-ом-","-нн-"],"correctIndex":0},{"question":"От каких глаголов образуются страдательные причастия?","options":["только от непереходных","только от переходных","от любых глаголов без исключений","только от возвратных"],"correctIndex":1},{"question":"Каким суффиксом образовано причастие «построенный»?","options":["-вш-","-ущ-","-енн-","-ем-"],"correctIndex":2},{"question":"Найдите действительное причастие прошедшего времени.","options":["читаемый","написавший","построенный","открытый"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-08T11:15:00+05:00","ends_at":"2026-07-08T12:00:00+05:00","room":"204"},{"topic":"Причастный оборот и пунктуация","objective":"Научиться находить причастный оборот в предложении, определять определяемое слово и правильно расставлять знаки препинания.","theory":"Причастие редко употребляется в одиночку — чаще всего рядом с ним стоят зависимые слова, поясняющие, к чему или как относится действие. Причастие вместе с зависимыми словами образует причастный оборот.\n\nНапример: Ученик, решающий трудную задачу, поднял руку. Здесь причастный оборот — «решающий трудную задачу»: причастие «решающий» + зависимые слова «трудную задачу».\n\nСлово, к которому относится причастный оборот, называется определяемым словом. В нашем примере определяемое слово — «ученик».\n\nГлавное правило пунктуации: причастный оборот выделяется запятыми, если стоит после определяемого слова. Например: Тропинка, ведущая к реке, заросла травой. Если же причастный оборот стоит перед определяемым словом, запятыми он не выделяется: Ведущая к реке тропинка заросла травой.\n\nЕсть особый случай: если причастный оборот стоит перед определяемым словом, но имеет добавочное значение причины или уступки (можно заменить его придаточным предложением с союзами «так как» или «хотя»), он всё равно выделяется запятой. Например: Уставший от долгой дороги, путник наконец сел отдохнуть (= так как путник устал...).\n\nЧтобы найти причастный оборот в предложении, нужно: 1) найти причастие; 2) определить, есть ли у него зависимые слова; 3) найти определяемое слово, к которому относится весь оборот; 4) определить место оборота относительно определяемого слова (до или после); 5) расставить знаки препинания по правилу.\n\nПричастный оборот в предложении всегда является одним членом предложения — определением, хотя состоит из нескольких слов.\n\nВажно не путать причастный оборот с деепричастным — деепричастный оборот всегда обособляется запятыми независимо от места в предложении, а причастный — только после определяемого слова. Об этом различии мы подробно поговорим позже, когда будем изучать деепричастие.","quiz":[{"question":"Что такое причастный оборот?","options":["причастие с зависимыми словами","причастие с существительным в родительном падеже","два причастия подряд","причастие в краткой форме"],"correctIndex":0},{"question":"Как называется слово, к которому относится причастный оборот?","options":["зависимое слово","определяемое слово","главное слово предложения","подлежащее"],"correctIndex":1},{"question":"В каком случае причастный оборот выделяется запятыми?","options":["всегда, независимо от места","только если стоит после определяемого слова","только если стоит перед определяемым словом","никогда не выделяется"],"correctIndex":1},{"question":"В каком предложении причастный оборот оформлен верно?","options":["«Ведущая к реке, тропинка заросла травой.»","«Тропинка ведущая к реке заросла травой.»","«Тропинка, ведущая к реке, заросла травой.»","«Тропинка ведущая, к реке, заросла травой.»"],"correctIndex":2},{"question":"Когда причастный оборот перед определяемым словом всё же выделяется запятой?","options":["никогда не выделяется","если имеет добавочное значение причины или уступки","если оборот длинный","если в обороте есть страдательное причастие"],"correctIndex":1},{"question":"Каким членом предложения является причастный оборот целиком?","options":["сказуемым","обстоятельством","определением","дополнением"],"correctIndex":2}],"hasExternalService":true,"externalServiceType":"learningapps","externalServiceTask":"Выполни в LearningApps упражнение «Найди причастный оборот»: распредели предложения по группам — оборот выделяется запятыми / не выделяется.","starts_at":"2026-07-10T08:30:00+05:00","ends_at":"2026-07-10T09:15:00+05:00","room":"204"},{"topic":"Правописание Н и НН в причастиях","objective":"Научиться грамотно писать Н и НН в полных и кратких причастиях, опираясь на чёткий алгоритм проверки.","theory":"Одна из самых частых ошибок на письме — неправильный выбор Н или НН в причастиях. Разберём чёткие правила.\n\nВ полных причастиях пишется НН, если есть хотя бы одно из условий: 1) слово образовано от глагола совершенного вида (что сделать?): решённая (от решить) задача, купленная (от купить) книга; 2) у причастия есть зависимое слово: жаренная в масле картошка (зависимое слово «в масле»), крашенный вчера забор; 3) слово оканчивается на -ованный/-ёванный: маринованные грибы, асфальтированная дорога (искл.: кованый, жёваный — здесь -ов-/-ев- входит в корень, поэтому пишется одна Н); 4) есть приставка (кроме приставки не-): скошенная трава, испечённый пирог; но: некошеная трава (приставка не- не считается).\n\nЕсли ни одно из этих условий не выполняется — то есть слово образовано от глагола несовершенного вида, без приставки, без зависимых слов и не оканчивается на -ованный — перед нами отглагольное прилагательное, и пишется одна Н: крашеный забор, гружёная машина, жареная картошка, вязаный шарф.\n\nОтдельно нужно запомнить слова-исключения, которые всегда пишутся с НН, даже без приставки и зависимых слов: данный, желанный, священный, нежданный, негаданный, невиданный, неслыханный, медленный, деланный, чванный, чеканный, жеманный.\n\nИ слова-исключения с одной Н: раненый (но: израненный — с приставкой уже НН), назван, смышлёный.\n\nОсобое правило для КРАТКИХ причастий: в краткой форме причастия всегда пишется одна Н, независимо от вида глагола и наличия зависимых слов: задача решена, картина написана, книга прочитана. А вот в кратких отглагольных прилагательных сохраняется столько Н, сколько было в полной форме: воспитанная девочка → девочка воспитанна (умна, воспитанна).\n\nАлгоритм для проверки: 1. Определи часть речи — причастие или прилагательное. 2. Полная форма или краткая? 3. Если краткое причастие — всегда Н. 4. Если полная форма — проверяем: приставка, зависимое слово, вид глагола, суффикс -ованн-/-еванн-. Если хоть одно условие есть — НН, если нет ни одного — Н.","quiz":[{"question":"Когда в полном причастии пишется НН?","options":["если слово образовано от глагола несовершенного вида без приставки","если есть зависимое слово, приставка (кроме не-) или слово от глагола совершенного вида","только в женском роде","только во множественном числе"],"correctIndex":1},{"question":"Как пишется краткое причастие?","options":["всегда с НН","всегда с одной Н","по общим правилам полных причастий","зависит от рода"],"correctIndex":1},{"question":"В каком слове пишется НН?","options":["кошеный","жареный","асфальтированная (дорога)","вязаный"],"correctIndex":2},{"question":"Найдите слово-исключение, которое пишется с НН без приставки и зависимых слов.","options":["раненый","смышлёный","желанный","названый (брат)"],"correctIndex":2},{"question":"Почему в слове «испечённый» пишется НН?","options":["потому что есть приставка","потому что краткая форма","потому что это прилагательное","потому что заканчивается на -ованный"],"correctIndex":0},{"question":"В каком примере пишется одна Н, потому что нет ни одного условия для НН?","options":["скошенная трава","испечённый пирог","жареная картошка","маринованные огурцы"],"correctIndex":2},{"question":"«Задача решена» — сколько Н нужно писать и почему?","options":["НН, потому что от совершенного вида","Н, потому что это краткая форма причастия","НН, потому что есть зависимое слово","Н, потому что это прилагательное"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-13T08:30:00+05:00","ends_at":"2026-07-13T09:15:00+05:00","room":"204"},{"topic":"Правописание НЕ с причастиями","objective":"Научиться правильно писать НЕ с причастиями слитно и раздельно в зависимости от наличия зависимых слов, противопоставления и формы причастия.","theory":"Правописание НЕ с причастиями похоже на правило написания НЕ с прилагательными, но имеет свои особенности, которые нужно чётко запомнить.\n\nНЕ с причастием пишется СЛИТНО, если: 1) причастие не употребляется без НЕ: негодующий взгляд (слова «годующий» не существует); 2) у полного причастия нет зависимых слов и нет противопоставления с союзом а: невыполненное задание, непрочитанная книга.\n\nНЕ с причастием пишется РАЗДЕЛЬНО, если: 1) у причастия есть зависимые слова: не выполненное вовремя задание, не прочитанная мной книга; 2) есть противопоставление с союзом а: не выполненное, а забытое задание; 3) причастие стоит в краткой форме: задание не выполнено, книга не прочитана — краткие причастия с НЕ пишутся раздельно всегда; 4) есть слова, усиливающие отрицание: далеко не, вовсе не, отнюдь не: отнюдь не выполненное задание.\n\nСравним для наглядности: Невыполненное задание лежало на столе (нет зависимых слов — слитно). Не выполненное в срок задание лежало на столе (есть зависимое слово «в срок» — раздельно). Задание не выполнено (краткая форма — раздельно). Задание не выполнено, а забыто (противопоставление — раздельно).\n\nВажно не путать причастие с отглагольным прилагательным в подобных случаях — принцип похож, но именно наличие зависимых слов у причастия — самый частый сигнал для раздельного написания, и на это нужно обращать особое внимание, потому что в предложениях с причастным оборотом зависимые слова почти всегда есть.\n\nАлгоритм проверки: 1. Есть ли слово без НЕ? Если нет — слитно. 2. Есть ли зависимые слова у причастия? Если да — раздельно. 3. Есть ли противопоставление с а? Если да — раздельно. 4. Краткая форма? Если да — раздельно. 5. Если ничего из этого нет — слитно.","quiz":[{"question":"Когда НЕ с причастием пишется слитно?","options":["если есть зависимые слова","если причастие в краткой форме","если нет зависимых слов, противопоставления и слово не употребляется без не","если есть слово «вовсе»"],"correctIndex":2},{"question":"Как пишется НЕ с краткими причастиями?","options":["слитно","раздельно всегда","по разным правилам, зависит от смысла","через дефис"],"correctIndex":1},{"question":"Найдите слово, где НЕ пишется раздельно.","options":["негодующий","непрочитанная (книга)","не прочитанная мной (книга)","нерешённая"],"correctIndex":2},{"question":"Почему «не выполненное в срок задание» пишется раздельно?","options":["потому что краткая форма","потому что есть зависимое слово «в срок»","потому что причастие не употребляется без не","потому что стоит в начале предложения"],"correctIndex":1},{"question":"Какое слово усиливает отрицание и требует раздельного написания?","options":["очень","вовсе не","уже","почти"],"correctIndex":1},{"question":"«Задание не выполнено, а забыто» — почему раздельно?","options":["краткая форма и противопоставление с а","слитно, а не раздельно","потому что нет зависимых слов","потому что действительное причастие"],"correctIndex":0}],"hasExternalService":true,"externalServiceType":"h5p","externalServiceTask":"Выполни в H5P упражнение «Заполни пропуски»: вставь НЕ слитно или раздельно с причастиями в предложениях.","starts_at":"2026-07-14T09:25:00+05:00","ends_at":"2026-07-14T10:10:00+05:00","room":"204"},{"topic":"Деепричастие как часть речи","objective":"Научиться распознавать деепричастия, понимать их грамматические признаки и отличать их от причастий.","theory":"Мы подробно изучили причастие — особую форму глагола с признаками прилагательного. Теперь познакомимся с ещё одной особой формой глагола — деепричастием.\n\nДеепричастие обозначает добавочное действие при основном действии, которое выражено глаголом-сказуемым, и отвечает на вопросы что делая? что сделав?\n\nНапример: Мальчик, читая книгу, улыбался. Здесь основное действие — «улыбался» (сказуемое), а добавочное — «читая» (деепричастие): мальчик одновременно и читал, и улыбался, но грамматически главное действие одно.\n\nДеепричастие, как и причастие, совмещает признаки двух частей речи, но в этот раз — признаки глагола и наречия.\n\nОт глагола деепричастие берёт: 1) вид — совершенный (что сделав? — прочитав, написав) или несовершенный (что делая? — читая, пиша); 2) возвратность (умываясь — умывая); 3) переходность (управляет теми же падежами, что и глагол, от которого образовано); 4) способность иметь при себе зависимые слова.\n\nОт наречия деепричастие берёт неизменяемость: деепричастие не изменяется ни по родам, ни по числам, ни по падежам — в отличие от причастия. Сравните: причастие «читающий, читающая, читающих» — изменяется; деепричастие «читая» — форма всегда одна и та же.\n\nВ предложении деепричастие является обстоятельством и обычно поясняет, как, когда, почему происходит основное действие.\n\nДеепричастия несовершенного вида образуются от основы глагола настоящего времени при помощи суффиксов -а/-я: читают → читая, кричат → крича, смеются → смеясь.\n\nДеепричастия совершенного вида образуются от основы инфинитива (или прошедшего времени) при помощи суффиксов -в, -вши, -ши: прочитать → прочитав, улыбнуться → улыбнувшись, испечь → испёкши.\n\nВажно не путать деепричастие с причастием: причастие отвечает на вопрос «какой?» и обозначает признак предмета, а деепричастие отвечает на вопрос «что делая? что сделав?» и обозначает добавочное действие. Причастие изменяется, деепричастие — нет.","quiz":[{"question":"Что обозначает деепричастие?","options":["признак предмета","добавочное действие при основном действии","количество предметов","признак признака"],"correctIndex":1},{"question":"На какие вопросы отвечает деепричастие?","options":["какой? какая?","кто? что?","что делая? что сделав?","сколько?"],"correctIndex":2},{"question":"Какой признак деепричастие берёт от наречия?","options":["вид","неизменяемость","переходность","возвратность"],"correctIndex":1},{"question":"Каким членом предложения является деепричастие?","options":["определением","сказуемым","обстоятельством","дополнением"],"correctIndex":2},{"question":"С помощью каких суффиксов образуются деепричастия несовершенного вида?","options":["-в, -вши","-а, -я","-ущ, -ющ","-нн, -енн"],"correctIndex":1},{"question":"Найдите деепричастие совершенного вида.","options":["читая","смеясь","прочитав","крича"],"correctIndex":2},{"question":"Чем деепричастие отличается от причастия?","options":["деепричастие изменяется по родам, причастие нет","деепричастие неизменяемо и обозначает добавочное действие, причастие изменяется и обозначает признак предмета","деепричастие всегда в краткой форме","деепричастие не образуется от глаголов"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-15T11:15:00+05:00","ends_at":"2026-07-15T12:00:00+05:00","room":"204"},{"topic":"Деепричастный оборот и пунктуация","objective":"Научиться находить деепричастный оборот в предложении и правильно обособлять его запятыми независимо от места в предложении.","theory":"Деепричастие, как и причастие, часто употребляется с зависимыми словами. Деепричастие вместе с зависимыми словами образует деепричастный оборот.\n\nНапример: Мальчик, читая интересную книгу, забыл обо всём на свете. Деепричастный оборот здесь — «читая интересную книгу».\n\nГлавное правило пунктуации, которое нужно запомнить твёрдо: деепричастный оборот ВСЕГДА выделяется запятыми, независимо от того, где он стоит — до, после или в середине основного действия.\n\nСравните с причастным оборотом, где запятые ставятся только при определённых условиях (после определяемого слова). С деепричастным оборотом такой зависимости от места нет: Читая книгу, мальчик забыл обо всём на свете (в начале). Мальчик, читая книгу, забыл обо всём на свете (в середине). Мальчик забыл обо всём на свете, читая книгу (в конце). Во всех трёх случаях оборот выделяется запятыми.\n\nОдиночное деепричастие (без зависимых слов) тоже обособляется запятыми: Улыбаясь, мальчик поздоровался с друзьями.\n\nИсключение: если деепричастие превратилось в устойчивое выражение (фразеологизм) и утратило значение добавочного действия, запятые не ставятся: работать спустя рукава, бежать сломя голову, слушать затаив дыхание.\n\nЧтобы найти деепричастный оборот в предложении: 1) найди слово, отвечающее на вопрос «что делая?» или «что сделав?»; 2) проверь, есть ли у него зависимые слова — если да, это оборот целиком; 3) убедись, что это не фразеологизм; 4) выдели весь оборот запятыми с обеих сторон (если он не в начале или конце предложения — тогда запятая ставится с одной стороны).\n\nВажно помнить: деепричастие и деепричастный оборот обозначают действие того же лица (предмета), что и глагол-сказуемое. Нельзя сказать «Подходя к дому, у меня зазвонил телефон» — это грамматическая ошибка, потому что подходит «я», а телефон звонит сам.","quiz":[{"question":"Что такое деепричастный оборот?","options":["деепричастие с зависимыми словами","причастие с зависимыми словами","деепричастие в краткой форме","два деепричастия подряд"],"correctIndex":0},{"question":"Когда деепричастный оборот выделяется запятыми?","options":["только после сказуемого","только в начале предложения","всегда, независимо от места в предложении","только если нет зависимых слов"],"correctIndex":2},{"question":"Нужно ли обособлять одиночное деепричастие?","options":["нет, никогда","да, как и деепричастный оборот","только в конце предложения","только в начале предложения"],"correctIndex":1},{"question":"В каком случае деепричастие НЕ обособляется запятыми?","options":["если оно в начале предложения","если стало фразеологизмом (бежать сломя голову)","если оно совершенного вида","если у него есть зависимые слова"],"correctIndex":1},{"question":"Найдите предложение с грамматической ошибкой в употреблении деепричастия.","options":["«Читая книгу, мальчик улыбался.»","«Подходя к дому, у меня зазвонил телефон.»","«Улыбаясь, мальчик поздоровался.»","«Закрыв дверь, я вышел на улицу.»"],"correctIndex":1},{"question":"Чем деепричастный оборот принципиально отличается от причастного в пунктуации?","options":["деепричастный никогда не выделяется запятыми","деепричастный обособляется всегда, а причастный — только после определяемого слова","они оформляются одинаково","причастный обособляется всегда, а деепричастный — только после слова"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"learningapps","externalServiceTask":"Выполни в LearningApps упражнение «Найди деепричастный оборот»: распредели предложения по группам (оборот в начале / середине / конце) и расставь запятые.","starts_at":"2026-07-17T08:30:00+05:00","ends_at":"2026-07-17T09:15:00+05:00","room":"204"},{"topic":"Наречие как часть речи и его разряды","objective":"Научиться определять наречие как часть речи, различать его разряды по значению и синтаксическую роль в предложении.","theory":"Мы завершили изучение особых форм глагола — причастия и деепричастия. Теперь переходим к самостоятельной части речи — наречию.\n\nНаречие — это самостоятельная неизменяемая часть речи, которая обозначает признак действия, признак признака или (реже) признак предмета. Наречие отвечает на вопросы как? когда? где? куда? откуда? почему? зачем? в какой степени?\n\nНапример: идти быстро (признак действия), очень красивый (признак признака — прилагательного), яйцо всмятку (признак предмета — редкий случай).\n\nГлавная особенность наречия — неизменяемость: оно не склоняется, не спрягается, не изменяется по родам, числам и падежам. Сравните: причастие «быстрый» изменяется (быстрого, быстрым, быстрая), а наречие «быстро» остаётся неизменным в любом предложении.\n\nПо значению наречия делятся на разряды: 1) образа действия — как? каким образом? (быстро, весело, по-новому); 2) меры и степени — насколько? в какой степени? (очень, чуть-чуть, вдвое, совсем); 3) места — где? куда? откуда? (далеко, вперёд, издалека); 4) времени — когда? как долго? (сегодня, давно, зимой); 5) причины — почему? (сгоряча, спросонья); 6) цели — зачем? (нарочно, назло).\n\nВ предложении наречие чаще всего является обстоятельством: Он говорил тихо (обстоятельство образа действия). Иногда наречие может относиться не к глаголу, а к прилагательному или другому наречию, усиливая или уточняя признак: очень интересная книга, слишком быстро.\n\nНаречия образуются разными способами: от прилагательных при помощи суффиксов -о/-е (быстрый → быстро, искренний → искренне); от существительных с предлогом (вдали, сначала, набок); от числительных (дважды, втрое); от местоимений (почему, затем); повтором слов (еле-еле, чуть-чуть).\n\nВажно не путать наречие с краткой формой прилагательного среднего рода: они могут звучать одинаково (Небо ясно — краткое прилагательное; Он говорил ясно — наречие), но отличаются вопросом и синтаксической ролью: прилагательное отвечает на вопрос «каково?» и является сказуемым, а наречие отвечает на вопрос «как?» и является обстоятельством.","quiz":[{"question":"Что обозначает наречие?","options":["признак предмета по действию","признак действия, признака или предмета","действие предмета","количество предметов"],"correctIndex":1},{"question":"Как изменяется наречие?","options":["по родам, числам, падежам","никак, оно неизменяемо","только по числам","только по временам"],"correctIndex":1},{"question":"К какому разряду относится наречие «далеко»?","options":["образа действия","меры и степени","места","времени"],"correctIndex":2},{"question":"Каким членом предложения обычно является наречие?","options":["подлежащим","определением","обстоятельством","дополнением"],"correctIndex":2},{"question":"От какой части речи чаще всего образуются наречия на -о/-е?","options":["от существительных","от прилагательных","от числительных","от местоимений"],"correctIndex":1},{"question":"Чем отличается наречие «ясно» в предложении «Он говорил ясно» от краткого прилагательного «ясно» в «Небо ясно»?","options":["ничем не отличается","наречие отвечает на «как?» и является обстоятельством, прилагательное — на «каково?» и является сказуемым","наречие изменяется по родам, прилагательное нет","прилагательное неизменяемо, а наречие изменяется"],"correctIndex":1},{"question":"Найдите наречие меры и степени.","options":["вчера","очень","далеко","нарочно"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-20T08:30:00+05:00","ends_at":"2026-07-20T09:15:00+05:00","room":"204"},{"topic":"Степени сравнения наречий","objective":"Научиться образовывать простую и составную сравнительную и превосходную степени наречий и отличать их от степеней сравнения прилагательных.","theory":"Некоторые наречия (образованные от качественных прилагательных на -о/-е) могут образовывать степени сравнения, подобно прилагательным. Различают сравнительную и превосходную степень.\n\nСравнительная степень наречия показывает, что признак действия проявляется у одного предмета сильнее или слабее, чем у другого. Она бывает простая и составная.\n\nПростая сравнительная степень образуется при помощи суффиксов -ее (-ей), -е, -ше: быстро → быстрее (быстрей), громко → громче, далеко → дальше, рано → раньше. Такая форма не изменяется и в предложении обычно является обстоятельством: Он бежал быстрее всех.\n\nСоставная сравнительная степень образуется при помощи слов более или менее + исходное наречие: более быстро, менее заметно.\n\nПревосходная степень наречия в современном русском языке образуется только составным способом: простая сравнительная степень + слово всех (или всего): быстрее всех, громче всех, лучше всего. Например: Он бегает быстрее всех в классе.\n\nОчень важно НЕ ПУТАТЬ простую сравнительную степень наречия с простой сравнительной степенью краткого прилагательного — они могут выглядеть абсолютно одинаково: «быстрее», «громче», «выше». Различить их можно только по контексту и синтаксической роли: Он говорил громче обычного (наречие: относится к глаголу «говорил», отвечает на вопрос «как?», является обстоятельством). Его голос был громче обычного (краткое прилагательное: относится к существительному «голос», является сказуемым).\n\nПроверочный вопрос: если сравнительная форма относится к глаголу и отвечает на вопрос «как?» — это наречие; если относится к существительному и отвечает на вопрос «каков?» — это прилагательное.\n\nНекоторые наречия образуют сравнительную степень не по общему правилу, а особым (супплетивным) способом, то есть от другого корня: хорошо → лучше, плохо → хуже, много → больше, мало → меньше. Эти формы нужно запомнить.","quiz":[{"question":"Какие степени сравнения есть у наречий?","options":["только сравнительная","сравнительная и превосходная","только превосходная","уменьшительная и увеличительная"],"correctIndex":1},{"question":"Как образуется простая сравнительная степень наречия?","options":["при помощи слова «более»","при помощи суффиксов -ее/-ей, -е, -ше","при помощи приставки наи-","при помощи слова «самый»"],"correctIndex":1},{"question":"Как образуется превосходная степень наречия в современном русском языке?","options":["простым суффиксом","простая сравнительная степень + слово «всех/всего»","приставкой наи-","она вообще не образуется"],"correctIndex":1},{"question":"В предложении «Он говорил громче обычного» слово «громче» — это...","options":["краткое прилагательное","наречие в сравнительной степени","причастие","деепричастие"],"correctIndex":1},{"question":"Как отличить сравнительную степень наречия от сравнительной степени краткого прилагательного?","options":["никак нельзя отличить","по тому, к какому слову относится форма и на какой вопрос отвечает","по количеству букв","по роду"],"correctIndex":1},{"question":"Какая форма сравнительной степени у наречия «хорошо»?","options":["хорошее","лучше","хорошее самое","более хорошо"],"correctIndex":1},{"question":"Найдите пример составной сравнительной степени наречия.","options":["быстрее","более заметно","лучше всех","выше"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-21T09:25:00+05:00","ends_at":"2026-07-21T10:10:00+05:00","room":"204"},{"topic":"Слитное, раздельное, дефисное написание наречий","objective":"Научиться применять правила слитного, раздельного и дефисного написания наречий на основе разбора состава слова и контекста.","theory":"Правописание наречий — одна из сложных тем 7 класса, потому что здесь много правил и исключений. Рассмотрим основные случаи.\n\nДЕФИС в наречиях пишется: 1) в наречиях с приставкой по- и суффиксами -ому/-ему, -и: по-новому, по-весеннему, по-русски, по-дружески; 2) в наречиях с приставкой в- (во-) и суффиксами -ых/-их, образованных от порядковых числительных: во-первых, в-третьих; 3) в наречиях, образованных повтором слова или однокоренных слов: еле-еле, точь-в-точь, крепко-накрепко; 4) в неопределённых наречиях с частицами -то, -либо, -нибудь и приставкой кое-: где-то, куда-либо, кое-как.\n\nСЛИТНО пишутся наречия: 1) образованные соединением предлога с наречием: доныне, извне, навсегда; 2) образованные соединением предлога с кратким прилагательным: сгоряча, набело, вправо; 3) образованные соединением предлога с существительным, если между ними нельзя вставить слово или падежный вопрос, и существительное само по себе не употребляется (или сильно изменило значение): вдребезги, наперекор, сначала, наизусть; 4) наречия на -верх, -низ и подобные, если они не имеют пояснительных слов: вверх, вниз, взапуски.\n\nРАЗДЕЛЬНО пишутся: 1) сочетания существительного с предлогом, если существительное сохраняет некоторые падежные формы и между предлогом и словом можно вставить определение или задать падежный вопрос: в открытую, на скаку, до смерти, без устали; 2) наречные сочетания с предлогами без, до, на, с, если существительное начинается с гласной: без устали, до отвала; 3) устойчивые сочетания, в которых существительное сохранило хотя бы часть своего первоначального значения: на ходу, на бегу, под мышкой.\n\nЧтобы не ошибиться, полезно запомнить пары слов-«ловушек»: вначале (наречие, слитно) — в начале (сущ. с предлогом, есть падежный вопрос: в начале урока); впустую (наречие) — в пустую комнату (прилагательное + сущ.); насмерть (наречие: биться насмерть) — на смерть (сущ. с предлогом: обречь на смерть).\n\nОбщий алгоритм проверки: 1. Определи, от какой части речи образовано наречие. 2. Проверь, можно ли вставить между частями слово-определение или задать падежный вопрос — если да, скорее всего, это существительное с предлогом (раздельно). 3. Проверь список суффиксов и приставок, требующих дефиса. 4. Если ни одно правило не подошло явно — сверься со словарём, так как многие наречия являются словарными словами и их написание нужно запомнить.","quiz":[{"question":"Когда в наречии пишется дефис?","options":["всегда после приставки по-","при приставке по- и суффиксах -ому/-ему/-и","только в сложных словах","никогда"],"correctIndex":1},{"question":"Найдите наречие, которое пишется через дефис.","options":["вовремя","по-новому","сначала","вдребезги"],"correctIndex":1},{"question":"Как пишутся наречия, образованные повтором слова?","options":["слитно","раздельно","через дефис","по-разному в зависимости от контекста"],"correctIndex":2},{"question":"Какое наречие пишется слитно?","options":["в открытую","без устали","вправо","на скаку"],"correctIndex":2},{"question":"В каком случае сочетание с предлогом пишется раздельно?","options":["если существительное полностью утратило значение","если между предлогом и словом можно вставить определение или задать падежный вопрос","если это устойчивая связка","никогда не пишется раздельно"],"correctIndex":1},{"question":"Выберите верный вариант: «Мы встретились ... урока» (в начале / вначале).","options":["в начале (раздельно, есть падежный вопрос)","вначале (слитно, наречие)","оба варианта верны всегда","ни один не верен"],"correctIndex":0},{"question":"Выберите верный вариант: «... было трудно, потом стало легче» (в начале / вначале).","options":["в начале","вначале","в-начале","вна чале"],"correctIndex":1},{"question":"Найдите неопределённое наречие с приставкой кое-.","options":["кое-как","по-зимнему","в-третьих","еле-еле"],"correctIndex":0}],"hasExternalService":true,"externalServiceType":"h5p","externalServiceTask":"Выполни в H5P упражнение «Заполни пропуски»: выбери слитное, раздельное или дефисное написание наречий в предложениях.","starts_at":"2026-07-22T11:15:00+05:00","ends_at":"2026-07-22T12:00:00+05:00","room":"204"},{"topic":"Служебные части речи: предлог, союз, частица","objective":"Научиться различать предлоги, союзы и частицы по их функции в предложении и правильно писать похожие по звучанию служебные слова и омонимичные сочетания.","theory":"Мы изучили самостоятельные части речи и особые формы глагола. Завершим курс темой служебных частей речи — предлога, союза и частицы. Они отличаются от самостоятельных частей речи тем, что не имеют собственного лексического значения, не изменяются и не являются членами предложения — они лишь помогают связывать слова и части предложения или добавляют оттенки смысла.\n\nПРЕДЛОГ выражает зависимость одного слова от другого в словосочетании, обычно указывает на падеж существительного или местоимения: идти в школу, думать о друге, выйти из дома. Предлоги бывают простые (в, на, из, о, при) и производные — образованные от других частей речи (наречий, существительных, деепричастий): вследствие, в течение, навстречу, благодаря, несмотря на. Производные предлоги важно не путать с самостоятельными частями речи, от которых они образованы. Сравните: В течение недели шёл дождь (предлог, можно заменить на «на протяжении», пишется слитно). В течении реки много поворотов (существительное с предлогом, есть падежный вопрос «в чём?», можно вставить определение «в быстром течении»).\n\nСОЮЗ связывает однородные члены предложения или части сложного предложения: и, а, но, зато, чтобы, потому что, если. Союзы бывают сочинительные (связывают равноправные части: и, а, но, или) и подчинительные (связывают главное и придаточное предложения: потому что, чтобы, если, когда, хотя). Союзы тоже часто путают с похожими сочетаниями самостоятельных частей речи: Он опоздал, зато успел на следующий автобус (союз зато = но, слитно). За то дело он не брался (местоимение с предлогом за + указательное то, есть падежный вопрос «за что?»). Он старался, чтобы всё получилось (союз чтобы, слитно). Что бы мне почитать? (местоимение что с частицей бы, которую можно переставить: «Что мне бы почитать?»).\n\nЧАСТИЦА вносит в предложение дополнительные смысловые оттенки (отрицание, усиление, вопрос, сомнение) или служит для образования форм слова. Например: не, ни (отрицательные), же, ведь, даже, только (усилительные), ли, разве, неужели (вопросительные), бы (формообразующая, для условного наклонения), пусть, давай (формообразующая, для повелительного наклонения).\n\nОбщий способ различения служебных частей речи: если слово можно убрать из предложения без потери смысла связи — скорее всего, это частица; если слово связывает части сложного предложения — союз; если слово стоит перед существительным/местоимением и выражает падежные отношения — предлог. Этот навык особенно важен для орфографии — правильное определение части речи помогает выбрать слитное или раздельное написание.","quiz":[{"question":"Чем служебные части речи отличаются от самостоятельных?","options":["они изменяются по падежам","не имеют лексического значения и не являются членами предложения","всегда стоят в начале предложения","обозначают признак предмета"],"correctIndex":1},{"question":"Что выражает предлог?","options":["зависимость одного слова от другого, указывает на падеж","связь частей сложного предложения","дополнительный оттенок значения","признак действия"],"correctIndex":0},{"question":"В каком предложении «в течение» — предлог?","options":["«В течении реки много поворотов.»","«В течение недели шёл дождь.»","«В быстром течении реки утонула лодка.»","«О течении реки ходят легенды.»"],"correctIndex":1},{"question":"Какие союзы связывают главное и придаточное предложения?","options":["сочинительные","подчинительные","сравнительные","усилительные"],"correctIndex":1},{"question":"В каком предложении «чтобы» пишется слитно как союз?","options":["«Что бы мне почитать?»","«Он старался, чтобы всё получилось.»","«Что бы ни случилось, я приду.»","«За что бы взяться?»"],"correctIndex":1},{"question":"Какую роль выполняет частица?","options":["связывает однородные члены","выражает падежные отношения","вносит дополнительные смысловые оттенки","обозначает признак предмета"],"correctIndex":2},{"question":"Найдите отрицательную частицу.","options":["же","бы","не","ли"],"correctIndex":2},{"question":"Как отличить союз «зато» от сочетания «за то»?","options":["никак, они пишутся одинаково","«зато» можно заменить союзом «но», «за то» имеет падежный вопрос «за что?»","«за то» всегда в начале предложения","«зато» всегда с большой буквы"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-24T08:30:00+05:00","ends_at":"2026-07-24T09:15:00+05:00","room":"204"}]'::jsonb)
    LOOP
      INSERT INTO public.lessons (group_id, subject_id, topic, title, description, status, starts_at, ends_at, started_at, ended_at, room, school_id)
      VALUES (
        v_group_id, v_subject_id, lesson_data->>'topic', lesson_data->>'topic', lesson_data->>'objective',
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN 'completed' ELSE 'scheduled' END,
        (lesson_data->>'starts_at')::timestamptz, (lesson_data->>'ends_at')::timestamptz,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'starts_at')::timestamptz ELSE NULL END,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'ends_at')::timestamptz ELSE NULL END,
        lesson_data->>'room', v_school_id
      )
      RETURNING id INTO v_lesson_id;

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, duration_min, school_id)
      VALUES (v_lesson_id, 1, 'middle', 'theory', 'presentation', lesson_data->>'topic', lesson_data->>'theory', 15, v_school_id);

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, duration_min, school_id)
      VALUES (v_lesson_id, 2, 'middle', 'task', 'quiz_qia', 'Проверь себя', 15, v_school_id)
      RETURNING id INTO v_stage_id;

      qpos := 0;
      FOR quiz_item IN SELECT * FROM jsonb_array_elements(lesson_data->'quiz')
      LOOP
        qpos := qpos + 1;
        INSERT INTO public.quiz_questions (stage_id, question_text, options, correct_option_index, position, points, time_per_question_seconds, school_id)
        VALUES (v_stage_id, quiz_item->>'question', quiz_item->'options', (quiz_item->>'correctIndex')::int, qpos, 1, 30, v_school_id);
      END LOOP;

      IF (lesson_data->>'hasExternalService')::boolean THEN
        INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, config, duration_min, school_id)
        VALUES (
          v_lesson_id, 3, 'middle', 'task', lesson_data->>'externalServiceType',
          lesson_data->>'externalServiceTask', lesson_data->>'externalServiceTask',
          jsonb_build_object('url',
            CASE lesson_data->>'externalServiceType'
              WHEN 'wokwi' THEN 'https://wokwi.com/projects/new/arduino-uno'
              WHEN 'codesandbox' THEN 'https://codesandbox.io/p/sandbox/vanilla'
              WHEN 'geogebra' THEN 'https://www.geogebra.org/classic'
              WHEN 'phet' THEN 'https://phet.colorado.edu/sims/html/forces-and-motion-basics/latest/forces-and-motion-basics_en.html'
              WHEN 'desmos' THEN 'https://www.desmos.com/calculator'
              WHEN 'blockly_games' THEN 'https://blockly.games/'
              WHEN 'visualgo' THEN 'https://visualgo.net/en'
              WHEN 'p5js' THEN 'https://editor.p5js.org/'
              WHEN 'excalidraw' THEN 'https://excalidraw.com/'
              WHEN 'learningapps' THEN 'https://learningapps.org/'
              WHEN 'sqlonline' THEN 'https://sqlime.org/'
              WHEN 'h5p' THEN 'https://h5p.eduos.snruz.uz/library'
              ELSE NULL
            END
          ),
          15, v_school_id
        );
      END IF;
    END LOOP;
  END IF;

  -- === 7-А класс | Математика (11 уроков) ===
  SELECT id INTO v_group_id FROM public.groups WHERE name = '7-А класс';
  SELECT id INTO v_subject_id FROM public.subjects WHERE group_id = v_group_id AND name = 'Математика';
  IF NOT EXISTS (SELECT 1 FROM public.lessons WHERE group_id = v_group_id AND subject_id = v_subject_id AND description IS NOT NULL) THEN
    FOR lesson_data IN SELECT * FROM jsonb_array_elements('[{"topic":"Степень с натуральным показателем и её свойства","objective":"Научиться возводить числа и переменные в натуральную степень и применять основные свойства степеней при упрощении выражений.","theory":"Степенью числа a с натуральным показателем n (n>1) называют произведение n одинаковых множителей, каждый из которых равен a: a^n = a·a·...·a (n раз). Число a — основание степени, n — показатель степени. Например, 2^4=2·2·2·2=16, а (-3)^3=(-3)·(-3)·(-3)=-27. Также договариваются: a^1=a для любого a, а a^0=1 для любого a≠0.\n\nЗнак результата зависит от знака основания и чётности показателя. Если основание отрицательное и показатель чётный, степень положительна: (-2)^4=16. Если показатель нечётный, степень отрицательна: (-2)^3=-8.\n\nОсновные свойства степеней с одинаковым основанием a≠0:\n1) a^m·a^n=a^(m+n) — при умножении степеней показатели складываются. Пример: 2^3·2^5=2^8=256.\n2) a^m:a^n=a^(m-n) (при m≥n) — при делении показатели вычитаются. Пример: 5^7:5^4=5^3=125.\n3) (a^m)^n=a^(mn) — степень степени. Пример: (3^2)^3=3^6=729.\n4) (ab)^n=a^n·b^n — степень произведения. Пример: (2·5)^3=2^3·5^3=1000.\n5) (a/b)^n=a^n/b^n при b≠0.\n\nЭти правила ускоряют упрощение выражений. Например: x^3·x^5:x^2. Сначала x^3·x^5=x^8, затем x^8:x^2=x^6.\n\nВажно не путать сложение показателей с умножением оснований: a^2+a^3 нельзя объединить в одну степень — это разные слагаемые, а не произведение одинаковых оснований.\n\nСтепени применяются повсеместно: при записи больших чисел (10^6=1000000), в формулах площади и объёма (площадь квадрата со стороной a равна a^2, объём куба — a^3), в науке — для очень больших и очень малых величин.\n\nПомните порядок действий: возведение в степень выполняется раньше умножения, деления, сложения и вычитания. В выражении 2+3^2 сначала считаем 3^2=9, затем 2+9=11, а не (2+3)^2=25.\n\nПример: вычислим 2^3·2^2-3^2. Сначала 2^3·2^2=2^5=32, затем 3^2=9, итог 32-9=23.\n\nПонимание степеней — фундамент для следующей темы: одночленов и многочленов.","quiz":[{"question":"Чему равно значение выражения 2^5?","options":["10","32","25","16"],"correctIndex":1},{"question":"Чему равно (-2)^3?","options":["-8","8","-6","6"],"correctIndex":0},{"question":"Упростите: a^4 · a^3","options":["a^7","a^12","a^1","2a^7"],"correctIndex":0},{"question":"Упростите: x^9 : x^4","options":["x^5","x^13","x^36","x^4"],"correctIndex":0},{"question":"Чему равно (a^2)^3?","options":["a^5","a^6","a^8","a^9"],"correctIndex":1},{"question":"Чему равно a^0 при a≠0?","options":["0","1","a","не существует"],"correctIndex":1},{"question":"Вычислите значение выражения 3+2^3.","options":["11","125","17","9"],"correctIndex":0}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-07T10:20:00+05:00","ends_at":"2026-07-07T11:05:00+05:00","room":"204"},{"topic":"Одночлены: стандартный вид и умножение одночленов","objective":"Научиться определять одночлен, приводить его к стандартному виду и выполнять умножение и возведение одночленов в степень.","theory":"Одночленом называют выражение, представляющее собой произведение чисел, переменных и их степеней. Например: 5x, -3a^2b, 7, xy^3, (2/3)m^2n. А выражения x+2, 3/x, x^2-1 одночленами не являются: в первом есть сложение, во втором переменная в знаменателе, в третьем тоже сложение.\n\nЧисловой множитель одночлена называют коэффициентом. Если коэффициент не записан явно, он равен 1 (у xy) или -1 (у -ab).\n\nОдночлен записан в стандартном виде, если в нём один числовой множитель на первом месте, а каждая переменная встречается один раз в виде степени. Например, 3·x·x·y·2 нужно упростить: 3·2=6, x·x=x^2, получаем 6x^2y — стандартный вид.\n\nСтепенью одночлена называют сумму показателей всех переменных. У 6x^2y степень равна 2+1=3. У числа (одночлена без переменных) степень равна 0.\n\nЧтобы привести одночлен к стандартному виду: 1) перемножить числовые множители — получить коэффициент; 2) перемножить степени с одинаковыми основаниями по правилу a^m·a^n=a^(m+n).\n\nПример: приведём 2a^3b·(-5ab^2) к стандартному виду. Числа: 2·(-5)=-10. Переменные: a^3·a=a^4, b·b^2=b^3. Итог: -10a^4b^3.\n\nУмножение одночленов: перемножаем коэффициенты и складываем показатели одинаковых переменных. Пример: 4x^2y^3·3xy^4=(4·3)·(x^2·x)·(y^3·y^4)=12x^3y^7.\n\nВозведение одночлена в степень использует свойства (ab)^n=a^n·b^n и (a^m)^n=a^(mn). Пример: (3x^2y)^3=3^3·(x^2)^3·y^3=27x^6y^3. Возводится в степень и коэффициент, и каждая переменная отдельно.\n\nОдночлены — простейшие алгебраические выражения, из которых строятся более сложные конструкции — многочлены, к изучению которых мы перейдём на следующем уроке.","quiz":[{"question":"Какое из выражений является одночленом?","options":["x+5","3x^2y","4/x","x-y^2"],"correctIndex":1},{"question":"Приведите одночлен 2a·3a^2 к стандартному виду.","options":["6a^3","5a^3","6a^2","6a"],"correctIndex":0},{"question":"Чему равен коэффициент одночлена -7x^3y?","options":["7","-7","3","1"],"correctIndex":1},{"question":"Чему равна степень одночлена 4x^2y^3?","options":["2","3","5","6"],"correctIndex":2},{"question":"Выполните умножение: 3x^2 · 5x^4","options":["15x^6","8x^6","15x^8","15x^2"],"correctIndex":0},{"question":"Вычислите (2x^3)^2","options":["4x^5","4x^6","2x^6","4x^9"],"correctIndex":1},{"question":"Какое из выражений НЕ является одночленом?","options":["5xy^2","-x","x+y","8"],"correctIndex":2}],"hasExternalService":true,"externalServiceType":"geogebra","externalServiceTask":"В GeoGebra постройте прямоугольник со сторонами 3a и 2a² (сторону a задайте ползунком), с помощью инструмента «Площадь» найдите его площадь и сравните результат с одночленом 6a³, полученным при умножении 3a·2a².","starts_at":"2026-07-08T08:30:00+05:00","ends_at":"2026-07-08T09:15:00+05:00","room":"204"},{"topic":"Многочлены: стандартный вид, сложение и вычитание","objective":"Научиться приводить многочлен к стандартному виду и выполнять сложение и вычитание многочленов.","theory":"Многочленом называется сумма (или разность) нескольких одночленов. Каждый из них называют членом многочлена. Например, 3x^2-5x+7 — многочлен из трёх членов. Многочлен из двух членов называют двучленом (например, 2x+3y), из трёх — трёхчленом (например, x^2+2x+1).\n\nМногочлен записан в стандартном виде, если все его члены — одночлены стандартного вида и среди них нет подобных слагаемых. Подобные слагаемые имеют одинаковую буквенную часть (одинаковые переменные в одинаковых степенях) и отличаются только коэффициентом. Например, 3x^2 и -7x^2 — подобные, а 3x^2 и 3x — нет.\n\nЧтобы привести многочлен к стандартному виду, нужно привести подобные слагаемые — сложить их коэффициенты, оставив буквенную часть без изменений. Пример: 5x^2+3x-2x^2+7x-4 = (5x^2-2x^2)+(3x+7x)-4 = 3x^2+10x-4.\n\nСтепенью многочлена называют наибольшую из степеней входящих в него одночленов (после приведения к стандартному виду). У 3x^2+10x-4 степень равна 2.\n\nСложение многочленов: раскрываем скобки (при знаке «+» перед скобкой знаки слагаемых не меняются) и приводим подобные слагаемые. Пример: (2x^2+3x-1)+(x^2-5x+4)=2x^2+3x-1+x^2-5x+4=3x^2-2x+3.\n\nВычитание многочленов требует внимания к знакам: если перед скобкой стоит минус, знак каждого слагаемого внутри неё меняется на противоположный. Пример: (5x^2-2x+3)-(2x^2-4x+1)=5x^2-2x+3-2x^2+4x-1=3x^2+2x+2.\n\nЧастая ошибка — забыть поменять знак у всех членов вычитаемого многочлена, а не только у первого. Чтобы избежать ошибки, полезно мысленно умножить каждый член скобки на -1.\n\nМногочлены используются для описания площадей сложных фигур, формул физики и экономики, а также как основа для дальнейших преобразований — умножения многочленов, которое мы разберём на следующем уроке.","quiz":[{"question":"Сколько членов у многочлена 4x^2-3x+7?","options":["1","2","3","4"],"correctIndex":2},{"question":"Какие из слагаемых являются подобными: 5x^2, -3x, 2x^2, 7?","options":["5x^2 и -3x","5x^2 и 2x^2","-3x и 7","все подобны"],"correctIndex":1},{"question":"Приведите подобные слагаемые: 3a+5a-2a","options":["6a","10a","0","6a^2"],"correctIndex":0},{"question":"Упростите: (2x^2+3x)+(x^2-x)","options":["3x^2+2x","3x^2+4x","x^2+2x","3x^2-2x"],"correctIndex":0},{"question":"Упростите: (5x-3)-(2x-1)","options":["3x-4","3x-2","7x-4","3x+2"],"correctIndex":1},{"question":"Чему равна степень многочлена 7x^3-2x^2+x?","options":["1","2","3","7"],"correctIndex":2},{"question":"Упростите: (4x^2-5x+2)-(x^2+3x-6)","options":["3x^2-8x+8","3x^2-2x-4","5x^2-8x-4","3x^2-8x-4"],"correctIndex":0}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-09T11:15:00+05:00","ends_at":"2026-07-09T12:00:00+05:00","room":"204"},{"topic":"Умножение одночлена на многочлен и многочлена на многочлен","objective":"Научиться умножать одночлен на многочлен и многочлен на многочлен, применяя распределительный закон.","theory":"Чтобы умножить одночлен на многочлен, нужно умножить этот одночлен на каждый член многочлена и сложить полученные произведения. Это правило — следствие распределительного закона: a(b+c)=ab+ac.\n\nПример: умножим 3x на (2x^2-5x+4). 3x·2x^2=6x^3, 3x·(-5x)=-15x^2, 3x·4=12x. Складываем: 6x^3-15x^2+12x.\n\nЕсли одночлен отрицательный, знаки всех членов многочлена при умножении меняются на противоположные. Пример: -2x·(x^2-3x+1)=-2x^3+6x^2-2x.\n\nЧтобы умножить многочлен на многочлен, нужно каждый член одного многочлена умножить на каждый член другого и сложить полученные произведения, приведя подобные слагаемые.\n\nПример: (x+3)(x+5). x·x=x^2, x·5=5x, 3·x=3x, 3·5=15. Складываем: x^2+5x+3x+15=x^2+8x+15.\n\nБолее сложный пример: (2x-3)(x^2+4x-1). 2x·x^2=2x^3, 2x·4x=8x^2, 2x·(-1)=-2x, -3·x^2=-3x^2, -3·4x=-12x, -3·(-1)=3. Складываем: 2x^3+8x^2-2x-3x^2-12x+3=2x^3+5x^2-14x+3.\n\nПри умножении многочленов «в столбик» удобно умножать весь второй многочлен сначала на первый член первого, затем на второй его член и т.д., записывая промежуточные результаты, а затем складывать их, приводя подобные — как при умножении многозначных чисел в столбик.\n\nПолезная проверка: количество слагаемых до приведения подобных равно произведению числа членов первого многочлена на число членов второго — например, при умножении двучлена на трёхчлен получится 2·3=6 произведений.\n\nУмножение многочленов лежит в основе формул сокращённого умножения, которые значительно ускоряют вычисления в частных, но очень распространённых случаях. Их мы изучим на следующем уроке.","quiz":[{"question":"Умножьте: 4x·(2x+3)","options":["8x^2+12x","8x+12x","6x^2+7x","8x^2+3"],"correctIndex":0},{"question":"Умножьте: -2x·(x^2-3x+5)","options":["-2x^3+6x^2-10x","-2x^3-6x^2-10x","2x^3+6x^2-10x","-2x^3+6x^2+10x"],"correctIndex":0},{"question":"Раскройте скобки: (x+2)(x+7)","options":["x^2+9x+14","x^2+14x+9","x^2+9x+9","2x^2+9x+14"],"correctIndex":0},{"question":"Раскройте скобки: (x-4)(x+3)","options":["x^2-x-12","x^2+x-12","x^2-7x-12","x^2-x+12"],"correctIndex":0},{"question":"Раскройте скобки: (2x-1)(3x+2)","options":["6x^2+x-2","6x^2-x-2","5x^2+x-2","6x^2+4x-2"],"correctIndex":0},{"question":"Сколько слагаемых получится при раскрытии скобок (a+b)(c+d+e) до приведения подобных?","options":["2","3","5","6"],"correctIndex":3},{"question":"Раскройте скобки: (x-2)(x^2+3x-1)","options":["x^3+x^2-7x+2","x^3-x^2-7x+2","x^3+x^2-5x+2","x^3+5x^2-7x+2"],"correctIndex":0}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-13T09:25:00+05:00","ends_at":"2026-07-13T10:10:00+05:00","room":"204"},{"topic":"ФСУ: квадрат суммы и квадрат разности","objective":"Научиться применять формулы квадрата суммы и квадрата разности двух выражений для быстрого возведения в квадрат и упрощения выражений.","theory":"Многие выражения вида (a+b)^2 или (a-b)^2 встречаются настолько часто, что для них выведены специальные формулы сокращённого умножения. Они позволяют не выполнять умножение многочлена на многочлен вручную каждый раз, а сразу получать результат.\n\nВыведем формулу квадрата суммы. По определению степени (a+b)^2=(a+b)(a+b). Раскроем скобки: a·a+a·b+b·a+b·b=a^2+2ab+b^2.\n\nФормула квадрата суммы: (a+b)^2=a^2+2ab+b^2 — квадрат первого выражения, плюс удвоенное произведение первого на второе, плюс квадрат второго.\n\nАналогично: (a-b)^2=(a-b)(a-b)=a^2-2ab+b^2 — квадрат первого, минус удвоенное произведение, плюс квадрат второго. Последний член всегда со знаком «плюс», ведь b^2 — это (-b)^2, а квадрат любого числа неотрицателен.\n\nЭти формулы имеют геометрическое объяснение. Представим квадрат со стороной (a+b). Его площадь можно посчитать двумя способами: как (a+b)^2 целиком или разбив квадрат на четыре части — квадрат со стороной a (площадь a^2), квадрат со стороной b (площадь b^2) и два прямоугольника со сторонами a и b (площадь каждого ab). Сумма площадей частей a^2+2ab+b^2 равна площади всего квадрата.\n\nПримеры: (x+3)^2=x^2+2·x·3+3^2=x^2+6x+9. (2x-5)^2=(2x)^2-2·2x·5+5^2=4x^2-20x+25 — возводится в квадрат весь член 2x, а не только x.\n\nПроверка при a=3, b=7: 3^2+2·3·7+7^2=9+42+49=100, что совпадает с (3+7)^2=10^2=100.\n\nЧастые ошибки: забывают удвоенное произведение (пишут a^2+b^2 вместо a^2+2ab+b^2), либо не возводят в квадрат весь коэффициент при переменной.\n\nФормулы квадрата суммы и разности ускоряют вычисления и применяются при упрощении дробей и решении уравнений. На следующем уроке мы изучим формулу разности квадратов.","quiz":[{"question":"Чему равно (a+b)^2?","options":["a^2+b^2","a^2+2ab+b^2","a^2-2ab+b^2","a^2+ab+b^2"],"correctIndex":1},{"question":"Чему равно (x-5)^2?","options":["x^2-10x+25","x^2-25","x^2-5x+25","x^2+10x+25"],"correctIndex":0},{"question":"Раскройте (2x+3)^2","options":["4x^2+12x+9","2x^2+12x+9","4x^2+6x+9","4x^2+9"],"correctIndex":0},{"question":"Раскройте (3x-1)^2","options":["9x^2-6x+1","9x^2-3x+1","9x^2+6x+1","3x^2-6x+1"],"correctIndex":0},{"question":"Какой знак у среднего слагаемого в формуле квадрата разности (a-b)^2?","options":["плюс","минус","зависит от a и b","такого слагаемого нет"],"correctIndex":1},{"question":"Вычислите 21^2, представив 21 как (20+1).","options":["441","421","440","401"],"correctIndex":0},{"question":"Чему равен последний член в разложении (a-b)^2?","options":["-b^2","b^2","-2ab","2ab"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"geogebra","externalServiceTask":"В GeoGebra постройте квадрат со стороной (a+b), задав a и b ползунками, разбейте его на квадрат со стороной a, квадрат со стороной b и два прямоугольника со сторонами a и b; сравните сумму площадей четырёх частей с площадью всего квадрата (a+b)².","starts_at":"2026-07-14T10:20:00+05:00","ends_at":"2026-07-14T11:05:00+05:00","room":"204"},{"topic":"ФСУ — Часть 2: разность квадратов","objective":"Научиться применять формулу разности квадратов для разложения и упрощения выражений вида a²-b².","theory":"На предыдущем уроке мы изучили формулы квадрата суммы и квадрата разности. Теперь рассмотрим ещё одну формулу сокращённого умножения — разность квадратов.\n\nНайдём произведение (a-b)(a+b). Раскроем скобки: a·a+a·b-b·a-b·b=a^2+ab-ab-b^2. Слагаемые ab и -ab взаимно уничтожаются, и остаётся a^2-b^2.\n\nФормула разности квадратов: (a-b)(a+b)=a^2-b^2. Её можно применять в обе стороны: чтобы быстро перемножить (a-b)(a+b), и чтобы разложить разность квадратов a^2-b^2 на множители (a-b)(a+b).\n\nПримеры перемножения: (x-4)(x+4)=x^2-16; (3x-2)(3x+2)=(3x)^2-2^2=9x^2-4; (5+y)(5-y)=25-y^2.\n\nПримеры разложения на множители: x^2-9=(x-3)(x+3), так как 9=3^2; 16x^2-25=(4x-5)(4x+5), так как 16x^2=(4x)^2, 25=5^2; 49-a^2=(7-a)(7+a).\n\nРазность квадратов удобна для устного счёта. Вычислим 52·48: 52=50+2, 48=50-2, значит 52·48=(50+2)(50-2)=50^2-2^2=2500-4=2496.\n\nВажно распознавать разность квадратов в разных формах. Например, x^4-1 — тоже разность квадратов, ведь x^4=(x^2)^2, а 1=1^2, поэтому x^4-1=(x^2-1)(x^2+1). Причём (x^2-1) сам раскладывается дальше: x^2-1=(x-1)(x+1). Итог: x^4-1=(x-1)(x+1)(x^2+1).\n\nЧастая ошибка — путать разность квадратов a^2-b^2 с квадратом разности (a-b)^2. Это разные выражения: a^2-b^2=(a-b)(a+b), а (a-b)^2=a^2-2ab+b^2. Проверяйте: в исходном выражении разность двух точных квадратов через минус (одно слагаемое) или квадрат целой разности (одна скобка в квадрате)?\n\nЗнание трёх формул сокращённого умножения готовит нас к теме разложения многочленов на множители различными способами, с которой мы начнём на следующем уроке.","quiz":[{"question":"Чему равно (a-b)(a+b)?","options":["a^2-b^2","a^2+b^2","a^2-2ab+b^2","a^2+2ab-b^2"],"correctIndex":0},{"question":"Разложите на множители x^2-25.","options":["(x-5)(x+5)","(x-25)(x+1)","(x-5)^2","(x+5)^2"],"correctIndex":0},{"question":"Вычислите (x-6)(x+6).","options":["x^2-36","x^2-12x+36","x^2+36","x^2-6"],"correctIndex":0},{"question":"Разложите на множители 9x^2-16.","options":["(3x-4)(3x+4)","(9x-16)(9x+16)","(3x-16)(3x+16)","(9x-4)(x+4)"],"correctIndex":0},{"question":"Что из перечисленного является разностью квадратов?","options":["x^2-2x+1","x^2+4","x^2-49","x^2+2x-1"],"correctIndex":2},{"question":"Найдите значение 102·98 с помощью формулы разности квадратов (102=100+2, 98=100-2).","options":["9996","9904","10004","9800"],"correctIndex":0},{"question":"Чем отличается (a-b)^2 от a^2-b^2?","options":["ничем, это одно и то же","(a-b)^2 содержит средний член -2ab, а a^2-b^2 — нет","a^2-b^2 всегда больше","(a-b)^2 нельзя разложить на множители"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-15T08:30:00+05:00","ends_at":"2026-07-15T09:15:00+05:00","room":"204"},{"topic":"Разложение на множители: общий множитель и группировка","objective":"Научиться раскладывать многочлены на множители, вынося общий множитель за скобки и используя способ группировки.","theory":"Разложить многочлен на множители — значит представить его в виде произведения нескольких многочленов (или одночлена и многочлена). Это действие, обратное раскрытию скобок, и оно требуется для упрощения дробей, решения уравнений и работы с формулами.\n\nПервый способ — вынесение общего множителя за скобки. Если каждый член многочлена содержит одинаковый множитель, его можно вынести, разделив на него каждый член.\n\nПравило: 1) найти наибольший общий делитель коэффициентов всех членов; 2) найти переменные, входящие во все члены, в наименьшей из встречающихся степеней; 3) записать общий множитель перед скобкой, а в скобке — результат деления каждого члена на этот множитель.\n\nПример: 6x^2+9x. Общий делитель чисел 6 и 9 — число 3. Переменная x есть в обоих членах в наименьшей степени 1. Общий множитель 3x. Выносим: 6x^2+9x=3x(2x+3).\n\nПример: 4a^3b-8a^2b^2+12ab. Общий делитель чисел 4,8,12 — число 4, переменные a и b — в степени 1. Общий множитель 4ab: 4a^3b-8a^2b^2+12ab=4ab(a^2-2ab+3).\n\nВторой способ — группировка. Он применяется, когда у всех членов нет общего множителя, но он есть у отдельных групп. Члены объединяют в группы (обычно по два), в каждой группе выносят свой общий множитель, а затем, если в скобках появляется одинаковое выражение, его тоже выносят за скобку.\n\nПример: ax+ay+bx+by. Сгруппируем: (ax+ay)+(bx+by)=a(x+y)+b(x+y)=(x+y)(a+b).\n\nЕщё пример: x^3-x^2+2x-2=(x^3-x^2)+(2x-2)=x^2(x-1)+2(x-1)=(x-1)(x^2+2).\n\nВажно правильно выбирать способ группировки: иногда нужно переставить члены местами, чтобы группы дали одинаковую скобку. Если группировка не удалась с первого раза, стоит попробовать другой порядок членов.\n\nОба способа часто применяются вместе: сначала выносят общий множитель для всего многочлена, а затем раскладывают оставшийся многочлен группировкой или по формулам. На следующем уроке мы соединим все приёмы, включая формулы сокращённого умножения, для разложения более сложных многочленов.","quiz":[{"question":"Вынесите общий множитель: 5x+10","options":["5(x+2)","5(x+10)","x(5+10)","5x(1+2)"],"correctIndex":0},{"question":"Вынесите общий множитель: 6a^2-9a","options":["3a(2a-3)","3(2a^2-3a)","6a(a-9)","3a(2a-9)"],"correctIndex":0},{"question":"Разложите способом группировки: ab+ac+db+dc","options":["(a+d)(b+c)","(a-d)(b+c)","(a+d)(b-c)","(ab)(cd)"],"correctIndex":0},{"question":"Разложите: x^3+x^2+x+1","options":["(x+1)(x^2+1)","(x-1)(x^2+1)","(x+1)(x^2-1)","x(x^2+x+1)"],"correctIndex":0},{"question":"Какой общий множитель можно вынести в выражении 12x^3y-18x^2y^2?","options":["6x^2y","6xy","12x^2y","3xy"],"correctIndex":0},{"question":"Разложите на множители: 3x^2+3x","options":["3x(x+1)","3(x^2+x)","x(3x+3)","3x(x-1)"],"correctIndex":0},{"question":"Какой способ используется, когда у всех членов многочлена нет общего множителя, но он есть у пар членов?","options":["вынесение общего множителя","способ группировки","формула квадрата суммы","деление многочленов"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-16T11:15:00+05:00","ends_at":"2026-07-16T12:00:00+05:00","room":"204"},{"topic":"Разложение на множители с помощью формул сокращённого умножения","objective":"Научиться раскладывать многочлены на множители, применяя формулы квадрата суммы/разности и разности квадратов, в том числе в комбинации с вынесением общего множителя.","theory":"На предыдущих уроках мы научились раскладывать многочлены, вынося общий множитель и используя группировку. Теперь применим для разложения формулы сокращённого умножения: (a+b)^2=a^2+2ab+b^2, (a-b)^2=a^2-2ab+b^2, a^2-b^2=(a-b)(a+b). Читая их справа налево, получаем способы разложения на множители.\n\nРазность квадратов: если многочлен имеет вид a^2-b^2, он раскладывается как (a-b)(a+b). Пример: 25x^2-4=(5x)^2-2^2=(5x-2)(5x+2).\n\nКвадрат суммы или разности: если трёхчлен вида a^2+2ab+b^2, он равен (a+b)^2; если вида a^2-2ab+b^2 — равен (a-b)^2. Чтобы это проверить: первый и последний член должны быть точными квадратами, а средний член — удвоенным произведением их корней (с соответствующим знаком).\n\nПример: x^2+10x+25. Первый член — квадрат x, последний — квадрат 5. Средний член: 2·x·5=10x — совпадает. Значит, это (x+5)^2.\n\nПример: 4x^2-12x+9. Первый член (2x)^2, последний 3^2. Средний член 2·2x·3=12x, а в многочлене -12x — знак минус, значит это (2x-3)^2.\n\nЧасто разложение требует сначала вынести общий множитель, а затем применить формулу. Пример: 2x^2-8=2(x^2-4)=2(x-2)(x+2).\n\nЕщё пример: 3x^3-12x=3x(x^2-4)=3x(x-2)(x+2).\n\nАлгоритм разложения многочлена на множители: 1) проверить наличие общего множителя у всех членов и вынести его; 2) проверить, подходит ли оставшийся многочлен под формулу сокращённого умножения; 3) если формула не подходит, попробовать способ группировки; 4) разложение завершено, когда каждый множитель уже нельзя разложить дальше.\n\nРазложение на множители помогает сокращать алгебраические дроби, решать уравнения (произведение равно нулю, когда хотя бы один множитель равен нулю) и упрощать выражения. С решения уравнений мы и продолжим на следующих уроках.","quiz":[{"question":"Разложите на множители: x^2-16","options":["(x-4)(x+4)","(x-8)(x+8)","(x-16)(x+1)","(x-4)^2"],"correctIndex":0},{"question":"Разложите на множители: x^2+6x+9","options":["(x+3)^2","(x+9)^2","(x+3)(x-3)","(x+6)(x+3)"],"correctIndex":0},{"question":"Разложите на множители: x^2-8x+16","options":["(x-4)^2","(x-8)^2","(x-4)(x+4)","(x-16)^2"],"correctIndex":0},{"question":"Разложите на множители: 3x^2-27","options":["3(x-3)(x+3)","(3x-9)(x+3)","3(x-9)(x+1)","(x-3)(3x+9)"],"correctIndex":0},{"question":"Является ли многочлен x^2+4x+4 точным квадратом? Если да, каким?","options":["да, (x+2)^2","да, (x+4)^2","нет, это не точный квадрат","да, (x-2)^2"],"correctIndex":0},{"question":"Разложите на множители: 5x^3-20x","options":["5x(x-2)(x+2)","5(x^3-4x)","5x(x-4)(x+4)","x(5x-20)"],"correctIndex":0},{"question":"Какой первый шаг стоит сделать при разложении многочлена 4x^2-8x на множители?","options":["применить формулу разности квадратов","вынести общий множитель 4x","сгруппировать члены","разложить на (2x-4)(2x+4)"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"geogebra","externalServiceTask":"В GeoGebra постройте прямоугольник со сторонами (x-2) и (x+2), задав x ползунком, вычислите его площадь и сравните результат с разложением x²-4=(x-2)(x+2), наблюдая, как меняется площадь при изменении x.","starts_at":"2026-07-20T09:25:00+05:00","ends_at":"2026-07-20T10:10:00+05:00","room":"204"},{"topic":"Линейные уравнения с одной переменной","objective":"Научиться решать линейные уравнения с одной переменной, включая уравнения, требующие раскрытия скобок и приведения подобных слагаемых.","theory":"Уравнением называют равенство, содержащее переменную, значение которой нужно найти. Линейным уравнением с одной переменной называют уравнение вида ax+b=0 (или сводящееся к такому виду), где a и b — числа, x — переменная, a≠0.\n\nРешить уравнение — значит найти все его корни, то есть значения переменной, при которых уравнение превращается в верное равенство. Линейное уравнение имеет ровно один корень: x=-b/a.\n\nПри решении используют два свойства, не меняющих множество корней: 1) любое слагаемое можно перенести из одной части уравнения в другую, изменив знак на противоположный; 2) обе части уравнения можно умножить или разделить на одно и то же число, не равное нулю.\n\nПример 1: 3x+7=16. Перенесём 7 вправо с противоположным знаком: 3x=9. Разделим на 3: x=3. Проверка: 3·3+7=16 — верно.\n\nПример 2: 5x-3=2x+9. Перенесём 2x влево (-2x), а -3 вправо (+3): 3x=12, x=4.\n\nПример 3, с раскрытием скобок: 2(x+3)-5=3(x-1)+4. Раскроем: 2x+6-5=3x-3+4, приведём подобные: 2x+1=3x+1. Перенесём: -x=0, x=0.\n\nОсобые случаи. Если переменная полностью «исчезает» и получается верное равенство (например, 5=5), уравнение имеет бесконечно много корней. Если получается неверное равенство (например, 5=8), корней нет.\n\nПример: 2(x+1)=2x+2. Раскроем: 2x+2=2x+2 — верно при любом x, значит корней бесконечно много.\n\nПример: 2(x+1)=2x+5. Раскроем: 2x+2=2x+5, сократим 2x: 2=5 — неверно, корней нет.\n\nАлгоритм решения линейного уравнения: раскрыть скобки (если есть); перенести слагаемые с переменной в одну часть, числа — в другую; привести подобные слагаемые; разделить обе части на коэффициент при переменной.\n\nУмение решать линейные уравнения — база для темы линейной функции, где уравнение y=kx+b покажет, как переменные величины связаны друг с другом на координатной плоскости.","quiz":[{"question":"Решите уравнение: x+5=12","options":["x=7","x=17","x=-7","x=6"],"correctIndex":0},{"question":"Решите уравнение: 4x=20","options":["x=5","x=16","x=24","x=80"],"correctIndex":0},{"question":"Решите уравнение: 3x-2=10","options":["x=4","x=8/3","x=3","x=6"],"correctIndex":0},{"question":"Решите уравнение: 5x+3=2x+12","options":["x=3","x=5","x=9","x=1"],"correctIndex":0},{"question":"Решите уравнение: 2(x-1)=x+4","options":["x=6","x=2","x=3","x=-6"],"correctIndex":0},{"question":"Сколько корней имеет уравнение 3(x+2)=3x+6?","options":["один корень","нет корней","бесконечно много корней","два корня"],"correctIndex":2},{"question":"Сколько корней имеет уравнение 2x+1=2x+5?","options":["один корень","нет корней","бесконечно много корней","три корня"],"correctIndex":1},{"question":"Каков первый шаг при решении уравнения 4(x-2)+3=2x+1?","options":["раскрыть скобки","сразу разделить на 4","перенести числа влево","умножить обе части на x"],"correctIndex":0}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-21T10:20:00+05:00","ends_at":"2026-07-21T11:05:00+05:00","room":"204"},{"topic":"Линейная функция y=kx+b и её график","objective":"Научиться строить график линейной функции y=kx+b и определять влияние коэффициентов k и b на расположение прямой.","theory":"Функцией называют зависимость, при которой каждому значению переменной x соответствует единственное значение переменной y. Линейной функцией называют функцию, заданную формулой y=kx+b, где k — угловой коэффициент, b — свободный член (сдвиг).\n\nГрафиком линейной функции всегда является прямая. Чтобы построить прямую, достаточно найти координаты двух её точек и провести через них прямую линию.\n\nПример: построим график y=2x+1. При x=0, y=1 — точка (0;1); при x=1, y=3 — точка (1;3); при x=-1, y=-1 — точка (-1;-1). Отметим точки и соединим прямой.\n\nЧисло b показывает, в какой точке прямая пересекает ось Oy: при x=0, y=k·0+b=b, значит точка (0;b) всегда лежит на графике.\n\nЧисло k определяет наклон и направление прямой: если k>0, функция возрастает (прямая идёт снизу вверх слева направо); если k<0, функция убывает; если k=0, график — горизонтальная прямая y=b; чем больше |k|, тем круче прямая, чем меньше |k| — тем более пологая прямая.\n\nЧастный случай — функция y=kx (при b=0) — её график всегда проходит через начало координат (0;0).\n\nОсобый случай — прямая x=c не является графиком функции в привычном смысле, так как одному x соответствует бесконечно много y — эта запись не имеет вида y=kx+b.\n\nДве прямые y=k1x+b1 и y=k2x+b2 называют параллельными, если k1=k2, но b1≠b2 — тогда прямые не пересекаются. Если k1≠k2, прямые обязательно пересекаются в одной точке.\n\nПример: прямые y=3x+2 и y=3x-5 параллельны (k=3 у обеих), а прямые y=2x+1 и y=-x+4 пересекаются, поскольку их угловые коэффициенты различны.\n\nПонимание линейной функции открывает путь к следующей теме — системам линейных уравнений с двумя переменными, где нам предстоит находить точку пересечения двух таких прямых.","quiz":[{"question":"Какую фигуру задаёт график линейной функции y=kx+b?","options":["прямую линию","параболу","окружность","ломаную"],"correctIndex":0},{"question":"В какой точке график функции y=3x+5 пересекает ось Oy?","options":["(0;5)","(5;0)","(0;3)","(3;0)"],"correctIndex":0},{"question":"При каком условии функция y=kx+b является возрастающей?","options":["k>0","k<0","k=0","b>0"],"correctIndex":0},{"question":"Через какую точку всегда проходит график функции y=kx (при b=0)?","options":["(0;0)","(1;1)","(0;k)","(k;0)"],"correctIndex":0},{"question":"Какая из прямых параллельна прямой y=4x-2?","options":["y=4x+7","y=-4x-2","y=2x-2","y=4-x"],"correctIndex":0},{"question":"Чему равно значение y при x=2 для функции y=-2x+3?","options":["-1","1","7","-7"],"correctIndex":0},{"question":"Что представляет собой график функции y=5 (при k=0)?","options":["горизонтальную прямую","вертикальную прямую","точку","параболу"],"correctIndex":0},{"question":"Пересекаются ли прямые y=2x+1 и y=2x-3?","options":["да, в одной точке","нет, они параллельны","да, в двух точках","они совпадают"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-22T08:30:00+05:00","ends_at":"2026-07-22T09:15:00+05:00","room":"204"},{"topic":"Системы двух линейных уравнений с двумя переменными","objective":"Научиться решать системы двух линейных уравнений с двумя переменными графическим способом и способом подстановки.","theory":"Системой двух линейных уравнений с двумя переменными называют пару уравнений {a1x+b1y=c1; a2x+b2y=c2}, для которых нужно найти значения x и y, одновременно удовлетворяющие обоим уравнениям. Решением системы называют пару чисел (x;y), обращающую оба уравнения в верные равенства.\n\nПервый способ — графический. Каждое уравнение, если выразить y через x, задаёт прямую на координатной плоскости. Решением системы является точка пересечения этих прямых — только в ней координаты удовлетворяют обоим уравнениям.\n\nПример: решим графически систему {y=x+1; y=-x+3}. Первая прямая проходит через (0;1) и (1;2), вторая — через (0;3) и (1;2). Прямые пересекаются в точке (1;2). Проверка: 2=1+1 — верно; 2=-1+3 — верно.\n\nВозможны три случая расположения прямых: 1) прямые пересекаются в одной точке — единственное решение (разные угловые коэффициенты); 2) прямые параллельны и не совпадают — решений нет; 3) прямые совпадают — бесконечно много решений.\n\nГрафический способ нагляден, но не всегда точен, особенно при дробных координатах, поэтому чаще применяют способ подстановки: из одного уравнения выражают одну переменную через другую и подставляют это выражение во второе уравнение, получая уравнение с одной переменной.\n\nПример: {y=2x-1; 3x+y=9}. Подставим y=2x-1 во второе уравнение: 3x+(2x-1)=9, 5x-1=9, 5x=10, x=2. Тогда y=2·2-1=3. Решение: (2;3). Проверка: 3·2+3=9 — верно.\n\nЕщё пример: {x+y=7; 2x-y=2}. Из первого уравнения y=7-x. Подставим во второе: 2x-(7-x)=2, 3x-7=2, 3x=9, x=3, y=7-3=4. Решение: (3;4).\n\nСистемы линейных уравнений применяются для решения текстовых задач с двумя неизвестными: на движение, на смеси и сплавы, на совместную работу. Освоение этого способа завершает блок «Выражения, уравнения и функции» и готовит основу для более сложных систем и функций в следующих классах.","quiz":[{"question":"Что является решением системы двух линейных уравнений с двумя переменными?","options":["пара чисел (x;y), удовлетворяющая обоим уравнениям","любое число x","только значение y","все точки одной из прямых"],"correctIndex":0},{"question":"Чем графически является решение системы двух линейных уравнений?","options":["точкой пересечения графиков","серединой отрезка между прямыми","точкой пересечения с осью Ox","угловым коэффициентом прямой"],"correctIndex":0},{"question":"Сколько решений имеет система, если прямые уравнений параллельны и не совпадают?","options":["одно","ни одного","бесконечно много","два"],"correctIndex":1},{"question":"Сколько решений имеет система, если прямые совпадают?","options":["одно","ни одного","бесконечно много","три"],"correctIndex":2},{"question":"Решите систему способом подстановки: {y=x+2; x+y=8}","options":["(3;5)","(5;3)","(2;6)","(4;4)"],"correctIndex":0},{"question":"Решите систему: {y=3x; 2x+y=10}","options":["(2;6)","(6;2)","(1;3)","(2;3)"],"correctIndex":0},{"question":"Какой первый шаг в способе подстановки?","options":["выразить одну переменную через другую из одного уравнения","построить графики обеих прямых","сложить оба уравнения почленно","умножить оба уравнения на число"],"correctIndex":0},{"question":"Прямые двух уравнений системы имеют разные угловые коэффициенты. Сколько решений у системы?","options":["ни одного","ровно одно","бесконечно много","невозможно определить"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"desmos","externalServiceTask":"В Desmos постройте графики двух уравнений системы {y=x+1; y=-x+3}, используя ползунки измените коэффициенты в уравнениях и найдите координаты точки пересечения графиков — сравните результат с решением, полученным способом подстановки.","starts_at":"2026-07-23T11:15:00+05:00","ends_at":"2026-07-23T12:00:00+05:00","room":"204"}]'::jsonb)
    LOOP
      INSERT INTO public.lessons (group_id, subject_id, topic, title, description, status, starts_at, ends_at, started_at, ended_at, room, school_id)
      VALUES (
        v_group_id, v_subject_id, lesson_data->>'topic', lesson_data->>'topic', lesson_data->>'objective',
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN 'completed' ELSE 'scheduled' END,
        (lesson_data->>'starts_at')::timestamptz, (lesson_data->>'ends_at')::timestamptz,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'starts_at')::timestamptz ELSE NULL END,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'ends_at')::timestamptz ELSE NULL END,
        lesson_data->>'room', v_school_id
      )
      RETURNING id INTO v_lesson_id;

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, duration_min, school_id)
      VALUES (v_lesson_id, 1, 'middle', 'theory', 'presentation', lesson_data->>'topic', lesson_data->>'theory', 15, v_school_id);

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, duration_min, school_id)
      VALUES (v_lesson_id, 2, 'middle', 'task', 'quiz_qia', 'Проверь себя', 15, v_school_id)
      RETURNING id INTO v_stage_id;

      qpos := 0;
      FOR quiz_item IN SELECT * FROM jsonb_array_elements(lesson_data->'quiz')
      LOOP
        qpos := qpos + 1;
        INSERT INTO public.quiz_questions (stage_id, question_text, options, correct_option_index, position, points, time_per_question_seconds, school_id)
        VALUES (v_stage_id, quiz_item->>'question', quiz_item->'options', (quiz_item->>'correctIndex')::int, qpos, 1, 30, v_school_id);
      END LOOP;

      IF (lesson_data->>'hasExternalService')::boolean THEN
        INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, config, duration_min, school_id)
        VALUES (
          v_lesson_id, 3, 'middle', 'task', lesson_data->>'externalServiceType',
          lesson_data->>'externalServiceTask', lesson_data->>'externalServiceTask',
          jsonb_build_object('url',
            CASE lesson_data->>'externalServiceType'
              WHEN 'wokwi' THEN 'https://wokwi.com/projects/new/arduino-uno'
              WHEN 'codesandbox' THEN 'https://codesandbox.io/p/sandbox/vanilla'
              WHEN 'geogebra' THEN 'https://www.geogebra.org/classic'
              WHEN 'phet' THEN 'https://phet.colorado.edu/sims/html/forces-and-motion-basics/latest/forces-and-motion-basics_en.html'
              WHEN 'desmos' THEN 'https://www.desmos.com/calculator'
              WHEN 'blockly_games' THEN 'https://blockly.games/'
              WHEN 'visualgo' THEN 'https://visualgo.net/en'
              WHEN 'p5js' THEN 'https://editor.p5js.org/'
              WHEN 'excalidraw' THEN 'https://excalidraw.com/'
              WHEN 'learningapps' THEN 'https://learningapps.org/'
              WHEN 'sqlonline' THEN 'https://sqlime.org/'
              WHEN 'h5p' THEN 'https://h5p.eduos.snruz.uz/library'
              ELSE NULL
            END
          ),
          15, v_school_id
        );
      END IF;
    END LOOP;
  END IF;

  -- === 7-А класс | Английский язык (11 уроков) ===
  SELECT id INTO v_group_id FROM public.groups WHERE name = '7-А класс';
  SELECT id INTO v_subject_id FROM public.subjects WHERE group_id = v_group_id AND name = 'Английский язык';
  IF NOT EXISTS (SELECT 1 FROM public.lessons WHERE group_id = v_group_id AND subject_id = v_subject_id AND description IS NOT NULL) THEN
    FOR lesson_data IN SELECT * FROM jsonb_array_elements('[{"topic":"Present Perfect: базовое употребление","objective":"Научиться образовывать и использовать Present Perfect для выражения действий, связанных с настоящим моментом.","theory":"Present Perfect (настоящее совершённое время) показывает связь прошлого действия с настоящим моментом. Мы используем его, когда действие уже произошло, но результат важен сейчас, или когда точное время действия неизвестно либо неважно.\n\nОбразование: подлежащее + have/has + причастие прошедшего времени (Past Participle, 3-я форма глагола). Для I, You, We, They используем have, для He, She, It — has.\n\nПримеры: I have finished my homework. She has visited London twice. We haven''t seen this film. Have you ever eaten sushi?\n\nПричастие прошедшего времени образуется двумя способами: у правильных глаголов добавляется -ed (finish → finished, play → played), у неправильных — берётся третья форма из таблицы (go → gone, see → seen, eat → eaten, write → written, do → done).\n\nКлючевые слова-маркеры: already (уже) — перед глаголом: I have already done it; just (только что) — перед глаголом: She has just arrived; yet (ещё) — в вопросах и отрицаниях, в конце предложения: Have you finished yet? I haven''t finished yet; ever (когда-либо) — в вопросах: Have you ever been to Paris?; never (никогда) — в утверждениях: I have never tried skiing.\n\nВажно: Present Perfect не указывает точное время действия. Если названо точное время (вчера, в 2020 году), нужно использовать Past Simple: неправильно \"I have visited London yesterday\", правильно \"I visited London yesterday\".\n\nВопросительная форма строится инверсией: Have/Has + подлежащее + причастие? Has she called you?\nОтрицательная форма: have/has + not (haven''t/hasn''t) + причастие: They haven''t done their project yet.\n\nPresent Perfect часто используется для рассказа о жизненном опыте, о недавно завершённых действиях с видимым результатом и в новостях, когда важен сам факт события. Запомните структуру и слова-сигналы — они помогут правильно выбирать между Present Perfect и Past Simple в следующих уроках.","quiz":[{"question":"Choose the correct form: \"She ___ her homework already.\"","options":["has finish","has finished","have finished","finished"],"correctIndex":1},{"question":"Which word usually goes at the END of a Present Perfect question or negative sentence?","options":["already","just","yet","ever"],"correctIndex":2},{"question":"Complete: \"I ___ never ___ sushi before.\"","options":["have / eat","have / eaten","has / eaten","has / eat"],"correctIndex":1},{"question":"What is the Past Participle (3rd form) of \"go\"?","options":["went","gone","going","goes"],"correctIndex":1},{"question":"Choose correct: \"___ you ever been to London?\"","options":["Do","Did","Have","Has"],"correctIndex":2},{"question":"Which sentence is correct?","options":["I have visited my grandmother yesterday.","I visited my grandmother yesterday.","I have visit my grandmother yesterday.","I has visited my grandmother yesterday."],"correctIndex":1},{"question":"Fill: \"He ___ just ___ his room.\"","options":["have/cleaned","has/cleaned","has/clean","have/clean"],"correctIndex":1},{"question":"Choose the correct auxiliary: \"They ___ not finished the test.\"","options":["has","have","is","are"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-07T12:10:00+05:00","ends_at":"2026-07-07T12:55:00+05:00","room":"204"},{"topic":"Present Perfect и Past Simple: в чём разница","objective":"Научиться различать и правильно выбирать между Present Perfect и Past Simple в речи.","theory":"На прошлом уроке мы изучили Present Perfect. Теперь сравним его с Past Simple, которое вы уже знаете. Оба времени говорят о прошлом, но используются по-разному.\n\nPast Simple используется, когда мы точно знаем или называем время действия: вчера, на прошлой неделе, в 2010 году. Действие полностью завершено и не связано напрямую с настоящим. Пример: I visited my grandmother last Sunday.\n\nPresent Perfect используется, когда время не важно или неизвестно, а важен результат или сам факт того, что действие произошло, и это связано с настоящим. Пример: I have visited my grandmother.\n\nСравните пары: Past Simple — I lost my keys yesterday (указано время); Present Perfect — I have lost my keys (неизвестно когда, но сейчас ключей нет — результат важен сейчас). Past Simple — She wrote three letters last month; Present Perfect — She has written three letters this month (месяц ещё не закончился).\n\nМаркеры времени: Past Simple — yesterday, last week/month/year, ago, in 2005, when I was young. Present Perfect — already, just, yet, ever, never, this week/month/year (если период не закончился), so far, recently.\n\nОсобый случай: since (с какого-то момента) и for (в течение) сигнализируют о Present Perfect: I have lived here since 2015. I have known him for five years.\n\nСтруктурная разница: Past Simple — подлежащее + глагол в прошедшем времени (I played, she went); Present Perfect — подлежащее + have/has + 3-я форма (I have played, she has gone).\n\nТипичная ошибка — смешивать конкретное указание времени с Present Perfect. Если в предложении есть точное время в прошлом, используйте только Past Simple. Задавайте себе вопрос: важно ли КОГДА это произошло, или важно, ЧТО произошло и как это влияет на настоящее? Первый случай — Past Simple, второй — Present Perfect.","quiz":[{"question":"\"I ___ this book last year.\"","options":["have read","read","has read","am reading"],"correctIndex":1},{"question":"\"She ___ her homework already.\"","options":["did","has done","done","do"],"correctIndex":1},{"question":"Which time marker is typically used with Past Simple?","options":["yesterday","already","just","yet"],"correctIndex":0},{"question":"Which time marker is typically used with Present Perfect (not Past Simple)?","options":["last week","two days ago","since 2018","in 1995"],"correctIndex":2},{"question":"\"We ___ to Paris in 2019.\"","options":["have been","went","has gone","go"],"correctIndex":1},{"question":"Choose the correct sentence:","options":["I have seen that movie yesterday.","I saw that movie yesterday.","I have see that movie yesterday.","I seen that movie yesterday."],"correctIndex":1},{"question":"\"He ___ football for two hours yesterday.\"","options":["has played","played","has been playing","play"],"correctIndex":1},{"question":"Fill: \"___ you finish your project yet?\"","options":["Did","Have","Has","Do"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"learningapps","externalServiceTask":"Пройти интерактивное упражнение LearningApps на сортировку предложений по временам Present Perfect и Past Simple.","starts_at":"2026-07-09T08:30:00+05:00","ends_at":"2026-07-09T09:15:00+05:00","room":"204"},{"topic":"Present Perfect Continuous: длительность действия","objective":"Научиться образовывать Present Perfect Continuous и использовать его для описания длительных действий, начавшихся в прошлом и продолжающихся сейчас.","theory":"Present Perfect Continuous показывает действие, которое началось в прошлом и продолжается до сих пор, подчёркивая его ДЛИТЕЛЬНОСТЬ, процесс.\n\nОбразование: подлежащее + have/has + been + глагол с окончанием -ing. I/You/We/They + have been + V-ing; He/She/It + has been + V-ing.\n\nПримеры: I have been studying English for three years. She has been waiting for the bus for twenty minutes. It has been raining since morning.\n\nЭто время часто используется с предлогами for (в течение — for two hours) и since (с какого-то момента — since Monday, since 2020), которые указывают на длительность действия.\n\nРазница между Present Perfect Simple и Continuous: Simple подчёркивает РЕЗУЛЬТАТ: I have written five letters (готово пять писем). Continuous подчёркивает ПРОЦЕСС: I have been writing letters all morning (важен процесс, возможно, не закончил).\n\nСравните: He has painted the wall (стена покрашена — результат виден) vs He has been painting the wall (он занимался покраской, возможно, ещё не закончил).\n\nВопросительная форма: Have/Has + подлежащее + been + V-ing? How long have you been learning English? Has she been crying?\nОтрицательная форма: have/has + not + been + V-ing: I haven''t been feeling well lately.\n\nВажно: глаголы состояния (know, like, love, want, believe, understand) обычно не используются в длительных формах, включая эту. С ними используется только Present Perfect Simple: I have known her for ten years (не \"have been knowing\").\n\nPresent Perfect Continuous особенно полезен, чтобы спросить или рассказать, КАК ДОЛГО что-то происходит: How long have you been living in this city? — I have been living here since I was born. Запомните формулу have/has + been + V-ing и обращайте внимание на предлоги for и since — они почти всегда сигнализируют об этом времени.","quiz":[{"question":"Structure: subject + ___ + been + V-ing.","options":["do/does","have/has","did","will"],"correctIndex":1},{"question":"\"I ___ for the bus for 20 minutes.\"","options":["have waiting","have been waiting","has been waiting","waited"],"correctIndex":1},{"question":"Which preposition means \"starting from a specific point in time\"?","options":["for","since","ago","yet"],"correctIndex":1},{"question":"Which preposition means \"duration\" (a period of time)?","options":["since","ago","for","yet"],"correctIndex":2},{"question":"\"It ___ raining since morning.\"","options":["is","has","has been","have been"],"correctIndex":2},{"question":"Which verb is usually NOT used in continuous forms?","options":["run","know","play","write"],"correctIndex":1},{"question":"Choose the correct question:","options":["How long have you been study English?","How long you have been studying English?","How long have you been studying English?","How long has you been studying English?"],"correctIndex":2}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-10T10:20:00+05:00","ends_at":"2026-07-10T11:05:00+05:00","room":"204"},{"topic":"Модальные глаголы: must, have to, should","objective":"Научиться выражать обязанность, необходимость и совет с помощью модальных глаголов must, have to и should.","theory":"Модальные глаголы — особые вспомогательные глаголы, выражающие отношение говорящего к действию: обязанность, совет, возможность, разрешение. Разберём must, have to и should.\n\nMUST выражает сильную обязанность, часто личное мнение говорящего о важности и необходимости. После must глагол стоит в начальной форме без to. Пример: You must wear a helmet when riding a bike. Отрицание \"must not/mustn''t\" означает ЗАПРЕТ: You mustn''t smoke here.\n\nHAVE TO тоже выражает обязанность, но чаще указывает на внешние правила, обстоятельства, а не личное мнение говорящего. Пример: I have to wear a uniform at school. Изменяется по лицам и временам: I/You/We/They have to, He/She/It has to; в прошедшем — had to, в будущем — will have to. Отрицание \"don''t have to/doesn''t have to\" означает ОТСУТСТВИЕ необходимости (не запрет!): You don''t have to come if you''re busy.\n\nВажное отличие: mustn''t (запрещено) и don''t have to (необязательно) — РАЗНЫЕ значения. Сравните: You mustn''t use your phone during the exam (запрещено!) vs You don''t have to bring a pen, we have spare ones (необязательно, но можно).\n\nSHOULD выражает совет, рекомендацию — что было бы правильно сделать, но необязательство. Пример: You should drink more water. Отрицание: shouldn''t — You shouldn''t eat too much sugar. После should тоже используется глагол без to.\n\nСила модальных глаголов от сильного к мягкому: must (сильная необходимость/личное мнение) → have to (обязанность по правилам) → should (совет).\n\nВопросы: Do you have to work on weekends? Should I call the doctor? Must и should не меняют форму по лицам (He must go, She should rest), а have to изменяется как обычный глагол (has to). Модальные глаголы помогают выразить, насколько что-то важно, обязательно или желательно.","quiz":[{"question":"Which modal expresses a strong prohibition (запрет)?","options":["should","mustn''t","don''t have to","might"],"correctIndex":1},{"question":"Which phrase means \"it''s not necessary\"?","options":["must","mustn''t","don''t have to","should"],"correctIndex":2},{"question":"\"You ___ wear a seatbelt in the car.\" (an external rule)","options":["should","have to","might","could"],"correctIndex":1},{"question":"Choose the correct form for \"he\": \"He ___ finish his homework before dinner.\"","options":["have to","has to","having to","had"],"correctIndex":1},{"question":"\"You ___ eat so much junk food.\" (advice)","options":["shouldn''t","mustn''t","don''t have to","can''t"],"correctIndex":0},{"question":"Which modal is followed by a bare infinitive (without \"to\")?","options":["have to","need to","must","ought to"],"correctIndex":2},{"question":"\"___ you have to wear a uniform at your school?\"","options":["Must","Do","Does","Are"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-13T10:20:00+05:00","ends_at":"2026-07-13T11:05:00+05:00","room":"204"},{"topic":"Модальные глаголы: can, could, may, might","objective":"Научиться использовать can, could, may и might для выражения возможности, разрешения и предположения.","theory":"Продолжаем изучать модальные глаголы: can, could, may, might, которые выражают возможность, разрешение и вероятность.\n\nCAN используется для: 1) умения/способности — I can swim; 2) разрешения (неформально) — Can I open the window?; 3) возможности в целом — It can be very cold in winter here. Отрицание: cannot/can''t — I can''t ride a bike.\n\nCOULD — прошедшая форма can (умение в прошлом), а также более вежливая форма для просьб и предположений. 1) Умение в прошлом: When I was five, I could already read. 2) Вежливая просьба: Could you help me, please? — вежливее, чем Can you help me? 3) Предположение о возможности: It could rain later — не уверенность, а вероятность.\n\nMAY используется для: 1) формального разрешения — May I come in? (более вежливо и официально, чем can); 2) предположения о вероятности — She may be at home now. Отрицание: may not — It may not rain today.\n\nMIGHT похож на may, но выражает МЕНЬШУЮ уверенность, более слабую вероятность. Пример: He might come to the party, but I''m not sure. Might часто используется вместо may в разговорной речи: It might snow tomorrow.\n\nСравнение уверенности при предположениях от большей к меньшей: must (почти на 100%) → will → may → might/could (менее уверен). Пример: She must be tired (я почти уверен) vs She might be tired (возможно, но не уверен).\n\nВажно не путать разрешение и возможность: Can I use your pen? — прошу разрешения; It can be dangerous to swim here — говорю о возможности/факте.\n\nВсе эти модальные глаголы не меняются по лицам (He can, she may, it might) и после них глагол используется без частицы to. В вопросах модальный глагол ставится перед подлежащим: Can you help me? May I ask a question? Запомните: can/could — умение и обычные просьбы; may/might — вежливость и предположения о вероятности, где might выражает наименьшую уверенность.","quiz":[{"question":"Which modal expresses ability in the past?","options":["can","could","may","must"],"correctIndex":1},{"question":"Which is the MOST polite/formal way to ask permission?","options":["Can I come in?","Could I come in?","May I come in?","Might I come in?"],"correctIndex":2},{"question":"\"It ___ rain later, I''m not sure.\" (weak possibility)","options":["must","will","might","can"],"correctIndex":2},{"question":"\"I ___ swim when I was five.\"","options":["can","could","may","must"],"correctIndex":1},{"question":"Which shows STRONGER certainty about a guess?","options":["might","could","must","may"],"correctIndex":2},{"question":"\"___ you help me carry this bag?\" (polite request)","options":["Must","Could","Do","Are"],"correctIndex":1},{"question":"Choose the correct sentence:","options":["She can speaks French.","She cans speak French.","She can speak French.","She can to speak French."],"correctIndex":2}],"hasExternalService":true,"externalServiceType":"h5p","externalServiceTask":"Выполнить интерактивное упражнение H5P на выбор правильного модального глагола (can/could/may/might) в диалогах о разрешении и предположениях.","starts_at":"2026-07-14T12:10:00+05:00","ends_at":"2026-07-14T12:55:00+05:00","room":"204"},{"topic":"Пассивный залог — Часть 1 (Present, Past)","objective":"Научиться образовывать и использовать страдательный залог (Passive Voice) в Present Simple и Past Simple.","theory":"В английском языке есть два залога: активный (Active Voice) — подлежащее само выполняет действие, и пассивный (Passive Voice) — подлежащее испытывает действие на себе.\n\nСравните: Active — The teacher checks our homework (учитель выполняет действие); Passive — Our homework is checked by the teacher (важнее сам предмет, а не исполнитель).\n\nПассив используется, когда: 1) неважно или неизвестно, кто выполняет действие — The window was broken; 2) важен сам предмет действия — This book was written in 1997; 3) в официальном, научном стиле — Rules must be followed.\n\nОбразование: подлежащее + глагол to be (в нужном времени) + Past Participle (3-я форма глагола).\n\nPresent Simple Passive: am/is/are + V3. Active: They make cars in this factory → Passive: Cars are made in this factory. Active: Everyone speaks English here → Passive: English is spoken here.\n\nPast Simple Passive: was/were + V3. Active: Someone stole my bike yesterday → Passive: My bike was stolen yesterday. Active: Workers built this house in 1990 → Passive: This house was built in 1990.\n\nWas используется с единственным числом, were — с множественным.\n\nЕсли нужно указать исполнителя, используется предлог BY: This picture was painted by Picasso. Но чаще исполнитель вообще не упоминается, так как он неважен или очевиден.\n\nОтрицательная форма: to be + not + V3 — The letter wasn''t sent yesterday.\nВопросительная форма: to be + подлежащее + V3? — Is this room cleaned every day? Was the bridge built recently?\n\nЧтобы превратить активное предложение в пассивное: 1) дополнение из активного предложения становится подлежащим; 2) ставится to be в нужном времени; 3) смысловой глагол берётся в 3-й форме; 4) при необходимости добавляется \"by + исполнитель\". Запомните эту формулу — в следующем уроке продолжим изучать пассив в других временах.","quiz":[{"question":"Passive form structure: subject + to be + ?","options":["make","made (V3)","making","makes"],"correctIndex":1},{"question":"\"English ___ in many countries.\"","options":["speaks","is spoken","spoke","speak"],"correctIndex":1},{"question":"\"This house ___ in 1990.\"","options":["built","was built","is built","builds"],"correctIndex":1},{"question":"Which word introduces the \"doer\" of the action in passive sentences?","options":["with","from","by","to"],"correctIndex":2},{"question":"Choose the correct passive sentence:","options":["The cake made by my mother.","The cake is made by my mother.","The cake making by my mother.","The cake makes by my mother."],"correctIndex":1},{"question":"\"My bike ___ yesterday.\"","options":["is stolen","was stolen","stole","steals"],"correctIndex":1},{"question":"Active: \"They clean the classroom every day.\" Passive:","options":["The classroom cleans every day.","The classroom is cleaned every day.","The classroom was cleaned every day.","The classroom cleaned every day."],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-16T08:30:00+05:00","ends_at":"2026-07-16T09:15:00+05:00","room":"204"},{"topic":"Пассивный залог — Часть 2 (будущее время, модальные глаголы)","objective":"Научиться образовывать пассивный залог в Future Simple и с модальными глаголами.","theory":"В прошлом уроке мы изучили пассивный залог в Present Simple и Past Simple. Теперь рассмотрим, как образуется пассив в будущем времени и с модальными глаголами.\n\nFuture Simple Passive: will + be + V3. Active: They will build a new school next year → Passive: A new school will be built next year. Active: The company will announce the results tomorrow → Passive: The results will be announced tomorrow.\n\nКонструкция одинакова для всех лиц — will be + V3, без изменений по лицам.\n\nОтрицательная форма: will not (won''t) + be + V3 — The project won''t be finished by Friday.\nВопросительная форма: Will + подлежащее + be + V3? — Will the letter be sent today?\n\nПассив с модальными глаголами: модальный глагол (must, can, should, may, might, have to) + be + V3.\n\nПримеры: Active: You must finish this report today → Passive: This report must be finished today. Active: You can solve this problem easily → Passive: This problem can be solved easily. Active: We should recycle plastic → Passive: Plastic should be recycled. Active: They have to repair the road → Passive: The road has to be repaired.\n\nФормула: subject + modal verb + be + V3. После модального глагола ВСЕГДА идёт \"be\" в начальной форме, а не is/was/are.\n\nПочему используем пассив с модальными глаголами? По тем же причинам: когда неважно, кто должен выполнить действие, а важно само правило или требование. Это часто встречается в правилах, инструкциях и объявлениях: Seatbelts must be worn at all times. This medicine should be taken twice a day. Mistakes can be corrected easily.\n\nОбщая схема пассива для всех времён: [подлежащее] + [форма to be или модальный глагол + be] + [V3] + (by + исполнитель, если нужно). Понимание пассива помогает читать научные тексты, инструкции, новости и официальные документы, где часто неважно, кто именно выполняет действие.","quiz":[{"question":"Future Passive formula:","options":["will + V3","will + be + V3","was + V3","is + V3"],"correctIndex":1},{"question":"\"A new school ___ next year.\"","options":["will build","will be built","builds","is building"],"correctIndex":1},{"question":"Passive with a modal verb formula:","options":["modal + been + V3","modal + be + V3","modal + V3","modal + being + V3"],"correctIndex":1},{"question":"Active: \"You must finish this report today.\" Passive:","options":["This report must finished today.","This report must be finish today.","This report must be finished today.","This report must being finished today."],"correctIndex":2},{"question":"\"Plastic ___ recycled.\" (should, passive)","options":["should be","should","is should be","should being"],"correctIndex":0},{"question":"Choose the correct sentence:","options":["The letter will sent tomorrow.","The letter will be sent tomorrow.","The letter is sent tomorrow.","The letter will be send tomorrow."],"correctIndex":1},{"question":"\"This medicine ___ twice a day.\" (should, passive)","options":["should take","should be taken","should taken","should be take"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-17T10:20:00+05:00","ends_at":"2026-07-17T11:05:00+05:00","room":"204"},{"topic":"Условные предложения 1 типа (First Conditional)","objective":"Научиться строить и использовать условные предложения первого типа для реальных ситуаций в будущем.","theory":"Условные предложения (Conditional Sentences) описывают ситуацию \"если... то...\". Сегодня изучаем Первый тип (First Conditional) — для реальных, возможных ситуаций в будущем.\n\nФормула: If + Present Simple, ... will + инфинитив (без to). Пример: If it rains tomorrow, we will stay at home.\n\nПредложение состоит из двух частей: условие (if-clause) — If it rains..., и результат (main clause) — ...we will stay at home. Части можно менять местами. Если предложение начинается с if-части, после неё ставится запятая: If you study hard, you will pass the exam. Если начинается с главной части, запятая не нужна: You will pass the exam if you study hard.\n\nВажное правило: в if-части НИКОГДА не используется will, даже если речь о будущем! Используется Present Simple. Неправильно: If it will rain, we will stay home. Правильно: If it rains, we will stay home.\n\nПримеры: If I finish my homework early, I will watch a movie. If you don''t hurry, you will miss the bus. She will be angry if you forget her birthday. If they win the match, they will celebrate.\n\nFirst Conditional используется, когда говорящий считает ситуацию реальной и вполне возможной — реалистичным сценарием, а не фантазией.\n\nВместо will иногда можно использовать другие модальные глаголы в главной части: If you finish early, you can go home (разрешение). If it rains, we should take an umbrella (совет). If you study, you may pass the exam (возможность).\n\nОтрицательная форма в if-части: if + don''t/doesn''t + глагол — If you don''t wear a coat, you will catch a cold. Отрицательная форма в главной части: won''t + инфинитив — If you don''t hurry, you won''t catch the train.\n\nЗапомните главное правило: if-часть — Present Simple, главная часть — will + инфинитив. Использование will в обеих частях — одна из самых частых ошибок учеников.","quiz":[{"question":"First Conditional formula:","options":["If + will, will","If + Present Simple, will + infinitive","If + Past Simple, would","If + Present Perfect, will"],"correctIndex":1},{"question":"\"If it ___ tomorrow, we will stay home.\"","options":["will rain","rains","rained","is raining"],"correctIndex":1},{"question":"Choose the correct sentence:","options":["If it will rain, we will stay home.","If it rains, we will stay home.","If it rains, we stay home will.","If rains it, we will stay home."],"correctIndex":1},{"question":"\"If you don''t hurry, you ___ the bus.\"","options":["will miss","miss","missed","won''t miss"],"correctIndex":0},{"question":"What kind of situation does First Conditional describe?","options":["Impossible fantasy","Real, possible future situation","Past regret","Unreal present"],"correctIndex":1},{"question":"\"She will be angry if you ___ her birthday.\"","options":["will forget","forget","forgot","forgetting"],"correctIndex":1},{"question":"Complete: \"If you study hard, you ___ pass the exam.\"","options":["pass","will pass","passed","passing"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"learningapps","externalServiceTask":"Пройти упражнение LearningApps на составление условных предложений 1 типа (if + Present Simple, will + infinitive).","starts_at":"2026-07-20T10:20:00+05:00","ends_at":"2026-07-20T11:05:00+05:00","room":"204"},{"topic":"Условные предложения 2 типа (Second Conditional)","objective":"Научиться строить условные предложения второго типа для описания нереальных или маловероятных ситуаций в настоящем или будущем.","theory":"Мы уже знаем First Conditional — для реальных возможных ситуаций. Теперь изучим Second Conditional — он используется для НЕРЕАЛЬНЫХ, воображаемых, маловероятных ситуаций в настоящем или будущем.\n\nФормула: If + Past Simple, ... would + инфинитив (без to). Пример: If I had a million dollars, I would buy a big house (если бы у меня был миллион долларов — это фантазия).\n\nВажно понять: несмотря на использование Past Simple в if-части, речь идёт НЕ о прошлом, а о настоящем или будущем — просто о нереальной, гипотетической ситуации.\n\nСравните: First Conditional (реально) — If it rains, I will take an umbrella; Second Conditional (нереально) — If I were a bird, I would fly around the world.\n\nОсобое правило: с глаголом to be в Second Conditional для всех лиц (включая I, he, she, it) традиционно используется форма WERE, а не was: If I were you, I would apologize. If she were taller, she would join the basketball team. В разговорной речи иногда говорят \"was\", но в правильной речи используется were для всех лиц.\n\nПримеры: If I won the lottery, I would travel around the world. If he studied more, he would get better grades (сейчас он не учится усердно). We would help you if we had more time (сейчас у нас нет времени). If they lived closer, we would see them more often.\n\nКонструкция \"If I were you, I would...\" — частая фраза для дачи совета: If I were you, I would talk to the teacher. If I were you, I wouldn''t buy that phone.\n\nОтрицательная форма в if-части: if + didn''t + глагол — If it didn''t rain so much, we would go for a walk. Отрицательная форма в главной части: wouldn''t + инфинитив — If I had more money, I wouldn''t worry so much.\n\nКлючевое отличие от First Conditional: реальная возможность (Present Simple + will) против нереальной фантазии (Past Simple + would). Past Simple в if-части Second Conditional НЕ означает прошедшее время — это грамматическая особенность, показывающая нереальность ситуации в настоящем.","quiz":[{"question":"Second Conditional formula:","options":["If + Present Simple, will","If + Past Simple, would + infinitive","If + will, would","If + Past Perfect, would have"],"correctIndex":1},{"question":"\"If I ___ a million dollars, I would buy a house.\"","options":["have","had","will have","has"],"correctIndex":1},{"question":"Which form of \"to be\" is traditionally used for all persons in Second Conditional?","options":["was","is","were","be"],"correctIndex":2},{"question":"\"If I ___ you, I would apologize.\"","options":["am","was","were","be"],"correctIndex":2},{"question":"What kind of situation does Second Conditional describe?","options":["Real future possibility","Unreal/hypothetical present or future situation","Past fact","Habitual action"],"correctIndex":1},{"question":"\"If he studied more, he ___ better grades.\"","options":["will get","would get","gets","got"],"correctIndex":1},{"question":"Choose the correct sentence:","options":["If I won the lottery, I will travel the world.","If I win the lottery, I would travel the world.","If I won the lottery, I would travel the world.","If I would win the lottery, I travel the world."],"correctIndex":2}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-21T12:10:00+05:00","ends_at":"2026-07-21T12:55:00+05:00","room":"204"},{"topic":"Косвенная речь: утверждения (Reported Speech)","objective":"Научиться передавать чужие слова (утверждения) в косвенной речи с правильным сдвигом времён.","theory":"Когда мы пересказываем чужие слова, не цитируя их дословно, мы используем косвенную речь (Reported Speech). Сегодня разберём, как передавать утверждения (statements).\n\nПрямая речь (Direct Speech) — точные слова человека в кавычках: Tom said, \"I am tired.\" Косвенная речь (Reported Speech) — пересказ без кавычек, обычно с глаголом said (that): Tom said that he was tired.\n\nОбратите внимание на два изменения: 1) местоимение меняется (I → he); 2) время глагола сдвигается назад — Backshift.\n\nОсновное правило сдвига времён (если said/told стоит в прошедшем): Present Simple → Past Simple: \"I like pizza\" → He said he liked pizza. Present Continuous → Past Continuous: \"I am reading\" → She said she was reading. Present Perfect → Past Perfect: \"I have finished\" → He said he had finished. Past Simple → Past Perfect: \"I visited Paris\" → She said she had visited Paris. will → would: \"I will help you\" → He said he would help me. can → could: \"I can swim\" → She said she could swim. must → had to: \"I must go\" → He said he had to go.\n\nСлово \"that\" после said часто опускается: He said that he was tired = He said he was tired.\n\nТакже меняются указатели места и времени: today → that day, tomorrow → the next day, yesterday → the day before, now → then, here → there, this → that.\n\nПример: Direct — \"I will finish this project tomorrow,\" she said. Reported — She said (that) she would finish that project the next day.\n\nРазличие между say и tell: say используется без указания слушателя либо с \"to someone\" (He said (to me) that he was busy); tell ВСЕГДА требует указания, кому сказали (He told me that he was busy — нельзя просто \"He told that...\").\n\nПримеры: \"I am learning English,\" said Anna → Anna said she was learning English. \"We have finished our homework,\" they said → They said they had finished their homework. \"I can''t come to the party,\" he said → He said he couldn''t come to the party. Косвенная речь важна для пересказа диалогов, новостей и историй — главное запомнить таблицу сдвига времён и менять местоимения по смыслу.","quiz":[{"question":"Direct: \"I am tired,\" he said. Reported:","options":["He said he is tired.","He said he was tired.","He said he has been tired.","He says he was tired."],"correctIndex":1},{"question":"Present Simple in reported speech shifts to:","options":["Present Continuous","Past Simple","Present Perfect","Future Simple"],"correctIndex":1},{"question":"\"will\" in reported speech becomes:","options":["would","will","could","shall"],"correctIndex":0},{"question":"Which verb ALWAYS needs an object (a person) after it?","options":["say","tell","speak","talk"],"correctIndex":1},{"question":"Direct: \"I have finished my homework,\" she said. Reported:","options":["She said she has finished her homework.","She said she finished her homework.","She said she had finished her homework.","She said she was finishing her homework."],"correctIndex":2},{"question":"\"Tomorrow\" in reported speech usually changes to:","options":["the next day","today","that day","yesterday"],"correctIndex":0},{"question":"Direct: \"I can swim,\" he said. Reported:","options":["He said he can swim.","He said he could swim.","He said he swims.","He said he would swim."],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-23T08:30:00+05:00","ends_at":"2026-07-23T09:15:00+05:00","room":"204"},{"topic":"Относительные придаточные (Relative Clauses)","objective":"Научиться объединять два простых предложения в одно с помощью относительных местоимений who, which, that, where.","theory":"Relative Clauses (определительные придаточные предложения) помогают объединить два простых предложения в одно, избегая повторов, и дать дополнительную информацию о человеке, предмете или месте.\n\nОтносительные местоимения: WHO — для людей: This is the girl who won the competition. WHICH — для предметов, животных, вещей: I read the book which you gave me. THAT — может заменять и who, и which, особенно в разговорной речи: This is the girl that won the competition. WHERE — для мест: This is the school where I study. WHOSE — для выражения принадлежности: That''s the boy whose bag was stolen.\n\nКак объединить два предложения: 1) I have a friend. + She lives in London. → I have a friend who lives in London. 2) This is the book. + I bought the book yesterday. → This is the book which I bought yesterday. 3) This is the town. + I was born in this town. → This is the town where I was born.\n\nОпределительные придаточные бывают двух типов. Defining (ограничительные) — дают важную информацию, без которой предложение теряет смысл; запятые НЕ ставятся: The man who called you is my uncle. Non-defining (описательные, необязательные) — дают дополнительную информацию, которую можно убрать без потери смысла; выделяются запятыми, и вместо that используется who/which: My brother, who lives in Tashkent, is a doctor.\n\nВ defining clauses местоимение who/which/that иногда можно опустить, если оно является дополнением (не подлежащим): The book (which/that) I bought is interesting — можно убрать. The girl who won the prize is my classmate — who здесь подлежащее, убрать нельзя.\n\nПримеры: The teacher who taught us history retired last year. The car which/that broke down belongs to my neighbour. This is the restaurant where we celebrated my birthday. That''s the student whose project won first prize.\n\nRelative Clauses делают речь более связной, взрослой и естественной — вместо двух коротких простых предложений строится одно грамотное сложное предложение, что особенно ценится на письме и в устных ответах.","quiz":[{"question":"Which relative pronoun is used for people?","options":["which","who","where","whose"],"correctIndex":1},{"question":"Which relative pronoun is used for places?","options":["who","which","where","that"],"correctIndex":2},{"question":"\"This is the book ___ you gave me.\"","options":["who","which","where","whose"],"correctIndex":1},{"question":"\"That''s the boy ___ bag was stolen.\" (possession)","options":["who","which","whose","where"],"correctIndex":2},{"question":"In defining clauses, when can the relative pronoun be omitted?","options":["When it''s the subject","When it''s the object","Never","Always"],"correctIndex":1},{"question":"Which type of clause uses commas?","options":["Defining clause","Non-defining clause","Both","Neither"],"correctIndex":1},{"question":"Combine: \"I have a friend. She lives in London.\"","options":["I have a friend which lives in London.","I have a friend who lives in London.","I have a friend where lives in London.","I have a friend whose lives in London."],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"h5p","externalServiceTask":"Выполнить интерактивное упражнение H5P на перевод предложений из прямой речи в косвенную и на объединение предложений с помощью relative clauses.","starts_at":"2026-07-24T10:20:00+05:00","ends_at":"2026-07-24T11:05:00+05:00","room":"204"}]'::jsonb)
    LOOP
      INSERT INTO public.lessons (group_id, subject_id, topic, title, description, status, starts_at, ends_at, started_at, ended_at, room, school_id)
      VALUES (
        v_group_id, v_subject_id, lesson_data->>'topic', lesson_data->>'topic', lesson_data->>'objective',
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN 'completed' ELSE 'scheduled' END,
        (lesson_data->>'starts_at')::timestamptz, (lesson_data->>'ends_at')::timestamptz,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'starts_at')::timestamptz ELSE NULL END,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'ends_at')::timestamptz ELSE NULL END,
        lesson_data->>'room', v_school_id
      )
      RETURNING id INTO v_lesson_id;

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, duration_min, school_id)
      VALUES (v_lesson_id, 1, 'middle', 'theory', 'presentation', lesson_data->>'topic', lesson_data->>'theory', 15, v_school_id);

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, duration_min, school_id)
      VALUES (v_lesson_id, 2, 'middle', 'task', 'quiz_qia', 'Проверь себя', 15, v_school_id)
      RETURNING id INTO v_stage_id;

      qpos := 0;
      FOR quiz_item IN SELECT * FROM jsonb_array_elements(lesson_data->'quiz')
      LOOP
        qpos := qpos + 1;
        INSERT INTO public.quiz_questions (stage_id, question_text, options, correct_option_index, position, points, time_per_question_seconds, school_id)
        VALUES (v_stage_id, quiz_item->>'question', quiz_item->'options', (quiz_item->>'correctIndex')::int, qpos, 1, 30, v_school_id);
      END LOOP;

      IF (lesson_data->>'hasExternalService')::boolean THEN
        INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, config, duration_min, school_id)
        VALUES (
          v_lesson_id, 3, 'middle', 'task', lesson_data->>'externalServiceType',
          lesson_data->>'externalServiceTask', lesson_data->>'externalServiceTask',
          jsonb_build_object('url',
            CASE lesson_data->>'externalServiceType'
              WHEN 'wokwi' THEN 'https://wokwi.com/projects/new/arduino-uno'
              WHEN 'codesandbox' THEN 'https://codesandbox.io/p/sandbox/vanilla'
              WHEN 'geogebra' THEN 'https://www.geogebra.org/classic'
              WHEN 'phet' THEN 'https://phet.colorado.edu/sims/html/forces-and-motion-basics/latest/forces-and-motion-basics_en.html'
              WHEN 'desmos' THEN 'https://www.desmos.com/calculator'
              WHEN 'blockly_games' THEN 'https://blockly.games/'
              WHEN 'visualgo' THEN 'https://visualgo.net/en'
              WHEN 'p5js' THEN 'https://editor.p5js.org/'
              WHEN 'excalidraw' THEN 'https://excalidraw.com/'
              WHEN 'learningapps' THEN 'https://learningapps.org/'
              WHEN 'sqlonline' THEN 'https://sqlime.org/'
              WHEN 'h5p' THEN 'https://h5p.eduos.snruz.uz/library'
              ELSE NULL
            END
          ),
          15, v_school_id
        );
      END IF;
    END LOOP;
  END IF;

  -- === 7-А класс | Программирование (8 уроков) ===
  SELECT id INTO v_group_id FROM public.groups WHERE name = '7-А класс';
  SELECT id INTO v_subject_id FROM public.subjects WHERE group_id = v_group_id AND name = 'Программирование';
  IF NOT EXISTS (SELECT 1 FROM public.lessons WHERE group_id = v_group_id AND subject_id = v_subject_id AND description IS NOT NULL) THEN
    FOR lesson_data IN SELECT * FROM jsonb_array_elements('[{"topic":"Алгоритм: понятие и основные свойства","objective":"Сформировать у учащихся представление об алгоритме и научить определять его основные свойства на бытовых примерах.","theory":"Что такое алгоритм? В повседневной жизни мы постоянно выполняем последовательности действий: завариваем чай, собираем портфель в школу, переходим дорогу по правилам. Каждая такая последовательность точных действий, выполнение которых приводит к решению определённой задачи, называется алгоритмом.\n\nТермин «алгоритм» происходит от имени средневекового математика аль-Хорезми, который описывал правила выполнения арифметических действий столбиком. Сегодня алгоритмы применяются не только в математике, но и в кулинарии (рецепты), в инструкциях к технике, в компьютерных программах и играх.\n\nУ любого алгоритма есть исполнитель — тот, кто (или что) выполняет действия. Исполнителем может быть человек, робот, компьютерная программа или даже дрессированное животное. Важно, что исполнитель умеет выполнять лишь определённый набор команд — систему команд исполнителя.\n\nАлгоритм обладает несколькими важными свойствами:\n1. Дискретность — алгоритм состоит из отдельных, чётко разделённых шагов, которые выполняются один за другим.\n2. Определённость (детерминированность) — каждый шаг должен быть понятен и однозначен, не допускать двойного толкования.\n3. Результативность — выполнение алгоритма обязательно должно приводить к результату за конечное число шагов.\n4. Массовость — алгоритм можно применить не к одной конкретной задаче, а к целому классу похожих задач (например, алгоритм деления столбиком подходит для любых чисел, а не только для одного примера).\n5. Понятность — алгоритм должен быть записан на языке, понятном исполнителю.\n\nРассмотрим пример: алгоритм перехода дороги по пешеходному переходу можно описать так: 1) подойти к переходу; 2) посмотреть налево; 3) если машин нет — начать движение, посмотреть направо; 4) если машин нет — дойти до середины дороги; 5) снова посмотреть налево; 6) дойти до тротуара. Каждый шаг чёткий, порядок важен, а результат — переход дороги — достигается за конечное число действий.\n\nВ программировании алгоритмы записывают так, чтобы их мог понять и выполнить компьютер. Компьютер — очень «буквальный» исполнитель: он делает ровно то, что написано, ни на шаг больше и не меньше, поэтому важно продумывать алгоритм заранее, до того как переводить его в программный код.\n\nХороший способ проверить, правильно ли составлен алгоритм, — «проиграть» его вручную, как будто вы сами исполнитель, шаг за шагом выполняя инструкции и отслеживая результат на каждом этапе.","quiz":[{"question":"Что называется алгоритмом?","options":["Любой текст с числами","Точная последовательность действий, ведущая к решению задачи","Название языка программирования","Устройство для хранения данных"],"correctIndex":1},{"question":"Как называется тот, кто выполняет алгоритм?","options":["Автор","Редактор","Исполнитель","Наблюдатель"],"correctIndex":2},{"question":"Свойство алгоритма, означающее, что он состоит из отдельных чётких шагов, называется:","options":["Массовость","Дискретность","Результативность","Понятность"],"correctIndex":1},{"question":"Свойство алгоритма, означающее, что его можно применить к целому классу похожих задач, а не только к одной:","options":["Дискретность","Определённость","Массовость","Результативность"],"correctIndex":2},{"question":"Почему важно, чтобы каждый шаг алгоритма был однозначным (свойство определённости)?","options":["Чтобы алгоритм был длиннее","Чтобы исполнитель не мог по-разному истолковать команду","Чтобы алгоритм нельзя было записать","Это не важно"],"correctIndex":1},{"question":"Какое из перечисленного НЕ является примером алгоритма?","options":["Рецепт приготовления блюда","Инструкция по сборке мебели","Случайный набор слов без порядка","Правила перехода дороги"],"correctIndex":2},{"question":"Компьютер как исполнитель алгоритма:","options":["Сам додумывает недостающие шаги","Выполняет ровно то, что написано в алгоритме","Может пропускать непонятные шаги","Меняет порядок команд по своему усмотрению"],"correctIndex":1},{"question":"Свойство результативности означает, что:","options":["Алгоритм может выполняться бесконечно","Алгоритм обязательно приводит к результату за конечное число шагов","Алгоритм не обязан заканчиваться","Результат может отсутствовать"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-09T09:25:00+05:00","ends_at":"2026-07-09T10:10:00+05:00","room":"204"},{"topic":"Способы записи алгоритмов: блок-схемы","objective":"Научить учащихся составлять и читать блок-схемы линейных алгоритмов с помощью стандартных графических блоков.","theory":"Алгоритм можно записать разными способами: словесно (обычным текстом), на специальном алгоритмическом языке (псевдокоде) или графически — в виде блок-схемы. Блок-схема — это наглядный способ изображения алгоритма с помощью связанных между собой геометрических фигур (блоков), каждая из которых обозначает определённый тип действия.\n\nОсновные элементы блок-схемы:\n— Овал (эллипс) — обозначает начало или конец алгоритма. В овале пишут слово «Начало» или «Конец».\n— Параллелограмм — блок ввода или вывода данных. В нём записывают, какие данные вводятся (например, с клавиатуры) или выводятся (например, на экран).\n— Прямоугольник — блок обработки данных, то есть выполнение какого-либо действия или вычисления (например, «вычислить сумму a и b»).\n— Ромб — блок проверки условия (используется в алгоритмах с ветвлением, о которых мы поговорим позже).\n— Стрелки — показывают порядок выполнения шагов, то есть направление алгоритма от блока к блоку.\n\nВсе блоки соединяются стрелками сверху вниз (или слева направо), показывая, в какой последовательности выполняются действия. Такой алгоритм, где команды выполняются одна за другой строго по порядку, без пропусков и повторов, называется линейным алгоритмом.\n\nРассмотрим пример: алгоритм вычисления площади прямоугольника по его длине и ширине.\n1. Начало.\n2. Ввести длину a.\n3. Ввести ширину b.\n4. Вычислить S = a × b.\n5. Вывести значение S.\n6. Конец.\n\nВ блок-схеме это будет выглядеть так: овал «Начало» → параллелограмм «Ввод a, b» → прямоугольник «S = a × b» → параллелограмм «Вывод S» → овал «Конец». Каждый блок соединён стрелкой со следующим, и весь путь читается сверху вниз без ветвлений и повторов.\n\nЗачем нужны блок-схемы? Они помогают увидеть весь ход решения задачи «на одной картинке», заранее найти ошибки в логике (например, забытый шаг), а главное — блок-схема не привязана к конкретному языку программирования: один и тот же алгоритм, записанный в виде блок-схемы, потом можно перевести в код на любом языке — Python, JavaScript, Pascal и других.\n\nСоставляя блок-схему, важно помнить: каждый блок должен содержать одну понятную операцию, стрелки должны показывать единственно верный путь выполнения (для линейного алгоритма — без разветвлений), а сама схема должна начинаться с блока «Начало» и обязательно заканчиваться блоком «Конец».","quiz":[{"question":"Как называется способ записи алгоритма с помощью связанных геометрических фигур?","options":["Псевдокод","Блок-схема","Таблица","График"],"correctIndex":1},{"question":"Какой блок обозначает начало или конец алгоритма?","options":["Прямоугольник","Ромб","Овал","Параллелограмм"],"correctIndex":2},{"question":"Какой блок используется для ввода или вывода данных?","options":["Овал","Параллелограмм","Ромб","Стрелка"],"correctIndex":1},{"question":"Какой блок отвечает за обработку данных (вычисления, действия)?","options":["Прямоугольник","Овал","Ромб","Параллелограмм"],"correctIndex":0},{"question":"Что показывают стрелки в блок-схеме?","options":["Цвет блока","Порядок выполнения шагов алгоритма","Количество переменных","Название программы"],"correctIndex":1},{"question":"Алгоритм, в котором все действия выполняются строго по порядку без повторов и разветвлений, называется:","options":["Циклическим","Разветвлённым","Линейным","Случайным"],"correctIndex":2},{"question":"Какой блок пока не используется в линейных алгоритмах, а понадобится позже для проверки условий?","options":["Прямоугольник","Овал","Ромб","Параллелограмм"],"correctIndex":2},{"question":"Почему блок-схема удобна тем, что она не привязана к конкретному языку программирования?","options":["Потому что её нельзя перевести в код","Потому что один и тот же алгоритм в виде блок-схемы можно затем реализовать на любом языке программирования","Потому что блок-схемы всегда пишут на английском","Потому что в блок-схеме нет логики"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"blockly_games","externalServiceTask":"Пройти уровни 1–4 игры «Лабиринт» (Maze) на blockly-games.appspot.com, составляя линейную последовательность блоков-команд движения, которая проведёт персонажа к цели.","starts_at":"2026-07-10T12:10:00+05:00","ends_at":"2026-07-10T12:55:00+05:00","room":"204"},{"topic":"Исполнители и система команд исполнителя","objective":"Сформировать понятие исполнителя алгоритма и системы команд исполнителя (СКИ), научиться определять допустимые и недопустимые команды для конкретного исполнителя.","theory":"Мы уже знаем, что алгоритм — это последовательность действий, а исполнитель — тот, кто эти действия выполняет. Но у каждого исполнителя есть свои возможности и ограничения: он умеет выполнять только определённый, заранее известный набор команд. Этот набор называется системой команд исполнителя (СКИ).\n\nНапример, дрессированная собака-исполнитель понимает команды «сидеть», «лежать», «голос», но не поймёт команду «принеси кофе с сахаром» — такой команды нет в её системе команд. Робот-пылесос умеет двигаться вперёд, поворачивать и включать всасывание, но не умеет, например, подниматься по лестнице. Компьютерная программа-исполнитель «Черепашка» (популярный учебный исполнитель) обычно умеет: двигаться вперёд на n шагов, поворачивать на угол, поднимать и опускать перо для рисования линии.\n\nВажное правило: алгоритм для конкретного исполнителя может содержать только те команды, которые входят в его систему команд (СКИ). Если в алгоритме встречается команда, которую исполнитель не понимает, — исполнитель либо откажется её выполнять, либо выдаст ошибку, либо сделает что-то непредсказуемое.\n\nКаждая команда СКИ имеет: название (например, «вперёд», «направо»); параметры, если они нужны (например, «вперёд 5» — пройти 5 шагов); результат выполнения — как изменится состояние исполнителя или окружающей среды после выполнения команды.\n\nРассмотрим пример исполнителя «Чертёжник», который живёт на клетчатом поле и умеет выполнять команды: «вперёд n» (пройти n клеток в текущем направлении, оставляя след), «направо» (повернуться на 90° по часовой стрелке), «налево» (повернуться на 90° против часовой стрелки). С помощью этих трёх команд можно нарисовать, например, квадрат со стороной 4 клетки: вперёд 4, направо, вперёд 4, направо, вперёд 4, направо, вперёд 4, направо. Чертёжник выполнит эти восемь команд строго по порядку, и в результате на поле появится квадрат.\n\nВажно понимать, что один и тот же результат разные исполнители могут достигать разными командами, потому что у них разные системы команд. Поэтому, составляя алгоритм, программист всегда должен сначала выяснить: а что вообще умеет делать исполнитель, для которого пишется программа? В современном программировании исполнителем чаще всего выступает компьютер, а система команд — это операторы и функции конкретного языка программирования (например, JavaScript или Python), с которыми мы познакомимся в следующих уроках.","quiz":[{"question":"Что такое система команд исполнителя (СКИ)?","options":["Список ошибок исполнителя","Набор команд, которые исполнитель умеет выполнять","Название компьютера","График работы исполнителя"],"correctIndex":1},{"question":"Может ли исполнитель выполнить команду, которой нет в его СКИ?","options":["Да, всегда","Нет, он не сможет её корректно выполнить","Да, но только по ночам","Это зависит от погоды"],"correctIndex":1},{"question":"Кто из перечисленных может быть исполнителем алгоритма?","options":["Только человек","Только компьютер","Человек, робот, животное или компьютерная программа","Только робот"],"correctIndex":2},{"question":"Исполнитель «Чертёжник» умеет выполнять команды «вперёд n», «направо», «налево». Что означает команда «вперёд 4»?","options":["Повернуться на 4 градуса","Пройти 4 клетки в текущем направлении","Нарисовать 4 квадрата","Подождать 4 секунды"],"correctIndex":1},{"question":"Сколько команд «вперёд 4» и «направо» потребуется Чертёжнику, чтобы нарисовать квадрат со стороной 4 клетки?","options":["2 команды «вперёд», 2 команды «направо»","4 команды «вперёд», 4 команды «направо»","1 команда «вперёд», 4 команды «направо»","4 команды «вперёд», 1 команда «направо»"],"correctIndex":1},{"question":"Почему перед написанием алгоритма важно знать систему команд исполнителя?","options":["Это не важно","Чтобы использовать в алгоритме только те команды, которые исполнитель способен выполнить","Чтобы алгоритм был длиннее","Чтобы исполнитель устал"],"correctIndex":1},{"question":"В современном программировании роль системы команд исполнителя обычно играют:","options":["Операторы и функции языка программирования","Названия файлов","Цвета в интерфейсе","Имена пользователей"],"correctIndex":0},{"question":"Что произойдёт, если в алгоритме для робота-пылесоса написать команду «подняться по лестнице», которой нет в его СКИ?","options":["Робот выполнит её мгновенно","Робот не сможет корректно выполнить эту команду","Робот полетит","Ничего, команда не имеет значения"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-13T11:15:00+05:00","ends_at":"2026-07-13T12:00:00+05:00","room":"204"},{"topic":"Переменные и типы данных","objective":"Научить учащихся объявлять переменные и различать основные типы данных (числовой, строковый, логический) в программировании.","theory":"Когда компьютерная программа работает с информацией, ей нужно где-то эту информацию хранить. Для этого используются переменные. Переменная — это именованная область памяти компьютера, в которой можно хранить какое-либо значение и изменять его в ходе выполнения программы.\n\nПредставьте переменную как подписанную коробку: на коробке написано имя (например, age), а внутри лежит значение (например, число 13). В любой момент программы можно заглянуть в эту коробку (использовать значение) или положить туда новое значение (изменить переменную) — старое при этом исчезает, а имя коробки остаётся прежним.\n\nЧтобы создать переменную, её нужно объявить — то есть придумать ей имя и, как правило, сразу присвоить начальное значение. В языке JavaScript, например, это делается так: let age = 13; — здесь let — ключевое слово для объявления переменной, age — имя переменной, а 13 — присваиваемое значение. Знак = здесь называется оператором присваивания и означает не «равно», как в математике, а «положить в переменную значение справа».\n\nИмена переменных должны быть понятными и обычно начинаются с буквы (например, name, score, isReady), не могут содержать пробелов и не должны совпадать со служебными словами языка.\n\nКаждая переменная хранит значение определённого типа данных. Основные типы данных, с которыми мы будем работать:\n1. Числовой тип (number) — целые и дробные числа: 7, -3, 3.14. С числами можно выполнять арифметические операции: сложение, вычитание, умножение, деление.\n2. Строковый тип (string) — текст, последовательность символов, заключённая в кавычки: \"Привет\", ''Ташкент'', \"7 класс\". Строки можно объединять («склеивать»), но нельзя напрямую складывать как числа.\n3. Логический тип (boolean) — может принимать только два значения: true (истина) или false (ложь). Логические переменные используются, когда нужно хранить ответ на вопрос «да или нет» — например, isStudent = true означает «является учеником».\n\nВажно не путать типы данных: число 7 и строка \"7\" — это разные вещи для компьютера, хотя выглядят похоже. Число можно использовать в вычислениях (7 + 3 = 10), а строку \"7\" компьютер воспринимает как текст.\n\nПеременные — это фундамент программирования: без них невозможно было бы хранить результаты вычислений, ответы пользователя, состояние игры или любые другие данные, с которыми работает программа. В следующих уроках мы научимся выполнять над переменными арифметические операции и строить более сложные алгоритмы с их использованием.","quiz":[{"question":"Что такое переменная в программировании?","options":["Постоянное число","Именованная область памяти для хранения и изменения значения","Название программы","Тип ошибки"],"correctIndex":1},{"question":"Какая команда в JavaScript объявляет переменную age со значением 13?","options":["age = 13;","let age = 13;","13 = age;","var: age 13"],"correctIndex":1},{"question":"Что означает символ = в строке let score = 10;?","options":["Математическое равенство","Присваивание значения переменной","Сравнение двух чисел","Ничего не означает"],"correctIndex":1},{"question":"Какой тип данных используется для хранения текста, например \"Привет\"?","options":["Числовой (number)","Строковый (string)","Логический (boolean)","Массив"],"correctIndex":1},{"question":"Какой тип данных может принимать только значения true или false?","options":["Строковый","Числовой","Логический (boolean)","Символьный"],"correctIndex":2},{"question":"Чем отличается число 7 от строки \"7\" в программировании?","options":["Ничем не отличаются","Число можно использовать в вычислениях, а строка — это текст","Строка \"7\" быстрее числа 7","Число 7 нельзя хранить в переменной"],"correctIndex":1},{"question":"Какое из следующих имён переменных корректно (не содержит пробелов и не является служебным словом)?","options":["my score","7class","totalScore","let"],"correctIndex":2},{"question":"Переменная isReady = true; скорее всего хранит:","options":["Число очков","Текст сообщения","Логический ответ на вопрос \"готов ли?\"","Список имён"],"correctIndex":2}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-16T09:25:00+05:00","ends_at":"2026-07-16T10:10:00+05:00","room":"204"},{"topic":"Арифметические операции и выражения","objective":"Научить учащихся выполнять арифметические операции над переменными и правильно вычислять значения выражений с учётом порядка операций.","theory":"В прошлом уроке мы научились хранить данные в переменных. Теперь разберёмся, как эти данные обрабатывать с помощью арифметических операций — точно так же, как на уроках математики, только с использованием переменных и особых знаков-операторов.\n\nОсновные арифметические операторы в программировании:\n+ (сложение): a + b\n- (вычитание): a - b\n* (умножение): a * b\n/ (деление): a / b\n% (остаток от деления, или «деление по модулю»): a % b — показывает, какой остаток получится при делении a на b. Например, 7 % 2 = 1, потому что 7 делится на 2 с остатком 1.\n\nКомбинация переменных, чисел и операторов образует выражение. Например: S = a * b — здесь a * b — это выражение, значение которого вычисляется и сохраняется в переменную S.\n\nПорядок вычисления выражений подчиняется тем же правилам, что и в математике: сначала вычисляются операции в скобках; затем умножение и деление (слева направо); и только потом сложение и вычитание (слева направо).\n\nНапример, выражение 2 + 3 * 4 равно 14, а не 20, потому что сначала выполняется умножение (3 * 4 = 12), а затем сложение (2 + 12 = 14). Если нужно, чтобы сложение выполнилось первым, нужно использовать скобки: (2 + 3) * 4 = 20.\n\nРассмотрим практический пример. Пусть у нас есть переменные price = 15000 (цена товара) и count = 3 (количество товаров). Чтобы вычислить общую стоимость покупки, напишем: total = price * count, и в переменной total окажется значение 45000.\n\nЕщё один пример с оператором остатка от деления %: он часто используется, чтобы проверить, делится ли число нацело на другое. Например, если number % 2 равно 0, значит, число number чётное, а если результат равен 1 — число нечётное. Это очень полезный приём, которым мы ещё воспользуемся в будущих уроках при построении алгоритмов с условиями.\n\nВажно также запомнить оператор присваивания с одновременным вычислением: например, запись total = total + 10 означает «взять текущее значение total, прибавить к нему 10 и записать результат обратно в total». Такая операция часто сокращённо записывается как total += 10 — это то же самое действие, но короче.\n\nПонимание арифметических операций и порядка их выполнения — необходимый навык для построения любых, даже самых сложных программ, потому что почти любая задача рано или поздно сводится к вычислению какого-то выражения.","quiz":[{"question":"Какой оператор используется для умножения в программировании?","options":["x","*","^","×"],"correctIndex":1},{"question":"Чему равен результат выражения 2 + 3 * 4?","options":["20","14","24","9"],"correctIndex":1},{"question":"Как получить результат 20 из чисел 2, 3 и 4, используя сложение и умножение?","options":["2 + 3 * 4","(2 + 3) * 4","2 * 3 + 4","2 * (3 + 4) - 4"],"correctIndex":1},{"question":"Что вычисляет оператор % (остаток от деления)?","options":["Процент от числа","Остаток от деления одного числа на другое","Квадратный корень","Среднее значение"],"correctIndex":1},{"question":"Чему равно значение 7 % 2?","options":["3","3.5","1","0"],"correctIndex":2},{"question":"Как с помощью оператора % проверить, что число чётное?","options":["number % 2 равно 1","number % 2 равно 0","number / 2 равно 0","number * 2 равно 0"],"correctIndex":1},{"question":"Что означает запись total = total + 10?","options":["Ошибка в программе","К текущему значению total прибавить 10 и сохранить результат обратно в total","Создать новую переменную","Сравнить total и 10"],"correctIndex":1},{"question":"Каков правильный порядок выполнения операций в выражениях без скобок?","options":["Сложение и вычитание, затем умножение и деление","Умножение и деление, затем сложение и вычитание","Все операции выполняются одновременно","Порядок не важен"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"codesandbox","externalServiceTask":"Создать новый JavaScript-проект в CodeSandbox, объявить переменные price и count, вычислить их произведение (total = price * count) и остаток от деления count на 2 с помощью оператора %, вывести оба результата в консоль через console.log().","starts_at":"2026-07-17T12:10:00+05:00","ends_at":"2026-07-17T12:55:00+05:00","room":"204"},{"topic":"Алгоритмы с ветвлением: условный оператор if-else","objective":"Научить учащихся строить алгоритмы с ветвлением, используя условный оператор if-else и операторы сравнения.","theory":"До сих пор мы рассматривали линейные алгоритмы, где все команды выполняются одна за другой строго по порядку. Но в жизни часто нужно принимать решение в зависимости от условия: «если идёт дождь — возьму зонт, иначе — не возьму». Такие алгоритмы называются алгоритмами с ветвлением, а реализуются они с помощью условного оператора if-else («если-иначе»).\n\nОбщая структура условного оператора: if (условие) { действия, если условие истинно (true) } else { действия, если условие ложно (false) }.\n\nУсловие — это выражение, которое проверяется и может быть либо истинным (true), либо ложным (false) — то есть имеет логический тип данных, о котором мы говорили в уроке про переменные. Чтобы построить условие, используются операторы сравнения: == (равно), != (не равно), > (больше), < (меньше), >= (больше или равно), <= (меньше или равно).\n\nРассмотрим пример: программа проверяет возраст ученика и определяет, может ли он учиться в 7 классе. if (age >= 12 && age <= 14) { console.log(\"Подходящий возраст для 7 класса\"); } else { console.log(\"Возраст не соответствует 7 классу\"); }\n\nЗдесь символ && означает логическое «И» — условие истинно, только если оба условия слева и справа от && истинны одновременно. Существует также оператор || — логическое «ИЛИ», при котором достаточно истинности хотя бы одного из условий.\n\nИногда нужно проверить не два, а несколько вариантов — тогда используется цепочка else if: if (score >= 90) { \"Отлично\" } else if (score >= 70) { \"Хорошо\" } else if (score >= 50) { \"Удовлетворительно\" } else { \"Нужно подтянуть знания\" }.\n\nТакая цепочка проверяет условия по порядку сверху вниз и выполняет только тот блок, условие которого оказалось первым истинным, после чего пропускает все остальные проверки.\n\nВажно понимать: блок else необязателен — можно написать просто if (условие) { ... } без else, тогда, если условие ложно, программа просто ничего не сделает и перейдёт к следующим командам после условного оператора.\n\nВетвление — это один из фундаментальных строительных блоков любой программы, наравне с линейными алгоритмами и циклами (о которых пойдёт речь в следующем уроке). Именно ветвление позволяет программам «принимать решения» и по-разному реагировать на разные ситуации — например, проверять правильность введённого пароля, определять победителя игры или выводить разные сообщения в зависимости от результатов теста.","quiz":[{"question":"Для чего используется условный оператор if-else?","options":["Для повторения действий","Для выполнения разных действий в зависимости от условия","Для хранения данных","Для вывода текста на экран без условий"],"correctIndex":1},{"question":"Какой тип данных имеет условие внутри оператора if?","options":["Числовой","Строковый","Логический (true/false)","Массив"],"correctIndex":2},{"question":"Какой оператор сравнения означает \"больше или равно\"?","options":["=>",">=","=<","=="],"correctIndex":1},{"question":"Что произойдёт, если условие в if окажется ложным (false), а блок else отсутствует?","options":["Программа завершится с ошибкой","Выполнится блок if всё равно","Программа пропустит блок if и продолжит выполнение дальше","Программа зациклится"],"correctIndex":2},{"question":"Что означает оператор && в условии?","options":["Логическое \"ИЛИ\" — достаточно одного истинного условия","Логическое \"И\" — оба условия должны быть истинны одновременно","Присваивание значения","Сравнение на неравенство"],"correctIndex":1},{"question":"В цепочке if / else if / else, сколько блоков выполнится, если несколько условий истинны одновременно?","options":["Все истинные блоки","Только первый по порядку блок с истинным условием","Только последний блок","Ни одного"],"correctIndex":1},{"question":"Какое выражение проверяет, что переменная score НЕ равна 100?","options":["score = 100","score == 100","score != 100","score >= 100"],"correctIndex":2},{"question":"Дан код: if (age >= 12 && age <= 14) {...}. При каком значении age условие будет истинным?","options":["age = 10","age = 13","age = 20","age = 5"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-20T11:15:00+05:00","ends_at":"2026-07-20T12:00:00+05:00","room":"204"},{"topic":"Алгоритмы с повторением: циклы","objective":"Научить учащихся использовать циклы for и while для замены повторяющихся действий компактной конструкцией повторения.","theory":"Представьте, что нужно вывести на экран числа от 1 до 100 или нарисовать 20 одинаковых квадратов подряд. Записывать 100 отдельных команд вывода или 20 раз повторять одинаковый набор команд рисования — долго, неудобно и легко ошибиться. Для таких задач в программировании существуют циклы — конструкции, которые позволяют повторить одну и ту же группу команд (тело цикла) заданное число раз или до тех пор, пока выполняется определённое условие.\n\nЕсть два основных вида циклов, с которыми мы познакомимся:\n\n1. Цикл с известным числом повторений — for. Он используется, когда заранее известно, сколько раз нужно повторить действие. Структура цикла for в JavaScript: for (let i = 1; i <= 5; i++) { console.log(i); }. Здесь: let i = 1 — начальное значение счётчика (переменной-счётчика i); i <= 5 — условие, при котором цикл продолжает выполняться; i++ — действие, увеличивающее счётчик на 1 после каждого повторения (сокращённая запись i = i + 1). Этот цикл выведет на экран числа 1, 2, 3, 4, 5 — то есть повторится ровно 5 раз.\n\n2. Цикл с условием — while. Он используется, когда заранее неизвестно точное число повторений, но известно условие, при котором цикл должен продолжаться. Структура: let i = 1; while (i <= 5) { console.log(i); i++; }. Цикл while проверяет условие перед каждым повторением: если условие истинно — тело цикла выполняется ещё раз, если ложно — цикл завершается. Важно не забыть внутри цикла изменить переменную, от которой зависит условие, иначе цикл никогда не закончится — это называется «бесконечный цикл» и считается ошибкой в программе.\n\nЦиклы особенно полезны в паре с массивами и при работе с графикой: например, чтобы нарисовать 10 одинаковых кругов в ряд, можно один раз описать, как рисуется круг, и обернуть эту команду в цикл for от 0 до 9, каждый раз немного сдвигая координату x. Так вместо десяти одинаковых строк кода получится компактная конструкция из нескольких строк.\n\nКаждый цикл состоит из тела цикла (команды, которые повторяются) и условия продолжения. Понимание циклов — важнейший шаг в программировании, потому что подавляющее большинство реальных задач (обработка списков учеников, подсчёт суммы оценок, отрисовка узоров, игровые механики) построено именно на повторении действий с изменяющимися данными.","quiz":[{"question":"Для чего используются циклы в программировании?","options":["Для хранения текста","Для повторения группы команд заданное число раз или пока выполняется условие","Для сравнения двух чисел","Для объявления переменных"],"correctIndex":1},{"question":"В цикле for (let i = 1; i <= 5; i++) сколько раз выполнится тело цикла?","options":["4 раза","5 раз","6 раз","Бесконечно"],"correctIndex":1},{"question":"Что делает часть i++ в цикле for?","options":["Уменьшает i на 1","Увеличивает счётчик i на 1 после каждого повторения","Останавливает цикл","Присваивает i значение 0"],"correctIndex":1},{"question":"Когда используется цикл while вместо for?","options":["Когда заранее известно точное число повторений","Когда повторение нужно выполнять, пока выполняется определённое условие, а точное число повторений неизвестно","Когда не нужно никаких повторений","Только для вывода текста"],"correctIndex":1},{"question":"Что называется \"телом цикла\"?","options":["Условие цикла","Группа команд, которая повторяется внутри цикла","Название переменной-счётчика","Первая строка программы"],"correctIndex":1},{"question":"Что произойдёт, если в цикле while забыть изменить переменную, от которой зависит условие?","options":["Цикл выполнится один раз","Возникнет бесконечный цикл","Программа автоматически исправит ошибку","Ничего не изменится"],"correctIndex":1},{"question":"В цикле while (i <= 5) { ... i++; } когда цикл проверяет условие?","options":["После выполнения тела цикла один раз в конце всей программы","Перед каждым повторением тела цикла","Условие никогда не проверяется","Только один раз в самом начале"],"correctIndex":1},{"question":"Зачем удобно использовать цикл при рисовании 10 одинаковых кругов в ряд?","options":["Потому что без цикла это невозможно сделать вообще","Чтобы не повторять одинаковый код 10 раз вручную, а описать рисование круга один раз внутри цикла","Потому что цикл рисует круги случайным образом","Цикл нужен только для чисел, а не для графики"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-23T09:25:00+05:00","ends_at":"2026-07-23T10:10:00+05:00","room":"204"},{"topic":"Массивы: хранение наборов данных","objective":"Научить учащихся создавать массивы, обращаться к их элементам по индексу и обрабатывать массив с помощью цикла.","theory":"В предыдущих уроках мы хранили в переменной одно значение: одно число, одну строку. Но что делать, если нужно хранить сразу много однотипных значений — например, оценки одного ученика по пяти предметам, или имена всех учеников класса? Заводить для этого 25 отдельных переменных (name1, name2, name3...) было бы неудобно. Для хранения упорядоченного набора значений в программировании используется массив.\n\nМассив — это структура данных, которая хранит несколько значений под одним именем, при этом каждое значение занимает своё пронумерованное место — индекс. Важная особенность: нумерация индексов в большинстве языков программирования (включая JavaScript) начинается не с 1, а с 0.\n\nСоздать массив в JavaScript можно так: let grades = [5, 4, 5, 3, 4]; Здесь grades — это массив из пяти чисел. Обратиться к конкретному элементу массива можно по его индексу в квадратных скобках: grades[0] вернёт первый элемент — число 5, а grades[3] вернёт четвёртый элемент — число 3. Индекс последнего элемента массива всегда на 1 меньше, чем количество элементов (длина массива), потому что счёт начинается с нуля.\n\nЧтобы узнать, сколько всего элементов в массиве, используется свойство length: grades.length вернёт число 5.\n\nМассивы можно изменять: например, grades[2] = 4; заменит третий элемент массива (индекс 2) на значение 4. Также можно добавить новый элемент в конец массива с помощью метода push: grades.push(5); добавит число 5 в конец массива.\n\nСамое мощное применение массивов раскрывается в связке с циклами, которые мы изучили в прошлом уроке. Вместо того чтобы обращаться к каждому элементу массива по отдельности, можно перебрать все элементы массива с помощью цикла for: for (let i = 0; i < grades.length; i++) { console.log(grades[i]); }. Этот цикл выведет на экран все пять оценок по очереди: сначала grades[0], затем grades[1], и так далее до grades[4], потому что условие цикла i < grades.length останавливает перебор ровно на границе массива.\n\nС помощью цикла и массива легко решать такие задачи, как подсчёт суммы или среднего значения всех оценок, поиск максимального элемента, подсчёт количества пятёрок и многое другое — практически любая обработка списка данных строится по этому шаблону: цикл, который проходит по всем индексам массива от 0 до length - 1.\n\nМассивы — это один из важнейших инструментов программирования, потому что реальные программы почти всегда работают не с одним значением, а с наборами данных: списками учеников, оценками, товарами в магазине, сообщениями в чате и так далее.","quiz":[{"question":"Что такое массив?","options":["Одно число","Структура данных, хранящая несколько значений под одним именем с пронумерованными местами","Название переменной","Тип условного оператора"],"correctIndex":1},{"question":"С какого числа начинается нумерация индексов элементов массива в JavaScript?","options":["С 1","С 0","С -1","С 10"],"correctIndex":1},{"question":"Дан массив let grades = [5, 4, 5, 3, 4];. Чему равен grades[0]?","options":["4","5","3","undefined"],"correctIndex":1},{"question":"Для массива grades = [5, 4, 5, 3, 4] чему равен grades[3]?","options":["5","4","3","2"],"correctIndex":2},{"question":"Что вернёт grades.length для массива из 5 элементов?","options":["4","5","0","Индекс последнего элемента"],"correctIndex":1},{"question":"Какой индекс имеет последний элемент массива из 5 элементов?","options":["5","4","6","0"],"correctIndex":1},{"question":"Какой метод добавляет новый элемент в конец массива?","options":["grades.length","grades.push()","grades.delete()","grades.start()"],"correctIndex":1},{"question":"Зачем удобно использовать цикл for вместе с массивом?","options":["Чтобы удалить массив","Чтобы перебрать и обработать все элементы массива по очереди, не обращаясь к каждому вручную","Чтобы создать новую переменную","Циклы нельзя использовать с массивами"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"visualgo","externalServiceTask":"Открыть раздел Array/List на visualgo.net, выполнить операции добавления элемента, доступа по индексу и удаления элемента, наблюдая, как меняются индексы остальных элементов массива.","starts_at":"2026-07-24T12:10:00+05:00","ends_at":"2026-07-24T12:55:00+05:00","room":"204"}]'::jsonb)
    LOOP
      INSERT INTO public.lessons (group_id, subject_id, topic, title, description, status, starts_at, ends_at, started_at, ended_at, room, school_id)
