        VALUES (v_stage_id, quiz_item->>'question', quiz_item->'options', (quiz_item->>'correctIndex')::int, qpos, 1, 30, v_school_id);
      END LOOP;

      IF (lesson_data->>'hasExternalService')::boolean THEN
        INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, config, duration_min, school_id)
        VALUES (
          v_lesson_id, 3, 'middle', 'task', lesson_data->>'externalServiceType',
          lesson_data->>'externalServiceTask', lesson_data->>'externalServiceTask',
          jsonb_build_object('url',
            CASE lesson_data->>'externalServiceType'
              WHEN 'wokwi' THEN 'https://wokwi.com/projects/new/arduino-uno'
              WHEN 'codesandbox' THEN 'https://codesandbox.io/p/sandbox/vanilla'
              WHEN 'geogebra' THEN 'https://www.geogebra.org/classic'
              WHEN 'phet' THEN 'https://phet.colorado.edu/sims/html/forces-and-motion-basics/latest/forces-and-motion-basics_en.html'
              WHEN 'desmos' THEN 'https://www.desmos.com/calculator'
              WHEN 'blockly_games' THEN 'https://blockly.games/'
              WHEN 'visualgo' THEN 'https://visualgo.net/en'
              WHEN 'p5js' THEN 'https://editor.p5js.org/'
              WHEN 'excalidraw' THEN 'https://excalidraw.com/'
              WHEN 'learningapps' THEN 'https://learningapps.org/'
              WHEN 'sqlonline' THEN 'https://sqlime.org/'
              WHEN 'h5p' THEN 'https://h5p.eduos.snruz.uz/library'
              ELSE NULL
            END
          ),
          15, v_school_id
        );
      END IF;
    END LOOP;
  END IF;

  -- === 3-А класс | Робототехника (6 уроков) ===
  SELECT id INTO v_group_id FROM public.groups WHERE name = '3-А класс';
  SELECT id INTO v_subject_id FROM public.subjects WHERE group_id = v_group_id AND name = 'Робототехника';
  IF NOT EXISTS (SELECT 1 FROM public.lessons WHERE group_id = v_group_id AND subject_id = v_subject_id AND description IS NOT NULL) THEN
    FOR lesson_data IN SELECT * FROM jsonb_array_elements('[{"topic":"Что такое робот и его части","objective":"Ученики поймут, что такое робот, и научатся называть его основные части: корпус, датчики, моторы и контроллер.","theory":"Робот — это специальное устройство, которое человек создаёт, чтобы оно могло выполнять разные задания само, без постоянной помощи человека. Робот может двигаться, реагировать на окружающий мир и выполнять команды, которые в него заложил человек-программист.\n\nУ любого робота, даже самого простого, есть несколько главных частей, без которых он не сможет работать.\n\nПервая часть — это корпус (тело) робота. Корпус — как скелет и кожа одновременно: он держит все детали вместе и защищает их. Корпус может быть сделан из пластика, металла или даже из деталей конструктора LEGO.\n\nВторая важная часть — датчики. Датчики — это \"органы чувств\" робота. Они помогают роботу узнавать, что происходит вокруг: светло вокруг или темно, есть ли рядом препятствие, громкий ли звук услышал робот. Например, датчик расстояния похож на глаза робота — он \"видит\", когда рядом появляется стена или человек, и робот может остановиться, чтобы не столкнуться.\n\nТретья часть — моторы (их ещё называют актуаторы, \"исполнительные механизмы\"). Моторы заставляют части робота двигаться: крутить колёса, поднимать руку-манипулятор, поворачивать голову. Без моторов робот был бы просто неподвижной коробкой с датчиками.\n\nЧетвёртая, самая важная часть — это \"мозг\" робота, или контроллер (маленький компьютер). Контроллер получает сигналы от датчиков (\"Я вижу стену!\"), думает по программе, которую написал человек, и отправляет команды моторам (\"Поверни направо!\"). Именно контроллер решает, что робот должен сделать в конкретный момент.\n\nИ ещё одна необходимая часть — источник питания, обычно это батарейка или аккумулятор. Без энергии ни один робот работать не будет — так же как без сил не сможет бежать даже самый быстрый спортсмен.\n\nРоботов создают для самых разных дел: одни роботы работают на заводах и собирают машины, другие убирают квартиру (робот-пылесос), третьи помогают исследовать космос (роботы-марсоходы), а четвёртые просто развлекают нас, как роботы-игрушки. Но у всех у них есть эти четыре главные части: корпус, датчики, моторы и \"мозг\"-контроллер, а также источник питания.\n\nНа следующих уроках мы подробно разберём каждую из этих частей и узнаем, как они помогают роботу быть по-настоящему \"умным\" помощником человека.","quiz":[{"question":"Что такое робот?","options":["Устройство, которое может выполнять задания самостоятельно по заданной программе","Обычная игрушка без электроники","Живое существо","Книга с картинками про технику"],"correctIndex":0},{"question":"Как называется часть робота, которая держит вместе все детали и защищает их?","options":["Датчик","Корпус","Мотор","Контроллер"],"correctIndex":1},{"question":"Какую роль в роботе играют датчики?","options":["Двигают колёса","Хранят батарейку","Помогают роботу \"чувствовать\" окружающий мир (свет, звук, препятствия)","Красят корпус"],"correctIndex":2},{"question":"Что делают моторы (актуаторы) в роботе?","options":["Заставляют части робота двигаться","Слушают звуки","Пишут программу","Заряжают батарейку"],"correctIndex":0},{"question":"Как называют \"мозг\" робота, который получает сигналы от датчиков и отправляет команды моторам?","options":["Корпус","Контроллер","Батарейка","Датчик расстояния"],"correctIndex":1},{"question":"Зачем роботу нужен источник питания (батарейка)?","options":["Чтобы робот был красивым","Чтобы у робота были глаза","Чтобы он получал энергию для работы","Чтобы он не сломался"],"correctIndex":2},{"question":"Какой пример робота помогает исследовать космос?","options":["Робот-пылесос","Робот-марсоход","Робот-игрушка","Робот-повар"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-07T08:30:00+05:00","ends_at":"2026-07-07T09:15:00+05:00","room":"101"},{"topic":"Электрическая цепь и питание робота","objective":"Ученики поймут, что такое электрическая цепь и как энергия от батарейки доходит до частей робота.","theory":"На прошлом уроке мы узнали, что каждому роботу нужен источник питания — батарейка или аккумулятор. Но как же энергия от батарейки попадает к моторам и лампочкам робота? Для этого нужна электрическая цепь.\n\nЭлектрическая цепь — это путь, по которому течёт электрический ток, как дорога, по которой едут машины. Чтобы ток мог течь, цепь должна быть замкнутой (закрытой), то есть представлять собой круг без разрывов. Если в цепи есть разрыв — например, оторван провод, — ток течь не будет, и лампочка не загорится, а мотор не заработает. Такую цепь называют разомкнутой.\n\nПростая электрическая цепь состоит из нескольких частей:\n1) Источник питания — батарейка. Она даёт энергию, как сердце качает кровь по телу.\n2) Провода — по ним течёт ток, как вода по трубам.\n3) Потребитель энергии — например, лампочка (светодиод) или мотор. Он \"берёт\" энергию и превращает её в свет или движение.\n4) Выключатель — с его помощью человек может замкнуть или разомкнуть цепь, то есть включить или выключить устройство.\n\nПредставь простой пример: у тебя есть батарейка, два провода и маленькая лампочка. Если соединить провода от лампочки к двум концам батарейки (плюсу и минусу), получится замкнутая цепь — и лампочка загорится! А если добавить выключатель, ты сможешь включать и выключать свет одной кнопкой, не отсоединяя провода каждый раз руками.\n\nУ батарейки есть два полюса — плюс (+) и минус (–). Ток течёт от одного полюса к другому только по замкнутой цепи. Важно соединять провода правильно, иначе устройство может не заработать.\n\nВ настоящих роботах всё устроено похожим образом, только гораздо сложнее: там много проводов, которые идут от батарейки к контроллеру (\"мозгу\"), от контроллера к моторам и датчикам. Но принцип остаётся тем же самым — энергия течёт по замкнутой цепи от источника питания к тем частям, которые эту энергию используют.\n\nПонимание электрической цепи — это первый шаг к тому, чтобы самому собирать простые схемы для роботов, зажигать лампочки и приводить в движение моторчики.","quiz":[{"question":"Что такое электрическая цепь?","options":["Путь, по которому течёт электрический ток","Название батарейки","Программа для робота","Датчик света"],"correctIndex":0},{"question":"Что произойдёт, если в цепи есть разрыв (она разомкнута)?","options":["Лампочка загорится ярче","Ток не будет течь, и устройство не заработает","Мотор будет крутиться быстрее","Батарейка зарядится"],"correctIndex":1},{"question":"Какая часть цепи даёт энергию всей цепи?","options":["Провод","Выключатель","Батарейка (источник питания)","Лампочка"],"correctIndex":2},{"question":"Для чего нужен выключатель в цепи?","options":["Чтобы измерять температуру","Чтобы замыкать и размыкать цепь, включать и выключать устройство","Чтобы хранить энергию","Чтобы издавать звук"],"correctIndex":1},{"question":"Сколько полюсов у батарейки и как они называются?","options":["Один полюс — только плюс","Три полюса","Два полюса — плюс (+) и минус (–)","У батарейки нет полюсов"],"correctIndex":2},{"question":"По чему в электрической цепи течёт ток от батарейки к лампочке?","options":["По воздуху","По проводам","По корпусу робота","По датчику"],"correctIndex":1},{"question":"Какая цепь называется замкнутой?","options":["Цепь, в которой провода образуют полный круг без разрывов","Цепь без батарейки","Цепь, где провода перепутаны","Цепь без лампочки"],"correctIndex":0}],"hasExternalService":true,"externalServiceType":"wokwi","externalServiceTask":"Собери в Wokwi простую электрическую цепь: батарейка, провода и светодиод (LED), чтобы лампочка загорелась, а затем добавь в схему выключатель.","starts_at":"2026-07-09T10:20:00+05:00","ends_at":"2026-07-09T11:05:00+05:00","room":"101"},{"topic":"Датчики робота: как он чувствует мир","objective":"Ученики узнают о разных видах датчиков робота и научатся объяснять, зачем каждый из них нужен.","theory":"На первом уроке мы говорили, что датчики — это \"органы чувств\" робота. Сегодня разберём подробнее, какие бывают датчики и зачем они нужны роботу.\n\nДатчик света (фотодатчик) помогает роботу понимать, светло вокруг или темно. Такой датчик похож на маленький глаз, который реагирует на яркость. Например, робот-игрушка с датчиком света может сам включать фонарик, когда в комнате становится темно, точно так же, как уличные фонари включаются вечером.\n\nДатчик звука реагирует на громкие или тихие звуки вокруг робота. С его помощью робот может, например, \"услышать\" хлопок в ладоши и после этого начать двигаться или остановиться. Это похоже на то, как наши уши слышат звуки и посылают сигнал в мозг.\n\nДатчик расстояния (ультразвуковой датчик) помогает роботу понимать, есть ли перед ним препятствие и как далеко оно находится. Он работает похоже на то, как летучая мышь ориентируется в темноте: посылает сигнал вперёд и \"слушает\", когда этот сигнал вернётся обратно, отразившись от стены или предмета. Чем быстрее сигнал вернулся, тем ближе препятствие. Благодаря такому датчику робот-пылесос не врезается в мебель, а вовремя поворачивает в сторону.\n\nДатчик касания (кнопка-бампер) реагирует, когда робот к чему-то прикоснулся. Это как если бы у робота была кожа, которая чувствует прикосновение. Когда бампер робота задевает препятствие, датчик \"сообщает\" контроллеру, что нужно остановиться или изменить направление.\n\nЕсть и другие датчики: датчик температуры (чувствует, тепло или холодно), датчик цвета (определяет, какого цвета предмет перед роботом), датчик линии (помогает роботу двигаться точно по нарисованной на полу линии, например чёрной полосе на белом листе).\n\nВсе эти датчики собирают информацию об окружающем мире и отправляют её в контроллер — \"мозг\" робота. Контроллер получает эти сигналы, \"понимает\" их согласно заложенной программе и решает, что делать дальше: остановиться, повернуть, включить свет или издать звук.\n\nБез датчиков робот был бы \"слепым\" и \"глухим\" — он не смог бы реагировать на изменения вокруг себя и мог бы, например, врезаться в стену. Именно датчики делают робота по-настоящему полезным помощником, способным подстраиваться под окружающий мир.","quiz":[{"question":"Какой датчик помогает роботу понять, светло вокруг или темно?","options":["Датчик звука","Датчик света","Датчик касания","Датчик расстояния"],"correctIndex":1},{"question":"Как работает датчик расстояния (ультразвуковой)?","options":["Он слушает музыку","Он посылает сигнал и определяет, за сколько времени он вернётся обратно","Он измеряет температуру воздуха","Он определяет цвет предмета"],"correctIndex":1},{"question":"На что похож принцип работы ультразвукового датчика расстояния?","options":["На то, как летучая мышь ориентируется в темноте","На то, как работает батарейка","На то, как крутится колесо","На то, как работает выключатель"],"correctIndex":0},{"question":"Какой датчик реагирует, когда робот к чему-то прикоснулся?","options":["Датчик звука","Датчик касания (бампер)","Датчик света","Датчик линии"],"correctIndex":1},{"question":"Для чего роботу-пылесосу нужен датчик расстояния?","options":["Чтобы не врезаться в мебель и вовремя поворачивать","Чтобы включать музыку","Чтобы заряжать батарейку","Чтобы разговаривать"],"correctIndex":0},{"question":"Что делает датчик линии?","options":["Определяет громкость звука","Помогает роботу двигаться точно по нарисованной линии","Заряжает робота","Включает свет в комнате"],"correctIndex":1},{"question":"Куда датчики отправляют собранную информацию?","options":["В батарейку","В контроллер (\"мозг\" робота)","В корпус","В провода"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-14T08:30:00+05:00","ends_at":"2026-07-14T09:15:00+05:00","room":"101"},{"topic":"Моторы и движение робота","objective":"Ученики поймут, как моторы и колёса позволяют роботу двигаться, поворачивать и останавливаться.","theory":"Мы уже знаем, что датчики — это \"органы чувств\" робота, а контроллер — его \"мозг\". Но чтобы робот мог что-то делать, а не просто \"думать\", ему нужны моторы — те части, которые превращают команды контроллера в настоящее движение.\n\nМотор — это устройство, которое превращает электрическую энергию (ту, что течёт по проводам от батарейки) в механическое движение, то есть в кручение. Когда контроллер отправляет мотору сигнал \"работай!\", внутри мотора начинает вращаться маленькая деталь — вал. К этому валу можно прикрепить колесо, и тогда при вращении вала колесо тоже начнёт крутиться, и робот поедет.\n\nУ большинства колёсных роботов есть минимум два мотора — по одному на каждое колесо (левое и правое). Именно два отдельных мотора позволяют роботу не только ехать вперёд, но и поворачивать! Если оба мотора крутят колёса с одинаковой скоростью в одну сторону, робот едет прямо. Если левое колесо крутится быстрее правого, робот поворачивает направо. А если один мотор крутится вперёд, а другой — назад, робот разворачивается почти на месте, как танк.\n\nКроме обычных моторов для колёс, в роботах часто используют сервомоторы (сервоприводы) — специальные моторы, которые могут поворачиваться на точный угол, например ровно на 90 градусов, и оставаться в этом положении. Сервомоторы часто ставят в манипуляторы — \"руки\" робота, чтобы робот мог, например, аккуратно взять предмет и повернуть его в нужную сторону.\n\nЧтобы робот остановился, контроллер просто перестаёт подавать энергию на моторы — и колёса перестают крутиться. У некоторых роботов есть ещё и тормоза, как в машине, чтобы останавливаться быстрее и точнее.\n\nКроме колёс, роботы могут двигаться и по-другому: на гусеницах (как танк) — это помогает ехать по неровной поверхности; на ногах (как роботы-андроиды или роботы-собаки) — это сложнее всего запрограммировать, зато такие роботы могут подниматься по лестнице; с помощью пропеллеров (винтов) — так летают роботы-дроны.\n\nВажно понимать: моторы сами по себе \"не знают\", что им делать. Они лишь выполняют команды, которые получают от контроллера. Именно связка \"датчики + контроллер + моторы\" делает робота по-настоящему умным: датчики \"видят\" мир, контроллер \"решает\", а моторы \"выполняют\" решение, приводя робота в движение.","quiz":[{"question":"Что делает мотор в роботе?","options":["Хранит энергию","Превращает электрическую энергию в движение","Видит препятствия","Издаёт звук"],"correctIndex":1},{"question":"Сколько моторов обычно есть у простого колёсного робота для движения и поворотов?","options":["Один","Минимум два — по одному на каждое колесо","Пять","Ни одного"],"correctIndex":1},{"question":"Как робот поворачивает направо, если у него по мотору на каждое колесо?","options":["Оба колеса крутятся с одинаковой скоростью","Левое колесо крутится быстрее правого","Оба мотора выключены","Оба колеса крутятся назад"],"correctIndex":1},{"question":"Что такое сервомотор?","options":["Обычная батарейка","Мотор, который может поворачиваться на точный угол и удерживать положение","Датчик света","Провод для передачи тока"],"correctIndex":1},{"question":"Как робот останавливается?","options":["Контроллер перестаёт подавать энергию на моторы","Мотор ломается","Датчик выключает свет","Батарейка взрывается"],"correctIndex":0},{"question":"Как передвигаются роботы-дроны?","options":["На колёсах","На гусеницах","С помощью пропеллеров (винтов)","На ногах"],"correctIndex":2},{"question":"Какая связка частей делает робота по-настоящему \"умным\"?","options":["Только корпус","Датчики + контроллер + моторы","Только батарейка","Только провода"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-16T10:20:00+05:00","ends_at":"2026-07-16T11:05:00+05:00","room":"101"},{"topic":"Алгоритм — план действий для робота","objective":"Ученики поймут, что такое алгоритм, и научатся составлять простую последовательность команд для робота.","theory":"Мы уже знаем, из каких частей состоит робот: корпус, датчики, моторы и контроллер — \"мозг\" робота. Но откуда контроллер знает, что и в какой момент делать? Ответ прост: человек заранее пишет для робота программу — набор команд, который называется алгоритмом.\n\nАлгоритм — это чёткая последовательность шагов (команд), которые нужно выполнить одну за другой, чтобы получить нужный результат. Мы, люди, тоже постоянно используем алгоритмы, даже не задумываясь об этом! Например, алгоритм чистки зубов: 1) взять зубную щётку, 2) нанести пасту, 3) почистить зубы, 4) прополоскать рот. Если поменять шаги местами или пропустить один из них, результат может получиться неправильным.\n\nДля робота алгоритм — это точно такой же список шагов, только записанный на понятном роботу языке команд. Например, чтобы робот проехал от одной стены комнаты до другой и остановился, можно составить такой алгоритм:\n1) Включить моторы и ехать вперёд.\n2) Проверять расстояние до стены с помощью датчика.\n3) Если расстояние стало маленьким — остановить моторы.\n\nОчень важно, что робот выполняет команды строго по порядку, ровно в той последовательности, в которой их записал человек. Робот не умеет \"додумывать\" и не может пропустить шаг по своему желанию — он делает именно то, что написано в программе, ни больше ни меньше. Поэтому, если программист ошибётся в порядке команд, робот может выполнить задание неправильно: например, поехать не в ту сторону или не остановиться вовремя.\n\nСоставлять алгоритмы можно разными способами. Один из самых удобных способов для начинающих — использовать блок-схемы или готовые графические \"кубики\"-команды, которые нужно расставить в правильном порядке, как конструктор. Такие кубики часто используют в специальных программах для обучения программированию — там не нужно писать текст, а достаточно перетаскивать блоки с командами вроде \"шаг вперёд\", \"повернуть направо\", \"поднять руку\".\n\nУмение составлять алгоритмы — это главный навык, который отличает настоящего программиста робота от простого пользователя. Ведь именно правильно составленный алгоритм превращает набор железных деталей — корпуса, моторов и датчиков — в робота, который умеет выполнять полезные и интересные задачи.\n\nНа следующем уроке мы пойдём ещё дальше и узнаем, как заставить робота повторять одни и те же действия много раз, не записывая одну и ту же команду снова и снова.","quiz":[{"question":"Что такое алгоритм?","options":["Чёткая последовательность шагов для получения нужного результата","Название батарейки","Вид датчика","Тип мотора"],"correctIndex":0},{"question":"Почему важно соблюдать правильный порядок шагов в алгоритме?","options":["Это не важно, порядок можно менять","Если поменять порядок шагов, результат может получиться неправильным","Робот сам исправит ошибку","Порядок важен только для человека, не для робота"],"correctIndex":1},{"question":"Может ли робот сам пропустить шаг в программе, если ему \"не хочется\" его выполнять?","options":["Да, робот выбирает шаги по желанию","Нет, робот выполняет команды строго по порядку, как записано","Робот выполняет только последний шаг","Робот выполняет шаги в случайном порядке"],"correctIndex":1},{"question":"Какой пример алгоритма из обычной жизни приведён в тексте?","options":["Алгоритм чистки зубов","Алгоритм полёта на Луну","Алгоритм постройки дома","Алгоритм приготовления борща"],"correctIndex":0},{"question":"Каким удобным способом начинающие могут составлять алгоритмы для робота?","options":["Только с помощью длинного текста на английском языке","С помощью графических блоков-команд, которые расставляют по порядку","Устно, не записывая ничего","Алгоритмы всегда придумывает сам робот"],"correctIndex":1},{"question":"Что произойдёт, если программист ошибётся в порядке команд алгоритма?","options":["Робот всё равно выполнит задание правильно","Робот может выполнить задание неправильно","Робот сломается навсегда","Ничего не изменится"],"correctIndex":1},{"question":"Какой навык отличает настоящего программиста робота от простого пользователя?","options":["Умение красить корпус робота","Умение составлять правильные алгоритмы","Умение менять батарейки","Умение громко говорить"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"blockly_games","externalServiceTask":"Пройди уровень «Лабиринт» в Blockly Games: составь последовательность блоков-команд, чтобы провести робота от старта до финиша по лабиринту.","starts_at":"2026-07-21T08:30:00+05:00","ends_at":"2026-07-21T09:15:00+05:00","room":"101"},{"topic":"Циклы: повторяем команды в программе","objective":"Ученики поймут, что такое цикл (повторение) в программе, и научатся использовать его вместо повторяющихся одинаковых команд.","theory":"На прошлом уроке мы узнали, что такое алгоритм — последовательность команд для робота. Мы составляли программы, где команды шли одна за другой: вперёд, проверить, остановиться. Но что делать, если роботу нужно повторить одно и то же действие много раз подряд?\n\nПредставь, что робот должен нарисовать на полу квадрат. Для этого ему нужно: проехать вперёд, повернуть на 90 градусов, снова проехать вперёд, снова повернуть на 90 градусов — и так четыре раза, чтобы получился квадрат с четырьмя сторонами и четырьмя углами. Можно, конечно, записать эти восемь команд подряд одну за другой. Но представь, что нужно нарисовать не квадрат, а фигуру с двадцатью сторонами — записывать сорок одинаковых команд подряд было бы очень долго и неудобно, да и легко ошибиться.\n\nДля таких случаев в программировании придумали цикл — специальную команду, которая говорит роботу: \"повтори эти действия несколько раз\". Вместо того чтобы записывать команду \"проехать вперёд, повернуть на 90 градусов\" четыре раза подряд, программист один раз записывает эти два действия и добавляет цикл \"повторить 4 раза\". Робот сам выполнит эти два действия ровно четыре раза подряд — и нарисует квадрат.\n\nЦиклы бывают разные. Самый простой — цикл с заранее известным числом повторений, например \"повторить 4 раза\" или \"повторить 10 раз\". Есть и другой вид цикла — \"повторяй, пока выполняется условие\". Например: \"повторяй ехать вперёд, пока датчик расстояния не покажет, что рядом стена\". В этом случае робот не знает заранее, сколько раз он повторит действие — он остановится сам, как только сработает датчик.\n\nИспользование циклов делает программы короче, понятнее и надёжнее. Чем короче программа, тем меньше вероятность ошибиться при её написании. Кроме того, если нужно поменять число повторений — например, нарисовать не квадрат, а пятиугольник, — достаточно поменять одну цифру в цикле (\"повторить 5 раз\" вместо \"повторить 4 раза\"), а не переписывать всю программу заново.\n\nЦиклы широко используются не только в роботах, но и в компьютерных играх, мультфильмах и даже в приложениях на телефоне — везде, где нужно повторить одно и то же действие много раз. Освоив циклы, ты сможешь составлять для робота гораздо более сложные и интересные программы, чем раньше, — и при этом писать их короче и быстрее.","quiz":[{"question":"Что такое цикл в программе робота?","options":["Команда, которая заставляет робота остановиться навсегда","Специальная команда, которая заставляет робота повторить действия несколько раз","Название датчика","Вид мотора"],"correctIndex":1},{"question":"Зачем нужен цикл, если можно просто записать одинаковые команды подряд много раз?","options":["Цикл делает программу короче, понятнее и легче для изменения","Цикл нужен только для украшения программы","Без цикла робот вообще не может двигаться","Цикл нужен, чтобы отключить датчики"],"correctIndex":0},{"question":"Сколько раз нужно повторить действия \"проехать вперёд, повернуть на 90 градусов\", чтобы робот нарисовал квадрат?","options":["2 раза","4 раза","10 раз","1 раз"],"correctIndex":1},{"question":"Какой цикл говорит роботу \"повторяй действие, пока не сработает условие\"?","options":["Цикл с заранее известным числом повторений","Цикл \"повторяй, пока выполняется условие\"","Цикл без повторений","Это не цикл, а датчик"],"correctIndex":1},{"question":"Что нужно изменить в программе с циклом, чтобы робот нарисовал пятиугольник вместо квадрата?","options":["Переписать всю программу заново","Поменять число повторений в цикле (например, \"повторить 5 раз\")","Поменять батарейку","Добавить новый мотор"],"correctIndex":1},{"question":"Где ещё, кроме программ для роботов, используются циклы?","options":["Только в роботах, больше нигде","В компьютерных играх, мультфильмах и приложениях на телефоне","Только в электрических цепях","Только в датчиках расстояния"],"correctIndex":1},{"question":"Что произойдёт, если робот использует цикл \"повторяй ехать вперёд, пока не сработает датчик расстояния до стены\"?","options":["Робот остановится сам, когда датчик обнаружит стену","Робот будет ехать вечно","Робот сразу остановится, не начиная движение","Робот поедет назад"],"correctIndex":0}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-23T10:20:00+05:00","ends_at":"2026-07-23T11:05:00+05:00","room":"101"}]'::jsonb)
    LOOP
      INSERT INTO public.lessons (group_id, subject_id, topic, title, description, status, starts_at, ends_at, started_at, ended_at, room, school_id)
      VALUES (
        v_group_id, v_subject_id, lesson_data->>'topic', lesson_data->>'topic', lesson_data->>'objective',
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN 'completed' ELSE 'scheduled' END,
        (lesson_data->>'starts_at')::timestamptz, (lesson_data->>'ends_at')::timestamptz,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'starts_at')::timestamptz ELSE NULL END,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'ends_at')::timestamptz ELSE NULL END,
        lesson_data->>'room', v_school_id
      )
      RETURNING id INTO v_lesson_id;

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, duration_min, school_id)
      VALUES (v_lesson_id, 1, 'middle', 'theory', 'presentation', lesson_data->>'topic', lesson_data->>'theory', 15, v_school_id);

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, duration_min, school_id)
      VALUES (v_lesson_id, 2, 'middle', 'task', 'quiz_qia', 'Проверь себя', 15, v_school_id)
      RETURNING id INTO v_stage_id;

      qpos := 0;
      FOR quiz_item IN SELECT * FROM jsonb_array_elements(lesson_data->'quiz')
      LOOP
        qpos := qpos + 1;
        INSERT INTO public.quiz_questions (stage_id, question_text, options, correct_option_index, position, points, time_per_question_seconds, school_id)
        VALUES (v_stage_id, quiz_item->>'question', quiz_item->'options', (quiz_item->>'correctIndex')::int, qpos, 1, 30, v_school_id);
      END LOOP;

      IF (lesson_data->>'hasExternalService')::boolean THEN
        INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, config, duration_min, school_id)
        VALUES (
          v_lesson_id, 3, 'middle', 'task', lesson_data->>'externalServiceType',
          lesson_data->>'externalServiceTask', lesson_data->>'externalServiceTask',
          jsonb_build_object('url',
            CASE lesson_data->>'externalServiceType'
              WHEN 'wokwi' THEN 'https://wokwi.com/projects/new/arduino-uno'
              WHEN 'codesandbox' THEN 'https://codesandbox.io/p/sandbox/vanilla'
              WHEN 'geogebra' THEN 'https://www.geogebra.org/classic'
              WHEN 'phet' THEN 'https://phet.colorado.edu/sims/html/forces-and-motion-basics/latest/forces-and-motion-basics_en.html'
              WHEN 'desmos' THEN 'https://www.desmos.com/calculator'
              WHEN 'blockly_games' THEN 'https://blockly.games/'
              WHEN 'visualgo' THEN 'https://visualgo.net/en'
              WHEN 'p5js' THEN 'https://editor.p5js.org/'
              WHEN 'excalidraw' THEN 'https://excalidraw.com/'
              WHEN 'learningapps' THEN 'https://learningapps.org/'
              WHEN 'sqlonline' THEN 'https://sqlime.org/'
              WHEN 'h5p' THEN 'https://h5p.eduos.snruz.uz/library'
              ELSE NULL
            END
          ),
          15, v_school_id
        );
      END IF;
    END LOOP;
  END IF;

  -- === 3-А класс | Русский язык (8 уроков) ===
  SELECT id INTO v_group_id FROM public.groups WHERE name = '3-А класс';
  SELECT id INTO v_subject_id FROM public.subjects WHERE group_id = v_group_id AND name = 'Русский язык';
  IF NOT EXISTS (SELECT 1 FROM public.lessons WHERE group_id = v_group_id AND subject_id = v_subject_id AND description IS NOT NULL) THEN
    FOR lesson_data IN SELECT * FROM jsonb_array_elements('[{"topic":"Корень слова и однокоренные слова","objective":"Научиться находить корень слова и подбирать к нему однокоренные слова.","theory":"Слово состоит из частей, которые называются морфемами. Самая главная часть слова — это корень. Корень — это общая часть родственных (однокоренных) слов, в которой заключено их главное, общее значение.\n\nНапример, слова лес, лесник, лесной, перелесок — все они связаны с лесом. Общая часть этих слов — лес-. Это и есть корень.\n\nЧтобы найти корень слова, нужно подобрать к нему несколько однокоренных слов и найти в них одинаковую часть. Например: вода, водный, водяной, подводный — корень вод-.\n\nОднокоренные слова — это слова, у которых один и тот же корень и близкое значение. Важно не путать однокоренные слова с формами одного и того же слова. Например, стол, столы, столу, о столе — это не разные однокоренные слова, а формы одного слова «стол». А вот стол, столик, столовая, застолье — это уже разные однокоренные слова, потому что у каждого своё значение, хотя корень один — стол-.\n\nБудь внимателен: некоторые слова похожи по звучанию, но имеют разные корни и разное значение. Например, гора и горе — это не однокоренные слова, хотя звучат похоже: гора связана с высокими холмами, а горе — с печалью.\n\nТакже нужно помнить о чередовании согласных в корне. Например, снег — снежок — снежинка: корень снег-/снеж-. Друг — друзья — дружба: корень друг-/друз-/друж-. При добавлении разных частей слова звуки могут немного изменяться, но смысл корня остаётся общим.\n\nЧтобы правильно определить корень, полезно задать вопрос: «Какое общее значение объединяет эти слова?» Если находишь несколько слов с одинаковым смыслом и одинаковой частью — значит, ты нашёл корень.\n\nЗнание корня помогает грамотно писать безударные гласные: если сомневаешься, как написать букву в корне, нужно подобрать проверочное однокоренное слово, где эта буква под ударением. Например, вода — воды (ударение на о), дом — домик, лес — лесом, трава — травы.\n\nУмение выделять корень и подбирать однокоренные слова — основа для дальнейшего изучения состава слова: приставки, суффикса и окончания, с которыми мы познакомимся на следующих уроках.","quiz":[{"question":"Что такое корень слова?","options":["Часть слова после окончания","Общая часть родственных (однокоренных) слов","Часть слова, которая всегда пишется с большой буквы","Последняя буква в слове"],"correctIndex":1},{"question":"Найди однокоренные слова к слову «лес»:","options":["лесть, лестница, лесной","лесник, лесной, перелесок","лестница, лев, лето","лестный, лесть, лестно"],"correctIndex":1},{"question":"Какое слово НЕ является однокоренным к слову «вода»?","options":["водный","водяной","подводный","садовый"],"correctIndex":3},{"question":"Слова «гора» и «горе» — это:","options":["однокоренные слова с одинаковым значением","формы одного и того же слова","слова с разными корнями и разным значением, хотя звучат похоже","синонимы"],"correctIndex":2},{"question":"Слова «стол», «столы», «о столе» — это:","options":["однокоренные слова","формы одного и того же слова","слова с разными корнями","антонимы"],"correctIndex":1},{"question":"В словах «снег», «снежок», «снежинка» происходит:","options":["замена корня","чередование согласных в корне","исчезновение корня","удвоение корня"],"correctIndex":1},{"question":"Чтобы проверить безударную гласную в корне, нужно:","options":["написать слово несколько раз","подобрать проверочное однокоренное слово, где гласная под ударением","посмотреть в конце учебника","заменить слово на синоним"],"correctIndex":1},{"question":"Какой корень в словах «друг», «друзья», «дружба»?","options":["дру-","друг-/друз-/друж- (чередующийся корень)","ба","корня нет"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-07T09:25:00+05:00","ends_at":"2026-07-07T10:10:00+05:00","room":"101"},{"topic":"Приставка — часть слова перед корнем","objective":"Научиться находить приставку в слове и понимать, как она изменяет значение слова.","theory":"На прошлом уроке мы узнали, что корень — главная часть слова, в которой заключено его основное значение. Но слова редко состоят только из одного корня — к нему часто присоединяются другие части. Сегодня мы познакомимся с приставкой.\n\nПриставка — это часть слова, которая стоит перед корнем и служит для образования новых слов. Приставка меняет значение слова, часто на противоположное или на близкое, но другое.\n\nНапример, от корня -ход- (ходить) можно образовать много новых слов с помощью разных приставок: приходить, уходить, входить, выходить, переходить, обходить. Видишь, как меняется смысл слова в зависимости от приставки? При-ходить — прибыть куда-то, у-ходить — покинуть место, вы-ходить — выйти наружу.\n\nВ русском языке много приставок, вот самые распространённые: в-, вы-, за-, из-(ис-), на-, над-, о-(об-), от-, пере-, по-, под-, при-, про-, раз-(рас-), с-, у-.\n\nЧтобы найти приставку в слове, нужно: 1) сначала найти корень слова (подобрать однокоренные слова); 2) посмотреть, что стоит перед корнем — это и будет приставка.\n\nНапример, в слове «подводный» корень -вод- (вода), перед ним стоит приставка под-, а после корня — суффикс -н- и окончание -ый.\n\nВажно запомнить: приставка пишется слитно со словом, в отличие от предлога, который пишется отдельно. Например: «отошёл от дома» — «ото-» приставка в слове «отошёл» пишется слитно, а «от» перед словом «дома» — предлог, пишется раздельно. Чтобы отличить приставку от предлога, можно попробовать вставить между ними другое слово: «от (какого?) дома» — если получилось вставить слово, значит это предлог; к приставке вставить ничего нельзя, потому что она — часть слова.\n\nЕсть приставки на з/с: без-/бес-, воз-/вос-, из-/ис-, раз-/рас-. Выбор буквы (з или с) зависит от следующего за приставкой звука: если он звонкий — пишем з (безопасный), если глухой — с (бесполезный).\n\nУмение находить приставку помогает не только грамотно писать слова слитно, но и понимать смысл различных слов с одним и тем же корнем. Это пригодится на следующем уроке, когда мы изучим ещё одну важную часть слова — суффикс.","quiz":[{"question":"Что такое приставка?","options":["Часть слова, которая стоит после корня","Часть слова, которая стоит перед корнем и образует новые слова","Отдельное слово перед существительным","Последняя часть слова"],"correctIndex":1},{"question":"Какая приставка в слове «приходить»?","options":["при-","ходить-","при-ход","-ить"],"correctIndex":0},{"question":"Чем приставка отличается от предлога?","options":["Приставка пишется раздельно, предлог слитно","Приставка — часть слова и пишется слитно, а предлог — отдельное слово и пишется раздельно","Ничем не отличается","Приставка всегда стоит после слова"],"correctIndex":1},{"question":"В каком слове есть приставка «под-»?","options":["вода","водный","подводный","водяной"],"correctIndex":2},{"question":"Как определить, приставка перед словом или предлог?","options":["Посчитать буквы","Попробовать вставить между ними другое слово — если получится, это предлог","Посмотреть на цвет чернил","Приставки не бывает перед предлогом"],"correctIndex":1},{"question":"В приставках без-/бес-, из-/ис- выбор буквы з или с зависит от:","options":["настроения пишущего","следующего за приставкой звука (звонкий или глухой)","первой буквы слова","количества слогов в слове"],"correctIndex":1},{"question":"Что происходит со значением слова «ходить» при добавлении разных приставок (приходить, уходить, выходить)?","options":["Значение слова не меняется","Значение слова меняется, показывая разное направление действия","Слово перестаёт быть глаголом","Слово становится существительным"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"learningapps","externalServiceTask":"Составь пары: подбери подходящую приставку (в-, вы-, при-, у-, пере-) к корню -ход-, чтобы получить новое слово с нужным значением.","starts_at":"2026-07-09T09:25:00+05:00","ends_at":"2026-07-09T10:10:00+05:00","room":"101"},{"topic":"Суффикс — часть слова после корня","objective":"Научиться находить суффикс в слове и понимать его роль в образовании новых слов.","theory":"Мы уже знаем, что перед корнем может стоять приставка. А что находится после корня? Там часто стоит ещё одна важная часть слова — суффикс.\n\nСуффикс — это часть слова, которая стоит после корня и служит для образования новых слов, а также помогает выразить отношение говорящего к предмету: ласку, уменьшительность, увеличение или указывает на профессию, признак и так далее.\n\nНапример, от корня -дом- можно образовать слова: домик (маленький дом, ласково), домище (большой дом), домашний (относящийся к дому). Суффиксы -ик-, -ищ-, -ашн- меняют не только оттенок значения, но иногда и часть речи слова: «дом» — существительное, «домашний» — уже имя прилагательное!\n\nСамые распространённые суффиксы, обозначающие маленький предмет или ласковое отношение: -ик-, -ек-, -очк-, -ечк-, -оньк-, -еньк-. Например: стол — столик, книга — книжечка, берёза — берёзонька.\n\nСуффикс -ищ- обозначает большой размер: дом — домище, рука — ручища.\n\nСуффиксы, обозначающие профессию человека или того, кто выполняет действие: -тель-, -ник-, -чик-, -щик-. Например: учить — учитель, лес — лесник, лётать — лётчик, камень — каменщик.\n\nЧтобы найти суффикс в слове, нужно: 1) найти корень (подобрать однокоренные слова); 2) найти окончание слова (изменяемую часть в конце); 3) то, что осталось между корнем и окончанием, — это и есть суффикс.\n\nНапример, в слове «лесник» корень -лес-, окончание нулевое, а между ними стоит суффикс -ник-, который указывает на профессию.\n\nВ одном слове может быть несколько суффиксов подряд. Например, в слове «учительница» есть корень -уч-, суффикс -и-, суффикс -тель-, суффикс -ниц- и окончание -а.\n\nСуффикс, в отличие от приставки, может изменять часть речи слова. Например: от глагола «читать» с помощью суффикса -тель- образуется существительное «читатель»; от существительного «зима» с помощью суффикса -н- образуется прилагательное «зимний».\n\nЗнание суффиксов помогает не только правильно образовывать новые слова, но и понимать смысловые оттенки — ласковое, увеличительное или профессиональное значение. На следующем уроке мы узнаем о последней части слова — об окончании.","quiz":[{"question":"Что такое суффикс?","options":["Часть слова перед корнем","Часть слова после корня, образующая новые слова","Последняя изменяемая часть слова","Слово перед предложением"],"correctIndex":1},{"question":"Какой суффикс в слове «домик»?","options":["дом-","-ик","-ом-","-к"],"correctIndex":1},{"question":"Какой суффикс указывает на профессию в слове «лесник»?","options":["лес-","-ик","-ник","суффикса нет"],"correctIndex":2},{"question":"Суффикс -ищ- обычно обозначает:","options":["маленький предмет","ласковое отношение","большой размер предмета","профессию"],"correctIndex":2},{"question":"Что происходит со словом «зима», когда добавляется суффикс -н- (зимний)?","options":["Слово остаётся существительным","Слово превращается в имя прилагательное","Слово исчезает","Меняется только окончание"],"correctIndex":1},{"question":"Как найти суффикс в слове?","options":["Найти корень и окончание — то, что осталось между ними, это суффикс","Посчитать все буквы в слове","Найти первую букву слова","Суффикс всегда первая часть слова"],"correctIndex":0},{"question":"Сколько суффиксов в слове «учительница»?","options":["Один","Ни одного","Несколько (-и-, -тель-, -ниц-)","Суффиксов не бывает больше одного в слове"],"correctIndex":2}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-13T08:30:00+05:00","ends_at":"2026-07-13T09:15:00+05:00","room":"101"},{"topic":"Окончание и основа слова","objective":"Научиться находить окончание слова, отличать окончание от основы и понимать роль окончания в предложении.","theory":"Мы уже познакомились с тремя частями слова: корнем, приставкой и суффиксом. Сегодня узнаем о последней, четвёртой части слова — окончании, а также о том, что такое основа слова, и завершим изучение состава слова.\n\nОкончание — это изменяемая часть слова, которая стоит в самом конце и служит для связи слов в предложении и словосочетании. Окончание показывает число, род, падеж имени существительного или прилагательного, лицо и число глагола.\n\nНапример, слово «книга» изменяется: книга, книги, книге, книгу, книгой, о книге. Меняется именно окончание — -а, -и, -е, -у, -ой, -е, а остальная часть слова «книг-» остаётся неизменной.\n\nЧасть слова без окончания называется основой слова. В основу входят приставка, корень и суффикс. Основа выражает главное лексическое значение слова, а окончание — грамматическое (указывает на форму слова).\n\nНапример, в слове «книгой» основа — «книг-», окончание — «-ой». В слове «подводный» основа — «подводн-» (приставка под- + корень -вод- + суффикс -н-), окончание — «-ый».\n\nКак найти окончание? Нужно изменить слово: например, по числам (один — много) или по вопросам (кто? кого? кому?). Та часть, которая меняется, — это окончание. Например: стол — стола — столу — столом — о столе. Меняющаяся часть — окончание, а «стол-» — основа.\n\nВажно помнить: не у всех слов есть окончание. Некоторые слова не изменяются — например, наречия (быстро, вчера, далеко) или неизменяемые существительные (пальто, кино, метро). У таких слов нет окончания, вся часть слова — это основа.\n\nСуществует также «нулевое окончание». Это значит, что окончание есть, но оно не выражено буквами. Например, в слове «стол» (именительный падеж, единственное число) окончание нулевое, потому что при изменении слова (стола, столу, столом) окончание уже видно, а в начальной форме оно «пустое».\n\nТеперь мы знаем все четыре части слова: приставка — перед корнем, корень — главная часть с общим значением, суффикс — после корня, окончание — изменяемая часть в конце слова. Вместе они называются «состав слова», а раздел науки о языке, который его изучает, — морфемика. Умение разбирать слово по составу поможет грамотно писать слова и понимать, как образуются новые слова.","quiz":[{"question":"Что такое окончание слова?","options":["Неизменяемая часть слова в начале","Изменяемая часть слова, стоящая в конце и служащая для связи слов","Главная часть слова со значением","Часть слова, которая никогда не меняется"],"correctIndex":1},{"question":"Что такое основа слова?","options":["Часть слова без окончания","Только корень слова","Только окончание слова","Первая буква слова"],"correctIndex":0},{"question":"Какое окончание в слове «книгой»?","options":["книг-","-ой","-ий","окончания нет"],"correctIndex":1},{"question":"Что такое нулевое окончание?","options":["Окончание, которого вообще не существует в языке","Окончание, которое есть, но не выражено буквами на письме","Окончание из одной буквы «о»","Окончание, которое всегда пишется как ноль"],"correctIndex":1},{"question":"У каких слов не бывает окончания?","options":["У всех имён существительных","У неизменяемых слов, например наречий и слов вроде «пальто»","У всех глаголов","У всех слов с приставкой"],"correctIndex":1},{"question":"Как найти окончание слова?","options":["Изменить слово по числам или падежам и посмотреть, какая часть меняется","Найти первую букву слова","Посчитать количество слогов","Окончание всегда последняя буква алфавита в слове"],"correctIndex":0},{"question":"Что входит в основу слова?","options":["Только окончание","Приставка, корень и суффикс (всё, кроме окончания)","Только корень","Только суффикс и окончание"],"correctIndex":1},{"question":"Как называется раздел науки о языке, изучающий состав слова?","options":["Фонетика","Синтаксис","Морфемика","Орфография"],"correctIndex":2}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-14T09:25:00+05:00","ends_at":"2026-07-14T10:10:00+05:00","room":"101"},{"topic":"Имя существительное: род существительных","objective":"Научиться определять род имени существительного (мужской, женский, средний) и правильно согласовывать с ним другие слова.","theory":"Мы закончили изучать состав слова и переходим к частям речи — большим группам слов, которые отвечают на одинаковые вопросы и обладают похожими признаками. Сегодня подробнее изучим имя существительное, а именно его род.\n\nИмя существительное — часть речи, которая обозначает предмет и отвечает на вопросы кто? или что? Например: мальчик, книга, окно, радость.\n\nКаждое имя существительное в русском языке относится к одному из трёх родов: мужской, женский или средний.\n\nМужской род: к этим словам можно подставить слово «он мой». Например: стол (он мой), карандаш (он мой), папа (он мой), день (он мой). Существительные мужского рода обычно оканчиваются на согласный (стол, дом) или на -й (герой, чай), а иногда — на -ь (день, конь).\n\nЖенский род: к этим словам можно подставить слово «она моя». Например: книга (она моя), мама (она моя), дверь (она моя), песня (она моя). Существительные женского рода обычно оканчиваются на -а, -я или на -ь (дверь, мышь).\n\nСредний род: к этим словам можно подставить слово «оно моё». Например: окно (оно моё), солнце (оно моё), поле (оно моё), яблоко (оно моё). Существительные среднего рода обычно оканчиваются на -о, -е.\n\nОсобую сложность вызывают слова, оканчивающиеся на мягкий знак -ь: часть из них мужского рода (день, конь, дождь, словарь), а часть — женского рода (дверь, мышь, ночь, тетрадь). Здесь нельзя определить род только по окончанию — нужно проверять, подставляя слово «он мой» или «она моя».\n\nОпределять род существительного очень важно, потому что от рода зависит, как изменяется прилагательное или местоимение рядом с этим существительным. Например: «красивый дом» (мужской род), «красивая книга» (женский род), «красивое окно» (средний род). Если ошибиться с родом, прилагательное будет согласовано неверно.\n\nТакже есть небольшая группа существительных общего рода — они могут быть и мужского, и женского рода в зависимости от того, о ком идёт речь: например, «сирота», «неряха», «умница». «Он большой умница» и «она большая умница» — оба варианта верны.\n\nУмение точно определять род имени существительного — важный шаг к грамотной речи и письму, ведь от него зависит правильное согласование слов в предложении.","quiz":[{"question":"На какие вопросы отвечает имя существительное?","options":["какой? какая?","что делать?","кто? что?","как? когда?"],"correctIndex":2},{"question":"Сколько родов у имён существительных в русском языке?","options":["Два","Три","Четыре","Пять"],"correctIndex":1},{"question":"Как определить мужской род существительного?","options":["Подставить слово «оно моё»","Подставить слово «он мой»","Подставить слово «она моя»","Посмотреть на количество букв"],"correctIndex":1},{"question":"К какому роду относится слово «окно»?","options":["Мужской","Женский","Средний","Общий"],"correctIndex":2},{"question":"Почему слова на -ь (день, дверь) требуют особого внимания при определении рода?","options":["Они всегда среднего рода","Среди них есть слова и мужского, и женского рода — нужно проверять","У них вообще нет рода","Они всегда во множественном числе"],"correctIndex":1},{"question":"Какое словосочетание составлено верно по согласованию рода?","options":["красивый книга","красивая книга","красивое книга","красивые книга"],"correctIndex":1},{"question":"Приведи пример слова общего рода:","options":["стол","книга","умница","окно"],"correctIndex":2},{"question":"От чего зависит правильное окончание прилагательного, стоящего рядом с существительным?","options":["От настроения говорящего","От рода, числа и падежа существительного","От длины слова","От времени суток"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"learningapps","externalServiceTask":"Распредели слова-карточки (стол, книга, окно, дверь, солнце, мяч и другие) по трём группам: мужской, женский, средний род.","starts_at":"2026-07-16T09:25:00+05:00","ends_at":"2026-07-16T10:10:00+05:00","room":"101"},{"topic":"Число и падеж имени существительного","objective":"Научиться определять число (единственное/множественное) имени существительного и различать падежи по их вопросам.","theory":"На прошлом уроке мы научились определять род имени существительного. Теперь узнаем, как существительные изменяются по числам и падежам — это поможет грамотно строить предложения.\n\nЧисло имени существительного показывает, идёт ли речь об одном предмете или о нескольких. Единственное число — один предмет: стол, книга, окно. Множественное число — несколько предметов: столы, книги, окна. Обычно множественное число образуется с помощью окончаний -ы, -и, -а, -я: стол — столы, книга — книги, окно — окна, друг — друзья.\n\nЕсть существительные, которые употребляются только в единственном числе: молоко, сахар, мужество, любовь. А есть слова только во множественном числе: ножницы, брюки, каникулы, ворота — у них нет формы единственного числа.\n\nТеперь о падеже. Падеж — это изменение формы имени существительного, которое показывает его роль в предложении, связь с другими словами. В русском языке шесть падежей, у каждого своё название и свой вопрос:\n1) Именительный падеж — кто? что? (есть кто? стол)\n2) Родительный падеж — кого? чего? (нет кого? стола)\n3) Дательный падеж — кому? чему? (дать кому? столу)\n4) Винительный падеж — кого? что? (вижу что? стол)\n5) Творительный падеж — кем? чем? (доволен чем? столом)\n6) Предложный падеж — о ком? о чём? (думаю о чём? о столе)\n\nЧтобы определить падеж существительного в предложении, нужно найти слово, к которому оно относится, и задать от него правильный вопрос. Например, в предложении «Мама подарила книгу дочке» слово «книгу» отвечает на вопрос «подарила что?» — это винительный падеж; слово «дочке» отвечает на вопрос «подарила кому?» — это дательный падеж.\n\nИзменение существительного по падежам называется склонением. Подробно склонение будем изучать в следующих классах, а сейчас важно запомнить названия падежей, их вопросы и научиться задавать эти вопросы к словам в предложении.\n\nПолезный приём для запоминания порядка падежей — фраза-подсказка: «Иван Родил Девчонку, Велел Тащить Пелёнку» — первые буквы слов подсказывают порядок падежей: Именительный, Родительный, Дательный, Винительный, Творительный, Предложный.\n\nУмение определять число и падеж существительного — важный навык, который поможет и в устной речи, и на письме, особенно когда мы будем изучать правописание падежных окончаний.","quiz":[{"question":"Что показывает число имени существительного?","options":["Падеж слова","Один предмет или несколько","Род слова","Часть речи"],"correctIndex":1},{"question":"Какое существительное стоит только во множественном числе?","options":["молоко","ножницы","стол","книга"],"correctIndex":1},{"question":"Сколько падежей в русском языке?","options":["Четыре","Пять","Шесть","Семь"],"correctIndex":2},{"question":"На какие вопросы отвечает винительный падеж?","options":["кто? что?","кого? чего?","кого? что?","кем? чем?"],"correctIndex":2},{"question":"В предложении «Мама подарила книгу дочке» в каком падеже стоит слово «дочке»?","options":["Именительный","Дательный","Творительный","Предложный"],"correctIndex":1},{"question":"Как называется изменение существительного по падежам?","options":["Спряжение","Склонение","Согласование","Чередование"],"correctIndex":1},{"question":"Вопросы «кем? чем?» относятся к какому падежу?","options":["Родительный","Творительный","Предложный","Дательный"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-20T08:30:00+05:00","ends_at":"2026-07-20T09:15:00+05:00","room":"101"},{"topic":"Имя прилагательное и его связь с существительным","objective":"Научиться находить имя прилагательное в тексте и правильно согласовывать его с именем существительным в роде, числе и падеже.","theory":"Мы подробно изучили имя существительное — часть речи, которая называет предметы. Теперь познакомимся с именем прилагательным — частью речи, которая помогает описать эти предметы и делает нашу речь яркой и точной.\n\nИмя прилагательное — часть речи, которая обозначает признак предмета и отвечает на вопросы какой? какая? какое? какие? Признак может быть разным: цвет (красный, синий), размер (большой, маленький), материал (деревянный, стеклянный), вкус (сладкий, кислый), характер (добрый, весёлый) и многое другое.\n\nНапример: яблоко (какое?) — красное, сладкое, круглое; мальчик (какой?) — весёлый, добрый, высокий; книга (какая?) — интересная, старая, толстая.\n\nСамая главная особенность имени прилагательного — оно никогда не употребляется само по себе, а всегда связано с именем существительным, к которому относится, и полностью согласуется с ним в роде, числе и падеже. Это значит, что при изменении существительного изменяется и прилагательное.\n\nНапример: красивый дом (мужской род, единственное число), красивая ваза (женский род, единственное число), красивое платье (средний род, единственное число), красивые дома (множественное число). Обрати внимание, как меняется окончание прилагательного в зависимости от рода и числа существительного: -ый/-ой (м.р.), -ая (ж.р.), -ое (ср.р.), -ые/-ие (мн.ч.).\n\nЧтобы определить род, число и падеж прилагательного, нужно посмотреть на существительное, с которым оно связано, — прилагательное всегда «повторяет» его форму. Например, в словосочетании «о синем море» существительное «море» стоит в предложном падеже, среднего рода, единственного числа — значит, и прилагательное «синем» стоит в той же форме.\n\nВ предложении имя прилагательное чаще всего является определением и отвечает на вопрос какой? Например: «Пушистый кот спал на тёплом одеяле» — «пушистый» определяет слово «кот», «тёплом» определяет слово «одеяле».\n\nИмена прилагательные делают нашу речь более выразительной, точной и красивой. Сравни два предложения: «Наступила осень» и «Наступила золотая, дождливая осень» — второе гораздо ярче описывает картину благодаря прилагательным.\n\nВажно помнить: чтобы не ошибиться в окончании прилагательного, всегда нужно смотреть на существительное, к которому оно относится, задавать от него вопрос какой? какая? какое? какие? — и по вопросу проверять правильность окончания.","quiz":[{"question":"На какие вопросы отвечает имя прилагательное?","options":["кто? что?","что делать?","какой? какая? какое? какие?","где? когда?"],"correctIndex":2},{"question":"Что обозначает имя прилагательное?","options":["Предмет","Признак предмета","Действие предмета","Количество предметов"],"correctIndex":1},{"question":"С какой частью речи всегда согласуется имя прилагательное?","options":["С глаголом","С именем существительным","С наречием","С предлогом"],"correctIndex":1},{"question":"В чём согласуется прилагательное с существительным?","options":["Только в числе","В роде, числе и падеже","Только в падеже","Прилагательное не согласуется с существительным"],"correctIndex":1},{"question":"Выбери верное словосочетание:","options":["красивый ваза","красивая ваза","красивое ваза","красивые ваза"],"correctIndex":1},{"question":"В предложении «Пушистый кот спал на тёплом одеяле» каким членом предложения являются прилагательные?","options":["Подлежащим","Сказуемым","Определением","Дополнением"],"correctIndex":2},{"question":"Как проверить правильное окончание прилагательного?","options":["Посмотреть на цвет обложки книги","Задать вопрос от существительного, к которому оно относится","Написать наугад","Прилагательное никогда не меняет окончание"],"correctIndex":1},{"question":"Какое из слов является именем прилагательным?","options":["бежит","радость","весёлый","быстро"],"correctIndex":2}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-21T09:25:00+05:00","ends_at":"2026-07-21T10:10:00+05:00","room":"101"},{"topic":"Глагол: настоящее, прошедшее и будущее время","objective":"Научиться определять время глагола (настоящее, прошедшее, будущее) и правильно изменять глаголы по временам.","theory":"Мы познакомились с именем существительным и именем прилагательным. Сегодняшний урок посвящён ещё одной важной части речи — глаголу, а именно временам глагола.\n\nГлагол — часть речи, которая обозначает действие предмета и отвечает на вопросы что делать? что сделать? что делает? что сделал? и другие похожие вопросы. Например: бежать, читать, писать, прыгнул, поёт.\n\nОдна из главных особенностей глагола — он изменяется по временам, то есть показывает, когда происходит действие: сейчас, было раньше или произойдёт потом. В русском языке три времени глагола: настоящее, прошедшее и будущее.\n\nНастоящее время показывает, что действие происходит сейчас, в момент речи. Глаголы настоящего времени отвечают на вопросы что делает? что делают? Например: мальчик читает, дети играют, солнце светит. Они изменяются по лицам и числам: я читаю, ты читаешь, он читает, мы читаем, вы читаете, они читают.\n\nПрошедшее время показывает, что действие уже произошло до момента речи. Глаголы прошедшего времени отвечают на вопросы что делал? что сделал? что сделала? что сделали? Например: мальчик читал, дети играли, солнце светило. Они образуются с помощью суффикса -л- и изменяются по родам (в единственном числе) и числам, но не изменяются по лицам: он читал, она читала, оно читало, они читали.\n\nБудущее время показывает, что действие произойдёт после момента речи. Глаголы будущего времени отвечают на вопросы что сделает? что будет делать? Будущее время бывает двух видов: простое (одно слово): я прочитаю, он напишет — и сложное (два слова: буду/будешь + начальная форма глагола): я буду читать, ты будешь играть.\n\nЧтобы определить время глагола, нужно задать к нему вопрос и посмотреть, когда происходит действие: играет — что делает? — настоящее время; играл — что делал? — прошедшее время; будет играть / сыграет — что сделает? — будущее время.\n\nВажно помнить: изменение глагола по временам — очень важный признак данной части речи, который отличает глагол от других частей речи. Ни существительное, ни прилагательное не изменяются по временам!\n\nПонимание времён глагола помогает нам точно и грамотно рассказывать о событиях: что происходит сейчас, что уже случилось и что ещё только будет. Это важный шаг к тому, чтобы уверенно строить рассказы, пересказы и сочинения на русском языке.","quiz":[{"question":"Что обозначает глагол?","options":["Предмет","Признак предмета","Действие предмета","Количество предметов"],"correctIndex":2},{"question":"Сколько времён у глагола в русском языке?","options":["Два","Три","Четыре","Пять"],"correctIndex":1},{"question":"На какие вопросы отвечает глагол настоящего времени?","options":["что делал? что сделал?","что делает? что делают?","что сделает?","какой? какая?"],"correctIndex":1},{"question":"С помощью какого суффикса образуется прошедшее время глагола?","options":["-л-","-ть-","-ущ-","-ем-"],"correctIndex":0},{"question":"По каким признакам изменяется глагол прошедшего времени в единственном числе?","options":["По лицам","По родам","По падежам","Не изменяется"],"correctIndex":1},{"question":"Какой глагол стоит в будущем времени?","options":["читает","читал","прочитает","читая"],"correctIndex":2},{"question":"Какая часть речи, в отличие от глагола, не изменяется по временам?","options":["Только глагол изменяется по временам, например существительное — нет","Все части речи изменяются по временам","Ничего не изменяется по временам","Наречие изменяется по временам так же, как глагол"],"correctIndex":0},{"question":"Сложное будущее время образуется с помощью:","options":["суффикса -л-","слова «буду/будешь» + начальная форма глагола","приставки не-","окончания -ешь"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"h5p","externalServiceTask":"Выполни интерактивное упражнение: распредели глаголы (играл, играет, будет играть, напишет, читал, поёт) по трём группам — настоящее, прошедшее, будущее время.","starts_at":"2026-07-23T09:25:00+05:00","ends_at":"2026-07-23T10:10:00+05:00","room":"101"}]'::jsonb)
    LOOP
      INSERT INTO public.lessons (group_id, subject_id, topic, title, description, status, starts_at, ends_at, started_at, ended_at, room, school_id)
      VALUES (
        v_group_id, v_subject_id, lesson_data->>'topic', lesson_data->>'topic', lesson_data->>'objective',
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN 'completed' ELSE 'scheduled' END,
        (lesson_data->>'starts_at')::timestamptz, (lesson_data->>'ends_at')::timestamptz,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'starts_at')::timestamptz ELSE NULL END,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'ends_at')::timestamptz ELSE NULL END,
        lesson_data->>'room', v_school_id
      )
      RETURNING id INTO v_lesson_id;

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, duration_min, school_id)
      VALUES (v_lesson_id, 1, 'middle', 'theory', 'presentation', lesson_data->>'topic', lesson_data->>'theory', 15, v_school_id);

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, duration_min, school_id)
      VALUES (v_lesson_id, 2, 'middle', 'task', 'quiz_qia', 'Проверь себя', 15, v_school_id)
      RETURNING id INTO v_stage_id;

      qpos := 0;
      FOR quiz_item IN SELECT * FROM jsonb_array_elements(lesson_data->'quiz')
      LOOP
        qpos := qpos + 1;
        INSERT INTO public.quiz_questions (stage_id, question_text, options, correct_option_index, position, points, time_per_question_seconds, school_id)
        VALUES (v_stage_id, quiz_item->>'question', quiz_item->'options', (quiz_item->>'correctIndex')::int, qpos, 1, 30, v_school_id);
      END LOOP;

      IF (lesson_data->>'hasExternalService')::boolean THEN
        INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, config, duration_min, school_id)
        VALUES (
          v_lesson_id, 3, 'middle', 'task', lesson_data->>'externalServiceType',
          lesson_data->>'externalServiceTask', lesson_data->>'externalServiceTask',
          jsonb_build_object('url',
            CASE lesson_data->>'externalServiceType'
              WHEN 'wokwi' THEN 'https://wokwi.com/projects/new/arduino-uno'
              WHEN 'codesandbox' THEN 'https://codesandbox.io/p/sandbox/vanilla'
              WHEN 'geogebra' THEN 'https://www.geogebra.org/classic'
              WHEN 'phet' THEN 'https://phet.colorado.edu/sims/html/forces-and-motion-basics/latest/forces-and-motion-basics_en.html'
              WHEN 'desmos' THEN 'https://www.desmos.com/calculator'
              WHEN 'blockly_games' THEN 'https://blockly.games/'
              WHEN 'visualgo' THEN 'https://visualgo.net/en'
              WHEN 'p5js' THEN 'https://editor.p5js.org/'
              WHEN 'excalidraw' THEN 'https://excalidraw.com/'
              WHEN 'learningapps' THEN 'https://learningapps.org/'
              WHEN 'sqlonline' THEN 'https://sqlime.org/'
              WHEN 'h5p' THEN 'https://h5p.eduos.snruz.uz/library'
              ELSE NULL
            END
          ),
          15, v_school_id
        );
      END IF;
    END LOOP;
  END IF;

  -- === 3-А класс | Математика (14 уроков) ===
  SELECT id INTO v_group_id FROM public.groups WHERE name = '3-А класс';
  SELECT id INTO v_subject_id FROM public.subjects WHERE group_id = v_group_id AND name = 'Математика';
  IF NOT EXISTS (SELECT 1 FROM public.lessons WHERE group_id = v_group_id AND subject_id = v_subject_id AND description IS NOT NULL) THEN
    FOR lesson_data IN SELECT * FROM jsonb_array_elements('[{"topic":"Нумерация чисел в пределах 1000","objective":"Научить читать, записывать и понимать разрядный состав трёхзначных чисел (сотни, десятки, единицы).","theory":"До сих пор мы работали с числами от 1 до 100. Теперь узнаем, как устроены числа от 100 до 1000 — трёхзначные числа.\n\nКаждое трёхзначное число состоит из сотен, десятков и единиц. Например, число 347 означает: 3 сотни, 4 десятка и 7 единиц. Можно записать это так: 347 = 300 + 40 + 7.\n\nРазряды в числе располагаются справа налево: первая цифра справа — разряд единиц, вторая — разряд десятков, третья — разряд сотен. В числе 347 цифра 7 стоит в разряде единиц, 4 — в разряде десятков, 3 — в разряде сотен.\n\nСамое маленькое трёхзначное число — 100 (1 сотня, 0 десятков, 0 единиц). Самое большое — 999 (9 сотен, 9 десятков, 9 единиц). После 999 идёт число 1000 — это уже четырёхзначное число, круглая тысяча.\n\nЧтобы прочитать число, надо назвать сотни, потом десятки и единицы вместе как двузначное число. Например: 508 читается «пятьсот восемь» (5 сотен и 8 единиц, десятков нет — на их месте стоит 0). 630 читается «шестьсот тридцать».\n\nВажно понимать роль нуля: если в разряде нет ни одной единицы счёта, там ставится цифра 0. Ноль — не пустое место, а полноправная цифра, которая показывает, что данного разряда «не хватает».\n\nРассмотрим пример из жизни. В школьной библиотеке 245 книг. Это значит: 2 сотни (200 книг), 4 десятка (40 книг) и 5 единиц (5 книг) — вместе 200+40+5=245.\n\nМожно представлять числа с помощью счётных палочек, связанных в пучки: пучок из 10 палочек — десяток, пучок из 10 таких пучков (100 палочек) — сотня. Если у нас есть 3 сотни, 5 десятков и 2 единицы палочек, всего это 352 палочки.\n\nТакже полезно тренироваться в разложении чисел на разрядные слагаемые: 706 = 700 + 0 + 6 (десятков нет), 900 = 900 + 0 + 0, 999 = 900 + 90 + 9.\n\nПонимание разрядного состава числа — основа для дальнейших действий: сложения, вычитания, сравнения чисел в пределах 1000. Поэтому важно уверенно определять, сколько сотен, десятков и единиц содержится в любом трёхзначном числе.","quiz":[{"question":"Сколько сотен, десятков и единиц в числе 583?","options":["5 сотен, 8 десятков, 3 единицы","8 сотен, 5 десятков, 3 единицы","5 сотен, 3 десятка, 8 единиц","3 сотни, 8 десятков, 5 единиц"],"correctIndex":0},{"question":"Какое число получится, если сложить 400 + 20 + 6?","options":["4026","426","460","246"],"correctIndex":1},{"question":"В каком разряде стоит цифра 7 в числе 728?","options":["единицы","десятки","сотни","тысячи"],"correctIndex":2},{"question":"Самое большое трёхзначное число — это...","options":["900","990","999","1000"],"correctIndex":2},{"question":"Как правильно записать число «шестьсот три»?","options":["63","630","603","636"],"correctIndex":2},{"question":"Сколько всего единиц (без десятков и сотен) в числе 305?","options":["0","3","5","35"],"correctIndex":2},{"question":"Какое число самое маленькое среди трёхзначных чисел?","options":["99","100","101","10"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-07T11:15:00+05:00","ends_at":"2026-07-07T12:00:00+05:00","room":"101"},{"topic":"Сравнение трёхзначных чисел","objective":"Научить сравнивать трёхзначные числа по разрядам и располагать их в порядке возрастания или убывания.","theory":"Чтобы сравнить два трёхзначных числа, не нужно ничего складывать — достаточно посмотреть на цифры по разрядам, начиная с самого старшего — сотен.\n\nПравило 1. Если в одном числе больше сотен, чем в другом, то оно и больше целиком, независимо от того, что стоит в десятках и единицах. Например: 512 > 498, потому что в числе 512 — 5 сотен, а в числе 498 — только 4 сотни.\n\nПравило 2. Если количество сотен одинаковое, сравниваем десятки. Например: 342 и 371 — в обоих числах 3 сотни, но во втором числе 7 десятков, а в первом только 4, значит 371 > 342.\n\nПравило 3. Если и сотни, и десятки совпадают, сравниваем единицы. Например: 256 и 253 — сотни и десятки одинаковые (2 сотни, 5 десятков), но единиц во втором числе меньше (3 против 6), значит 256 > 253.\n\nДля сравнения используют знаки: > («больше»), < («меньше»), = («равно»). Знак всегда «смотрит» на меньшее число, как открытый рот, который «хочет съесть» большее число.\n\nПолезно представлять числа на числовой прямой: чем правее находится число, тем оно больше. Например, если отметить числа 245 и 425 на прямой, то 425 окажется намного правее, потому что оно больше.\n\nПорядок чисел бывает возрастающий (от меньшего к большему: 123, 234, 345) и убывающий (от большего к меньшему: 345, 234, 123).\n\nРассмотрим пример: расставим числа 407, 470, 47, 704 в порядке возрастания. Сначала уберём 47 — это двузначное число, оно точно меньше всех трёхзначных. Среди 407, 470 и 704 сравним сотни: у 407 и 470 — по 4 сотни, у 704 — 7 сотен, значит 704 — самое большое. Между 407 и 470 сравним десятки: 0 и 7, значит 470 больше. Итог: 47 < 407 < 470 < 704.\n\nЭтот навык очень важен в жизни: например, сравнивая цены в магазине, расстояния на карте или количество очков в игре, мы постоянно сравниваем числа.","quiz":[{"question":"Какой знак нужно поставить между числами 384 и 348?","options":["384 < 348","384 > 348","384 = 348","сравнить нельзя"],"correctIndex":1},{"question":"Какое число больше: 609 или 690?","options":["609","690","они равны","невозможно определить"],"correctIndex":1},{"question":"Расположи числа 215, 152, 521 в порядке возрастания.","options":["152, 215, 521","521, 215, 152","215, 152, 521","152, 521, 215"],"correctIndex":0},{"question":"Сравни числа 473 и 479. Какой знак верный?","options":["473 > 479","473 < 479","473 = 479","479 < 473"],"correctIndex":1},{"question":"Какое число самое большое: 306, 360 или 630?","options":["306","360","630","все равны"],"correctIndex":2},{"question":"На числовой прямой число, стоящее правее, всегда...","options":["меньше","больше","равно соседнему","это зависит от цвета точки"],"correctIndex":1},{"question":"Почему сотни сравнивают в первую очередь?","options":["сотни — самый младший разряд","сотни — самый старший разряд и сильнее всего влияют на величину числа","единицы важнее сотен","порядок сравнения не имеет значения"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"desmos","externalServiceTask":"Отметьте на числовой прямой в Desmos точки 245, 254 и 425, сравните их положение и определите, какое число больше и на сколько.","starts_at":"2026-07-08T11:15:00+05:00","ends_at":"2026-07-08T12:00:00+05:00","room":"101"},{"topic":"Устное сложение и вычитание в пределах 1000","objective":"Научить выполнять устные вычисления сложения и вычитания круглых сотен, десятков и разрядных слагаемых в пределах 1000.","theory":"Устные приёмы вычислений помогают быстро складывать и вычитать числа без письменных вычислений в столбик, если числа удобные.\n\nПриём 1 — сложение и вычитание круглых сотен. Круглые сотни — это 100, 200, 300 ... 900. Складывать их легко, если считать не единицы, а сотни: 300 + 400 = 7 сотен = 700, как 3 + 4 = 7. Так же и вычитание: 800 − 500 = 3 сотни = 300, как 8 − 5 = 3.\n\nПриём 2 — сложение числа с круглыми десятками или сотнями по частям. Например, 234 + 300: складываем только сотни, десятки и единицы не меняются: 2 сотни + 3 сотни = 5 сотен, значит 234 + 300 = 534.\n\nДругой пример: 456 + 20. Складываем десятки: 5 десятков + 2 десятка = 7 десятков, сотни и единицы остаются без изменений: 456 + 20 = 476.\n\nПриём 3 — сложение и вычитание по разрядам, если нет перехода через десяток. Например: 523 + 145. Складываем сотни (5+1=6), десятки (2+4=6), единицы (3+5=8): получаем 668.\n\nТакой же приём работает и для вычитания: 768 − 234. Сотни: 7−2=5, десятки: 6−3=3, единицы: 8−4=4. Получаем 534.\n\nПриём 4 — округление для удобства. Чтобы быстро сложить 299 + 154, представим 299 как 300 − 1: 300 + 154 = 454, затем вычтем 1: 454 − 1 = 453.\n\nПолезно тренироваться складывать и вычитать «круглые» числа, чтобы потом легче было переходить к письменным вычислениям в столбик, где числа не всегда «удобные» и есть переход через разряд.\n\nПример задачи: в первом классе учится 230 учеников, а во втором — на 40 больше. Сколько учеников во втором классе? Решение: 230 + 40 = 270 учеников.\n\nУстный счёт развивает быстроту мышления и очень полезен в повседневной жизни — при покупках, подсчёте времени, оценке расстояний.","quiz":[{"question":"Чему равно 400 + 300?","options":["600","700","800","70"],"correctIndex":1},{"question":"Чему равно 900 − 500?","options":["300","500","400","40"],"correctIndex":2},{"question":"Чему равно 356 + 20?","options":["376","358","556","366"],"correctIndex":0},{"question":"Чему равно 645 + 231?","options":["876","866","886","966"],"correctIndex":0},{"question":"Чему равно 789 − 456?","options":["333","343","233","323"],"correctIndex":0},{"question":"Используя приём округления, вычисли 199 + 253.","options":["442","452","462","552"],"correctIndex":1},{"question":"Во дворе росло 320 деревьев, посадили ещё 150. Сколько деревьев стало?","options":["370","470","570","170"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-09T08:30:00+05:00","ends_at":"2026-07-09T09:15:00+05:00","room":"101"},{"topic":"Письменное сложение трёхзначных чисел в столбик","objective":"Научить складывать трёхзначные числа письменно «в столбик», включая случаи с переходом через разряд.","theory":"Когда числа неудобно складывать устно (есть переход через разряд), используют письменный приём — сложение «в столбик».\n\nПравила записи: числа записываются друг под другом так, чтобы единицы были под единицами, десятки под десятками, сотни под сотнями. Складывание начинают с самого младшего разряда — с единиц, и двигаются влево.\n\nРассмотрим пример: 356 + 178.\nСкладываем единицы: 6 + 8 = 14. Это больше 9, значит записываем 4, а 1 десяток запоминаем («переходит» в следующий разряд).\nСкладываем десятки: 5 + 7 = 12, плюс запомненная 1, получаем 13. Записываем 3, а 1 сотню запоминаем.\nСкладываем сотни: 3 + 1 = 4, плюс запомненная 1, получаем 5.\nИтог: 356 + 178 = 534.\n\nТакой переход, когда сумма в разряде получается больше 9 и нужно «занять» единицу в следующий разряд, называется переходом через разряд.\n\nЕщё пример: 487 + 265.\nЕдиницы: 7+5=12 → пишем 2, запоминаем 1.\nДесятки: 8+6=14, плюс 1 = 15 → пишем 5, запоминаем 1.\nСотни: 4+2=6, плюс 1 = 7.\nПолучаем 487 + 265 = 752.\n\nВажно всегда проверять результат прикидкой: 487 округлим до 500, 265 до 300, сумма примерно 800, наш точный ответ 752 — близко, значит, вероятно, верно.\n\nЕсли при сложении сотен тоже получается больше 9 (например, 6 сотен + 5 сотен = 11 сотен), то появляется новый разряд — тысячи. Например: 650 + 550 = 1200.\n\nПисьменное сложение — очень надёжный способ, который работает для любых чисел, если аккуратно выстроить разряды друг под другом и не забывать про «запоминание» единицы при переходе.\n\nТренировка в сложении столбиком пригодится при решении задач про покупки, расстояния и любые другие практические ситуации, где нужно точно посчитать сумму.","quiz":[{"question":"В каком разряде начинают складывать числа при сложении в столбик?","options":["с сотен","с десятков","с единиц","с любого, порядок не важен"],"correctIndex":2},{"question":"Вычисли: 356 + 178.","options":["524","534","544","434"],"correctIndex":1},{"question":"Вычисли: 487 + 265.","options":["742","762","752","652"],"correctIndex":2},{"question":"При сложении единиц 7 + 6 = 13. Что нужно сделать?","options":["записать 13 полностью в разряд единиц","записать 3, а 1 десяток запомнить и прибавить к десяткам","записать 1, а 3 запомнить","ничего не запоминать"],"correctIndex":1},{"question":"Вычисли: 245 + 379.","options":["624","614","634","524"],"correctIndex":0},{"question":"Если сумма сотен получается больше 9, то...","options":["это ошибка, так делать нельзя","появляется новый разряд — тысячи","нужно вычесть 10","ответ округляется"],"correctIndex":1},{"question":"В магазине купили тетради на 268 сум и ручку на 145 сум. Сколько всего потратили?","options":["403","423","413","313"],"correctIndex":2}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-10T10:20:00+05:00","ends_at":"2026-07-10T11:05:00+05:00","room":"101"},{"topic":"Письменное вычитание трёхзначных чисел в столбик","objective":"Научить вычитать трёхзначные числа письменно «в столбик», включая случаи с заимствованием через разряд.","theory":"Письменное вычитание, как и сложение, выполняется в столбик: числа записывают друг под другом по разрядам и вычитают, начиная с единиц.\n\nЕсли в разряде уменьшаемого цифра меньше, чем в этом же разряде вычитаемого, нужно «занять» единицу из соседнего старшего разряда — это называется заимствованием.\n\nРассмотрим пример: 532 − 275.\nЕдиницы: 2 − 5 — вычесть нельзя. Занимаем 1 десяток у соседнего разряда: 12 − 5 = 7. У десятков уменьшаемого теперь на 1 меньше — было 3, стало 2.\nДесятки: 2 − 7 — снова нельзя. Занимаем 1 сотню: 12 − 7 = 5. У сотен уменьшаемого теперь 4 − 1 = 4? Проверим: 5 − 1 = 4.\nСотни: 4 − 2 = 2.\nИтог: 532 − 275 = 257.\n\nЕщё пример: 700 − 348.\nЕдиницы: 0 − 8 — нельзя. Занимаем у десятков, но там тоже 0! Значит, занимаем у сотен: сотни становятся 6, десятки — 10. Теперь занимаем у десятков единицу: десятки становятся 9, единицы — 10. Считаем: 10 − 8 = 2.\nДесятки: 9 − 4 = 5.\nСотни: 6 − 3 = 3.\nИтог: 700 − 348 = 352.\n\nТакой случай, когда приходится занимать через несколько разрядов подряд из-за нулей, требует особого внимания — важно последовательно превращать сотню в десятки, а десяток в единицы.\n\nПроверить правильность вычитания можно сложением: если 532 − 275 = 257, то 257 + 275 должно снова дать 532. Проверим: 257 + 275 = 532 — верно!\n\nЗадача из жизни: у мамы было 850 сум, она потратила 470 сум на продукты. Сколько денег осталось? Решение: 850 − 470 = 380 сум.\n\nАккуратность в записи столбиком и внимательность при заимствовании — главный секрет правильных вычислений. Всегда полезно проверять ответ обратным действием — сложением.","quiz":[{"question":"Что означает «занять» единицу при вычитании в столбик?","options":["добавить лишнюю единицу к ответу","взять 1 единицу старшего разряда, чтобы она стала 10 единиц младшего разряда","вычесть единицу из ответа","ничего не значит, это ошибка"],"correctIndex":1},{"question":"Вычисли: 532 − 275.","options":["247","257","267","237"],"correctIndex":1},{"question":"Вычисли: 700 − 348.","options":["452","342","352","362"],"correctIndex":2},{"question":"Как проверить результат вычитания?","options":["сложить уменьшаемое с вычитаемым","сложить разность с вычитаемым — должно получиться уменьшаемое","вычесть разность из вычитаемого","проверить нельзя"],"correctIndex":1},{"question":"Вычисли: 604 − 259.","options":["345","355","335","445"],"correctIndex":0},{"question":"У мамы было 850 сум, она потратила 470. Сколько осталось?","options":["480","380","320","420"],"correctIndex":1},{"question":"Почему при вычитании 700 − 348 пришлось занимать через два разряда?","options":["потому что в десятках и единицах уменьшаемого стоят нули","потому что число 700 нечётное","потому что 348 больше 700","занимать было не нужно"],"correctIndex":0}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-13T09:25:00+05:00","ends_at":"2026-07-13T10:10:00+05:00","room":"101"},{"topic":"Периметр многоугольника","objective":"Научить находить периметр многоугольника (в том числе прямоугольника и квадрата) как сумму длин всех его сторон.","theory":"Периметр — это сумма длин всех сторон многоугольника, то есть расстояние, которое нужно пройти по контуру фигуры, обойдя её целиком по границе.\n\nСлово «периметр» происходит от греческих слов «пери» — вокруг и «метрон» — мера, то есть «измерение вокруг».\n\nЧтобы найти периметр любого многоугольника, нужно сложить длины всех его сторон. Например, у треугольника со сторонами 4 см, 5 см и 6 см периметр равен: 4 + 5 + 6 = 15 см.\n\nДля прямоугольника есть особенность: у него противоположные стороны равны — две длинных и две коротких. Поэтому периметр прямоугольника можно найти двумя способами:\n1) Сложить все четыре стороны: a + b + a + b.\n2) Использовать формулу: P = (a + b) × 2, где a — длина, b — ширина.\nНапример, прямоугольник со сторонами 7 см и 3 см: P = (7 + 3) × 2 = 10 × 2 = 20 см.\n\nДля квадрата все четыре стороны равны, поэтому формула ещё проще: P = a × 4, где a — сторона квадрата. Например, квадрат со стороной 5 см: P = 5 × 4 = 20 см.\n\nПериметр измеряется в единицах длины: миллиметрах, сантиметрах, дециметрах, метрах — в зависимости от размера фигуры.\n\nРассмотрим практическую задачу: нужно огородить забором прямоугольный участок земли длиной 12 метров и шириной 8 метров. Сколько метров забора потребуется? Решение: P = (12 + 8) × 2 = 20 × 2 = 40 метров забора.\n\nЕщё пример: пятиугольник со сторонами 3 см, 4 см, 3 см, 4 см и 5 см. Периметр: 3+4+3+4+5 = 19 см.\n\nВажно не путать периметр с площадью: периметр — это длина границы (контура) фигуры, а площадь — это то, сколько места фигура занимает внутри. Об этом мы подробно поговорим позже.\n\nЧтобы найти периметр, всегда нужно точно знать длины ВСЕХ сторон фигуры — либо они даны в условии, либо их измеряют линейкой.","quiz":[{"question":"Что такое периметр многоугольника?","options":["площадь внутри фигуры","сумма длин всех сторон фигуры","количество углов фигуры","длина самой длинной стороны"],"correctIndex":1},{"question":"Периметр треугольника со сторонами 4 см, 5 см, 6 см равен...","options":["10 см","20 см","15 см","24 см"],"correctIndex":2},{"question":"Формула периметра прямоугольника со сторонами a и b:","options":["P = a × b","P = (a + b) × 2","P = a + b","P = a × 2 + b"],"correctIndex":1},{"question":"Найди периметр прямоугольника со сторонами 7 см и 3 см.","options":["10 см","21 см","20 см","14 см"],"correctIndex":2},{"question":"Найди периметр квадрата со стороной 5 см.","options":["25 см","10 см","15 см","20 см"],"correctIndex":3},{"question":"Нужно огородить забором участок 12 м × 8 м. Сколько метров забора потребуется?","options":["20 м","96 м","40 м","30 м"],"correctIndex":2},{"question":"Чем периметр отличается от площади?","options":["периметр — длина границы фигуры, площадь — место внутри фигуры","это одно и то же","периметр больше площади всегда","периметр измеряется в квадратных единицах"],"correctIndex":0}],"hasExternalService":true,"externalServiceType":"geogebra","externalServiceTask":"Постройте в GeoGebra треугольник и прямоугольник произвольных размеров, измерьте длины сторон встроенным инструментом и вычислите периметр каждой фигуры.","starts_at":"2026-07-14T11:15:00+05:00","ends_at":"2026-07-14T12:00:00+05:00","room":"101"},{"topic":"Таблица умножения и деления: закрепление 6-9","objective":"Закрепить знание таблицы умножения и деления для чисел 6, 7, 8 и 9, применяя её при решении примеров и задач.","theory":"В предыдущих классах вы уже начали изучать таблицу умножения. Сейчас закрепим самые сложные её части — умножение и деление на 6, 7, 8 и 9, которые чаще всего вызывают трудности.\n\nУмножение — это действие, заменяющее сложение одинаковых слагаемых. Например, 6 × 4 означает «взять число 6 четыре раза»: 6+6+6+6 = 24.\n\nТаблица умножения на 6: 6×1=6, 6×2=12, 6×3=18, 6×4=24, 6×5=30, 6×6=36, 6×7=42, 6×8=48, 6×9=54.\nТаблица умножения на 7: 7×1=7, 7×2=14, 7×3=21, 7×4=28, 7×5=35, 7×6=42, 7×7=49, 7×8=56, 7×9=63.\nТаблица умножения на 8: 8×1=8, 8×2=16, 8×3=24, 8×4=32, 8×5=40, 8×6=48, 8×7=56, 8×8=64, 8×9=72.\nТаблица умножения на 9: 9×1=9, 9×2=18, 9×3=27, 9×4=36, 9×5=45, 9×6=54, 9×7=63, 9×8=72, 9×9=81.\n\nПолезное свойство умножения — переместительное: от перестановки множителей произведение не меняется. Например, 7×8 = 8×7 = 56. Это значит, что учить таблицу нужно только «половину» — остальное можно получить перестановкой.\n\nДеление — действие, обратное умножению. Если 6×7=42, то 42:6=7 и 42:7=6. Зная одно равенство умножения, можно сразу получить два равенства деления.\n\nПриём для запоминания: число 9 удобно умножать, замечая закономерность — сумма цифр произведения всегда равна 9 (18: 1+8=9, 27: 2+7=9, 36: 3+6=9 и так далее).\n\nПример задачи: в коробке 8 карандашей. Сколько карандашей в 6 таких коробках? Решение: 8 × 6 = 48 карандашей.\n\nОбратная задача: 56 яблок разложили поровну в 7 пакетов. Сколько яблок в каждом пакете? Решение: 56 : 7 = 8 яблок.\n\nХорошее знание таблицы умножения и деления — это фундамент для всех дальнейших тем: умножения многозначных чисел, деления с остатком, решения задач и уравнений.","quiz":[{"question":"Чему равно 7 × 8?","options":["54","56","64","48"],"correctIndex":1},{"question":"Чему равно 9 × 6?","options":["45","63","54","56"],"correctIndex":2},{"question":"Чему равно 48 : 8?","options":["5","6","7","8"],"correctIndex":1},{"question":"Чему равно 63 : 7?","options":["8","7","9","6"],"correctIndex":2},{"question":"Если 6 × 7 = 42, то чему равно 42 : 6?","options":["6","7","8","9"],"correctIndex":1},{"question":"В коробке 8 карандашей. Сколько карандашей в 6 коробках?","options":["42","56","48","64"],"correctIndex":2},{"question":"56 яблок разложили поровну в 7 пакетов. Сколько яблок в каждом пакете?","options":["9","7","6","8"],"correctIndex":3}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-15T11:15:00+05:00","ends_at":"2026-07-15T12:00:00+05:00","room":"101"},{"topic":"Взаимосвязь умножения и деления","objective":"Научить определять компоненты умножения и деления (множители, произведение, делимое, делитель, частное) и использовать их взаимосвязь для проверки вычислений.","theory":"У каждого арифметического действия есть свои названия компонентов (частей). Знание этих названий помогает понимать задачи и уравнения.\n\nВ умножении: числа, которые перемножают, называются множителями, а результат — произведением. Например, в равенстве 6 × 7 = 42 числа 6 и 7 — множители, а 42 — произведение.\n\nВ делении: число, которое делят, называется делимым, число, на которое делят, — делителем, а результат — частным. Например, в равенстве 42 : 6 = 7 число 42 — делимое, 6 — делитель, 7 — частное.\n\nУмножение и деление — взаимно обратные действия: одно «отменяет» другое. Если 8 × 5 = 40, то верны и деления: 40 : 8 = 5, и 40 : 5 = 8. Из одного равенства умножения получаются два равенства деления.\n\nЭта взаимосвязь используется для проверки вычислений. Чтобы проверить деление, умножаем частное на делитель — должно получиться делимое. Например, проверим 56 : 8 = 7: умножаем 7 × 8 = 56 — верно.\n\nЧтобы проверить умножение, можно разделить произведение на один из множителей — должен получиться другой множитель. Например, проверим 9 × 6 = 54: 54 : 9 = 6 — верно.\n\nВзаимосвязь компонентов помогает находить неизвестное число в равенстве. Правила:\n— Чтобы найти неизвестный множитель, нужно произведение разделить на известный множитель. Пример: x × 4 = 28, значит x = 28 : 4 = 7.\n— Чтобы найти неизвестное делимое, нужно частное умножить на делитель. Пример: x : 5 = 6, значит x = 6 × 5 = 30.\n— Чтобы найти неизвестный делитель, нужно делимое разделить на частное. Пример: 36 : x = 4, значит x = 36 : 4 = 9.\n\nТакие простые уравнения часто встречаются в задачах: «На сколько частей надо разделить 48 конфет, чтобы каждому досталось по 6?» Решаем: 48 : 6 = 8 частей.\n\nПонимание названий компонентов действий и их взаимосвязи — важный шаг к решению более сложных задач и уравнений в старших классах.","quiz":[{"question":"Как называются числа, которые умножают друг на друга?","options":["слагаемые","множители","делители","частные"],"correctIndex":1},{"question":"Как называется результат деления?","options":["произведение","делимое","частное","делитель"],"correctIndex":2},{"question":"В равенстве 45 : 9 = 5 число 45 называется...","options":["делителем","делимым","частным","произведением"],"correctIndex":1},{"question":"Как проверить результат умножения 7 × 6 = 42?","options":["сложить 7 и 6","разделить 42 на 7 (или на 6) и сравнить со вторым множителем","вычесть 6 из 7","умножить 42 на 7"],"correctIndex":1},{"question":"Найди неизвестный множитель: x × 5 = 35.","options":["x = 5","x = 6","x = 7","x = 8"],"correctIndex":2},{"question":"Найди неизвестное делимое: x : 4 = 9.","options":["x = 13","x = 36","x = 5","x = 45"],"correctIndex":1},{"question":"Найди неизвестный делитель: 42 : x = 6.","options":["x = 7","x = 6","x = 8","x = 36"],"correctIndex":0}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-16T08:30:00+05:00","ends_at":"2026-07-16T09:15:00+05:00","room":"101"},{"topic":"Умножение и деление на 10 и на 100","objective":"Научить умножать и делить круглые числа на 10 и 100, понимая закономерность добавления и убирания нулей.","theory":"Умножение и деление на 10 и на 100 — особые случаи, которые можно выполнять очень быстро, зная простое правило, без долгих вычислений.\n\nПравило умножения на 10: чтобы умножить число на 10, нужно приписать к нему справа один ноль. Например: 7 × 10 = 70, 23 × 10 = 230, 45 × 10 = 450.\n\nПравило умножения на 100: чтобы умножить число на 100, нужно приписать справа два нуля. Например: 7 × 100 = 700, 23 × 100 = 2300, 5 × 100 = 500.\n\nПочему так происходит? Потому что при умножении на 10 каждый разряд числа «сдвигается» на одну позицию влево: единицы становятся десятками, десятки — сотнями и так далее. Число 7 (7 единиц) становится 70 (7 десятков). Это же можно объяснить через сложение: 7 × 10 = 7+7+7+7+7+7+7+7+7+7 = 70.\n\nПравило деления на 10: чтобы разделить круглое число (оканчивающееся на 0) на 10, нужно убрать один ноль справа. Например: 70 : 10 = 7, 230 : 10 = 23, 800 : 10 = 80.\n\nПравило деления на 100: чтобы разделить число, оканчивающееся на два нуля, на 100, нужно убрать оба нуля. Например: 700 : 100 = 7, 2300 : 100 = 23, 900 : 100 = 9.\n\nВажно: делить на 10 или 100 без остатка можно только числа, которые оканчиваются на соответствующее количество нулей. Число 45 нельзя разделить на 10 без остатка, так как оно не оканчивается на 0.\n\nЭти правила очень удобны для устного счёта с большими числами. Например, если в одной коробке 100 карандашей и таких коробок 6, то всего карандашей: 100 × 6 = 600.\n\nРассмотрим задачу: у фермера было 800 кг картофеля, он разложил его в мешки по 100 кг. Сколько мешков получилось? Решение: 800 : 100 = 8 мешков.\n\nЗнание этих правил экономит время и силы, ведь не нужно каждый раз складывать число много раз подряд или делать вычисления в столбик — достаточно правильно добавить или убрать нули.","quiz":[{"question":"Чему равно 8 × 10?","options":["18","80","800","8"],"correctIndex":1},{"question":"Чему равно 34 × 100?","options":["340","3400","34000","304"],"correctIndex":1},{"question":"Чему равно 600 : 100?","options":["60","6","600","100"],"correctIndex":1},{"question":"Чему равно 250 : 10?","options":["25","250","2500","2.5"],"correctIndex":0},{"question":"Почему при умножении на 10 к числу «приписывают» ноль?","options":["потому что так короче писать","потому что каждый разряд числа сдвигается на одну позицию влево","это просто правило без объяснения","потому что 10 — круглое число"],"correctIndex":1},{"question":"У фермера 800 кг картофеля, он разложил его в мешки по 100 кг. Сколько получилось мешков?","options":["80","8","800","100"],"correctIndex":1},{"question":"Можно ли разделить число 45 на 10 без остатка?","options":["да, получится 4","да, получится 4.5","нет, так как 45 не оканчивается на ноль","да, получится 45"],"correctIndex":2}],"hasExternalService":true,"externalServiceType":"desmos","externalServiceTask":"В Desmos отметьте на числовой прямой числа 5, 50 и 500, чтобы увидеть, как умножение на 10 сдвигает число, и объясните закономерность.","starts_at":"2026-07-17T10:20:00+05:00","ends_at":"2026-07-17T11:05:00+05:00","room":"101"},{"topic":"Умножение двузначного числа на однозначное","objective":"Научить умножать двузначное число на однозначное письменным и разрядным способом.","theory":"Теперь научимся умножать двузначные числа (от 10 до 99) на однозначные (от 1 до 9) — например, 23 × 4 или 47 × 6.\n\nСпособ 1 — разрядное умножение (устно, по частям). Разложим двузначное число на десятки и единицы, умножим каждую часть отдельно, а потом сложим результаты.\nПример: 23 × 4. Разложим 23 = 20 + 3. Умножаем: 20 × 4 = 80, и 3 × 4 = 12. Складываем: 80 + 12 = 92. Значит, 23 × 4 = 92.\nЕщё пример: 34 × 2. Разложим 34 = 30 + 4. Умножаем: 30 × 2 = 60, 4 × 2 = 8. Складываем: 60 + 8 = 68.\n\nСпособ 2 — письменное умножение «в столбик». Записываем однозначное число под единицами двузначного числа: 47 × 6.\nСначала умножаем однозначное число на единицы: 6 × 7 = 42. Записываем 2, а 4 десятка запоминаем.\nЗатем умножаем однозначное число на десятки: 6 × 4 = 24, плюс запомненные 4, получаем 28. Записываем полностью — 28.\nИтог: 47 × 6 = 282.\nПроверим тем же разрядным способом: 47 = 40 + 7. 40 × 6 = 240, 7 × 6 = 42. Сумма: 240 + 42 = 282. Совпадает!\n\nЕщё пример на переход через разряд: 38 × 5. Единицы: 5 × 8 = 40, пишем 0, запоминаем 4. Десятки: 5 × 3 = 15, плюс 4 = 19. Итог: 38 × 5 = 190.\n\nВажно всегда умножать сначала единицы, потом десятки, и не забывать прибавлять «запомненное» число.\n\nРассмотрим задачу: в одной пачке 24 тетради. Сколько тетрадей в 3 таких пачках? Решение: 24 × 3 = 72 (20×3=60, 4×3=12, 60+12=72) тетради.\n\nУмножение двузначных чисел на однозначные — важный шаг к умножению ещё больших чисел, а также основа для решения задач на нахождение общего количества предметов, когда известны количество групп и число предметов в каждой группе.","quiz":[{"question":"Вычисли разрядным способом: 23 × 4.","options":["82","92","102","86"],"correctIndex":1},{"question":"Вычисли: 34 × 2.","options":["78","62","68","64"],"correctIndex":2},{"question":"Вычисли в столбик: 47 × 6.","options":["272","282","292","262"],"correctIndex":1},{"question":"Вычисли: 38 × 5.","options":["180","190","200","195"],"correctIndex":1},{"question":"При умножении 6 × 7 = 42 в разряде единиц пишем 2, а что делаем с 4?","options":["отбрасываем","запоминаем и прибавляем к результату умножения на десятки","вычитаем из ответа","записываем в разряд единиц"],"correctIndex":1},{"question":"В пачке 24 тетради. Сколько тетрадей в 3 пачках?","options":["62","82","72","68"],"correctIndex":2},{"question":"Разложи число 56 на разрядные слагаемые для умножения.","options":["56 = 5 + 6","56 = 50 + 6","56 = 5 + 60","56 = 500 + 6"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-20T09:25:00+05:00","ends_at":"2026-07-20T10:10:00+05:00","room":"101"},{"topic":"Деление двузначного числа на однозначное","objective":"Научить делить двузначное число на однозначное разрядным способом и способом подбора, включая случаи с остатком.","theory":"После умножения двузначных чисел научимся выполнять обратное действие — деление двузначного числа на однозначное.\n\nСпособ 1 — разрядное деление (когда десятки делятся без остатка). Разложим двузначное число на удобные слагаемые, каждое из которых делится на делитель без остатка.\nПример: 84 : 4. Разложим 84 = 80 + 4. Делим каждое слагаемое: 80 : 4 = 20, 4 : 4 = 1. Складываем частные: 20 + 1 = 21. Значит, 84 : 4 = 21.\nЕщё пример: 96 : 3. Разложим 96 = 90 + 6. Делим: 90 : 3 = 30, 6 : 3 = 2. Складываем: 30 + 2 = 32.\n\nСпособ 2 — подбор частного с проверкой умножением. Например, чтобы найти 91 : 7, подбираем такое число, которое при умножении на 7 даёт 91. Пробуем: 7×10=70 (мало), 7×13=91 — подходит! Значит, 91 : 7 = 13.\n\nИногда число не делится на делитель нацело — тогда получается деление с остатком. Например, 47 : 5. Ищем наибольшее число, кратное 5, которое не превышает 47: это 45 (5×9=45). Значит, частное — 9, а остаток: 47 − 45 = 2. Записывают так: 47 : 5 = 9 (остаток 2).\n\nВажное правило: остаток всегда должен быть МЕНЬШЕ делителя. Если остаток получился больше или равен делителю — значит, частное подобрано неверно, и его нужно увеличить.\n\nПроверка деления с остатком: делитель умножить на частное и прибавить остаток — должно получиться делимое. Проверим: 5 × 9 = 45, 45 + 2 = 47 — верно!\n\nЗадача: у учительницы 50 карандашей, она хочет раздать их поровну 8 ученикам. Сколько карандашей получит каждый и сколько останется? Решение: 50 : 8 — подбираем: 8×6=48 (подходит, 8×7=56 — уже много). Частное 6, остаток: 50−48=2. Каждый получит по 6 карандашей, 2 карандаша останутся.\n\nДеление двузначных чисел, в том числе с остатком, часто встречается в жизни — при распределении предметов поровну, планировании покупок и времени.","quiz":[{"question":"Вычисли разрядным способом: 84 : 4.","options":["20","21","22","24"],"correctIndex":1},{"question":"Вычисли: 96 : 3.","options":["30","31","32","33"],"correctIndex":2},{"question":"Вычисли подбором: 91 : 7.","options":["12","13","14","11"],"correctIndex":1},{"question":"Вычисли с остатком: 47 : 5.","options":["8 ост. 7","9 ост. 2","9 ост. 1","10 ост. 0"],"correctIndex":1},{"question":"Какое правило верно для остатка при делении?","options":["остаток должен быть больше делителя","остаток должен быть меньше делителя","остаток должен быть равен делителю","остаток не имеет значения"],"correctIndex":1},{"question":"У учительницы 50 карандашей на 8 учеников поровну. Сколько получит каждый и сколько останется?","options":["по 6, останется 2","по 5, останется 10","по 7, останется 0","по 6, останется 0"],"correctIndex":0},{"question":"Как проверить деление с остатком 47 : 5 = 9 (ост. 2)?","options":["умножить делитель на частное и прибавить остаток: 5×9=45, 45+2=47 — совпадает с делимым","сложить делитель и остаток","вычесть остаток из делителя","умножить остаток на частное"],"correctIndex":0}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-21T11:15:00+05:00","ends_at":"2026-07-21T12:00:00+05:00","room":"101"},{"topic":"Порядок действий в выражениях со скобками","objective":"Научить правильно определять порядок выполнения действий в числовых выражениях со скобками и без них.","theory":"Когда в выражении несколько действий, важно выполнять их в правильном порядке — иначе можно получить неверный ответ.\n\nПравило 1. Если в выражении нет скобок и есть только сложение и вычитание (или только умножение и деление), действия выполняются по порядку слева направо. Например: 30 − 8 + 5 = 22 + 5 = 27.\n\nПравило 2. Если в выражении есть и сложение/вычитание, и умножение/деление, сначала выполняют умножение и деление, а потом сложение и вычитание — независимо от того, в каком порядке они записаны. Например: 8 + 12 × 3. Сначала умножаем: 12 × 3 = 36. Потом складываем: 8 + 36 = 44.\n\nСравним с выражением, где стоят скобки: (8 + 12) × 3. Скобки показывают, что действие внутри них нужно выполнить в первую очередь, раньше всех остальных действий, даже если снаружи стоит умножение. Сначала считаем: 8 + 12 = 20. Потом умножаем: 20 × 3 = 60.\n\nВидим, что 8 + 12 × 3 = 44, а (8 + 12) × 3 = 60 — это совершенно разные числа! Скобки полностью меняют порядок и результат.\n\nОбщий порядок действий в выражении со скобками:\n1) Сначала выполняются действия в скобках.\n2) Затем — умножение и деление по порядку слева направо.\n3) В последнюю очередь — сложение и вычитание по порядку слева направо.\n\nРассмотрим более сложный пример: 50 − (6 + 4) × 3. Сначала скобки: 6 + 4 = 10. Затем умножение: 10 × 3 = 30. В последнюю очередь вычитание: 50 − 30 = 20.\n\nЕщё пример: 100 : (20 − 15) + 7. Скобки: 20 − 15 = 5. Деление: 100 : 5 = 20. Сложение: 20 + 7 = 27.\n\nСкобки в математике похожи на «важное дело», которое нужно сделать в первую очередь, прежде чем заниматься остальным.\n\nУмение правильно определять порядок действий — ключевой навык для решения любых числовых выражений и текстовых задач с несколькими действиями, которые встречаются всё чаще по мере усложнения материала.","quiz":[{"question":"В выражении без скобок 8 + 12 × 3 что нужно выполнить первым?","options":["сложение 8 + 12","умножение 12 × 3","любое действие по выбору","сначала посчитать слева направо всё подряд"],"correctIndex":1},{"question":"Вычисли: 8 + 12 × 3.","options":["60","36","44","68"],"correctIndex":2},{"question":"Вычисли: (8 + 12) × 3.","options":["44","60","36","23"],"correctIndex":1},{"question":"Какое действие выполняется первым в выражении со скобками?","options":["умножение","сложение","действие внутри скобок","деление"],"correctIndex":2},{"question":"Вычисли: 50 − (6 + 4) × 3.","options":["20","30","40","10"],"correctIndex":0},{"question":"Вычисли: 100 : (20 − 15) + 7.","options":["17","20","27","12"],"correctIndex":2},{"question":"Если в выражении есть и умножение, и сложение без скобок, что выполняется раньше?","options":["сложение","умножение","то, что записано первым слева","не имеет значения"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"desmos","externalServiceTask":"В Desmos введите выражение 8 + 12 × 3 и (8 + 12) × 3, сравните результаты и объясните, как скобки меняют порядок действий.","starts_at":"2026-07-22T11:15:00+05:00","ends_at":"2026-07-22T12:00:00+05:00","room":"101"},{"topic":"Площадь прямоугольника — понятие и единицы измерения","objective":"Сформировать понятие площади фигуры и познакомить с единицами измерения площади (квадратный сантиметр, квадратный дециметр, квадратный метр).","theory":"Мы уже умеем находить периметр — длину границы фигуры. Теперь познакомимся с новым понятием — площадью.\n\nПлощадь — это величина, которая показывает, сколько места занимает плоская фигура. Если периметр измеряет «путь по контуру», то площадь измеряет «поверхность внутри» фигуры.\n\nЧтобы измерить площадь, используют не обычные единицы длины (см, м), а квадратные единицы — квадраты определённого размера. Основная единица площади в начальной школе — квадратный сантиметр (см²). Это площадь квадрата со стороной 1 см.\n\nТакже используются:\n— квадратный дециметр (дм²) — площадь квадрата со стороной 1 дм (10 см);\n— квадратный метр (м²) — площадь квадрата со стороной 1 м (100 см).\n\nЧтобы найти площадь фигуры, можно посчитать, сколько квадратных сантиметров помещается внутри неё. Например, если начертить прямоугольник и разбить его на клетки размером 1 см × 1 см, то площадь равна количеству таких клеток.\n\nРассмотрим пример: прямоугольник разбит на 4 ряда по 5 клеток в каждом. Всего клеток: 4 ряда × 5 клеток = 20 клеток, каждая клетка — 1 см², значит площадь прямоугольника равна 20 см².\n\nВажно не путать площадь с периметром! У прямоугольника со сторонами 4 см и 5 см периметр равен (4+5)×2=18 см, а площадь — 20 см². Это разные величины с разным смыслом и разными единицами измерения.\n\nИнтересный факт: у фигур с одинаковым периметром может быть разная площадь, и наоборот. Например, квадрат со стороной 4 см имеет периметр 16 см и площадь 16 см², а прямоугольник 2 см × 6 см имеет тот же периметр 16 см, но площадь всего 12 см².\n\nЕдиницы площади выбирают в зависимости от размера объекта: площадь тетрадного листа удобно измерять в см², площадь комнаты или квартиры — в м².\n\nПонимание площади как «количества квадратиков внутри фигуры» — основа для следующего урока, где мы научимся быстро вычислять площадь прямоугольника по формуле, не считая клетки вручную.","quiz":[{"question":"Что такое площадь фигуры?","options":["длина границы фигуры","величина, показывающая, сколько места занимает фигура","количество углов фигуры","сумма всех сторон"],"correctIndex":1},{"question":"В каких единицах измеряется площадь?","options":["в сантиметрах","в квадратных единицах, например см²","в килограммах","в литрах"],"correctIndex":1},{"question":"Чему равен 1 квадратный дециметр?","options":["площади квадрата со стороной 1 см","площади квадрата со стороной 1 дм","площади квадрата со стороной 1 м","периметру квадрата со стороной 1 дм"],"correctIndex":1},{"question":"Прямоугольник разбит на 4 ряда по 5 клеток (каждая клетка 1 см²). Чему равна его площадь?","options":["9 см²","18 см²","20 см²","25 см²"],"correctIndex":2},{"question":"Чем площадь отличается от периметра?","options":["это одно и то же","площадь измеряет место внутри фигуры, периметр — длину её границы","периметр всегда больше площади","площадь измеряется в метрах, а периметр в квадратных метрах"],"correctIndex":1},{"question":"Квадрат со стороной 4 см и прямоугольник 2 см × 6 см имеют одинаковый периметр 16 см. Одинакова ли их площадь?","options":["да, у обоих 16 см²","нет, у квадрата 16 см², у прямоугольника 12 см²","нет, у квадрата меньше","сравнить невозможно"],"correctIndex":1},{"question":"Какую единицу лучше использовать для измерения площади комнаты?","options":["квадратный сантиметр","квадратный метр","сантиметр","метр"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-23T08:30:00+05:00","ends_at":"2026-07-23T09:15:00+05:00","room":"101"},{"topic":"Площадь прямоугольника — Часть 2: формула и задачи","objective":"Научить вычислять площадь прямоугольника и квадрата по формуле и применять её при решении задач.","theory":"На прошлом уроке мы считали площадь, пересчитывая клетки внутри фигуры. Это долго, если фигура большая. Сегодня узнаем быстрый способ — формулу площади прямоугольника.\n\nЕсли прямоугольник имеет длину a и ширину b, то его площадь вычисляется по формуле: S = a × b, где S — площадь.\n\nПочему так? Потому что если разбить прямоугольник на квадратные сантиметры, то по длине поместится a рядов, а по ширине — b клеток в каждом ряду, и общее число клеток равно произведению a × b.\n\nПример: прямоугольник со сторонами 5 см и 4 см. Площадь: S = 5 × 4 = 20 см². Это совпадает с тем, что было бы, если посчитать все клетки вручную.\n\nДля квадрата все стороны равны, поэтому формула ещё проще: S = a × a (сторону умножаем саму на себя). Например, квадрат со стороной 6 см: S = 6 × 6 = 36 см².\n\nВажно не забывать про единицы измерения: если стороны даны в сантиметрах, площадь получится в квадратных сантиметрах (см²); если стороны в метрах — площадь в квадратных метрах (м²).\n\nРассмотрим задачу: пол в комнате имеет форму прямоугольника длиной 6 м и шириной 4 м. Сколько квадратных метров плитки понадобится, чтобы застелить весь пол? Решение: S = 6 × 4 = 24 м².\n\nЕщё одна задача, где нужно найти сторону по известной площади. Площадь прямоугольника 36 см², одна сторона — 9 см. Найдите вторую сторону. Так как S = a × b, то b = S : a = 36 : 9 = 4 см.\n\nТакже можно сравнивать площади разных фигур: какой из двух огородов больше — 8 м × 5 м или 6 м × 7 м? Считаем: 8×5=40 м², 6×7=42 м² — второй огород больше.\n\nФормула площади прямоугольника — один из самых полезных инструментов в математике: она применяется при ремонте (расчёт плитки, обоев, ламината), в сельском хозяйстве (расчёт участков земли), в строительстве и во многих других областях жизни. Умение быстро находить площадь по длине и ширине экономит время и избавляет от необходимости считать клетки вручную.","quiz":[{"question":"Какая формула используется для вычисления площади прямоугольника?","options":["S = a + b","S = (a + b) × 2","S = a × b","S = a × 4"],"correctIndex":2},{"question":"Найди площадь прямоугольника со сторонами 5 см и 4 см.","options":["18 см²","20 см²","9 см²","25 см²"],"correctIndex":1},{"question":"Найди площадь квадрата со стороной 6 см.","options":["12 см²","24 см²","36 см²","30 см²"],"correctIndex":2},{"question":"Пол комнаты 6 м × 4 м. Сколько плитки (в м²) нужно, чтобы застелить пол?","options":["20 м²","24 м²","10 м²","28 м²"],"correctIndex":1},{"question":"Площадь прямоугольника 36 см², одна сторона 9 см. Чему равна вторая сторона?","options":["3 см","5 см","4 см","6 см"],"correctIndex":2},{"question":"Какой огород больше: 8 м × 5 м или 6 м × 7 м?","options":["8 м × 5 м","6 м × 7 м","они одинаковые","сравнить нельзя"],"correctIndex":1},{"question":"Если стороны прямоугольника даны в метрах, в каких единицах будет площадь?","options":["в метрах","в сантиметрах","в квадратных метрах","в квадратных сантиметрах"],"correctIndex":2}],"hasExternalService":true,"externalServiceType":"geogebra","externalServiceTask":"Постройте в GeoGebra прямоугольник со сторонами 5 см и 3 см, включите отображение площади и сверьте её с результатом по формуле S = a × b.","starts_at":"2026-07-24T10:20:00+05:00","ends_at":"2026-07-24T11:05:00+05:00","room":"101"}]'::jsonb)
    LOOP
      INSERT INTO public.lessons (group_id, subject_id, topic, title, description, status, starts_at, ends_at, started_at, ended_at, room, school_id)
      VALUES (
        v_group_id, v_subject_id, lesson_data->>'topic', lesson_data->>'topic', lesson_data->>'objective',
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN 'completed' ELSE 'scheduled' END,
        (lesson_data->>'starts_at')::timestamptz, (lesson_data->>'ends_at')::timestamptz,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'starts_at')::timestamptz ELSE NULL END,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'ends_at')::timestamptz ELSE NULL END,
        lesson_data->>'room', v_school_id
      )
      RETURNING id INTO v_lesson_id;

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, duration_min, school_id)
      VALUES (v_lesson_id, 1, 'middle', 'theory', 'presentation', lesson_data->>'topic', lesson_data->>'theory', 15, v_school_id);

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, duration_min, school_id)
      VALUES (v_lesson_id, 2, 'middle', 'task', 'quiz_qia', 'Проверь себя', 15, v_school_id)
      RETURNING id INTO v_stage_id;

      qpos := 0;
      FOR quiz_item IN SELECT * FROM jsonb_array_elements(lesson_data->'quiz')
      LOOP
        qpos := qpos + 1;
        INSERT INTO public.quiz_questions (stage_id, question_text, options, correct_option_index, position, points, time_per_question_seconds, school_id)
        VALUES (v_stage_id, quiz_item->>'question', quiz_item->'options', (quiz_item->>'correctIndex')::int, qpos, 1, 30, v_school_id);
      END LOOP;

      IF (lesson_data->>'hasExternalService')::boolean THEN
        INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, config, duration_min, school_id)
        VALUES (
          v_lesson_id, 3, 'middle', 'task', lesson_data->>'externalServiceType',
          lesson_data->>'externalServiceTask', lesson_data->>'externalServiceTask',
          jsonb_build_object('url',
            CASE lesson_data->>'externalServiceType'
              WHEN 'wokwi' THEN 'https://wokwi.com/projects/new/arduino-uno'
              WHEN 'codesandbox' THEN 'https://codesandbox.io/p/sandbox/vanilla'
              WHEN 'geogebra' THEN 'https://www.geogebra.org/classic'
              WHEN 'phet' THEN 'https://phet.colorado.edu/sims/html/forces-and-motion-basics/latest/forces-and-motion-basics_en.html'
              WHEN 'desmos' THEN 'https://www.desmos.com/calculator'
              WHEN 'blockly_games' THEN 'https://blockly.games/'
              WHEN 'visualgo' THEN 'https://visualgo.net/en'
              WHEN 'p5js' THEN 'https://editor.p5js.org/'
              WHEN 'excalidraw' THEN 'https://excalidraw.com/'
              WHEN 'learningapps' THEN 'https://learningapps.org/'
              WHEN 'sqlonline' THEN 'https://sqlime.org/'
              WHEN 'h5p' THEN 'https://h5p.eduos.snruz.uz/library'
              ELSE NULL
            END
          ),
          15, v_school_id
        );
      END IF;
    END LOOP;
  END IF;

  -- === 3-А класс | Английский язык (11 уроков) ===
  SELECT id INTO v_group_id FROM public.groups WHERE name = '3-А класс';
  SELECT id INTO v_subject_id FROM public.subjects WHERE group_id = v_group_id AND name = 'Английский язык';
  IF NOT EXISTS (SELECT 1 FROM public.lessons WHERE group_id = v_group_id AND subject_id = v_subject_id AND description IS NOT NULL) THEN
    FOR lesson_data IN SELECT * FROM jsonb_array_elements('[{"topic":"Приветствия и алфавит","objective":"Повторить английский алфавит и научиться правильно здороваться, представляться и прощаться на английском языке.","theory":"Английский алфавит состоит из 26 букв — от A до Z. Каждая буква имеет своё название и звук. Например, буква «B» называется [би], а в слове «book» звучит как [б]. Знание алфавита помогает читать новые слова и произносить их по буквам (spelling): если тебя спросят «How do you spell your name?» («Как пишется твоё имя по буквам?»), ты сможешь ответить, называя буквы одну за другой.\n\nКогда мы встречаем людей, мы используем приветствия (greetings). Утром говорят «Good morning!» (Доброе утро!), днём — «Good afternoon!» (Добрый день!), вечером — «Good evening!» (Добрый вечер!). В любое время можно сказать «Hello!» или «Hi!» (Привет!) — это самые дружелюбные приветствия.\n\nПосле приветствия часто спрашивают: «How are you?» (Как дела?). Ответить можно: «I''m fine, thank you!» (У меня всё хорошо, спасибо!), «I''m great!» (Отлично!) или «So-so.» (Так себе).\n\nЧтобы представиться, используется фраза «My name is...» (Меня зовут...) или короче «I''m...» (Я...). Например: «My name is Anna.» Если хочешь спросить имя у собеседника: «What''s your name?» (Как тебя зовут?)\n\nКогда разговор заканчивается, нужно попрощаться: «Bye!» или «Goodbye!» (Пока! До свидания!), а также «See you!» (Увидимся!) или «See you later!» (Увидимся позже!)\n\nЕщё важны слова вежливости — «Please» (пожалуйста) и «Thank you» (спасибо).\n\nДиалог-пример:\n— Hello! What''s your name?\n— Hi! My name is Tom. What''s your name?\n— I''m Kate. Nice to meet you!\n— Nice to meet you too!\n\nФраза «Nice to meet you!» означает «Приятно познакомиться!» — её говорят при первой встрече с новым человеком.\n\nЗапомнить эти фразы несложно, если использовать их каждый день на уроке английского: здороваться с учителем и одноклассниками, представляться и прощаться именно так, как принято в англоязычных странах.","quiz":[{"question":"Сколько букв в английском алфавите?","options":["24","25","26","27"],"correctIndex":2},{"question":"Как сказать «Привет!» на английском?","options":["Bye!","Hello!","Please","Thank you"],"correctIndex":1},{"question":"Что означает фраза «My name is...»?","options":["Как дела?","Меня зовут...","До свидания","Спасибо"],"correctIndex":1},{"question":"Как ответить на вопрос «How are you?», если всё хорошо?","options":["Goodbye!","What''s your name?","I''m fine, thank you!","Good night"],"correctIndex":2},{"question":"Что говорят вечером в качестве приветствия?","options":["Good morning!","Good afternoon!","Good evening!","Good night!"],"correctIndex":2},{"question":"Как попрощаться на английском?","options":["Hello!","Nice to meet you!","Goodbye!","How are you?"],"correctIndex":2},{"question":"Что означает «Nice to meet you!»?","options":["Приятно познакомиться!","Как тебя зовут?","До скорой встречи!","Спасибо большое!"],"correctIndex":0},{"question":"Какой вопрос нужно задать, чтобы узнать имя собеседника?","options":["How are you?","What''s your name?","Where are you?","See you!"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-08T08:30:00+05:00","ends_at":"2026-07-08T09:15:00+05:00","room":"101"},{"topic":"Числа от 1 до 20","objective":"Научиться называть, писать и использовать числа от 1 до 20 на английском языке.","theory":"На прошлом уроке мы повторили алфавит и приветствия, а сегодня познакомимся с числами (numbers) от 1 до 20 — они нужны, чтобы посчитать предметы, назвать возраст или номер дома.\n\nЧисла от 1 до 12 нужно просто запомнить, у каждого своё уникальное слово: 1 — one, 2 — two, 3 — three, 4 — four, 5 — five, 6 — six, 7 — seven, 8 — eight, 9 — nine, 10 — ten, 11 — eleven, 12 — twelve.\n\nЧисла от 13 до 19 образуются по правилу: к числу от 3 до 9 добавляется окончание «-teen». Например: three + teen = thirteen (13), four + teen = fourteen (14), five + teen = fifteen (15, теряется буква «e»!), six + teen = sixteen (16), seven + teen = seventeen (17), eight + teen = eighteen (18, пропадает одна «t»), nine + teen = nineteen (19).\n\nЧисло 20 — отдельное слово «twenty».\n\nКогда мы говорим о количестве предметов, число ставится перед существительным, и если предметов больше одного, к существительному добавляется окончание -s: «one book» (одна книга), но «two books» (две книги), «five pens» (пять ручек), «ten apples» (десять яблок).\n\nЧисла нужны, чтобы спросить и назвать возраст: «How old are you?» (Сколько тебе лет?). Ответ строится по формуле «I am + число + years old.»: «I am nine years old.» (Мне девять лет.)\n\nЧисла также нужны для простого счёта: «Let''s count! One, two, three, four, five...»\n\nСовет: чтобы легче запомнить числа, считай вслух предметы вокруг себя — карандаши, книги, окна — и произноси число по-английски. Помогает и счёт по кругу с друзьями.\n\nЗапомни разницу в произношении похожих чисел: thirteen (13) и thirty (30) звучат похоже, но в thirteen ударение падает на второй слог -teen, а в thirty — на первый слог. Это поможет не путать числа при разговоре.","quiz":[{"question":"Как по-английски будет число 15?","options":["fifteen","fiveteen","fivteen","fiftheen"],"correctIndex":0},{"question":"Как образуются числа от 13 до 19?","options":["добавлением «-ty» к числу","добавлением «-teen» к числу","отдельными словами для каждого числа","удвоением числа"],"correctIndex":1},{"question":"Как переводится «twenty»?","options":["двенадцать","двадцать","десять","две"],"correctIndex":1},{"question":"Как правильно сказать «две книги»?","options":["two book","two books","twos books","two boook"],"correctIndex":1},{"question":"Как ответить на вопрос «How old are you?», если тебе 9 лет?","options":["I am nine years old.","I have nine years old.","Nine years old me.","I am nine years."],"correctIndex":0},{"question":"Какое число обозначает слово «eleven»?","options":["10","11","12","13"],"correctIndex":1},{"question":"Какое число идёт после «nineteen»?","options":["eighteen","ten","twenty","twelve"],"correctIndex":2},{"question":"Как будет число 17?","options":["seventeen","sevenden","seventy","sevteen"],"correctIndex":0}],"hasExternalService":true,"externalServiceType":"learningapps","externalServiceTask":"Составь интерактивное упражнение «Найди пару» в LearningApps: сопоставить числа 1-20 с их английскими названиями.","starts_at":"2026-07-09T11:15:00+05:00","ends_at":"2026-07-09T12:00:00+05:00","room":"101"},{"topic":"Цвета и формы","objective":"Научиться называть основные цвета и геометрические формы на английском языке и описывать ими предметы.","theory":"Сегодня мы познакомимся с двумя темами — цвета (colors) и формы (shapes). Эти слова помогают описывать любые предметы вокруг нас: игрушки, одежду, картинки.\n\nОсновные цвета: red (красный), orange (оранжевый), yellow (жёлтый), green (зелёный), blue (синий), purple (фиолетовый), pink (розовый), brown (коричневый), black (чёрный), white (белый), grey (серый).\n\nЧтобы назвать цвет предмета, используется конструкция «It is + цвет»: «It is red.» (Он красный.) Если нужно описать сам предмет вместе с цветом, цвет ставится перед существительным: «a red apple» (красное яблоко), «a blue car» (синяя машина), «a green tree» (зелёное дерево).\n\nЧтобы спросить о цвете предмета: «What color is it?» (Какого это цвета?). Ответ: «It is yellow.»\n\nТеперь про формы. Основные геометрические формы: circle (круг), square (квадрат), triangle (треугольник), rectangle (прямоугольник), star (звезда), heart (сердце), oval (овал).\n\nЧтобы описать форму предмета, тоже используем «It is + форма»: «It is a circle.» Если нужно соединить форму и цвет вместе, порядок такой: сначала цвет, потом форма — «It is a red circle.» (Это красный круг.)\n\nОбрати внимание: перед единственным предметом ставится маленькое слово «a» (или «an» перед гласной буквой): «a square» (квадрат), «an oval» (овал, так как слово начинается с гласной «o»).\n\nЦвета и формы часто встречаются вместе в заданиях: «Find the red triangle.» (Найди красный треугольник.) или «Color the square blue.» (Закрась квадрат синим.)\n\nПолезное упражнение — оглядеться и назвать цвет и форму разных предметов: «The clock is round. It is a circle. It is black.» (Часы круглые. Это круг. Они чёрные.)\n\nЦвета и формы используются также, когда мы описываем флаги, знаки, рисунки. Сегодняшняя тема поможет тебе увереннее описывать окружающий мир и понимать простые задания на английском языке.","quiz":[{"question":"Как по-английски «красный»?","options":["blue","red","green","yellow"],"correctIndex":1},{"question":"Как спросить «Какого это цвета?»","options":["What is it?","What color is it?","How old is it?","Where is it?"],"correctIndex":1},{"question":"Как называется фигура «круг»?","options":["square","triangle","circle","star"],"correctIndex":2},{"question":"Выбери правильный порядок слов.","options":["circle red a","a red circle","red a circle","circle a red"],"correctIndex":1},{"question":"Какое слово ставится перед «oval» (овал)?","options":["a","an","the","some"],"correctIndex":1},{"question":"Как по-английски «квадрат»?","options":["rectangle","square","triangle","oval"],"correctIndex":1},{"question":"Переведи «a green tree».","options":["зелёная машина","зелёное дерево","зелёный круг","зелёный дом"],"correctIndex":1},{"question":"Как сказать «Это жёлтая звезда»?","options":["It is a yellow star.","It is a star yellow.","It a yellow star is.","Yellow it is a star."],"correctIndex":0}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-10T11:15:00+05:00","ends_at":"2026-07-10T12:00:00+05:00","room":"101"},{"topic":"Моя семья","objective":"Научиться называть членов семьи и рассказывать о своей семье с помощью притяжательного местоимения my.","theory":"Сегодня мы поговорим о семье (family) — одной из самых важных тем, потому что мы часто рассказываем о своих родных.\n\nОсновные слова: mother/mum (мама), father/dad (папа), parents (родители), sister (сестра), brother (брат), grandmother/grandma (бабушка), grandfather/grandpa (дедушка), grandparents (бабушка и дедушка), son (сын), daughter (дочь), aunt (тётя), uncle (дядя), cousin (двоюродный брат/сестра).\n\nЧтобы рассказать о своей семье, используется притяжательное местоимение «my» (мой, моя, моё, мои). Оно не меняется в зависимости от рода или числа существительного — в этом его удобство! Например: «my mother» (моя мама), «my father» (мой папа), «my brothers» (мои братья).\n\nЕсть и другие притяжательные местоимения: «your» (твой), «his» (его), «her» (её), «our» (наш), «their» (их). Например: «This is my sister. Her name is Kate.»\n\nЧтобы представить членов семьи, часто используется конструкция «This is + my + член семьи»: «This is my mother. Her name is Olga.» «This is my brother. His name is Ivan.»\n\nОбрати внимание на разницу между «his» и «her»: «his» используется, когда речь о мальчике или мужчине (his name — его имя), а «her» — когда о девочке или женщине (her name — её имя).\n\nЧтобы сказать, сколько человек в семье, используется фраза «I have got...» (У меня есть...): «I have got two sisters and one brother.» А чтобы спросить у собеседника про его семью: «Have you got any brothers or sisters?»\n\nСлово «family» само по себе означает «семья» целиком: «I love my family.»\n\nПопробуй составить короткий рассказ о своей семье:\n«This is my family. This is my mother. This is my father. This is my sister. Her name is Anna. I love my family.»\n\nТакие простые рассказы помогают закрепить лексику и грамматику одновременно, а также подготовиться к следующей теме — глаголу «to be».","quiz":[{"question":"Как по-английски «мама»?","options":["father","sister","mother","brother"],"correctIndex":2},{"question":"Что означает «grandfather»?","options":["дедушка","бабушка","дядя","тётя"],"correctIndex":0},{"question":"Какое местоимение используется для мальчика («его имя»)?","options":["her","his","my","their"],"correctIndex":1},{"question":"Переведи: «This is my sister.»","options":["Это мой брат.","Это моя сестра.","Это моя мама.","Это мой папа."],"correctIndex":1},{"question":"Как сказать «У меня есть два брата»?","options":["I have got two brothers.","I has two brothers.","I am two brothers.","Two brothers have I."],"correctIndex":0},{"question":"Какое слово означает «родители»?","options":["parents","cousins","grandparents","sisters"],"correctIndex":0},{"question":"Как спросить «У тебя есть братья или сёстры?»","options":["What''s your name?","Have you got any brothers or sisters?","How old are you?","Is this your family?"],"correctIndex":1},{"question":"Переведи «her name is Kate».","options":["его зовут Кейт","её зовут Кейт","меня зовут Кейт","их зовут Кейт"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-13T10:20:00+05:00","ends_at":"2026-07-13T11:05:00+05:00","room":"101"},{"topic":"Глагол to be — Часть 1","objective":"Научиться правильно использовать формы глагола to be (am, is, are) в утвердительных предложениях.","theory":"Сегодня мы начинаем изучать один из самых важных глаголов английского языка — «to be» (быть). Он необычен тем, что не имеет одной формы, а меняется в зависимости от того, о ком мы говорим.\n\nУ глагола «to be» есть три формы в настоящем времени: am, is, are.\n\nФорма «am» используется только с местоимением «I» (я): «I am a student.» (Я ученик.) Часто «I am» сокращают до «I''m»: «I''m nine years old.»\n\nФорма «is» используется с местоимениями «he» (он), «she» (она), «it» (оно/это), а также с именами и названиями одного предмета или человека: «He is my brother.» «She is a teacher.» «It is a book.» «Tom is my friend.» Сокращённые формы: «He''s», «She''s», «It''s».\n\nФорма «are» используется с местоимениями «you» (ты/вы), «we» (мы), «they» (они), а также когда речь о нескольких предметах или людях: «You are my friend.» «We are students.» «They are books.» Сокращённые формы: «You''re», «We''re», «They''re».\n\nГлагол «to be» помогает рассказать о том, кто мы, какие мы, где мы находимся. Например:\n— Кто? «I am Anna.»\n— Какой/какая? «She is happy.» «The cat is small.»\n— Где? «We are at school.» «The book is on the table.»\n\nВажно запомнить простую таблицу-подсказку:\nI → am\nhe / she / it → is\nyou / we / they → are\n\nХороший способ запомнить — короткое правило-считалочка: «I am, he/she/it is, we/you/they are».\n\nПримеры полных предложений: «I am a good student.» «My mother is kind.» «My friends are funny.»\n\nГлагол «to be» — фундамент, на котором строится множество других конструкций английского языка, поэтому важно выучить его формы наизусть и уметь быстро подставлять нужную форму в зависимости от подлежащего. На следующем уроке мы научимся строить с этим глаголом вопросы и отрицания.","quiz":[{"question":"Какая форма глагола to be используется с «I»?","options":["is","are","am","be"],"correctIndex":2},{"question":"Какая форма используется с «she»?","options":["am","is","are","was"],"correctIndex":1},{"question":"Заполни пропуск: «We ___ students.»","options":["am","is","are","be"],"correctIndex":2},{"question":"Заполни пропуск: «He ___ my brother.»","options":["am","is","are","been"],"correctIndex":1},{"question":"Как правильно сократить «I am»?","options":["I''s","I''m","Im''","I''am"],"correctIndex":1},{"question":"Заполни пропуск: «They ___ my friends.»","options":["is","am","are","be"],"correctIndex":2},{"question":"Заполни пропуск: «It ___ a book.»","options":["am","are","is","be"],"correctIndex":2},{"question":"Какая форма используется с «you»?","options":["am","is","are","was"],"correctIndex":2}],"hasExternalService":true,"externalServiceType":"h5p","externalServiceTask":"Создай в H5P упражнение «Заполни пропуски»: выбрать правильную форму am/is/are в 6-8 предложениях.","starts_at":"2026-07-15T08:30:00+05:00","ends_at":"2026-07-15T09:15:00+05:00","room":"101"},{"topic":"Глагол to be — Часть 2","objective":"Научиться строить вопросительные и отрицательные предложения с глаголом to be.","theory":"На прошлом уроке мы выучили утвердительные формы глагола «to be»: am, is, are. Сегодня научимся задавать вопросы и говорить «нет» с помощью этого же глагола.\n\nНачнём с отрицаний. Чтобы сделать предложение отрицательным, после глагола to be добавляется слово «not» (не). Получается: am not, is not, are not. Часто эти формы сокращают: is not → isn''t, are not → aren''t. А «am not» в обычных предложениях не сокращают, говорят «I''m not».\n\nПримеры: «I am not tired.» или «I''m not tired.» (Я не устал.) «She is not at home.» или «She isn''t at home.» (Её нет дома.) «They are not ready.» или «They aren''t ready.» (Они не готовы.)\n\nТеперь про вопросы. Чтобы задать вопрос с глаголом to be, нужно поставить сам глагол (am/is/are) в самое начало предложения, перед подлежащим.\n\nСравни:\nУтверждение: «You are happy.» Вопрос: «Are you happy?»\nУтверждение: «She is a teacher.» Вопрос: «Is she a teacher?»\n\nНа такие вопросы отвечают кратко: «Yes, I am.» / «No, I''m not.»; «Yes, she is.» / «No, she isn''t.»; «Yes, they are.» / «No, they aren''t.»\n\nКроме вопросов «да/нет», есть специальные вопросы с вопросительными словами: «What» (что/какой), «Who» (кто), «Where» (где), «How» (как). После вопросительного слова тоже ставится глагол to be, а потом подлежащее: «What is your name?» «Who is that boy?» «Where are you?» «How old are you?»\n\nНа такие вопросы нельзя ответить просто «да» или «нет» — нужен развёрнутый ответ: «Where are you?» — «I am at school.»\n\nЗапомни главное правило: в вопросах с to be глагол «прыгает» в начало предложения перед подлежащим, а в отрицаниях после глагола добавляется «not». Потренируйся составлять свои вопросы и отрицания про себя, своих друзей и семью — это лучший способ запомнить новое правило.","quiz":[{"question":"Как правильно сократить «is not»?","options":["is''nt","isn''t","isnt''","in''t"],"correctIndex":1},{"question":"Выбери правильный вопрос.","options":["You are happy?","Are you happy?","Happy you are?","Are happy you?"],"correctIndex":1},{"question":"Как ответить «Нет» на вопрос «Is she a teacher?»","options":["No, she is.","No, she isn''t.","No, she not.","No, isn''t she."],"correctIndex":1},{"question":"Заполни пропуск: «___ they ready?»","options":["Is","Am","Are","Be"],"correctIndex":2},{"question":"Какое вопросительное слово используется, чтобы спросить «где»?","options":["What","Who","Where","How"],"correctIndex":2},{"question":"Выбери правильное отрицание: «They ___ at home.»","options":["isn''t","aren''t","am not","not are"],"correctIndex":1},{"question":"Как спросить «Сколько тебе лет?»","options":["What is your name?","How old are you?","Where are you?","Who are you?"],"correctIndex":1},{"question":"Выбери правильный краткий ответ «Да» на «Are you tired?»","options":["Yes, I am.","Yes, I is.","Yes, am I.","Yes, I are."],"correctIndex":0}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-16T11:15:00+05:00","ends_at":"2026-07-16T12:00:00+05:00","room":"101"},{"topic":"Животные — there is/there are","objective":"Научиться называть животных на английском языке и использовать конструкцию there is/there are для описания их местонахождения.","theory":"Сегодня мы поговорим о животных (animals) — домашних (pets) и диких (wild animals) — и научимся новой полезной конструкции: «there is / there are».\n\nСначала — словарь животных. Домашние животные: a dog (собака), a cat (кошка), a hamster (хомяк), a parrot (попугай), a rabbit (кролик), a fish (рыбка). Дикие животные: a lion (лев), a tiger (тигр), an elephant (слон), a monkey (обезьяна), a bear (медведь), a wolf (волк), a fox (лиса), a zebra (зебра).\n\nКонструкция «there is / there are» нужна, чтобы сказать, что где-то что-то есть, находится.\n\n«There is» используется с единственным числом: «There is a cat in the garden.» (В саду есть кошка.)\n\n«There are» используется со множественным числом: «There are two dogs in the yard.» (Во дворе две собаки.)\n\nПорядок слов: сначала «there is/are», потом сам предмет, а потом место, где он находится. Место вводится предлогами: «in» (в), «on» (на), «under» (под), «near» (около).\n\nПримеры: «There is a monkey in the tree.» «There are three birds on the roof.» «There is a mouse under the table.»\n\nЧтобы задать вопрос, «is/are» ставится перед словом «there»: «Is there a cat in the box?» «Are there any lions at the zoo?» Ответ: «Yes, there is.» / «No, there isn''t.» или «Yes, there are.» / «No, there aren''t.»\n\nЖивотных можно описывать и с помощью уже знакомого глагола to be и прилагательных: «The elephant is big.» «The rabbit is small.» «Monkeys are funny.»\n\nСовет: если существительное с окончанием «-s» (множественное число), нужно «are»; если без «-s» (единственное число), нужно «is».\n\nПопробуй составить свои предложения о зоопарке или о своих домашних животных: «I have got a cat. There is a cat in my house. Her name is Musya.» Эта конструкция очень часто встречается в описаниях картинок, поэтому важно хорошо её запомнить.","quiz":[{"question":"Как сказать «домашнее животное» на английском?","options":["wild animal","pet","zoo","farm"],"correctIndex":1},{"question":"Заполни пропуск: «___ a cat in the garden.»","options":["There is","There are","Is there","Are there"],"correctIndex":0},{"question":"Заполни пропуск: «___ two dogs in the yard.»","options":["There is","There are","Is there","There am"],"correctIndex":1},{"question":"Как по-английски «слон»?","options":["monkey","elephant","tiger","bear"],"correctIndex":1},{"question":"Выбери правильный вопрос.","options":["There is a lion at the zoo?","Is there a lion at the zoo?","There a lion is at the zoo?","Lion is there at the zoo?"],"correctIndex":1},{"question":"Переведи «The rabbit is small.»","options":["Кролик большой.","Кролик маленький.","Кролик быстрый.","Кролик смешной."],"correctIndex":1},{"question":"Какой предлог означает «под»?","options":["in","on","under","near"],"correctIndex":2},{"question":"Как ответить «Да» на вопрос «Are there any lions at the zoo?»","options":["Yes, there is.","Yes, there are.","Yes, it is.","Yes, they is."],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-17T11:15:00+05:00","ends_at":"2026-07-17T12:00:00+05:00","room":"101"},{"topic":"Части тела — have got/has got","objective":"Научиться называть части тела на английском языке и использовать конструкцию have got/has got для их описания.","theory":"Сегодня тема урока — части тела (parts of the body). Мы также познакомимся с новой полезной конструкцией «have got / has got», которая означает «иметь, обладать чем-либо».\n\nСначала выучим слова: a head (голова), hair (волосы), eyes (глаза), ears (уши), a nose (нос), a mouth (рот), teeth (зубы), a neck (шея), arms (руки от плеча до кисти), hands (кисти рук), legs (ноги), feet (ступни), fingers (пальцы рук).\n\nОбрати внимание: многие части тела парные (два глаза, два уха, две руки), поэтому такие слова обычно ставят во множественном числе: eyes, ears, hands, legs, feet.\n\nКонструкция «have got / has got» означает «иметь» и похожа на русское «у меня есть».\n\nС местоимениями I, you, we, they используется «have got»: «I have got blue eyes.» «You have got long hair.» «We have got two hands.»\n\nС местоимениями he, she, it используется «has got»: «He has got brown eyes.» «She has got curly hair.»\n\nВ разговорной речи их часто сокращают: «I''ve got», «She''s got», «He''s got».\n\nЧтобы построить отрицание, добавляется «not»: «I haven''t got green eyes.» «She hasn''t got short hair.»\n\nЧтобы задать вопрос, слово «have/has» ставится перед подлежащим: «Have you got a pet?» «Has she got long hair?»\n\nЧасти тела помогают описывать внешность: «I have got two eyes, two ears, one nose and one mouth. I have got ten fingers.»\n\nЧасти тела используются и в весёлой песенке «Head, Shoulders, Knees and Toes» (Голова, плечи, колени, пальцы ног), где нужно показывать части тела руками, называя их по-английски — отличный способ запомнить новые слова через движение.\n\nПопробуй выучить части тела, показывая их на себе, и составь пару предложений о себе с конструкцией «have got»: «I have got two hands and two legs. I have got brown hair.»","quiz":[{"question":"Как по-английски «глаза»?","options":["ears","eyes","nose","mouth"],"correctIndex":1},{"question":"Какая форма используется с «he»?","options":["have got","has got","am got","is got"],"correctIndex":1},{"question":"Заполни пропуск: «I ___ blue eyes.»","options":["has got","have got","is got","am got"],"correctIndex":1},{"question":"Как сказать «У неё длинные волосы»?","options":["She have got long hair.","She has got long hair.","She has long got hair.","She got has long hair."],"correctIndex":1},{"question":"Как по-английски «зубы»?","options":["teeth","hair","hands","feet"],"correctIndex":0},{"question":"Выбери правильный вопрос.","options":["You have got a pet?","Have got you a pet?","Have you got a pet?","Got you have a pet?"],"correctIndex":2},{"question":"Как сделать отрицание от «I have got»?","options":["I not have got","I have not got","I haven''t got","I hasn''t got"],"correctIndex":2},{"question":"Как по-английски «ступни»?","options":["hands","feet","arms","fingers"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"learningapps","externalServiceTask":"Создай упражнение «Подпиши части тела» (перетаскивание подписей) на картинке человека в LearningApps.","starts_at":"2026-07-20T10:20:00+05:00","ends_at":"2026-07-20T11:05:00+05:00","room":"101"},{"topic":"Еда и напитки — like/don''t like","objective":"Научиться называть еду и напитки на английском языке и выражать своё отношение к ним с помощью глагола like.","theory":"Сегодня тема — еда и напитки (food and drinks). Мы научимся называть продукты и рассказывать, что нам нравится, а что нет, с помощью глагола «like» (нравиться).\n\nСлова по теме еда: bread (хлеб), cheese (сыр), milk (молоко), an egg (яйцо), rice (рис), soup (суп), meat (мясо), fish (рыба), an apple (яблоко), a banana (банан), an orange (апельсин), a carrot (морковь), a tomato (помидор), a cake (торт), chocolate (шоколад), ice cream (мороженое). Напитки: water (вода), juice (сок), tea (чай), milk (молоко).\n\nЧтобы сказать, что нам нравится еда, используется конструкция «I like + еда»: «I like apples.» «I like chocolate.» Если нравится очень сильно, можно сказать «I love»: «I love ice cream!»\n\nЕсли не нравится, используется отрицание «I don''t like» (от «do not like»): «I don''t like fish.» «I don''t like carrots.»\n\nОбрати внимание: с местоимениями he, she, it вместо «don''t» используется «doesn''t»: «She doesn''t like milk.» «He likes bananas.» (заметь окончание «-s» у глагола likes при he/she/it!)\n\nЧтобы спросить, нравится ли собеседнику еда: «Do you like pizza?» Ответ: «Yes, I do.» или «No, I don''t.»\n\nПолезные фразы: «I am hungry.» (Я голоден.) «I am thirsty.» (Я хочу пить.) Чтобы вежливо попросить еду за столом: «Can I have some water, please?»\n\nДиалог-пример:\n— Do you like apples?\n— Yes, I do! I like apples very much.\n— Do you like fish?\n— No, I don''t. I don''t like fish, but I like chicken.\n\nПопробуй составить список из пяти продуктов, которые тебе нравятся, и пяти, которые не нравятся, используя «I like...» и «I don''t like...». Это отличная тренировка новой лексики и грамматики, которая поможет увереннее рассказывать о своих вкусах на английском языке.","quiz":[{"question":"Как сказать «Мне нравится шоколад»?","options":["I like chocolate.","I likes chocolate.","I am like chocolate.","I liked chocolate."],"correctIndex":0},{"question":"Как сказать «Мне не нравится рыба»?","options":["I not like fish.","I don''t like fish.","I doesn''t like fish.","I no like fish."],"correctIndex":1},{"question":"Какая форма используется с «she» в отрицании?","options":["don''t","doesn''t","isn''t","aren''t"],"correctIndex":1},{"question":"Заполни пропуск: «He ___ bananas.» (нравятся)","options":["like","likes","liking","is like"],"correctIndex":1},{"question":"Как спросить «Тебе нравится пицца?»","options":["You like pizza?","Do you like pizza?","Are you like pizza?","Like you pizza?"],"correctIndex":1},{"question":"Как по-английски «яблоко»?","options":["an apple","a banana","an orange","a carrot"],"correctIndex":0},{"question":"Как сказать «Я голоден»?","options":["I am thirsty.","I am hungry.","I like food.","I have food."],"correctIndex":1},{"question":"Какой краткий ответ означает «Нет, не нравится»?","options":["Yes, I do.","No, I don''t.","Yes, I like.","No, I doesn''t."],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-22T08:30:00+05:00","ends_at":"2026-07-22T09:15:00+05:00","room":"101"},{"topic":"Дни недели и распорядок дня","objective":"Научиться называть дни недели и рассказывать о распорядке дня, используя глаголы в Present Simple.","theory":"Сегодня мы выучим дни недели (days of the week) и научимся рассказывать о том, что мы делаем каждый день, используя время Present Simple (настоящее простое время).\n\nДни недели: Monday (понедельник), Tuesday (вторник), Wednesday (среда), Thursday (четверг), Friday (пятница), Saturday (суббота), Sunday (воскресенье). Обрати внимание: в английском языке все дни недели пишутся с заглавной буквы! Суббота и воскресенье вместе называются «the weekend» (выходные).\n\nЧтобы спросить, какой сегодня день: «What day is it today?» Ответ: «It is Monday.» Чтобы сказать, что что-то происходит по определённым дням, используется предлог «on»: «On Monday I have English.»\n\nPresent Simple используется, чтобы говорить о regular actions (регулярных действиях), привычках и распорядке дня: «I get up at seven o''clock.» (Я встаю в семь часов.)\n\nТипичные глаголы распорядка дня: get up (вставать), wash my face (умываться), have breakfast (завтракать), go to school (идти в школу), have lunch (обедать), do homework (делать домашнее задание), have dinner (ужинать), go to bed (ложиться спать).\n\nГлавное правило Present Simple: с I, you, we, they глагол остаётся в основной форме: «I get up at seven.» «They go to school.» А с he, she, it к глаголу добавляется окончание «-s» (или «-es»): «She gets up at seven.» «He goes to school.»\n\nПример распорядка дня: «I get up at 7 o''clock. I wash my face and have breakfast. I go to school at 8 o''clock. I have lunch at school. I do my homework at 5 o''clock. I have dinner at 7 o''clock. I go to bed at 9 o''clock.»\n\nО времени говорят так: «at + число + o''clock»: «at seven o''clock», «at nine o''clock».\n\nОтрицание строится с помощью «don''t»/«doesn''t»: «I don''t watch TV in the morning.» «She doesn''t get up early on Sunday.»\n\nПопробуй составить рассказ о своём распорядке дня, используя новые глаголы и дни недели: «On Monday I go to school. On Saturday I don''t go to school. I play with my friends.»","quiz":[{"question":"Как по-английски «понедельник»?","options":["Sunday","Monday","Tuesday","Friday"],"correctIndex":1},{"question":"Как называются суббота и воскресенье вместе?","options":["the weekday","the weekend","the holiday","the day off"],"correctIndex":1},{"question":"Заполни пропуск: «She ___ up at seven o''clock.»","options":["get","gets","getting","got"],"correctIndex":1},{"question":"Заполни пропуск: «I ___ to school at 8 o''clock.»","options":["go","goes","going","went"],"correctIndex":0},{"question":"Как сказать «Я не смотрю телевизор утром»?","options":["I not watch TV.","I don''t watch TV.","I doesn''t watch TV.","I am not watch TV."],"correctIndex":1},{"question":"Какой предлог используется с днями недели («в понедельник»)?","options":["in","at","on","of"],"correctIndex":2},{"question":"Как по-английски «делать домашнее задание»?","options":["go to bed","do homework","have breakfast","wash my face"],"correctIndex":1},{"question":"Какое окончание добавляется к глаголу с he/she/it в Present Simple?","options":["-ing","-ed","-s","-er"],"correctIndex":2}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-23T11:15:00+05:00","ends_at":"2026-07-23T12:00:00+05:00","room":"101"},{"topic":"Погода и времена года","objective":"Научиться описывать погоду и называть времена года на английском языке, используя конструкцию It is + прилагательное.","theory":"Это наш последний урок в этой серии, и сегодня мы поговорим о погоде (weather) и временах года (seasons) — темах, которые мы обсуждаем практически каждый день.\n\nВ английском языке четыре времени года: spring (весна), summer (лето), autumn/fall (осень — в британском английском чаще «autumn», в американском — «fall»), winter (зима).\n\nЧтобы описать погоду, используется уже знакомая конструкция «It is + прилагательное». Слово «it» здесь не переводится, оно нужно для правильной грамматической конструкции — как в русском «На улице...». Основные слова: sunny (солнечно), rainy (дождливо), cloudy (облачно), windy (ветрено), snowy (снежно), hot (жарко), cold (холодно), warm (тепло), cool (прохладно).\n\nПримеры: «It is sunny today.» «It is cold in winter.» «It is rainy in autumn.»\n\nЧтобы спросить о погоде: «What''s the weather like today?» Ответ: «It''s sunny and warm.»\n\nКаждое время года имеет свои особенности:\nSpring (весна): «It is warm. Flowers grow.»\nSummer (лето): «It is hot. The sun shines.»\nAutumn (осень): «It is cool and windy. Leaves fall.»\nWinter (зима): «It is cold and snowy. It snows.»\n\nМожно рассказать, что мы любим делать в разные времена года, используя глагол «like»: «I like summer because it is hot and I can swim.» «I like winter because it snows and I can make a snowman.»\n\nЧтобы спросить о любимом времени года: «What is your favourite season?» Ответ: «My favourite season is spring.»\n\nСегодняшний урок соединяет многое из того, что мы изучили раньше: конструкцию «It is», глагол «like», вопросительные слова «what». Попробуй составить рассказ о своём любимом времени года: «My favourite season is summer. It is hot and sunny. I like summer because I can swim and play outside.» Поздравляю — теперь у тебя есть крепкая база для дальнейшего изучения английского языка!","quiz":[{"question":"Сколько времён года в английском языке?","options":["3","4","5","2"],"correctIndex":1},{"question":"Как по-английски «солнечно»?","options":["rainy","cloudy","sunny","snowy"],"correctIndex":2},{"question":"Заполни пропуск: «___ cold in winter.»","options":["It is","It are","It am","It be"],"correctIndex":0},{"question":"Как спросить «Какая сегодня погода?»","options":["What is your name?","What''s the weather like today?","How old are you?","What day is it?"],"correctIndex":1},{"question":"Как по-английски «зима»?","options":["spring","summer","autumn","winter"],"correctIndex":3},{"question":"Переведи «It is windy.»","options":["Идёт снег.","Ветрено.","Солнечно.","Дождливо."],"correctIndex":1},{"question":"Как спросить о любимом времени года?","options":["What is your favourite season?","What''s the weather like?","What day is it?","Do you like winter?"],"correctIndex":0},{"question":"Переведи «I like summer because it is hot.»","options":["Мне нравится зима, потому что холодно.","Мне нравится лето, потому что жарко.","Мне нравится осень, потому что ветрено.","Мне нравится весна, потому что тепло."],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"h5p","externalServiceTask":"Создай в H5P упражнение «Сопоставь погоду с временем года» (drag the words) с картинками four seasons.","starts_at":"2026-07-24T11:15:00+05:00","ends_at":"2026-07-24T12:00:00+05:00","room":"101"}]'::jsonb)
    LOOP
      INSERT INTO public.lessons (group_id, subject_id, topic, title, description, status, starts_at, ends_at, started_at, ended_at, room, school_id)
      VALUES (
        v_group_id, v_subject_id, lesson_data->>'topic', lesson_data->>'topic', lesson_data->>'objective',
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN 'completed' ELSE 'scheduled' END,
        (lesson_data->>'starts_at')::timestamptz, (lesson_data->>'ends_at')::timestamptz,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'starts_at')::timestamptz ELSE NULL END,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'ends_at')::timestamptz ELSE NULL END,
        lesson_data->>'room', v_school_id
      )
      RETURNING id INTO v_lesson_id;

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, duration_min, school_id)
      VALUES (v_lesson_id, 1, 'middle', 'theory', 'presentation', lesson_data->>'topic', lesson_data->>'theory', 15, v_school_id);

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, duration_min, school_id)
      VALUES (v_lesson_id, 2, 'middle', 'task', 'quiz_qia', 'Проверь себя', 15, v_school_id)
      RETURNING id INTO v_stage_id;

      qpos := 0;
      FOR quiz_item IN SELECT * FROM jsonb_array_elements(lesson_data->'quiz')
      LOOP
        qpos := qpos + 1;
        INSERT INTO public.quiz_questions (stage_id, question_text, options, correct_option_index, position, points, time_per_question_seconds, school_id)
        VALUES (v_stage_id, quiz_item->>'question', quiz_item->'options', (quiz_item->>'correctIndex')::int, qpos, 1, 30, v_school_id);
      END LOOP;

      IF (lesson_data->>'hasExternalService')::boolean THEN
        INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, config, duration_min, school_id)
        VALUES (
          v_lesson_id, 3, 'middle', 'task', lesson_data->>'externalServiceType',
          lesson_data->>'externalServiceTask', lesson_data->>'externalServiceTask',
          jsonb_build_object('url',
            CASE lesson_data->>'externalServiceType'
              WHEN 'wokwi' THEN 'https://wokwi.com/projects/new/arduino-uno'
              WHEN 'codesandbox' THEN 'https://codesandbox.io/p/sandbox/vanilla'
              WHEN 'geogebra' THEN 'https://www.geogebra.org/classic'
              WHEN 'phet' THEN 'https://phet.colorado.edu/sims/html/forces-and-motion-basics/latest/forces-and-motion-basics_en.html'
              WHEN 'desmos' THEN 'https://www.desmos.com/calculator'
              WHEN 'blockly_games' THEN 'https://blockly.games/'
              WHEN 'visualgo' THEN 'https://visualgo.net/en'
              WHEN 'p5js' THEN 'https://editor.p5js.org/'
              WHEN 'excalidraw' THEN 'https://excalidraw.com/'
              WHEN 'learningapps' THEN 'https://learningapps.org/'
              WHEN 'sqlonline' THEN 'https://sqlime.org/'
              WHEN 'h5p' THEN 'https://h5p.eduos.snruz.uz/library'
              ELSE NULL
            END
          ),
          15, v_school_id
        );
      END IF;
    END LOOP;
  END IF;

  -- === 3-А класс | Программирование (8 уроков) ===
  SELECT id INTO v_group_id FROM public.groups WHERE name = '3-А класс';
  SELECT id INTO v_subject_id FROM public.subjects WHERE group_id = v_group_id AND name = 'Программирование';
  IF NOT EXISTS (SELECT 1 FROM public.lessons WHERE group_id = v_group_id AND subject_id = v_subject_id AND description IS NOT NULL) THEN
    FOR lesson_data IN SELECT * FROM jsonb_array_elements('[{"topic":"Что такое алгоритм","objective":"Научить детей объяснять, что такое алгоритм, и находить примеры алгоритмов в повседневной жизни.","theory":"Алгоритм — это чёткая последовательность шагов, которые нужно выполнить по порядку, чтобы решить задачу или достичь цели. Слово «алгоритм» произошло от имени учёного аль-Хорезми, который жил много веков назад и придумывал понятные правила для решения математических задач.\n\nАлгоритмы окружают нас каждый день, даже если мы этого не замечаем. Когда ты чистишь зубы, ты выполняешь алгоритм: взять зубную щётку, выдавить пасту, почистить зубы, прополоскать рот. Когда ты завязываешь шнурки, готовишь бутерброд или переходишь дорогу — ты тоже следуешь алгоритму.\n\nУ любого алгоритма есть важные свойства. Во-первых, у него есть начало и конец — понятно, с чего мы начинаем и чем заканчиваем. Во-вторых, шаги идут строго по порядку. Если поменять их местами, результат может получиться совсем другим или неправильным. Например, если сначала «намазать хлеб маслом», а потом «взять хлеб» — так не получится, потому что хлеб нужен раньше масла. В-третьих, каждый шаг должен быть понятным и чётким, без слов вроде «сделай что-нибудь» — исполнитель должен точно знать, что делать.\n\nВ программировании алгоритмы записывают для компьютера или робота, чтобы они могли выполнить задачу. Компьютер не умеет думать сам — он просто аккуратно выполняет все шаги, которые ему написал человек-программист. Поэтому программисту важно продумать алгоритм заранее, шаг за шагом, ничего не упустив.\n\nНапример, алгоритм перехода дороги может выглядеть так: 1) подойти к пешеходному переходу; 2) посмотреть налево; 3) посмотреть направо; 4) если машин нет — идти; 5) дойти до другой стороны. Если поменять шаги местами или пропустить один из них, может случиться беда.\n\nНа следующих уроках мы узнаем, кто такие исполнители алгоритмов, а также научимся использовать особые «инструменты» — циклы и условия, — которые помогают составлять более умные и короткие алгоритмы для компьютеров и роботов.","quiz":[{"question":"Что такое алгоритм?","options":["Случайный набор действий без порядка","Чёткая последовательность шагов для достижения цели","Название компьютерной программы для игр","Имя изобретателя первого компьютера"],"correctIndex":1},{"question":"Какой из примеров является алгоритмом?","options":["Любимый цвет ученика","Число учеников в классе","Порядок действий при чистке зубов","Название школы"],"correctIndex":2},{"question":"Почему важно соблюдать порядок шагов в алгоритме?","options":["Потому что так красивее выглядит","От порядка шагов может зависеть результат","Порядок шагов вообще не важен","Чтобы шагов получилось побольше"],"correctIndex":1},{"question":"Что обязательно должно быть у алгоритма?","options":["Только середина, без начала и конца","Начало и конец","Только конец","Ни начала, ни конца, ни середины"],"correctIndex":1},{"question":"Как называют того, кто выполняет шаги алгоритма?","options":["Автор","Зритель","Исполнитель","Судья"],"correctIndex":2},{"question":"В честь кого получил своё название алгоритм?","options":["В честь учёного аль-Хорезми","В честь Билла Гейтса","В честь Исаака Ньютона","В честь Альберта Эйнштейна"],"correctIndex":0},{"question":"Что может произойти, если нарушить порядок действий в алгоритме?","options":["Ничего страшного не случится","Результат может получиться неправильным","Алгоритм выполнится быстрее","Компьютер обязательно сломается"],"correctIndex":1},{"question":"Какой из шагов НЕ подходит для чёткого алгоритма?","options":["Налей воды в чайник","Сделай что-нибудь интересное","Включи чайник","Дождись, пока закипит вода"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-08T10:20:00+05:00","ends_at":"2026-07-08T11:05:00+05:00","room":"101"},{"topic":"Исполнитель и его команды","objective":"Научить детей понимать, что такое исполнитель, и составлять простые команды, которые он может выполнить.","theory":"На прошлом уроке мы узнали, что алгоритм — это последовательность шагов. А того, кто эти шаги выполняет, называют исполнителем. Исполнителем может быть человек, робот или компьютерная программа.\n\nУ каждого исполнителя есть свой набор команд, которые он умеет понимать и выполнять — это называется системой команд исполнителя. Например, робот-пылесос понимает команды «двигайся вперёд», «поверни налево», «поверни направо» и «остановись». Но он не поймёт команду «свари суп» — такой команды нет в его системе команд.\n\nВажная особенность исполнителя в том, что он не думает и не догадывается сам — он просто точно выполняет то, что ему сказали, даже если это приведёт к ошибке. Если робота попросить «иди вперёд», а впереди стена, он всё равно пойдёт вперёд и врежется, потому что не умеет думать самостоятельно — он лишь выполняет команды.\n\nПоэтому, когда мы составляем программу для исполнителя, мы должны быть очень внимательными и точными. Представим воображаемого робота-черепашку, который умеет выполнять всего четыре команды: «вперёд», «назад», «повернуть налево», «повернуть направо». Если мы хотим, чтобы черепашка нарисовала квадрат, нам нужно записать для неё команды по порядку: вперёд, повернуть направо, вперёд, повернуть направо, вперёд, повернуть направо, вперёд, повернуть направо. После четырёх таких пар команд черепашка вернётся в начальную точку, и у неё получится квадрат.\n\nВ программировании люди пишут такие команды для компьютеров на специальном языке программирования — компьютер является исполнителем программы, написанной человеком. Важно помнить: если программа написана с ошибкой, компьютер не исправит её сам — он выполнит именно то, что написано, даже если это неправильно.\n\nСегодня на практике мы попробуем управлять исполнителем в специальной программе, где нужно составлять команды из блоков, чтобы провести персонажа через лабиринт до цели.","quiz":[{"question":"Кто такой исполнитель?","options":["Тот, кто придумывает алгоритм","Тот, кто выполняет команды алгоритма","Тот, кто проверяет ошибки в тексте","Прибор для печати документов"],"correctIndex":1},{"question":"Как называется набор команд, понятных исполнителю?","options":["Список покупок","Система команд исполнителя","Расписание уроков","Таблица умножения"],"correctIndex":1},{"question":"Может ли исполнитель сам догадаться, что делать, если команда непонятна?","options":["Да, он всегда угадывает правильно","Нет, он выполняет только то, что ему точно сказано","Да, но только по выходным","Нет, он вообще ничего не делает никогда"],"correctIndex":1},{"question":"Что произойдёт, если роботу-пылесосу дать команду, которой нет в его системе команд?","options":["Он выполнит её по-своему","Он не сможет её выполнить","Он вызовет мастера","Он придумает новую команду сам"],"correctIndex":1},{"question":"Сколько раз нужно повторить пару команд «вперёд, повернуть направо», чтобы черепашка нарисовала квадрат?","options":["Один раз","Два раза","Три раза","Четыре раза"],"correctIndex":3},{"question":"Кто в компьютерной программе является исполнителем?","options":["Программист","Клавиатура","Компьютер, выполняющий программу","Монитор"],"correctIndex":2},{"question":"Что случится, если в программе для компьютера есть ошибка?","options":["Компьютер сам исправит ошибку","Компьютер выполнит именно то, что написано, даже если это неверно","Программа не запустится никогда","Ошибки в программах невозможны"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"blockly_games","externalServiceTask":"Пройдите первый уровень «Лабиринт» (Maze) в Blockly Games: составьте команды движения и поворотов, чтобы провести персонажа к цели.","starts_at":"2026-07-10T08:30:00+05:00","ends_at":"2026-07-10T09:15:00+05:00","room":"101"},{"topic":"Циклы — повторяем действия","objective":"Познакомить детей с понятием цикла и научить находить действия, которые повторяются.","theory":"Представь, что тебе нужно попрыгать 10 раз. Ты не будешь придумывать 10 разных команд «прыгни» — гораздо удобнее сказать «повтори прыжок 10 раз». Именно так работает цикл в программировании.\n\nЦикл — это команда, которая заставляет исполнителя повторить одно и то же действие или группу действий несколько раз, без того, чтобы писать эту команду много раз подряд.\n\nПредставим, что нашей черепашке-исполнителю нужно нарисовать квадрат. Без цикла пришлось бы написать восемь команд подряд: вперёд, направо, вперёд, направо, вперёд, направо, вперёд, направо. С помощью цикла эту программу можно записать намного короче: «Повторить 4 раза: вперёд, направо». Результат будет точно такой же, но программа станет короче и понятнее.\n\nВ жизни циклы тоже встречаются часто. Например, алгоритм мытья каждой тарелки из стопки можно описать так: «Повторять, пока тарелки не закончатся: взять тарелку, помыть её, поставить сушиться». Или: «Повторить 20 раз: сделать один шаг вперёд» — если нужно пройти определённое расстояние.\n\nЕсть два основных вида циклов, с которыми мы познакомимся:\n1. Цикл с известным числом повторений — когда мы заранее знаем, сколько раз нужно повторить действие (например, «повторить 5 раз»).\n2. Цикл «пока» — когда действие повторяется, пока выполняется какое-то условие (например, «пока в комнате не станет чисто — мыть пол»). С этим видом цикла мы познакомимся подробнее на следующем уроке.\n\nЦиклы делают программы короче и удобнее. Представь, что нужно нарисовать не квадрат, а звезду с сотней лучей — без цикла пришлось бы писать сотни строк с командами, а с циклом — всего пару строк: «повторить 100 раз: сделай линию, поверни».\n\nПрограммисты используют циклы очень часто, потому что компьютерам приходится повторять одинаковые действия тысячи и даже миллионы раз — например, проверять каждую букву в тексте или каждого ученика в списке класса.","quiz":[{"question":"Что такое цикл в программировании?","options":["Команда для остановки программы","Повторение одного и того же действия несколько раз","Рисунок в виде круга","Ошибка в программе"],"correctIndex":1},{"question":"Зачем нужны циклы?","options":["Чтобы программа была длиннее","Чтобы не писать одинаковые команды много раз подряд","Чтобы компьютер работал медленнее","Циклы не нужны в программировании"],"correctIndex":1},{"question":"Сколько команд понадобится, чтобы нарисовать квадрат без цикла (по одной команде на каждое действие)?","options":["2","4","8","16"],"correctIndex":2},{"question":"Как можно короче записать рисование квадрата с помощью цикла?","options":["Повторить 4 раза: вперёд, направо","Повторить 8 раз: вперёд","Повторить 1 раз: вперёд, направо","Повторить 4 раза: назад"],"correctIndex":0},{"question":"Какой пример из жизни лучше всего описывает цикл?","options":["Один раз поздороваться с учителем","Помыть по очереди каждую тарелку из стопки","Выбрать любимый цвет","Назвать своё имя"],"correctIndex":1},{"question":"Цикл с известным числом повторений — это когда...","options":["Мы заранее не знаем, сколько раз повторить действие","Мы заранее знаем, сколько раз нужно повторить действие","Действие повторяется бесконечно","Действие не повторяется вовсе"],"correctIndex":1},{"question":"Почему программисты часто используют циклы?","options":["Потому что компьютерам часто нужно повторять одинаковые действия много раз","Потому что это делает программу непонятной","Потому что без циклов компьютер не включится","Потому что так требуют правила школы"],"correctIndex":0}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-13T11:15:00+05:00","ends_at":"2026-07-13T12:00:00+05:00","room":"101"},{"topic":"Циклы — Часть 2","objective":"Научить детей применять циклы для более сложных задач и понимать цикл «пока» и вложенные повторения.","theory":"На прошлом уроке мы узнали, что цикл — это повторение действий, и научились использовать цикл с известным числом повторений, например «повторить 4 раза». Сегодня мы разберём цикл «пока» и узнаем, как можно вкладывать одно повторение внутрь другого.\n\nЦикл «пока» отличается тем, что мы заранее не знаем точное число повторений — действие повторяется до тех пор, пока выполняется определённое условие. Например: «Пока в кувшине есть вода — наливай её в стакан» или «Пока не прозвенел звонок — пиши в тетради». Как только условие перестаёт быть верным (вода в кувшине закончилась, или звонок прозвенел), цикл останавливается.\n\nСравним два вида циклов на примере уборки в комнате:\n— Цикл с числом повторений: «Подмети пол 5 раз» — мы точно знаем число повторений заранее.\n— Цикл «пока»: «Подметай пол, пока не станет чисто» — мы не знаем заранее, сколько раз придётся подмести, это зависит от того, насколько грязно.\n\nЕщё один интересный приём — вложенные повторения, когда внутри одного цикла находится другой цикл. Представь, что нужно нарисовать не один квадрат, а целый ряд из 3 одинаковых квадратов рядом друг с другом. Мы можем написать: «Повторить 3 раза: (повторить 4 раза: вперёд, направо), затем сдвинуться в сторону для следующего квадрата». Внутренний цикл рисует один квадрат, а внешний цикл повторяет это рисование три раза для трёх квадратов.\n\nТакой приём похож на то, как в жизни мы можем сказать: «Повторить для каждого дня недели: (повторить для каждого урока: открыть учебник, послушать учителя, закрыть учебник)». Здесь внутри цикла «для каждого урока» находится другой цикл «для каждого дня» — то есть один цикл вложен в другой.\n\nЦиклы значительно упрощают программы, особенно когда нужно повторять сложные узоры или обрабатывать много одинаковых объектов — например, проверить оценки всех учеников в классе или нарисовать красивый орнамент из множества одинаковых фигур. Сегодня на практике мы потренируемся использовать циклы для прохождения более сложного уровня-лабиринта, где без повторения действий не обойтись.","quiz":[{"question":"Чем цикл «пока» отличается от цикла с известным числом повторений?","options":["В цикле «пока» мы заранее не знаем точное число повторений","Цикл «пока» никогда не заканчивается","Цикл «пока» повторяется ровно 1 раз","Между ними нет никакой разницы"],"correctIndex":0},{"question":"Когда останавливается цикл «пока»?","options":["Через 10 секунд","Когда условие перестаёт выполняться","Никогда не останавливается","Когда исполнитель устанет"],"correctIndex":1},{"question":"Какой пример подходит для цикла «пока»?","options":["Подмети пол ровно 5 раз","Подметай пол, пока не станет чисто","Подмети пол 1 раз","Не подметай пол совсем"],"correctIndex":1},{"question":"Что такое вложенный цикл?","options":["Цикл, который находится внутри другого цикла","Цикл без повторений","Цикл, который никогда не запускается","Ошибка в программе"],"correctIndex":0},{"question":"В примере с рисованием трёх квадратов подряд, что делает внутренний цикл?","options":["Сдвигает исполнителя на новое место для следующего квадрата","Рисует один квадрат","Считает количество квадратов","Останавливает программу"],"correctIndex":1},{"question":"В примере с рисованием трёх квадратов, что делает внешний цикл?","options":["Рисует одну линию","Повторяет рисование квадрата три раза","Стирает рисунок","Ничего не делает"],"correctIndex":1},{"question":"Почему вложенные циклы полезны в программировании?","options":["Они помогают создавать сложные повторяющиеся узоры и структуры","Они замедляют работу компьютера","Они запрещены в программах для детей","Они делают программу короче, но неправильной"],"correctIndex":0}],"hasExternalService":true,"externalServiceType":"blockly_games","externalServiceTask":"Пройдите уровень с циклами «Повторение» (Repeat) в Blockly Games, используя блок «повторить», чтобы провести персонажа по длинному коридору с одинаковыми повторяющимися шагами.","starts_at":"2026-07-15T10:20:00+05:00","ends_at":"2026-07-15T11:05:00+05:00","room":"101"},{"topic":"Условия: если — то — иначе","objective":"Научить детей понимать условную конструкцию «если — то — иначе» и применять её для принятия решений в алгоритме.","theory":"До сих пор исполнитель у нас всегда выполнял действия одно за другим, без выбора. Но в жизни часто приходится принимать решения в зависимости от ситуации. Например: «Если идёт дождь — возьми зонт, иначе — надень кепку». Такая конструкция в программировании называется условием, а слова «если... то... иначе...» — это условная конструкция.\n\nУсловие — это проверка, верно ли какое-то утверждение (да или нет). Если условие верно (истинно), исполнитель делает одно действие. Если условие неверно (ложно), исполнитель делает другое действие или вообще ничего не делает.\n\nРассмотрим примеры:\n— «Если светофор зелёный — иди, иначе — стой». Здесь условие — «светофор зелёный».\n— «Если на улице холодно — надень куртку». Здесь нет части «иначе» — если условие не выполняется, ничего дополнительно не делаем.\n— «Если у тебя в тетради есть ошибка — исправь её, иначе — переходи к следующему заданию».\n\nВ программировании условие часто сравнивает числа или проверяет какой-то признак. Например: «Если возраст ученика больше 10 лет — то он учится в старшей школе, иначе — в начальной». Или для игрового персонажа: «Если жизней осталось 0 — то игра заканчивается, иначе — игра продолжается».\n\nУсловие можно совмещать и с циклами. Например, робот-пылесос может работать по такому правилу: «Пока не убрана вся комната: если впереди препятствие — повернуть, иначе — двигаться вперёд». Здесь внутри цикла «пока» находится условие «если — иначе», которое помогает роботу принимать решение на каждом шагу.\n\nУсловие — это как развилка на дороге: в зависимости от того, что верно в данный момент, исполнитель выбирает один из двух путей. Без условий все программы выполняли бы одни и те же действия всегда одинаково, независимо от ситуации. А с условиями программа становится «умнее» — она умеет реагировать на разные обстоятельства.\n\nСегодня мы потренируемся придумывать условия для разных жизненных ситуаций и научимся правильно их записывать в формате «если... то... иначе...», чтобы в будущих уроках использовать их вместе с алгоритмами и циклами для решения более сложных задач.","quiz":[{"question":"Что означает часть «если» в условной конструкции?","options":["Действие, которое выполняется всегда","Проверка, верно ли какое-то утверждение","Название цикла","Конец программы"],"correctIndex":1},{"question":"Что делает исполнитель, если условие оказалось верным (истинным)?","options":["Выполняет действие из части «то»","Выполняет действие из части «иначе»","Останавливает программу навсегда","Ничего не делает"],"correctIndex":0},{"question":"Что делает исполнитель, если условие оказалось неверным (ложным)?","options":["Всегда выполняет часть «то»","Выполняет часть «иначе» (если она есть)","Немедленно ломается","Повторяет действие 10 раз"],"correctIndex":1},{"question":"Какой пример правильно использует конструкцию «если — то — иначе»?","options":["Если идёт дождь — возьми зонт, иначе — надень кепку","Возьми зонт и кепку одновременно всегда","Зонт — это головной убор","Дождь идёт каждый день"],"correctIndex":0},{"question":"В примере про робота-пылесоса, что происходит, если впереди препятствие?","options":["Робот продолжает ехать прямо","Робот поворачивает","Робот выключается","Робот начинает цикл заново с самого начала"],"correctIndex":1},{"question":"Может ли условная конструкция быть без части «иначе»?","options":["Нет, «иначе» обязательно всегда","Да, если для ложного случая не нужно никакого действия","Нет, программа не запустится без «иначе»","Да, но только у роботов"],"correctIndex":1},{"question":"Почему условия делают программу «умнее»?","options":["Потому что программа умеет реагировать по-разному на разные ситуации","Потому что условия ускоряют работу компьютера в 100 раз","Потому что без условий программы вообще не работают","Потому что условия убирают все ошибки"],"correctIndex":0}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-17T08:30:00+05:00","ends_at":"2026-07-17T09:15:00+05:00","room":"101"},{"topic":"Переменные — коробочка для данных","objective":"Познакомить детей с понятием переменной как «именованной коробочки», в которой хранится информация, и научить приводить примеры её использования.","theory":"Представь коробочку с наклейкой, на которой написано имя — например, «Очки». В эту коробочку можно положить какое-то число, например 10. Если ты наберёшь ещё очков, ты можешь убрать старое число и положить в ту же коробочку новое, например 15. Такая «коробочка с именем, в которой хранится информация», в программировании называется переменной.\n\nПеременная — это место в памяти компьютера, у которого есть своё имя и в котором хранится какое-то значение: число, слово или другая информация. Значение внутри переменной можно менять — отсюда и название «переменная», то есть «изменяемая».\n\nРассмотрим примеры переменных из игр и жизни:\n— Переменная «Очки» хранит количество очков игрока. В начале игры в ней лежит 0, а после каждого правильного ответа число увеличивается.\n— Переменная «Жизни» хранит, сколько попыток осталось у игрока. Обычно в начале там лежит 3, а после ошибки становится на 1 меньше.\n— Переменная «Имя» может хранить не число, а слово — например, имя ученика.\n\nЗачем нужны переменные? Без них программе пришлось бы постоянно «забывать» всё, что произошло. Представь игру, в которой нет переменной «Очки» — тогда компьютер не смог бы запомнить, сколько очков набрал игрок, и не смог бы показать результат в конце игры. Благодаря переменным программа помнит важную информацию, пока работает.\n\nС переменными можно выполнять простые действия:\n— Положить в переменную значение (например, «Очки = 0» — это значит, что в начале переменная «Очки» получает значение 0).\n— Изменить значение (например, «Очки = Очки + 10» означает: возьми то, что было в «Очках», прибавь 10 и положи обратно в ту же переменную).\n— Проверить значение переменной в условии (например: «Если Жизни = 0, то игра заканчивается» — это соединяет переменные с условиями, которые мы изучали на прошлом уроке).\n\nПеременные, циклы и условия вместе — это основные «строительные кирпичики», из которых программисты создают даже самые сложные программы и игры. На следующем уроке мы попробуем собрать вместе всё, что уже изучили: алгоритмы, исполнителя, циклы и условия — в одной программе из блоков.","quiz":[{"question":"Что такое переменная в программировании?","options":["Постоянное число, которое нельзя изменить","Коробочка с именем, в которой хранится информация","Название языка программирования","Ошибка в программе"],"correctIndex":1},{"question":"Может ли значение внутри переменной меняться?","options":["Нет, оно всегда одно и то же","Да, поэтому она и называется «переменная»","Только один раз в жизни программы","Только по выходным дням"],"correctIndex":1},{"question":"Что хранит переменная «Очки» в игре?","options":["Имя игрока","Количество очков игрока","Цвет фона игры","Название игры"],"correctIndex":1},{"question":"Что означает запись «Очки = Очки + 10»?","options":["Стереть все очки и поставить 10","Прибавить 10 к текущему значению очков и сохранить результат обратно в переменную","Отнять 10 очков","Эта запись ничего не значит"],"correctIndex":1},{"question":"Может ли переменная хранить не число, а слово?","options":["Нет, только числа","Да, например, имя ученика","Нет, это запрещено в программировании","Только цвет"],"correctIndex":1},{"question":"Зачем программе нужны переменные?","options":["Чтобы программа могла запоминать важную информацию, пока работает","Чтобы программа работала медленнее","Переменные вообще не нужны","Чтобы усложнить программу без пользы"],"correctIndex":0},{"question":"Как переменные связаны с условиями, которые мы изучали ранее?","options":["Никак не связаны","Значение переменной можно проверять в условии, например «если Жизни = 0»","Переменные заменяют условия полностью","Условия удаляют переменные"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-20T11:15:00+05:00","ends_at":"2026-07-20T12:00:00+05:00","room":"101"},{"topic":"Собираем программу из блоков","objective":"Научить детей объединять алгоритм, цикл, условие и переменную в одну программу из блоков для решения комплексной задачи.","theory":"Мы уже познакомились с четырьмя важными «кирпичиками» программирования: алгоритмом (порядком шагов), исполнителем и его командами, циклом (повторением действий) и условием («если — то — иначе»), а также узнали про переменные — коробочки для хранения информации. Настало время собрать всё это вместе в одну настоящую программу, как делают программисты.\n\nПредставим задачу: нужно провести робота через комнату с несколькими препятствиями к выходу, при этом считать, сколько раз робот повернул. Такая программа могла бы выглядеть так (на человеческом языке):\n\n1) Завести переменную «Повороты» и положить в неё 0.\n2) Повторять, пока робот не дошёл до выхода:\n   — Если впереди препятствие — повернуть и прибавить 1 к переменной «Повороты»;\n   — Иначе — сделать шаг вперёд.\n3) Когда робот дошёл до выхода — сообщить, сколько было поворотов.\n\nСмотри, как здесь соединяются разные части: есть общий алгоритм (порядок из трёх шагов), внутри него цикл «повторять, пока…», внутри цикла — условие «если — иначе», а ещё используется переменная «Повороты», которая меняется каждый раз, когда робот поворачивает.\n\nИменно так устроены настоящие программы и игры: они редко состоят только из одного цикла или только из одного условия — обычно эти части соединяются вместе, как конструктор Лего, где из простых деталей собирают сложные модели. Программист как будто строитель: у него есть отдельные блоки (команды, циклы, условия, переменные), и из них он собирает целое здание — программу.\n\nОчень важно, собирая такую программу, проверять её по шагам — как поведёт себя исполнитель на каждом этапе, не запутался ли порядок, правильно ли записано условие. Хорошие программисты часто мысленно «играют за компьютер», представляя, как исполнитель будет выполнять каждую команду по очереди.\n\nСегодня на практике мы соберём собственную программу из блоков, объединив команды движения, цикл и условие, чтобы провести персонажа через уровень с препятствиями — точно так же, как в примере с роботом выше.","quiz":[{"question":"Сколько основных «кирпичиков» программирования мы изучили до этого урока?","options":["Два: алгоритм и цикл","Четыре: алгоритм, исполнитель с командами, цикл, условие (и переменные)","Один: только условие","Ни одного"],"correctIndex":1},{"question":"В примере с роботом, для чего нужна переменная «Повороты»?","options":["Чтобы считать, сколько раз робот повернул","Чтобы остановить робота навсегда","Чтобы нарисовать комнату","Переменная в этом примере не используется"],"correctIndex":0},{"question":"Что происходит в примере, если впереди препятствие?","options":["Робот останавливается навсегда","Робот поворачивает и прибавляет 1 к переменной «Повороты»","Робот идёт вперёд, не обращая внимания","Ничего не происходит"],"correctIndex":1},{"question":"Какая часть программы отвечает за то, что действия повторяются, пока робот не дойдёт до выхода?","options":["Условие","Переменная","Цикл «повторять, пока»","Команда «стоп»"],"correctIndex":2},{"question":"С чем сравнивается сборка программы из блоков в тексте урока?","options":["Со строительством из конструктора Лего","С приготовлением супа","С игрой в футбол","С рисованием красками"],"correctIndex":0},{"question":"Зачем программисту мысленно «играть за компьютер», проверяя программу по шагам?","options":["Чтобы развлечься","Чтобы найти ошибки и убедиться, что исполнитель выполнит задачу правильно","Это вообще не нужно делать","Чтобы программа работала медленнее"],"correctIndex":1},{"question":"Что из перечисленного используется в примере программы про робота одновременно?","options":["Только цикл, без условия и переменной","Алгоритм, цикл, условие и переменная вместе","Только переменная, без цикла","Ничего из изученного ранее"],"correctIndex":1}],"hasExternalService":true,"externalServiceType":"blockly_games","externalServiceTask":"Пройдите продвинутый уровень «Лабиринт» в Blockly Games, объединив команды движения, блок цикла «повторить» и блок условия «если-иначе», чтобы провести персонажа мимо всех препятствий до цели.","starts_at":"2026-07-22T10:20:00+05:00","ends_at":"2026-07-22T11:05:00+05:00","room":"101"},{"topic":"Рисуем узоры с помощью кода","objective":"Научить детей применять алгоритм, циклы и команды движения исполнителя-черепашки для рисования простых узоров.","theory":"Сегодня мы применим всё, что узнали на предыдущих уроках, чтобы создать красивые узоры с помощью кода. Для этого нам поможет воображаемый исполнитель — черепашка, у которой есть маленький «карандаш». Когда черепашка двигается вперёд, она оставляет за собой линию на экране, как будто рисует.\n\nУ черепашки есть простой набор команд: «вперёд на N шагов», «повернуть на угол» (например, на 90 градусов — это прямой угол, как у квадрата, а другой угол даёт другую фигуру), «поднять карандаш» (двигаться, не рисуя) и «опустить карандаш» (снова начать рисовать).\n\nВспомним, как мы рисовали квадрат с помощью цикла: «Повторить 4 раза: вперёд, повернуть на 90 градусов». А что, если мы захотим нарисовать треугольник? У равностороннего треугольника три одинаковые стороны, и для того, чтобы черепашка вернулась в начало, ей нужно поворачивать на угол в 120 градусов после каждой стороны. Программа будет выглядеть так: «Повторить 3 раза: вперёд, повернуть на 120 градусов».\n\nА если мы хотим нарисовать узор из пяти одинаковых квадратов по кругу — по одному повёрнутому чуть иначе? Тогда пригодятся вложенные циклы, которые мы изучали ранее: внешний цикл повторяет рисование квадрата пять раз, а перед каждым новым квадратом черепашка немного поворачивается, чтобы получился красивый узор-звезда.\n\nОбрати внимание, как здесь соединяются знакомые нам темы: алгоритм задаёт общий план рисунка, цикл избавляет нас от повторения одинаковых команд, а команды исполнителя («вперёд», «повернуть») — это те самые точные шаги, которые понимает черепашка.\n\nРисование через код — это не просто красиво, это ещё и очень полезный навык: художники, дизайнеры игр и создатели мультфильмов часто используют программирование, чтобы рисовать сложные узоры, которые было бы очень трудно и долго нарисовать вручную, линия за линией.\n\nПоздравляем — за восемь уроков ты прошёл путь от простого понятия алгоритма до умения комбинировать алгоритмы, циклы, условия, переменные и команды исполнителя, чтобы создавать собственные небольшие программы!","quiz":[{"question":"Что делает черепашка-исполнитель, когда двигается вперёд с опущенным карандашом?","options":["Ничего не происходит","Оставляет за собой линию (рисует)","Стирает предыдущий рисунок","Останавливается навсегда"],"correctIndex":1},{"question":"Сколько раз нужно повторить действие «вперёд, повернуть на 90 градусов», чтобы получить квадрат?","options":["2 раза","3 раза","4 раза","6 раз"],"correctIndex":2},{"question":"На какой угол нужно поворачивать черепашку, чтобы нарисовать равносторонний треугольник?","options":["45 градусов","90 градусов","120 градусов","180 градусов"],"correctIndex":2},{"question":"Что делает команда «поднять карандаш»?","options":["Черепашка начинает двигаться, не оставляя линии","Черепашка рисует более толстую линию","Черепашка останавливается навсегда","Черепашка меняет цвет линии"],"correctIndex":0},{"question":"Зачем нужны вложенные циклы при рисовании узора из нескольких одинаковых квадратов по кругу?","options":["Они не нужны для такого узора","Внешний цикл повторяет рисование квадрата несколько раз, а внутренний рисует каждый квадрат","Только внутренний цикл нужен, внешний не используется","Вложенные циклы всегда рисуют треугольники"],"correctIndex":1},{"question":"Кто в реальной жизни использует программирование для рисования сложных узоров?","options":["Только программисты компьютерных вирусов","Художники, дизайнеры игр и создатели мультфильмов","Только водители автобусов","Никто не использует программирование для рисования"],"correctIndex":1},{"question":"Какие темы из предыдущих уроков используются при рисовании узоров через код?","options":["Только цвет и вкус","Алгоритм, цикл и команды исполнителя","Только имена учеников","Ничего из изученного раньше не используется"],"correctIndex":1}],"hasExternalService":false,"externalServiceType":null,"externalServiceTask":null,"starts_at":"2026-07-24T08:30:00+05:00","ends_at":"2026-07-24T09:15:00+05:00","room":"101"}]'::jsonb)
    LOOP
      INSERT INTO public.lessons (group_id, subject_id, topic, title, description, status, starts_at, ends_at, started_at, ended_at, room, school_id)
      VALUES (
        v_group_id, v_subject_id, lesson_data->>'topic', lesson_data->>'topic', lesson_data->>'objective',
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN 'completed' ELSE 'scheduled' END,
        (lesson_data->>'starts_at')::timestamptz, (lesson_data->>'ends_at')::timestamptz,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'starts_at')::timestamptz ELSE NULL END,
        CASE WHEN (lesson_data->>'starts_at')::timestamptz < '2026-07-08+05'::timestamptz THEN (lesson_data->>'ends_at')::timestamptz ELSE NULL END,
        lesson_data->>'room', v_school_id
      )
      RETURNING id INTO v_lesson_id;

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, duration_min, school_id)
      VALUES (v_lesson_id, 1, 'middle', 'theory', 'presentation', lesson_data->>'topic', lesson_data->>'theory', 15, v_school_id);

      INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, duration_min, school_id)
      VALUES (v_lesson_id, 2, 'middle', 'task', 'quiz_qia', 'Проверь себя', 15, v_school_id)
      RETURNING id INTO v_stage_id;

      qpos := 0;
      FOR quiz_item IN SELECT * FROM jsonb_array_elements(lesson_data->'quiz')
      LOOP
        qpos := qpos + 1;
        INSERT INTO public.quiz_questions (stage_id, question_text, options, correct_option_index, position, points, time_per_question_seconds, school_id)
        VALUES (v_stage_id, quiz_item->>'question', quiz_item->'options', (quiz_item->>'correctIndex')::int, qpos, 1, 30, v_school_id);
      END LOOP;

      IF (lesson_data->>'hasExternalService')::boolean THEN
        INSERT INTO public.lesson_stages (lesson_id, position, stage_role, stage_type, content_type, title, description, config, duration_min, school_id)
        VALUES (
          v_lesson_id, 3, 'middle', 'task', lesson_data->>'externalServiceType',
          lesson_data->>'externalServiceTask', lesson_data->>'externalServiceTask',
          jsonb_build_object('url',
            CASE lesson_data->>'externalServiceType'
              WHEN 'wokwi' THEN 'https://wokwi.com/projects/new/arduino-uno'
              WHEN 'codesandbox' THEN 'https://codesandbox.io/p/sandbox/vanilla'
              WHEN 'geogebra' THEN 'https://www.geogebra.org/classic'
              WHEN 'phet' THEN 'https://phet.colorado.edu/sims/html/forces-and-motion-basics/latest/forces-and-motion-basics_en.html'
              WHEN 'desmos' THEN 'https://www.desmos.com/calculator'
              WHEN 'blockly_games' THEN 'https://blockly.games/'
              WHEN 'visualgo' THEN 'https://visualgo.net/en'
              WHEN 'p5js' THEN 'https://editor.p5js.org/'
              WHEN 'excalidraw' THEN 'https://excalidraw.com/'
              WHEN 'learningapps' THEN 'https://learningapps.org/'
              WHEN 'sqlonline' THEN 'https://sqlime.org/'
              WHEN 'h5p' THEN 'https://h5p.eduos.snruz.uz/library'
              ELSE NULL
            END
          ),
          15, v_school_id
        );
      END IF;
    END LOOP;
  END IF;

END $$;
